import type { PromptExploderCaseResolverPartyCandidate } from '@/shared/contracts/prompt-exploder';
import {
  normalizeCaseResolverComparable,
  composeCandidateStreetNumber,
  extractCaseResolverDocumentDate,
} from '@/features/case-resolver/public';

import type { CaseResolverCaptureProposalState, CaseResolverCaptureCleanupResult } from './types';

const CAPTURE_HTML_TAG_PATTERN = /<[^>]+>/;
const CAPTURE_POSTAL_CODE_PATTERN = /\b\d{2}-\d{3}\b/;
const CAPTURE_COUNTRY_HINTS = [
  'polska',
  'poland',
  'niemcy',
  'germany',
  'france',
  'francja',
  'spain',
  'hiszpania',
  'italy',
  'wlochy',
  'uk',
  'england',
];
const CAPTURE_STREET_HINT_PATTERN =
  /\b(ul\.?|ulica|street|st\.?|avenue|ave\.?|road|rd\.?|al\.?|aleja|plac|pl\.)\b/i;
const CAPTURE_PARTY_LABEL_LINE_PATTERN =
  /^(addresser|from|od|nadawca|sender|wnioskodawca|addressee|to|do|adresat|recipient|odbiorca|organ)\s*[:-]?$/i;
const CAPTURE_HEADER_LINE_SEARCH_LIMIT = 140;
const CAPTURE_HEADER_BLOCK_EXTRA_SPAN = 6;

import {
  isLikelyCapturePersonNameLine,
  isLikelyCaptureOrganizationLine,
  normalizeCaptureTextLine,
} from '@/features/case-resolver/services/capture';

const isLikelyCaptureAddressContinuationLine = (line: string): boolean => {
  const trimmed = line.trim();
  if (trimmed.length === 0) return false;
  if (extractCaseResolverDocumentDate(trimmed)) return false;
  if (trimmed.length > 100) return false;
  const normalized = normalizeCaseResolverComparable(trimmed);
  const wordCount = trimmed.split(/\s+/).filter((token: string): boolean => token.length > 0).length;
  if (wordCount > 10) return false;
  if (CAPTURE_POSTAL_CODE_PATTERN.test(trimmed)) return true;
  if (/\d/.test(trimmed)) return true;
  if (CAPTURE_STREET_HINT_PATTERN.test(trimmed)) return true;
  return CAPTURE_COUNTRY_HINTS.some((hint: string): boolean => normalized !== null && normalized === hint);
};

const isLikelyCaptureHeaderPartyLine = (line: string): boolean => {
  const trimmed = line.trim();
  if (trimmed.length === 0) return false;
  if (extractCaseResolverDocumentDate(trimmed)) return false;
  if (trimmed.length > 90) return false;
  const wordCount = trimmed.split(/\s+/).filter((token: string): boolean => token.length > 0).length;
  if (wordCount > 10) return false;
  if (isLikelyCaptureAddressContinuationLine(trimmed)) return true;
  if (CAPTURE_PARTY_LABEL_LINE_PATTERN.test(trimmed)) return true;
  if (isLikelyCapturePersonNameLine(trimmed)) return true;
  if (isLikelyCaptureOrganizationLine(trimmed)) return true;
  return false;
};

const decodeBasicCaptureHtmlEntities = (value: string): string =>
  value
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, '\'');

const normalizeCaptureSourceText = (
  sourceText: string
): { plainText: string; sourceWasHtml: boolean } => {
  const sourceWasHtml = CAPTURE_HTML_TAG_PATTERN.test(sourceText);
  if (!sourceWasHtml) {
    return {
      plainText: sourceText,
      sourceWasHtml: false,
    };
  }

  const plainText = decodeBasicCaptureHtmlEntities(
    sourceText
      .replace(/\r\n/g, '\n')
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/(p|div|li|h1|h2|h3|h4|h5|h6|tr|section|article|blockquote)>/gi, '\n')
      .replace(/<li[^>]*>/gi, '')
      .replace(/<[^>]*>/g, '')
  );

  return {
    plainText,
    sourceWasHtml: true,
  };
};

const splitCaptureTextLines = (sourceText: string): string[] => sourceText.split(/\r?\n/);

const compactCaptureTextLines = (lines: string[]): string[] => {
  const compact: string[] = [];
  let previousBlank = false;
  lines.forEach((line: string): void => {
    const isBlank = line.trim().length === 0;
    if (isBlank && previousBlank) return;
    compact.push(line);
    previousBlank = isBlank;
  });
  while (compact.length > 0 && compact[0]?.trim().length === 0) {
    compact.shift();
  }
  while (compact.length > 0 && compact[compact.length - 1]?.trim().length === 0) {
    compact.pop();
  }
  return compact;
};

const resolveCaptureHeaderSearchLimit = (sourceLines: string[]): number => {
  const fallback = Math.min(sourceLines.length, CAPTURE_HEADER_LINE_SEARCH_LIMIT);
  if (fallback === 0) return 0;

  let blankRun = 0;
  for (let index = 0; index < fallback; index += 1) {
    const line = sourceLines[index]?.trim() ?? '';
    if (!line) {
      blankRun += 1;
      if (blankRun >= 2) {
        return Math.max(0, index - 1);
      }
      continue;
    }

    blankRun = 0;
    const wordCount = line.split(/\s+/).filter(Boolean).length;
    const looksLikeBodyParagraph =
      index >= 6 && wordCount >= 12 && line.length >= 70 && /[.;:]/.test(line);
    if (looksLikeBodyParagraph) {
      return index;
    }
  }

  return fallback;
};

const collectCandidateNameLines = (
  candidate: PromptExploderCaseResolverPartyCandidate
): string[] => {
  const lines = new Set<string>();
  const pushLine = (value: string | undefined): void => {
    if (!value) return;
    const normalized = value.trim();
    if (!normalized) return;
    lines.add(normalized);
  };

  pushLine(candidate.displayName);
  pushLine(candidate.organizationName);
  const personFullName = [
    candidate.firstName ?? '',
    candidate.middleName ?? '',
    candidate.lastName ?? '',
  ]
    .map((part: string): string => part.trim())
    .filter(Boolean)
    .join(' ')
    .trim();
  const personShortName = [candidate.firstName ?? '', candidate.lastName ?? '']
    .map((part: string): string => part.trim())
    .filter(Boolean)
    .join(' ')
    .trim();
  pushLine(personFullName);
  pushLine(personShortName);
  return [...lines];
};

const collectCandidateAddressLines = (
  candidate: PromptExploderCaseResolverPartyCandidate
): string[] => {
  const lines = new Set<string>();
  const pushLine = (value: string | undefined): void => {
    if (!value) return;
    const normalized = value.trim();
    if (!normalized) return;
    lines.add(normalized);
  };

  const street = candidate.street?.trim() ?? '';
  const streetNumber = candidate.streetNumber?.trim() ?? '';
  const houseNumber = candidate.houseNumber?.trim() ?? '';
  const postalCode = candidate.postalCode?.trim() ?? '';
  const city = candidate.city?.trim() ?? '';
  const country = candidate.country?.trim() ?? '';

  if (street.length > 0 && streetNumber.length > 0 && houseNumber.length > 0) {
    pushLine(`${street} ${streetNumber}/${houseNumber}`);
  }
  if (street.length > 0 && streetNumber.length > 0) {
    pushLine(`${street} ${streetNumber}`);
  }
  if (street.length > 0 && houseNumber.length > 0 && streetNumber.length === 0) {
    pushLine(`${street} ${houseNumber}`);
  }
  if (postalCode.length > 0 && city.length > 0) {
    pushLine(`${postalCode} ${city}`);
  }
  pushLine(country);

  const normalizedStreet = normalizeCaptureTextLine(street);
  const normalizedPostalCode = normalizeCaptureTextLine(postalCode);
  const normalizedCountry = normalizeCaptureTextLine(country);

  (candidate.rawText ?? '')
    .split(/\r?\n/)
    .map((line: string): string => line.trim())
    .filter((line: string): boolean => line.length > 0)
    .forEach((line: string): void => {
      const normalizedLine = normalizeCaptureTextLine(line);
      if (normalizedLine.length === 0) return;
      if (normalizedStreet !== null && normalizedLine.includes(normalizedStreet)) {
        pushLine(line);
        return;
      }
      if (normalizedPostalCode !== null && normalizedLine.includes(normalizedPostalCode)) {
        pushLine(line);
        return;
      }
      if (normalizedCountry !== null && normalizedLine === normalizedCountry) {
        pushLine(line);
      }
    });

  return [...lines];
};

const buildCandidateComparableText = (
  candidate: PromptExploderCaseResolverPartyCandidate
): string => {
  const parts = [
    candidate.rawText,
    candidate.displayName,
    candidate.organizationName,
    candidate.firstName,
    candidate.middleName,
    candidate.lastName,
    candidate.street,
    composeCandidateStreetNumber(candidate),
    candidate.city,
    candidate.postalCode,
    candidate.country,
  ]
    .filter((value: string | undefined): value is string => Boolean(value?.trim()))
    .map((value: string): string => normalizeCaptureTextLine(value))
    .filter(Boolean);
  return parts.join(' ').trim();
};

const candidateLikelyContainsSourceLine = (
  candidateComparableText: string,
  sourceLineKey: string
): boolean => {
  if (!candidateComparableText || !sourceLineKey) return false;
  if (candidateComparableText.includes(sourceLineKey)) return true;

  const meaningfulTokens = sourceLineKey
    .split(' ')
    .map((token: string): string => token.trim())
    .filter((token: string): boolean => token.length >= 3);
  if (meaningfulTokens.length === 0) return false;

  const matchedTokenCount = meaningfulTokens.reduce(
    (count: number, token: string): number =>
      candidateComparableText.includes(token) ? count + 1 : count,
    0
  );
  return matchedTokenCount >= 2 && matchedTokenCount === meaningfulTokens.length;
};

const collectCandidateRawHeaderBlockLines = (
  candidate: PromptExploderCaseResolverPartyCandidate
): string[] =>
  (candidate.rawText ?? '')
    .split(/\r?\n/)
    .map((line: string): string => line.trim())
    .filter((line: string): boolean => isLikelyCaptureHeaderPartyLine(line))
    .slice(0, 8);

const collectCandidateRemovalLineKeys = (
  candidate: PromptExploderCaseResolverPartyCandidate
): Set<string> => {
  const keys = new Set<string>();
  const pushLine = (line: string): void => {
    const key = normalizeCaptureTextLine(line);
    if (!key) return;
    keys.add(key);
  };

  collectCandidateNameLines(candidate).forEach(pushLine);
  collectCandidateAddressLines(candidate).forEach(pushLine);
  collectCandidateRawHeaderBlockLines(candidate).forEach(pushLine);

  return keys;
};

const findOrderedCaptureBlockIndices = (input: {
  sourceLineKeys: string[];
  blockLineKeys: string[];
  headerSearchLimit: number;
  excludedIndexes?: Set<number> | undefined;
}): number[] | null => {
  const { sourceLineKeys, blockLineKeys, headerSearchLimit, excludedIndexes } = input;

  const sanitizedBlock = blockLineKeys.filter(Boolean);
  if (sanitizedBlock.length < 1) return null;
  if (headerSearchLimit <= 0) return null;

  let bestMatch: number[] | null = null;
  let bestSpan = Number.POSITIVE_INFINITY;

  for (let start = 0; start < headerSearchLimit; start += 1) {
    if (excludedIndexes?.has(start)) continue;
    if (sourceLineKeys[start] !== sanitizedBlock[0]) continue;
    const matchIndexes: number[] = [start];
    let blockIndex = 1;

    for (
      let sourceIndex = start + 1;
      sourceIndex < headerSearchLimit && blockIndex < sanitizedBlock.length;
      sourceIndex += 1
    ) {
      if (excludedIndexes?.has(sourceIndex)) continue;
      if (sourceLineKeys[sourceIndex] !== sanitizedBlock[blockIndex]) continue;
      matchIndexes.push(sourceIndex);
      blockIndex += 1;
    }

    if (blockIndex !== sanitizedBlock.length) continue;
    const span = (matchIndexes[matchIndexes.length - 1] ?? start) - start;
    const maxSpan = sanitizedBlock.length + CAPTURE_HEADER_BLOCK_EXTRA_SPAN;
    if (span > maxSpan) continue;
    if (span < bestSpan) {
      bestSpan = span;
      bestMatch = matchIndexes;
    }
  }

  return bestMatch;
};

const stripAcceptedAddressLinesFromTextDetailed = (
  sourceText: string,
  proposalState: CaseResolverCaptureProposalState | null
): {
  text: string;
  removedLineCount: number;
  removedByRole: { addresser: number; addressee: number };
} => {
  if (!sourceText || !proposalState) {
    return {
      text: sourceText,
      removedLineCount: 0,
      removedByRole: {
        addresser: 0,
        addressee: 0,
      },
    };
  }

  const sourceLines = splitCaptureTextLines(sourceText);
  const sourceLineKeys = sourceLines.map((line: string): string => normalizeCaptureTextLine(line));
  const headerSearchLimit = resolveCaptureHeaderSearchLimit(sourceLines);
  if (headerSearchLimit <= 0) {
    return {
      text: sourceText,
      removedLineCount: 0,
      removedByRole: {
        addresser: 0,
        addressee: 0,
      },
    };
  }

  const removalIndexes = new Set<number>();
  const removedByRole = {
    addresser: 0,
    addressee: 0,
  };
  const removedIndexesByRole = {
    addresser: new Set<number>(),
    addressee: new Set<number>(),
  };
  let changed = false;
  const markForRemoval = (index: number, role: 'addresser' | 'addressee'): void => {
    if (removalIndexes.has(index)) return;
    removalIndexes.add(index);
    removedIndexesByRole[role].add(index);
    removedByRole[role] += 1;
    changed = true;
  };

  (
    [
      ['addresser', proposalState.addresser],
      ['addressee', proposalState.addressee],
    ] as const
  ).forEach(([role, proposal]) => {
    if (!proposal || proposal.action === 'ignore' || proposal.action === 'keepText') return;

    const beforeCount = removedByRole[role];
    const candidateComparableText = buildCandidateComparableText(proposal.candidate);
    const blockLineKeys = collectCandidateRawHeaderBlockLines(proposal.candidate)
      .map((line: string): string => normalizeCaptureTextLine(line))
      .filter(Boolean);
    const blockIndexes = findOrderedCaptureBlockIndices({
      sourceLineKeys,
      blockLineKeys,
      headerSearchLimit,
      excludedIndexes: removalIndexes,
    });
    if (blockIndexes) {
      blockIndexes.forEach((index: number): void => {
        markForRemoval(index, role);
      });
    }

    const pendingRemovalKeys = collectCandidateRemovalLineKeys(proposal.candidate);
    for (let index = 0; index < headerSearchLimit; index += 1) {
      if (pendingRemovalKeys.size === 0) break;
      if (removalIndexes.has(index)) continue;
      const key = sourceLineKeys[index];
      if (!key || !pendingRemovalKeys.has(key)) continue;
      markForRemoval(index, role);
      pendingRemovalKeys.delete(key);
    }

    if (candidateComparableText) {
      for (let index = 0; index < headerSearchLimit; index += 1) {
        if (removalIndexes.has(index)) continue;
        const line = sourceLines[index] ?? '';
        const trimmed = line.trim();
        if (!trimmed) continue;
        const key = sourceLineKeys[index];
        if (!key) continue;
        if (!candidateLikelyContainsSourceLine(candidateComparableText, key)) continue;
        if (
          !isLikelyCaptureHeaderPartyLine(trimmed) &&
          !isLikelyCaptureAddressContinuationLine(trimmed)
        ) {
          continue;
        }
        markForRemoval(index, role);
      }
    }

    const nameLineKeys = new Set(
      collectCandidateNameLines(proposal.candidate)
        .map((line: string): string => normalizeCaptureTextLine(line))
        .filter(Boolean)
    );

    let anchorIndex = -1;
    if (nameLineKeys.size > 0) {
      for (let index = 0; index < headerSearchLimit; index += 1) {
        if (removalIndexes.has(index)) continue;
        const key = sourceLineKeys[index];
        if (!key || !nameLineKeys.has(key)) continue;
        anchorIndex = index;
        break;
      }
    }
    if (anchorIndex < 0) {
      const roleRemovedIndexes = [...removedIndexesByRole[role]].sort(
        (left: number, right: number): number => left - right
      );
      anchorIndex = roleRemovedIndexes[0] ?? -1;
    }
    if (anchorIndex < 0 && candidateComparableText) {
      for (let index = 0; index < headerSearchLimit; index += 1) {
        if (removalIndexes.has(index)) continue;
        const line = sourceLines[index] ?? '';
        const trimmed = line.trim();
        if (!trimmed || !isLikelyCaptureHeaderPartyLine(trimmed)) continue;
        const key = sourceLineKeys[index];
        if (!key) continue;
        if (!candidateLikelyContainsSourceLine(candidateComparableText, key)) continue;
        anchorIndex = index;
        break;
      }
    }
    if (anchorIndex < 0) return;
    if (!removedIndexesByRole[role].has(anchorIndex)) {
      markForRemoval(anchorIndex, role);
    }

    let continuationSteps = 0;
    for (
      let index = anchorIndex + 1;
      index < headerSearchLimit && continuationSteps < 6;
      index += 1
    ) {
      const line = sourceLines[index] ?? '';
      const trimmed = line.trim();
      if (!trimmed) break;
      const key = sourceLineKeys[index];
      const continuationMatchesCandidate = key
        ? candidateLikelyContainsSourceLine(candidateComparableText, key)
        : false;
      const continuationLooksLikeHeader =
        isLikelyCaptureAddressContinuationLine(trimmed) ||
        (isLikelyCaptureHeaderPartyLine(trimmed) && continuationMatchesCandidate);
      if (!continuationLooksLikeHeader) {
        break;
      }
      markForRemoval(index, role);
      continuationSteps += 1;
    }

    if (removedByRole[role] <= beforeCount) {
      return;
    }
  });

  if (!changed) {
    return {
      text: sourceText,
      removedLineCount: 0,
      removedByRole,
    };
  }
  const filtered = sourceLines.filter((_, index: number): boolean => !removalIndexes.has(index));
  const newline = sourceText.includes('\r\n') ? '\r\n' : '\n';
  return {
    text: compactCaptureTextLines(filtered).join(newline),
    removedLineCount: removalIndexes.size,
    removedByRole,
  };
};

export const stripAcceptedAddressLinesFromText = (
  sourceText: string,
  proposalState: CaseResolverCaptureProposalState | null
): string => {
  return stripAcceptedAddressLinesFromTextDetailed(sourceText, proposalState).text;
};

export const stripCapturedAddressLinesFromText = stripAcceptedAddressLinesFromText;

const stripAcceptedDateLineFromTextDetailed = (
  sourceText: string,
  proposalState: CaseResolverCaptureProposalState | null
): { text: string; removedLineCount: number } => {
  if (!sourceText || !proposalState?.documentDate) {
    return {
      text: sourceText,
      removedLineCount: 0,
    };
  }
  const documentDate = proposalState.documentDate;
  if (documentDate.action !== 'useDetectedDate') {
    return {
      text: sourceText,
      removedLineCount: 0,
    };
  }

  const sourceLines = splitCaptureTextLines(sourceText);
  const sourceLineKeys = sourceLines.map((line: string): string => normalizeCaptureTextLine(line));
  const headerSearchLimit = resolveCaptureHeaderSearchLimit(sourceLines);
  if (headerSearchLimit <= 0) {
    return {
      text: sourceText,
      removedLineCount: 0,
    };
  }
  const sourceLineKey = documentDate.sourceLine
    ? normalizeCaptureTextLine(documentDate.sourceLine)
    : '';
  const normalizedCityHint =
    (documentDate.city ?? documentDate.cityHint)
      ? normalizeCaseResolverComparable(documentDate.city ?? documentDate.cityHint ?? '')
      : '';

  let removalIndex = -1;
  if (sourceLineKey) {
    for (let index = 0; index < headerSearchLimit; index += 1) {
      if (sourceLineKeys[index] !== sourceLineKey) continue;
      removalIndex = index;
      break;
    }
  }
  if (removalIndex < 0) {
    for (let index = 0; index < headerSearchLimit; index += 1) {
      const line = sourceLines[index] ?? '';
      const extractedDate = extractCaseResolverDocumentDate(line);
      if (extractedDate !== documentDate.isoDate) continue;
      if (
        normalizedCityHint &&
        !normalizeCaseResolverComparable(line).includes(normalizedCityHint)
      ) {
        continue;
      }
      removalIndex = index;
      break;
    }
  }

  if (removalIndex < 0) {
    return {
      text: sourceText,
      removedLineCount: 0,
    };
  }
  const filtered = sourceLines.filter((_, index: number): boolean => index !== removalIndex);
  const newline = sourceText.includes('\r\n') ? '\r\n' : '\n';
  return {
    text: compactCaptureTextLines(filtered).join(newline),
    removedLineCount: 1,
  };
};

export const stripAcceptedDateLineFromText = (
  sourceText: string,
  proposalState: CaseResolverCaptureProposalState | null
): string => {
  return stripAcceptedDateLineFromTextDetailed(sourceText, proposalState).text;
};

export const stripAcceptedCaptureContentFromTextWithReport = (
  sourceText: string,
  proposalState: CaseResolverCaptureProposalState | null
): CaseResolverCaptureCleanupResult => {
  if (!sourceText) {
    return {
      text: sourceText,
      report: {
        changed: false,
        sourceWasHtml: false,
        removedAddressLineCount: 0,
        removedAddresserLineCount: 0,
        removedAddresseeLineCount: 0,
        removedDateLineCount: 0,
      },
    };
  }
  const normalizedSource = normalizeCaptureSourceText(sourceText);
  const addressCleanup = stripAcceptedAddressLinesFromTextDetailed(
    normalizedSource.plainText,
    proposalState
  );
  const dateCleanup = stripAcceptedDateLineFromTextDetailed(addressCleanup.text, proposalState);
  return {
    text: dateCleanup.text,
    report: {
      changed: dateCleanup.text !== normalizedSource.plainText,
      sourceWasHtml: normalizedSource.sourceWasHtml,
      removedAddressLineCount: addressCleanup.removedLineCount,
      removedAddresserLineCount: addressCleanup.removedByRole.addresser,
      removedAddresseeLineCount: addressCleanup.removedByRole.addressee,
      removedDateLineCount: dateCleanup.removedLineCount,
    },
  };
};

export const stripAcceptedCaptureContentFromText = (
  sourceText: string,
  proposalState: CaseResolverCaptureProposalState | null
): string => {
  return stripAcceptedCaptureContentFromTextWithReport(sourceText, proposalState).text;
};

import type { CaseResolverCaptureAction, CaseResolverCaptureRole, CaseResolverCaptureRoleMapping, CaseResolverCaptureSettings } from '@/shared/contracts/case-resolver/capture';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import { parseJsonSetting } from '@/shared/utils/settings-json';

export const CASE_RESOLVER_CAPTURE_SETTINGS_KEY = 'case_resolver_capture_settings_v1';

export type {
  CaseResolverCaptureAction,
  CaseResolverCaptureRole,
  CaseResolverCaptureRoleMapping,
  CaseResolverCaptureSettings,
};

export const CASE_RESOLVER_CAPTURE_ACTION_OPTIONS: Array<
  LabeledOptionDto<CaseResolverCaptureAction>
> = [
  { value: 'useMatched', label: 'Use Matched Filemaker' },
  { value: 'createInFilemaker', label: 'Create in Filemaker' },
  { value: 'keepText', label: 'Keep as Text' },
  { value: 'ignore', label: 'Ignore' },
];

export const CASE_RESOLVER_CAPTURE_TARGET_ROLE_OPTIONS: Array<
  LabeledOptionDto<CaseResolverCaptureRole>
> = [
  { value: 'addresser', label: 'Addresser' },
  { value: 'addressee', label: 'Addressee' },
];

export const DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS: CaseResolverCaptureSettings = {
  enabled: true,
  autoOpenProposalModal: true,
  roleMappings: {
    addresser: {
      role: 'addresser',
      enabled: true,
      targetRole: 'addresser',
      defaultAction: 'useMatched',
      autoMatchPartyReference: true,
      autoMatchAddress: true,
      targetPath: 'addresser',
      required: true,
    },
    addressee: {
      role: 'addressee',
      enabled: true,
      targetRole: 'addressee',
      defaultAction: 'useMatched',
      autoMatchPartyReference: true,
      autoMatchAddress: true,
      targetPath: 'addressee',
      required: true,
    },
    subject: {
      role: 'subject',
      enabled: true,
      targetRole: 'subject',
      defaultAction: 'keepText',
      autoMatchPartyReference: false,
      autoMatchAddress: false,
      targetPath: 'subject',
      required: false,
    },
    reference: {
      role: 'reference',
      enabled: true,
      targetRole: 'reference',
      defaultAction: 'ignore',
      autoMatchPartyReference: false,
      autoMatchAddress: false,
      targetPath: 'reference',
      required: false,
    },
    other: {
      role: 'other',
      enabled: true,
      targetRole: 'other',
      defaultAction: 'ignore',
      autoMatchPartyReference: false,
      autoMatchAddress: false,
      targetPath: 'other',
      required: false,
    },
  },
};

const normalizeCaptureRole = (
  value: unknown,
  fallback: CaseResolverCaptureRole
): CaseResolverCaptureRole => {
  if (value === 'addresser' || value === 'addressee') {
    return value;
  }
  return fallback;
};

const normalizeCaptureAction = (
  value: unknown,
  fallback: CaseResolverCaptureAction
): CaseResolverCaptureAction => {
  if (value === 'useMatched') {
    return 'useMatched';
  }
  if (value === 'createInFilemaker') {
    return 'createInFilemaker';
  }
  if (value === 'keepText') {
    return 'keepText';
  }
  if (value === 'ignore') {
    return 'ignore';
  }
  return fallback;
};

const normalizeRoleMapping = (
  value: unknown,
  fallback: CaseResolverCaptureRoleMapping,
  fallbackTargetRole: CaseResolverCaptureRole
): CaseResolverCaptureRoleMapping => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return {
      role: fallback.role,
      targetPath: fallback.targetPath,
      required: fallback.required,
      enabled: fallback.enabled,
      targetRole: fallback.targetRole,
      defaultAction: fallback.defaultAction,
      autoMatchPartyReference: fallback.autoMatchPartyReference,
      autoMatchAddress: fallback.autoMatchAddress,
    };
  }

  const record = value as Record<string, unknown>;
  return {
    role: fallback.role,
    targetPath: fallback.targetPath,
    required: fallback.required,
    enabled: typeof record['enabled'] === 'boolean' ? record['enabled'] : fallback.enabled,
    targetRole: normalizeCaptureRole(
      record['targetRole'],
      normalizeCaptureRole(fallback.targetRole, fallbackTargetRole)
    ),
    defaultAction: normalizeCaptureAction(
      record['defaultAction'],
      fallback.defaultAction || 'keepText'
    ),
    autoMatchPartyReference:
      typeof record['autoMatchPartyReference'] === 'boolean'
        ? record['autoMatchPartyReference']
        : fallback.autoMatchPartyReference,
    autoMatchAddress:
      typeof record['autoMatchAddress'] === 'boolean'
        ? record['autoMatchAddress']
        : fallback.autoMatchAddress,
  };
};

const normalizeCaseResolverCaptureSettings = (input: unknown): CaseResolverCaptureSettings => {
  if (!input || typeof input !== 'object' || Array.isArray(input)) {
    return {
      ...DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS,
      roleMappings: {
        addresser: { ...DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.addresser },
        addressee: { ...DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.addressee },
        subject: { ...DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.subject },
        reference: { ...DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.reference },
        other: { ...DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.other },
      },
    };
  }

  const record = input as Record<string, unknown>;
  const roleMappings =
    record['roleMappings'] &&
    typeof record['roleMappings'] === 'object' &&
    !Array.isArray(record['roleMappings'])
      ? (record['roleMappings'] as Record<string, unknown>)
      : {};

  return {
    enabled:
      typeof record['enabled'] === 'boolean'
        ? record['enabled']
        : DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.enabled,
    autoOpenProposalModal:
      typeof record['autoOpenProposalModal'] === 'boolean'
        ? record['autoOpenProposalModal']
        : DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.autoOpenProposalModal,
    roleMappings: {
      addresser: normalizeRoleMapping(
        roleMappings['addresser'],
        DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.addresser,
        'addresser'
      ),
      addressee: normalizeRoleMapping(
        roleMappings['addressee'],
        DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.addressee,
        'addressee'
      ),
      subject: normalizeRoleMapping(
        roleMappings['subject'],
        DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.subject,
        'subject'
      ),
      reference: normalizeRoleMapping(
        roleMappings['reference'],
        DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.reference,
        'reference'
      ),
      other: normalizeRoleMapping(
        roleMappings['other'],
        DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS.roleMappings.other,
        'other'
      ),
    },
  };
};

export const parseCaseResolverCaptureSettings = (
  raw: string | null | undefined
): CaseResolverCaptureSettings =>
  normalizeCaseResolverCaptureSettings(
    parseJsonSetting<unknown>(raw, DEFAULT_CASE_RESOLVER_CAPTURE_SETTINGS)
  );

import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseMetadataDraft } from '@/shared/contracts/case-resolver/base';
export type { CaseMetadataDraft };

const NONE_OPTION_VALUE = '__none__';

export const buildCaseMetadataDraft = (caseFile: CaseResolverFile | null): CaseMetadataDraft => ({
  name: caseFile?.name ?? '',
  parentCaseId: caseFile?.parentCaseId ?? NONE_OPTION_VALUE,
  caseStatus: caseFile?.caseStatus === 'completed' ? 'completed' : 'pending',
  happeningDate: caseFile?.happeningDate ?? '',
  referenceCaseIds: caseFile?.referenceCaseIds ?? [],
  tagId: caseFile?.tagId ?? NONE_OPTION_VALUE,
  caseIdentifierId: caseFile?.caseIdentifierId ?? NONE_OPTION_VALUE,
  categoryId: caseFile?.categoryId ?? NONE_OPTION_VALUE,
});

const normalizeOptionalSelectValue = (value: string): string | null => {
  const normalized = value.trim();
  if (!normalized || normalized === NONE_OPTION_VALUE) return null;
  return normalized;
};

const normalizeReferenceCaseIds = (values: string[], activeCaseId: string): string[] =>
  Array.from(
    new Set(
      values
        .map((value): string => value.trim())
        .filter((value): boolean => value.length > 0 && value !== activeCaseId)
    )
  );

const areStringArraysEqual = (left: string[], right: string[]): boolean =>
  left.length === right.length && left.every((value, index): boolean => value === right[index]);

export const buildCaseMetadataPatch = (
  activeCaseFile: CaseResolverFile | null,
  draft: CaseMetadataDraft | null
): Partial<
  Pick<
    CaseResolverFile,
    | 'name'
    | 'parentCaseId'
    | 'referenceCaseIds'
    | 'tagId'
    | 'caseIdentifierId'
    | 'categoryId'
    | 'caseStatus'
    | 'happeningDate'
  >
> | null => {
  if (!activeCaseFile || !draft) return null;

  const normalizedDraft = {
    name: draft.name.trim() || activeCaseFile.name || 'Untitled Case',
    parentCaseId: (() => {
      const nextParentCaseId = normalizeOptionalSelectValue(draft.parentCaseId);
      return nextParentCaseId === activeCaseFile.id ? null : nextParentCaseId;
    })(),
    caseStatus: draft.caseStatus === 'completed' ? 'completed' : 'pending',
    happeningDate: draft.happeningDate.trim() || null,
    referenceCaseIds: normalizeReferenceCaseIds(draft.referenceCaseIds, activeCaseFile.id),
    tagId: normalizeOptionalSelectValue(draft.tagId),
    caseIdentifierId: normalizeOptionalSelectValue(draft.caseIdentifierId),
    categoryId: normalizeOptionalSelectValue(draft.categoryId),
  };

  const patch: Partial<
    Pick<
      CaseResolverFile,
      | 'name'
      | 'parentCaseId'
      | 'referenceCaseIds'
      | 'tagId'
      | 'caseIdentifierId'
      | 'categoryId'
      | 'caseStatus'
      | 'happeningDate'
    >
  > = {};

  if (normalizedDraft.name !== activeCaseFile.name) {
    patch.name = normalizedDraft.name;
  }
  if (normalizedDraft.parentCaseId !== (activeCaseFile.parentCaseId?.trim() || null)) {
    patch.parentCaseId = normalizedDraft.parentCaseId;
  }
  if (
    normalizedDraft.caseStatus !==
    (activeCaseFile.caseStatus === 'completed' ? 'completed' : 'pending')
  ) {
    patch.caseStatus = normalizedDraft.caseStatus as 'pending' | 'completed';
  }
  if (normalizedDraft.happeningDate !== (activeCaseFile.happeningDate?.trim() || null)) {
    patch.happeningDate = normalizedDraft.happeningDate;
  }
  if (
    !areStringArraysEqual(
      normalizedDraft.referenceCaseIds,
      normalizeReferenceCaseIds(activeCaseFile.referenceCaseIds ?? [], activeCaseFile.id)
    )
  ) {
    patch.referenceCaseIds = normalizedDraft.referenceCaseIds;
  }
  if (normalizedDraft.tagId !== (activeCaseFile.tagId?.trim() || null)) {
    patch.tagId = normalizedDraft.tagId;
  }
  if (normalizedDraft.caseIdentifierId !== (activeCaseFile.caseIdentifierId?.trim() || null)) {
    patch.caseIdentifierId = normalizedDraft.caseIdentifierId;
  }
  if (normalizedDraft.categoryId !== (activeCaseFile.categoryId?.trim() || null)) {
    patch.categoryId = normalizedDraft.categoryId;
  }

  return Object.keys(patch).length > 0 ? patch : null;
};

