'use client';

import { ArrowDown, ArrowUp, FileImage, FileText, FolderOpen, Plus } from 'lucide-react';
import React, { useEffect, useMemo, useState } from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { CaseFileTypeFilter, CaseSortKey, CaseSortOrder } from '@/shared/contracts/case-resolver/base';
import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverTag, CaseResolverIdentifier, CaseResolverCategory } from '@/shared/contracts/case-resolver/relations';
import { Button, Card, Badge } from '@/shared/ui/primitives.public';
import { EmptyState, Pagination } from '@/shared/ui/navigation-and-layout.public';
import { SearchInput, SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { DocumentSearchPage } from '@/shared/ui/templates.public';

import {
  useCaseResolverPageActions,
  useCaseResolverPageState,
} from '../context/CaseResolverPageContext';

type SortKey = Extract<CaseSortKey, 'updated' | 'created' | 'name'>;
type SortOrder = CaseSortOrder;
type FileTypeFilter = Extract<CaseFileTypeFilter, 'all' | 'document' | 'scanfile'>;

const FILE_TYPE_OPTIONS: Array<LabeledOptionDto<FileTypeFilter>> = [
  { value: 'all', label: 'All file types' },
  { value: 'document', label: 'Document' },
  { value: 'scanfile', label: 'Scan File' },
];

const SORT_OPTIONS: Array<LabeledOptionDto<SortKey>> = [
  { value: 'updated', label: 'Sort: Modified' },
  { value: 'created', label: 'Sort: Created' },
  { value: 'name', label: 'Sort: Name' },
];

type FileSearchRow = {
  file: CaseResolverFile;
  normalizedName: string;
  normalizedFolder: string;
  normalizedTag: string;
  normalizedCaseIdentifier: string;
  normalizedCategory: string;
  normalizedContent: string;
};

const stripHtml = (value: string): string =>
  value
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();

const toDateLabel = (value: string | null | undefined): string => {
  if (!value) return 'Unknown';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return 'Unknown';
  return new Intl.DateTimeFormat(undefined, {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  }).format(date);
};

const buildPathLabelMap = <
  T extends { id: string; name: string; parentId?: string | null | undefined },
>(
    items: T[]
  ): Map<string, string> => {
  const byId = new Map<string, T>(items.map((item: T): [string, T] => [item.id, item]));
  const cache = new Map<string, string>();

  const resolveLabel = (id: string, visited: Set<string>): string => {
    const cached = cache.get(id);
    if (cached) return cached;
    const item = byId.get(id);
    if (!item) return '';
    if (visited.has(id)) {
      cache.set(id, item.name);
      return item.name;
    }
    if (!item.parentId || !byId.has(item.parentId)) {
      cache.set(id, item.name);
      return item.name;
    }
    const nextVisited = new Set(visited);
    nextVisited.add(id);
    const parentLabel = resolveLabel(item.parentId, nextVisited);
    const label = `${parentLabel} / ${item.name}`;
    cache.set(id, label);
    return label;
  };

  items.forEach((item: T): void => {
    resolveLabel(item.id, new Set<string>());
  });

  return cache;
};

export function CaseResolverDocumentSearchPage(): React.JSX.Element {
  const {
    workspace,
    caseResolverTags: tags,
    caseResolverIdentifiers: identifiers,
    caseResolverCategories: categories,
  } = useCaseResolverPageState();
  const { onCreateDocumentFromSearch, onOpenFileFromSearch, onEditFileFromSearch } =
    useCaseResolverPageActions();
  const files: CaseResolverFile[] = useMemo(
    (): CaseResolverFile[] =>
      workspace.files.filter((file: CaseResolverFile): boolean => file.fileType !== 'case'),
    [workspace.files]
  );
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedFileType, setSelectedFileType] = useState<FileTypeFilter>('all');
  const [selectedTagId, setSelectedTagId] = useState<string>('__all__');
  const [selectedCaseIdentifierId, setSelectedCaseIdentifierId] = useState<string>('__all__');
  const [selectedCategoryId, setSelectedCategoryId] = useState<string>('__all__');
  const [sortBy, setSortBy] = useState<SortKey>('updated');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(24);

  const tagPathById = useMemo(
    () => buildPathLabelMap(tags.map((t) => ({ ...t, name: t.label || t.id }))),
    [tags]
  );
  const caseIdentifierPathById = useMemo(
    () => buildPathLabelMap(identifiers.map((i) => ({ ...i, name: i.name || i.label || i.id }))),
    [identifiers]
  );
  const categoryPathById = useMemo(() => buildPathLabelMap(categories), [categories]);
  const tagOptions = useMemo(
    () => [
      { value: '__all__', label: 'All tags' },
      ...tags.map((tag: CaseResolverTag) => ({
        value: tag.id,
        label: tagPathById.get(tag.id) || tag.label || tag.id,
      })),
    ],
    [tagPathById, tags]
  );
  const caseIdentifierOptions = useMemo(
    () => [
      { value: '__all__', label: 'All case identifiers' },
      ...identifiers.map((identifier: CaseResolverIdentifier) => ({
        value: identifier.id,
        label:
          caseIdentifierPathById.get(identifier.id) ||
          identifier.name ||
          identifier.label ||
          identifier.id,
      })),
    ],
    [caseIdentifierPathById, identifiers]
  );
  const categoryOptions = useMemo(
    () => [
      { value: '__all__', label: 'All categories' },
      ...categories.map((category: CaseResolverCategory) => ({
        value: category.id,
        label: categoryPathById.get(category.id) || category.name || category.id,
      })),
    ],
    [categories, categoryPathById]
  );

  const indexedRows = useMemo(
    (): FileSearchRow[] =>
      files.map(
        (file: CaseResolverFile): FileSearchRow => ({
          file,
          normalizedName: file.name.toLowerCase(),
          normalizedFolder: file.folder.toLowerCase(),
          normalizedTag: (file.tagId ? (tagPathById.get(file.tagId) ?? '') : '').toLowerCase(),
          normalizedCaseIdentifier: (file.caseIdentifierId
            ? (caseIdentifierPathById.get(file.caseIdentifierId) ?? '')
            : ''
          ).toLowerCase(),
          normalizedCategory: (file.categoryId
            ? (categoryPathById.get(file.categoryId) ?? '')
            : ''
          ).toLowerCase(),
          normalizedContent: (file.documentContentPlainText.trim().length > 0
            ? file.documentContentPlainText
            : stripHtml(file.documentContent)
          ).toLowerCase(),
        })
      ),
    [caseIdentifierPathById, categoryPathById, files, tagPathById]
  );

  const filteredFiles = useMemo((): CaseResolverFile[] => {
    const query = searchQuery.trim().toLowerCase();
    const tagFilter = selectedTagId === '__all__' ? null : selectedTagId;
    const caseIdentifierFilter =
      selectedCaseIdentifierId === '__all__' ? null : selectedCaseIdentifierId;
    const categoryFilter = selectedCategoryId === '__all__' ? null : selectedCategoryId;

    const filtered = indexedRows
      .filter((row: FileSearchRow): boolean => {
        if (selectedFileType !== 'all' && row.file.fileType !== selectedFileType) return false;
        if (tagFilter && row.file.tagId !== tagFilter) return false;
        if (caseIdentifierFilter && row.file.caseIdentifierId !== caseIdentifierFilter)
          return false;
        if (categoryFilter && row.file.categoryId !== categoryFilter) return false;
        if (!query) return true;
        return (
          row.normalizedName.includes(query) ||
          row.normalizedFolder.includes(query) ||
          row.normalizedTag.includes(query) ||
          row.normalizedCaseIdentifier.includes(query) ||
          row.normalizedCategory.includes(query) ||
          row.normalizedContent.includes(query)
        );
      })
      .map((row: FileSearchRow): CaseResolverFile => row.file);

    filtered.sort((left: CaseResolverFile, right: CaseResolverFile): number => {
      let delta: number;
      if (sortBy === 'name') {
        delta = left.name.localeCompare(right.name);
      } else if (sortBy === 'created') {
        delta = new Date(left.createdAt || 0).getTime() - new Date(right.createdAt || 0).getTime();
      } else {
        delta =
          new Date(left.updatedAt || left.createdAt || 0).getTime() -
          new Date(right.updatedAt || right.createdAt || 0).getTime();
      }
      return sortOrder === 'asc' ? delta : -delta;
    });

    return filtered;
  }, [
    indexedRows,
    searchQuery,
    selectedFileType,
    selectedTagId,
    selectedCaseIdentifierId,
    selectedCategoryId,
    sortBy,
    sortOrder,
  ]);

  const totalPages = Math.max(1, Math.ceil(filteredFiles.length / pageSize));
  useEffect(() => {
    if (page <= totalPages) return;
    setPage(totalPages);
  }, [page, totalPages]);
  useEffect(() => {
    setPage(1);
  }, [
    searchQuery,
    selectedFileType,
    selectedTagId,
    selectedCaseIdentifierId,
    selectedCategoryId,
    sortBy,
    sortOrder,
    pageSize,
  ]);

  const pagedFiles = useMemo((): CaseResolverFile[] => {
    const start = (page - 1) * pageSize;
    return filteredFiles.slice(start, start + pageSize);
  }, [filteredFiles, page, pageSize]);

  return (
    <DocumentSearchPage
      title='Document Search'
      startAdornment={
        <>
          <Button
            type='button'
            onClick={onCreateDocumentFromSearch}
            className='size-11 rounded-full bg-primary p-0 text-primary-foreground hover:bg-primary/90'
            aria-label='Create document'
            title='Create document'
          >
            <Plus className='size-5' />
          </Button>
        </>
      }
      titleAdornment={
        <Badge variant='neutral' className='bg-card/40 font-normal'>
          {filteredFiles.length} result{filteredFiles.length === 1 ? '' : 's'}
        </Badge>
      }
      endAdornment={
        <Pagination
          page={page}
          totalPages={totalPages}
          onPageChange={setPage}
          pageSize={pageSize}
          onPageSizeChange={setPageSize}
          pageSizeOptions={[12, 24, 48]}
          showPageSize
          variant='compact'
        />
      }
      filters={
        <div className='space-y-3'>
          <SearchInput
            value={searchQuery}
            onChange={(event: React.ChangeEvent<HTMLInputElement>): void => {
              setSearchQuery(event.target.value);
            }}
            onClear={(): void => {
              setSearchQuery('');
            }}
            placeholder='Search documents by name, folder, tag, case identifier, category, or content...'
            className='h-10 border-border bg-card/60 text-sm text-white'
          />
          <div className='grid gap-2 sm:grid-cols-2 lg:grid-cols-6'>
            <SelectSimple
              size='sm'
              value={selectedFileType}
              onValueChange={(value: string): void => {
                setSelectedFileType(value === 'document' || value === 'scanfile' ? value : 'all');
              }}
              options={FILE_TYPE_OPTIONS}
              triggerClassName='h-9 border-border bg-card/60 text-xs text-white'
              ariaLabel='Filter by file type'
              title='Filter by file type'
            />
            <SelectSimple
              size='sm'
              value={selectedTagId}
              onValueChange={setSelectedTagId}
              options={tagOptions}
              triggerClassName='h-9 border-border bg-card/60 text-xs text-white'
              ariaLabel='Filter by tag'
              title='Filter by tag'
            />
            <SelectSimple
              size='sm'
              value={selectedCaseIdentifierId}
              onValueChange={setSelectedCaseIdentifierId}
              options={caseIdentifierOptions}
              triggerClassName='h-9 border-border bg-card/60 text-xs text-white'
              ariaLabel='Filter by case identifier'
              title='Filter by case identifier'
            />
            <SelectSimple
              size='sm'
              value={selectedCategoryId}
              onValueChange={setSelectedCategoryId}
              options={categoryOptions}
              triggerClassName='h-9 border-border bg-card/60 text-xs text-white'
              ariaLabel='Filter by category'
              title='Filter by category'
            />
            <SelectSimple
              size='sm'
              value={sortBy}
              onValueChange={(value: string): void => {
                setSortBy(value === 'created' || value === 'name' ? value : 'updated');
              }}
              options={SORT_OPTIONS}
              triggerClassName='h-9 border-border bg-card/60 text-xs text-white'
              ariaLabel='Sort documents by'
              title='Sort documents by'
            />
            <Button
              type='button'
              variant='outline'
              onClick={(): void => {
                setSortOrder((current: SortOrder) => (current === 'asc' ? 'desc' : 'asc'));
              }}
              className='h-9 border-border bg-card/60 text-xs text-gray-200 hover:bg-muted/60'
              title={`Sorting ${sortOrder === 'asc' ? 'ascending' : 'descending'}`}
            >
              {sortOrder === 'asc' ? (
                <ArrowUp className='mr-1.5 size-3.5' />
              ) : (
                <ArrowDown className='mr-1.5 size-3.5' />
              )}
              {sortOrder === 'asc' ? 'Ascending' : 'Descending'}
            </Button>
          </div>
        </div>
      }
      loading={false}
      hasResults={filteredFiles.length > 0}
      emptyState={
        <EmptyState
          title='No documents found'
          description='Adjust search filters or create a new document.'
          icon={<FolderOpen className='size-10' />}
          action={
            <Button type='button' onClick={onCreateDocumentFromSearch}>
              <Plus className='mr-2 size-4' />
              Create Document
            </Button>
          }
        />
      }
    >
      <div className='grid gap-3 sm:grid-cols-2 xl:grid-cols-3'>
        {pagedFiles.map((file: CaseResolverFile) => {
          const previewText = (
            file.documentContentPlainText.trim().length > 0
              ? file.documentContentPlainText
              : stripHtml(file.documentContent)
          ).slice(0, 220);
          const tagLabel = file.tagId ? (tagPathById.get(file.tagId) ?? 'Unknown tag') : 'No tag';
          const caseIdentifierLabel = file.caseIdentifierId
            ? (caseIdentifierPathById.get(file.caseIdentifierId) ?? 'Unknown case identifier')
            : 'No case identifier';
          const categoryLabel = file.categoryId
            ? (categoryPathById.get(file.categoryId) ?? 'Unknown category')
            : 'No category';
          return (
            <Card key={file.id} variant='subtle' padding='md' className='bg-card/45'>
              <div className='mb-1 flex items-start justify-between gap-2'>
                <Button
                  variant='link'
                  className='h-auto p-0 line-clamp-2 justify-start text-left text-sm font-semibold text-white hover:text-cyan-200 hover:no-underline'
                  onClick={(): void => {
                    onOpenFileFromSearch(file.id);
                  }}
                >
                  <span className='line-clamp-2'>{file.name}</span>
                </Button>
                <Badge
                  variant='neutral'
                  className='shrink-0 border-border/60 bg-black/30 font-normal uppercase'
                >
                  {file.fileType}
                </Badge>
              </div>
              <div className='mb-2 text-[11px] text-muted-foreground'>{file.folder || '(root)'}</div>
              <div className='mb-2 line-clamp-3 text-xs text-muted-foreground'>
                {previewText || 'No content yet.'}
              </div>
              <div className='space-y-1 text-[11px] text-muted-foreground'>
                <div>Tag: {tagLabel}</div>
                <div>Case Identifier: {caseIdentifierLabel}</div>
                <div>Category: {categoryLabel}</div>
                <div>Modified: {toDateLabel(file.updatedAt)}</div>
              </div>
              <div className='mt-3 flex items-center justify-end gap-2'>
                <Button
                  type='button'
                  size='sm'
                  variant='outline'
                  className='h-8 border-white/20 px-2 text-xs'
                  onClick={(): void => {
                    onOpenFileFromSearch(file.id);
                  }}
                >
                  {file.fileType === 'scanfile' ? (
                    <FileImage className='mr-1.5 size-3.5' />
                  ) : (
                    <FileText className='mr-1.5 size-3.5' />
                  )}
                  Open
                </Button>
                <Button
                  type='button'
                  size='sm'
                  variant='outline'
                  className='h-8 border-white/20 px-2 text-xs'
                  onClick={(): void => {
                    onEditFileFromSearch(file.id);
                  }}
                >
                  Edit
                </Button>
              </div>
            </Card>
          );
        })}
      </div>
    </DocumentSearchPage>
  );
}

'use client';

import {
  ExternalLink as ExternalLinkIcon,
  FileText,
  FolderOpen,
  Image as ImageIcon,
} from 'lucide-react';
import React from 'react';

import type { CaseResolverAssetFile } from '@/shared/contracts/case-resolver/file';
import { Button, Label, Textarea, useToast, Card } from '@/shared/ui/primitives.public';
import { ExternalLink, FileUploadTrigger } from '@/shared/ui/forms-and-actions.public';
import { EmptyState } from '@/shared/ui/navigation-and-layout.public';
import { PanelHeader } from '@/shared/ui/templates.public';

import {
  useCaseResolverPageActions,
  useCaseResolverPageState,
} from '../context/CaseResolverPageContext';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const formatFileSize = (size: number | null): string => {
  if (size === null || size < 0 || !Number.isFinite(size)) return 'Unknown';
  if (size < 1024) return `${size} B`;
  if (size < 1024 * 1024) return `${(size / 1024).toFixed(1)} KB`;
  return `${(size / (1024 * 1024)).toFixed(2)} MB`;
};

const resolveAssetSubtitle = (asset: CaseResolverAssetFile): string => {
  if (asset.kind === 'image') return 'Image asset';
  if (asset.kind === 'pdf') return 'PDF document';
  if (asset.kind === 'file') return 'Generic file';
  return 'Node file';
};

export function CaseResolverFileViewer(): React.JSX.Element {
  const { selectedAsset, selectedFolderPath, activeFile } = useCaseResolverPageState();
  const { onUpdateSelectedAsset, onAttachAssetFile } = useCaseResolverPageActions();
  const { toast } = useToast();
  const [isDragActive, setIsDragActive] = React.useState(false);
  const [isAttachingImage, setIsAttachingImage] = React.useState(false);

  if (!selectedAsset) {
    return (
      <Card variant='glass' padding='md' className='flex h-[calc(100vh-120px)] flex-col gap-4'>
        <PanelHeader title='File Viewer' refreshable={false} />
        <EmptyState
          title='No file selected'
          description={
            selectedFolderPath !== null
              ? `Folder selected: ${selectedFolderPath || '(root)'}. Select a file to preview.`
              : activeFile
                ? `Case selected: ${activeFile.name}. Open a node file to enter canvas mode, or select another file to preview it here.`
                : 'Select a file from the tree to preview it here.'
          }
          icon={<FolderOpen className='size-12' />}
          className='flex-1 border-none bg-transparent'
        />
      </Card>
    );
  }

  const isImageAsset = selectedAsset.kind === 'image';
  const showImagePreview = isImageAsset && Boolean(selectedAsset.filepath);
  const showPdfPreview = selectedAsset.kind === 'pdf' && Boolean(selectedAsset.filepath);
  const showGenericPreview = !isImageAsset && !showPdfPreview;

  const handleAttachImageFile = React.useCallback(
    async (file: File): Promise<void> => {
      if (selectedAsset?.kind !== 'image') return;
      setIsAttachingImage(true);
      try {
        await onAttachAssetFile(selectedAsset.id, file, { expectedKind: 'image' });
      } catch (error: unknown) {
        logClientError(error);
        toast(error instanceof Error ? error.message : 'Failed to attach image file.', {
          variant: 'error',
        });
      } finally {
        setIsAttachingImage(false);
        setIsDragActive(false);
      }
    },
    [onAttachAssetFile, selectedAsset, toast]
  );

  return (
    <Card variant='glass' padding='md' className='flex h-[calc(100vh-120px)] flex-col gap-4'>
      <PanelHeader
        title={selectedAsset.name}
        subtitle={resolveAssetSubtitle(selectedAsset)}
        refreshable={false}
        customActions={
          selectedAsset.filepath ? (
            <ExternalLink
              href={selectedAsset.filepath}
              className='rounded border border-border/60 px-2 py-1 text-[11px] text-gray-200 hover:bg-muted/40'
            >
              Open
            </ExternalLink>
          ) : null
        }
      />

      <div className='mt-3 grid grid-cols-1 gap-2 text-xs text-gray-300 md:grid-cols-2'>
        <div className='mt-3 grid grid-cols-1 gap-2 text-xs text-gray-300 md:grid-cols-2'>
          <Card
            variant='subtle-compact'
            padding='sm'
            className='flex items-center justify-between border-border/50 bg-card/20'
          >
            <span className='text-gray-500'>Kind</span>
            <span className='uppercase text-[10px]'>{selectedAsset.kind}</span>
          </Card>
          <Card
            variant='subtle-compact'
            padding='sm'
            className='flex items-center justify-between border-border/50 bg-card/20'
          >
            <span className='text-gray-500'>Size</span>
            <span>{formatFileSize(selectedAsset.size)}</span>
          </Card>
          <Card
            variant='subtle-compact'
            padding='sm'
            className='flex items-center justify-between border-border/50 bg-card/20'
          >
            <span className='text-gray-500'>MIME</span>
            <span className='truncate pl-2'>{selectedAsset.mimeType ?? 'Unknown'}</span>
          </Card>
          <Card
            variant='subtle-compact'
            padding='sm'
            className='flex items-center justify-between border-border/50 bg-card/20'
          >
            <span className='text-gray-500'>Folder</span>
            <span className='truncate pl-2'>{selectedAsset.folder || '(root)'}</span>
          </Card>
        </div>

        <div className='mt-3 space-y-2'>
          <Label className='text-xs text-gray-400'>Description</Label>
          <Textarea
            value={selectedAsset.description}
            onChange={(event: React.ChangeEvent<HTMLTextAreaElement>): void => {
              onUpdateSelectedAsset({ description: event.target.value });
            }}
            className='min-h-[72px] border-border bg-card/60 text-xs text-white'
            placeholder='Optional description for this file...'
           aria-label='Optional description for this file...' title='Optional description for this file...'/>
        </div>
      </div>

      <Card
        variant='subtle-compact'
        padding='none'
        className='min-h-0 flex-1 overflow-hidden border-border/60 bg-card/25'
      >
        {isImageAsset ? (
          <div className='h-full p-3'>
            <FileUploadTrigger
              accept='image/*'
              onFilesSelected={(files: File[]) => {
                if (files[0]) void handleAttachImageFile(files[0]);
              }}
              disabled={isAttachingImage}
              asChild
            >
              <Card
                variant='subtle-compact'
                padding='sm'
                className={`relative flex h-full items-center justify-center overflow-hidden border-dashed transition ${
                  isDragActive
                    ? 'border-blue-500 bg-blue-500/10'
                    : 'border-border/70 bg-card/40 hover:bg-card/55'
                } ${isAttachingImage ? 'pointer-events-none opacity-70' : 'cursor-pointer'}`}
              >
                {showImagePreview ? (
                  <>
                    <img
                      src={selectedAsset.filepath ?? ''}
                      alt={selectedAsset.name || 'Selected asset preview'}
                      className='max-h-full max-w-full rounded object-contain'
                    />
                    <div className='absolute bottom-3 left-1/2 -translate-x-1/2 rounded bg-black/55 px-2 py-1 text-[11px] text-white'>
                      {isAttachingImage ? 'Uploading image...' : 'Drop image to replace'}
                    </div>
                  </>
                ) : (
                  <div className='flex flex-col items-center gap-2 text-center'>
                    <ImageIcon className='size-9 text-gray-400' />
                    <div className='text-sm font-medium text-gray-200'>
                      {isAttachingImage ? 'Uploading image...' : 'Drop image here'}
                    </div>
                    <div className='text-xs text-gray-400'>or click to browse files</div>
                  </div>
                )}
              </Card>
            </FileUploadTrigger>
          </div>
        ) : null}

        {showPdfPreview ? (
          <iframe
            title={selectedAsset.name}
            src={selectedAsset.filepath ?? ''}
            className='h-full w-full border-0'
          />
        ) : null}

        {showGenericPreview ? (
          <div className='flex h-full flex-col items-center justify-center gap-3 p-6 text-center'>
            {selectedAsset.kind === 'file' ? (
              <FileText className='size-10 text-gray-500' />
            ) : (
              <ImageIcon className='size-10 text-gray-500' />
            )}
            <div className='text-sm text-gray-300'>Preview not available for this file type.</div>
            <div className='text-xs text-gray-500'>
              Open the file in a new tab to inspect the full content.
            </div>
            {selectedAsset.filepath ? (
              <ExternalLink
                href={selectedAsset.filepath}
                className='inline-flex items-center gap-1 rounded border border-border/60 px-2 py-1 text-xs text-gray-200 hover:bg-muted/40'
              >
                <FolderOpen className='size-3.5' />
                Open file
                <ExternalLinkIcon className='size-3.5' />
              </ExternalLink>
            ) : (
              <Button
                type='button'
                disabled
                variant='outline'
                className='h-8 text-xs text-gray-500'
              >
                File path unavailable
              </Button>
            )}
          </div>
        ) : null}
      </Card>
    </Card>
  );
}

