  return (
    <DetailModal
      isOpen={open}
      onClose={() => onOpenChange(false)}
      title={
        <div className='flex items-center gap-2'>
          <Button
            type='button'
            size='sm'
            onClick={onManualUpdate}
            disabled={!hasPendingSnapshotChanges}
            className={
              hasPendingSnapshotChanges
                ? 'h-7 rounded-md border border-emerald-500/40 px-2 text-[11px] text-emerald-200 transition-colors hover:bg-emerald-500/10'
                : 'h-7 rounded-md border border-border/60 px-2 text-[11px] text-gray-500'
            }
          >
            Update
          </Button>
          <span>Node Inspector</span>
        </div>
      }
      subtitle='Inspect and edit selected node/edge settings.'
      size='xl'
    >
      <div className='space-y-3'>
        {selectedNode ? (
          <>
            <InsetPanel radius='compact' padding='sm' className='text-xs text-gray-300'>
              <div className='flex items-center justify-between gap-2'>
                <span className='text-gray-500'>Node</span>
                <span className='font-medium text-gray-100'>{selectedNode.title}</span>
              </div>
              <div className='mt-1 flex items-center justify-between gap-2'>
                <span className='text-gray-500'>Type</span>
                <span className='uppercase text-[10px] text-gray-200'>{selectedNode.type}</span>
              </div>
            </InsetPanel>

            {selectedNode.type === 'prompt' && selectedPromptMeta ? (
              <>
                {selectedPromptSourceFile ? (
                  <div className='space-y-2 rounded border border-sky-500/30 bg-sky-500/10 p-3'>
                    <div className='flex items-center justify-between gap-2 text-xs'>
                      <span className='text-sky-100'>Source Document</span>
                      <span className='truncate text-[11px] text-sky-200'>
                        {selectedPromptSourceFile.name}
                      </span>
                    </div>
                    <Button
                      type='button'
                      className='h-8 rounded-md border border-sky-400/50 px-2 text-xs text-sky-100 hover:bg-sky-500/20'
                      onClick={(): void => {
                        const nodeContext: CaseResolverEditorNodeContext | null =
                          selectedNode && selectedCanvasFileId && selectedWorkspaceId
                            ? {
                              nodeId: selectedNode.id,
                              fileId: selectedCanvasFileId,
                              workspaceId: selectedWorkspaceId,
                              mode: 'wysiwyg',
                            }
                            : null;
                        onEditFile(
                          selectedPromptSourceFile.id,
                          nodeContext ? { nodeContext } : undefined
                        );
                      }}
                    >
                      Open Edit Document
                    </Button>
                  </div>
                ) : null}

                <FormField label='Node Role'>
                  <SelectSimple
                    size='sm'
                    value={selectedPromptMeta.role}
                    onValueChange={(value: string): void => {
                      if (
                        value === 'text_note' ||
                        value === 'explanatory' ||
                        value === 'ai_prompt'
                      ) {
                        onUpdateSelectedNodeMeta?.({ role: value });
                      }
                    }}
                    options={CASE_RESOLVER_NODE_ROLE_OPTIONS}
                    triggerClassName='h-8 border-border bg-card/60 text-xs text-white'
                   ariaLabel='Node Role' title='Node Role'/>
                </FormField>

                <FormField label='Quotation Wrapper'>
                  <SelectSimple
                    size='sm'
                    value={selectedPromptMeta.quoteMode}
                    onValueChange={(value: string): void => {
                      if (value === 'none' || value === 'double' || value === 'single') {
                        onUpdateSelectedNodeMeta?.({ quoteMode: value });
                      }
                    }}
                    options={CASE_RESOLVER_QUOTE_MODE_OPTIONS}
                    triggerClassName='h-8 border-border bg-card/60 text-xs text-white'
                   ariaLabel='Quotation Wrapper' title='Quotation Wrapper'/>
                </FormField>

                <div className='grid grid-cols-2 gap-2'>
                  <FormField label='Surround Prefix'>
                    <Input
                      value={selectedPromptMeta.surroundPrefix}
                      onChange={(event: React.ChangeEvent<HTMLInputElement>): void => {
                        onUpdateSelectedNodeMeta?.({ surroundPrefix: event.target.value });
                      }}
                      className='h-8 border-border bg-card/60 text-xs text-white'
                      placeholder='e.g. <<'
                     aria-label='e.g. <<' title='e.g. <<'/>
                  </FormField>
                  <FormField label='Surround Suffix'>
                    <Input
                      value={selectedPromptMeta.surroundSuffix}
                      onChange={(event: React.ChangeEvent<HTMLInputElement>): void => {
                        onUpdateSelectedNodeMeta?.({ surroundSuffix: event.target.value });
                      }}
                      className='h-8 border-border bg-card/60 text-xs text-white'
                      placeholder='e.g. >>'
                     aria-label='e.g. >>' title='e.g. >>'/>
                  </FormField>
                </div>
                <div className='flex items-center justify-between rounded border border-border/60 bg-card/30 px-3 py-2'>
                  <div className='text-xs text-gray-300'>Include node in compiled output</div>
                  <Checkbox
                    checked={Boolean(selectedPromptMeta.includeInOutput)}
                    onCheckedChange={(checked: boolean): void => {
                      onUpdateSelectedNodeMeta?.({ includeInOutput: checked });
                    }}
                  />
                </div>
                <div className='flex items-center justify-between rounded border border-border/60 bg-card/30 px-3 py-2'>
                  <div className='text-xs text-gray-300'>Append new line at end</div>
                  <Checkbox
                    checked={selectedPromptMeta.appendTrailingNewline === true}
                    onCheckedChange={(checked: boolean): void => {
                      onUpdateSelectedNodeMeta?.({ appendTrailingNewline: checked });
                    }}
                  />
                </div>
                <FormField label='Text Color (Content Output)'>
                  <div className='flex flex-wrap items-center gap-2'>
                    <Input
                      type='color'
                      value={
                        CASE_RESOLVER_NODE_TEXT_COLOR_PATTERN.test(
                          selectedPromptMeta.textColor ?? ''
                        )
                          ? selectedPromptMeta.textColor
                          : '#ffffff'
                      }
                      onChange={(event: React.ChangeEvent<HTMLInputElement>): void => {
                        const nextColor = event.target.value.trim();
                        if (!CASE_RESOLVER_NODE_TEXT_COLOR_PATTERN.test(nextColor)) return;
                        onUpdateSelectedNodeMeta?.({ textColor: nextColor });
                      }}
                      className='h-9 w-14 p-1'
                     aria-label='Text Color (Content Output)' title='Text Color (Content Output)'/>
                    <Button
                      type='button'
                      variant='ghost'
                      size='sm'
                      className='h-7 px-2 text-[11px] text-gray-400 hover:text-gray-200'
                      disabled={!selectedPromptMeta.textColor}
                      onClick={(): void => {
                        onUpdateSelectedNodeMeta?.({ textColor: '' });
                      }}
                    >
                      Clear
                    </Button>
                    <span className='text-[11px] text-gray-500'>
                      {selectedPromptMeta.textColor
                        ? `Using ${selectedPromptMeta.textColor}`
                        : 'No color wrapper'}
                    </span>
                  </div>
                </FormField>
                <div className='space-y-2 rounded border border-border/60 bg-card/30 px-3 py-3'>
                  <div className='text-[11px] text-gray-300'>
                    Case Resolver Plain Text Validation
                  </div>
                  <ValidatorFormatterToggle
                    validatorEnabled={selectedPromptMeta.plainTextValidationEnabled ?? true}
                    formatterEnabled={selectedPromptMeta.plainTextFormatterEnabled ?? true}
                    validatorLabel='Validation'
                    formatterLabel='Auto Plain Text'
                    onValidatorChange={(next: boolean): void => {
                      const currentStackId =
                        selectedPromptMeta.plainTextValidationStackId?.trim() ?? '';
                      const fallbackStackId = currentStackId || defaultPlainTextStackId;
                      onUpdateSelectedNodeMeta?.({
                        plainTextValidationEnabled: next,
                        plainTextFormatterEnabled: next
                          ? (selectedPromptMeta.plainTextFormatterEnabled ?? true)
                          : false,
                        ...(next && fallbackStackId
                          ? { plainTextValidationStackId: fallbackStackId }
                          : {}),
                      });
                    }}
                    onFormatterChange={(next: boolean): void => {
                      onUpdateSelectedNodeMeta?.({ plainTextFormatterEnabled: next });
                    }}
                  />
                  {(selectedPromptMeta.plainTextValidationEnabled ?? true) ? (
                    plainTextPatternStackOptions.length > 0 ? (
                      <div className='space-y-1'>
                        <Label className='text-[11px] text-gray-400'>Validation Stack</Label>
                        <SelectSimple
                          size='sm'
                          value={
                            selectedPromptMeta.plainTextValidationStackId?.trim() ||
                            defaultPlainTextStackId
                          }
                          onValueChange={(value: string): void => {
                            onUpdateSelectedNodeMeta?.({ plainTextValidationStackId: value });
                          }}
                          options={plainTextPatternStackOptions}
                          triggerClassName='h-8 border-border bg-card/60 text-xs text-white'
                         ariaLabel='Select option' title='Select option'/>
                      </div>
                    ) : (
                      <p className='text-[11px] text-amber-200'>
                        No &ldquo;Case Resolver - Plain Text&rdquo; validation stacks are configured
                        yet.
                      </p>
                    )
                  ) : null}
                  {selectedPromptMeta.role === 'explanatory' ? (
                    <p className='text-[11px] text-gray-500'>
                      Explanatory nodes expose plain-text outputs plus an additional WYSIWYGContent
                      lane.
                    </p>
                  ) : null}
                </div>
                {selectedPromptMeta.role === 'ai_prompt' ? (
                  <div className='text-[11px] text-gray-500'>
                    Runtime AI prompt nodes are excluded by default and can be opted in.
                  </div>
                ) : null}
                {!selectedPromptSourceFile ? (
                  <FormField
                    label={
                      selectedPromptMeta.role === 'explanatory'
                        ? 'Explanatory Text (WYSIWYG)'
                        : 'Node Text'
                    }
                    description={
                      selectedPromptMeta.role === 'explanatory'
                        ? 'This rich text is appended to incoming WYSIWYGContent and transformed to plain text by validation patterns.'
                        : 'This text is merged with incoming text for this node.'
                    }
                  >
                    {selectedPromptMeta.role === 'explanatory' ? (
                      <div className='rounded border border-border/70 bg-card/40 p-2'>
                        <CaseResolverRichTextEditor
                          value={selectedPromptTemplate || ''}
                          onChange={onUpdateSelectedPromptTemplate || (() => {})}
                          placeholder='Write explanatory rich text to append to incoming WYSIWYG content.'
                          appearance='document-preview'
                        />
                      </div>
                    ) : (
                      <Textarea
                        value={selectedPromptTemplate || ''}
                        onChange={(event: React.ChangeEvent<HTMLTextAreaElement>): void => {
                          onUpdateSelectedPromptTemplate?.(event.target.value);
                        }}
                        rows={5}
                        className='border-border bg-card/60 text-xs text-white'
                        placeholder='Write note text to append/merge with incoming input.'
                       aria-label='Write note text to append/merge with incoming input.' title='Write note text to append/merge with incoming input.'/>
                    )}
                  </FormField>
                ) : null}

                <div className='grid gap-2 md:grid-cols-2'>
                  <div className='rounded border border-border/60 bg-card/30 p-3'>
                    <div className='mb-1 text-[11px] text-gray-400'>Input WYSIWYG Text Content</div>
                    <div className='max-h-52 overflow-auto whitespace-pre-wrap rounded border border-border/60 bg-card/50 p-2 text-[12px] text-gray-100'>
                      {selectedPromptInputText || '(empty)'}
                    </div>
                  </div>
                  <div className='space-y-2 rounded border border-border/60 bg-card/30 p-3'>
                    <div className='text-[11px] text-gray-400'>Output Preview</div>
                    {selectedPromptSecondaryOutputHint ? (
                      <div className='rounded border border-amber-500/35 bg-amber-500/10 p-2 text-[10px] text-amber-100'>
                        Only <span className='font-semibold'>wysiwygText</span> input is connected.{' '}
                        <span className='font-semibold'>plaintextContent</span> and{' '}
                        <span className='font-semibold'>plainText</span> outputs remain empty until
                        those lanes are connected.
                      </div>
                    ) : null}
                    <div className='space-y-1 text-[11px]'>
                      {outputPreviewRows.map((row) => (
                        <React.Fragment key={row.label}>
                          <div className='flex items-center justify-between gap-2'>
                            <div className='text-gray-500'>{row.label}</div>
                            <CopyButton
                              value={row.value || ''}
                              variant='ghost'
                              size='icon'
                              className='h-6 w-6 p-0 text-gray-400 hover:text-gray-200'
                            />
                          </div>
                          <div className='max-h-20 overflow-auto whitespace-pre-wrap rounded border border-border/60 bg-card/50 p-2 text-[12px] text-gray-100'>
                            {row.value || '(empty)'}
                          </div>
                        </React.Fragment>
                      ))}
                    </div>
                  </div>
                </div>

                <div className='rounded border border-border/60 bg-card/30 px-3 py-2 text-xs text-gray-400'>
                  Document nodes support <span className='text-gray-200'>wysiwygText</span>,{' '}
                  <span className='text-gray-200'>plaintextContent</span>, and{' '}
                  <span className='text-gray-200'>plainText</span> I/O.
                  {selectedPromptMeta.role === 'explanatory' ? (
                    <>
                      {' '}
                      Explanatory nodes also support{' '}
                      <span className='text-gray-200'>WYSIWYGContent</span> I/O.
                    </>
                  ) : null}
                  Use <span className='text-gray-200'>plainText</span> input to strip incoming HTML
                  to clean text automatically.
                </div>
              </>
            ) : (
              <CompactEmptyState
                title='Prompt Metadata'
                description='Select a Prompt node to configure metadata.'
                className='py-4'
               />
            )}
          </>
        ) : (
          <CompactEmptyState
            title='No Node Selected'
            description='Select a node on the map to edit it.'
            className='py-8'
           />
        )}

        {selectedEdge ? (
          <div className='space-y-2 rounded border border-border/60 bg-card/30 p-3'>
            <FormField
              label='Edge join operator'
              actions={
                <div className='flex items-center gap-1'>
                  <Split className='size-3.5 text-gray-500' />
                  <span className='text-[11px] text-gray-500'>
                    {edgeFromPort ?? 'output'} {'->'} {edgeToPort ?? 'input'}
                  </span>
                </div>
              }
            >
              <SelectSimple
                size='sm'
                value={selectedEdgeJoinMode}
                onValueChange={(value: string): void => {
                  if (
                    value === 'newline' ||
                    value === 'tab' ||
                    value === 'space' ||
                    value === 'none'
                  ) {
                    onUpdateSelectedEdgeMeta?.({ joinMode: value });
                  }
                }}
                options={CASE_RESOLVER_JOIN_MODE_OPTIONS}
                triggerClassName='h-8 border-border bg-card/60 text-xs text-white'
               ariaLabel='Edge join operator' title='Edge join operator'/>
            </FormField>
          </div>
        ) : (
          <CompactEmptyState
            title='No Connection Selected'
            description='Select a connection to choose how linked node text joins.'
            className='py-4'
           />
        )}
      </div>
    </DetailModal>
  );
}

'use client';

import { Eye, EyeOff } from 'lucide-react';
import { useSearchParams } from 'next/navigation';
import React from 'react';
import { createPortal } from 'react-dom';

import { Button, Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/shared/ui/primitives.public';

import { CaseResolverFolderTree } from './CaseResolverFolderTree';
import {
  useCaseResolverViewActionsContext,
  useCaseResolverViewStateContext,
} from './CaseResolverViewContext';
import { CaseResolverWorkspaceDebugPanel } from './CaseResolverWorkspaceDebugPanel';
import { CaseResolverPageProvider } from '../context/CaseResolverPageContext';
import { CaseResolverRuntimeProvider } from '../runtime';
import { CaseResolverCaptureMappingModal } from './page/CaseResolverCaptureMappingModal';
import { CaseResolverPageMainContent } from './page/CaseResolverPageMainContent';

type PendingNavigation = {
  kind: 'document' | 'case';
  action: () => void;
};

export function CaseResolverPageView(): React.JSX.Element {
  const searchParams = useSearchParams();
  const {
    state,
    caseTagOptions,
    caseIdentifierOptions,
    caseCategoryOptions,
    caseReferenceOptions,
    parentCaseOptions,
    partyOptions,
    isEditorDraftDirty,
    isActiveCaseMetadataDirty,
    activeCaseFile,
    activeCaseMetadataDraft,
  } = useCaseResolverViewStateContext();
  const {
    handleDeactivateActiveFile,
    handleToggleFolderLock,
    handleDeleteFile,
    handleDeleteAsset,
    handleToggleFileLock,
    handleCreateDocumentFromSearch,
    handleOpenFileFromSearch,
    handleEditFileFromSearch,
    handleGraphChange,
    handleRelationGraphChange,
    handleUpdateActiveCaseMetadata,
    setWorkspaceView,
    handleMoveFolder,
    handleSaveActiveCaseMetadata,
    handleDiscardActiveCaseMetadata,
    updateActiveCaseMetadataDraft,
    handleResetCaseContext,
  } = useCaseResolverViewActionsContext();
  const workspaceDebugEnabled = (searchParams.get('debugWorkspace')?.trim() ?? '') === '1';
  const {
    workspace,
    activeCaseId,
    requestedCaseStatus,
    requestedCaseIssue,
    canCreateInActiveCase,
    selectedFileId,
    selectedAssetId,
    selectedFolderPath,
    activeFile,
    selectedAsset,
    folderPanelCollapsed,
    setFolderPanelCollapsed,
    isMenuCollapsed,
    setIsMenuCollapsed,
    handleSelectFile,
    handleSelectAsset,
    handleSelectFolder,
    handleCreateFolder,
    handleCreateFile,
    handleCreateScanFile,
    handleCreateNodeFile,
    handleCreateImageAsset,
    handleUploadScanFiles,
    handleRunScanFileOcr,
    handleUploadAssets,
    handleAttachAssetFile,
    handleDeleteFolder,
    handleOpenFileEditor,
    editingDocumentDraft,
    caseResolverTags,
    caseResolverIdentifiers,
    caseResolverCategories,
    handleUpdateSelectedAsset,
    handleSaveFileEditor,
    handleDiscardFileEditorDraft,
    handleRetryCaseContext,
    ConfirmationModal,
    PromptInputModal,
  } = state;

  const [mounted, setMounted] = React.useState(false);
  React.useEffect(() => {
    setMounted(true);
  }, []);

  // Pending navigation stored as a callback so we can execute it after user confirms
  const [pendingNavigation, setPendingNavigation] = React.useState<PendingNavigation | null>(null);

  // Only guard document files — scan files don't have a text editor worth guarding
  const isDirtyDocumentDraft =
    isEditorDraftDirty &&
    editingDocumentDraft !== null &&
    editingDocumentDraft?.fileType !== 'scanfile';

  const guardNavigation = React.useCallback(
    (action: () => void): void => {
      if (isDirtyDocumentDraft) {
        setPendingNavigation({ kind: 'document', action });
        return;
      }
      if (isActiveCaseMetadataDirty) {
        setPendingNavigation({ kind: 'case', action });
        return;
      }
      action();
    },
    [isActiveCaseMetadataDirty, isDirtyDocumentDraft]
  );

  const menuToggleButton = !mounted
    ? null
    : createPortal(
      <Button
        size='xs'
        type='button'
        variant='outline'
        onClick={(): void => setIsMenuCollapsed(!isMenuCollapsed)}
        title={isMenuCollapsed ? 'Show side admin menu' : 'Hide side admin menu'}
        aria-label={isMenuCollapsed ? 'Show side admin menu' : 'Hide side admin menu'}
        className='fixed left-1/2 top-0 z-40 h-8 w-10 -translate-x-1/2 rounded-b-lg rounded-t-none border-t-0 bg-background/90 px-0 shadow-md backdrop-blur-sm animate-in fade-in slide-in-from-top-2'
      >
        {isMenuCollapsed ? <EyeOff className='size-4' /> : <Eye className='size-4' />}
      </Button>,
      document.body
    );

  return (
    <CaseResolverRuntimeProvider
      workspace={workspace}
      selectedFileId={selectedFileId}
      selectedAssetId={selectedAssetId}
      selectedFolderPath={selectedFolderPath}
      activeCaseId={activeCaseId}
      requestedFileId={state.requestedFileId}
      requestedContextStatus={requestedCaseStatus}
      requestedContextIssue={requestedCaseIssue}
    >
      <CaseResolverPageProvider
        value={{
          workspace,
          activeCaseId,
          requestedCaseStatus,
          requestedCaseIssue,
          canCreateInActiveCase,
          onRetryCaseContext: handleRetryCaseContext,
          onResetCaseContext: () => guardNavigation(handleResetCaseContext as () => void),
          selectedFileId,
          selectedAssetId,
          selectedFolderPath,
          activeFile,
          selectedAsset,
          activeCaseFile,
          panelCollapsed: folderPanelCollapsed,
          onPanelCollapsedChange: setFolderPanelCollapsed,
          onDeactivateActiveFile: () => guardNavigation(handleDeactivateActiveFile),
          onSelectFile: (fileId) => guardNavigation(() => handleSelectFile(fileId)),
          onSelectAsset: (assetId) => guardNavigation(() => handleSelectAsset(assetId)),
          onSelectFolder: (folderPath) => guardNavigation(() => handleSelectFolder(folderPath)),
          onCreateFile: handleCreateFile,
          onCreateFolder: handleCreateFolder,
          onDeleteFolder: handleDeleteFolder,
          onCreateScanFile: handleCreateScanFile,
          onCreateImageAsset: handleCreateImageAsset,
          onCreateNodeFile: (targetFolderPath) => {
            handleCreateNodeFile(targetFolderPath);
            setWorkspaceView('document');
          },
          onUploadScanFiles: handleUploadScanFiles,
          onRunScanFileOcr: handleRunScanFileOcr,
          onUploadAssets: handleUploadAssets,
          onAttachAssetFile: handleAttachAssetFile,
          onMoveFile: state.handleMoveFile,
          onMoveAsset: state.handleMoveAsset,
          onMoveFolder: handleMoveFolder,
          onRenameFile: state.handleRenameFile,
          onRenameAsset: state.handleRenameAsset,
          onRenameFolder: state.handleRenameFolder,
          onToggleFolderLock: handleToggleFolderLock,
          onDeleteFile: handleDeleteFile,
          onDeleteAsset: handleDeleteAsset,
          onToggleFileLock: handleToggleFileLock,
          onEditFile: (fileId, options) =>
            guardNavigation(() => handleOpenFileEditor(fileId, options)),
          caseResolverTags,
          caseResolverIdentifiers,
          caseResolverCategories,
          onCreateDocumentFromSearch: handleCreateDocumentFromSearch,
          onOpenFileFromSearch: (id) => guardNavigation(() => handleOpenFileFromSearch(id)),
          onEditFileFromSearch: (id) => guardNavigation(() => handleEditFileFromSearch(id)),
          onUpdateSelectedAsset: handleUpdateSelectedAsset,
          onGraphChange: handleGraphChange,
          onRelationGraphChange: handleRelationGraphChange,
          onLinkRelatedFiles: state.handleLinkRelatedFiles,
          onUnlinkRelatedFile: state.handleUnlinkRelatedFile,
          onUpdateActiveCase: handleUpdateActiveCaseMetadata,
          activeCaseMetadataDraft,
          isActiveCaseMetadataDirty,
          onUpdateActiveCaseDraft: updateActiveCaseMetadataDraft,
          onSaveActiveCase: handleSaveActiveCaseMetadata,
          onDiscardActiveCaseChanges: handleDiscardActiveCaseMetadata,
          caseTagOptions,
          caseIdentifierOptions,
          caseCategoryOptions,
          caseReferenceOptions,
          parentCaseOptions,
          partyOptions,
        }}
      >
        <div className='flex h-full flex-col overflow-hidden bg-background'>
          {menuToggleButton}
          <div className='flex flex-1 overflow-hidden'>
            {!folderPanelCollapsed && (
              <div
                className={`${
                  isMenuCollapsed ? 'w-[26rem]' : 'w-80'
                } flex-shrink-0 border-r border-border bg-card/20`}
              >
                <CaseResolverFolderTree />
              </div>
            )}

            <CaseResolverPageMainContent />
          </div>

          <CaseResolverCaptureMappingModal />

          <ConfirmationModal />
          <PromptInputModal />
          <CaseResolverWorkspaceDebugPanel enabled={workspaceDebugEnabled} />

          {/* Unsaved-changes guard dialog */}
          <Dialog
            open={pendingNavigation !== null}
            onOpenChange={(open) => {
              if (!open) setPendingNavigation(null);
            }}
          >
            <DialogContent className='max-w-md'>
              <DialogHeader>
                <DialogTitle>Unsaved Changes</DialogTitle>
                <DialogDescription>
                  {pendingNavigation?.kind === 'case'
                    ? 'You have unsaved changes in this case. What would you like to do?'
                    : 'You have unsaved changes in this document. What would you like to do?'}
                </DialogDescription>
              </DialogHeader>
              <DialogFooter className='flex-col gap-2 sm:flex-col'>
                <Button
                  onClick={() => {
                    if (pendingNavigation?.kind === 'case') {
                      handleSaveActiveCaseMetadata();
                    } else {
                      handleSaveFileEditor();
                    }
                    pendingNavigation?.action();
                    setPendingNavigation(null);
                  }}
                  className='w-full border-emerald-500/50 bg-emerald-500/10 text-emerald-300 hover:bg-emerald-500/20'
                  variant='outline'
                >
                  Save
                </Button>
                <Button
                  variant='ghost'
                  className='w-full'
                  onClick={() => setPendingNavigation(null)}
                >
                  Cancel
                </Button>
                <Button
                  onClick={() => {
                    if (pendingNavigation?.kind === 'case') {
                      handleDiscardActiveCaseMetadata();
                    } else {
                      handleDiscardFileEditorDraft();
                    }
                    pendingNavigation?.action();
                    setPendingNavigation(null);
                  }}
                  variant='outline'
                  className='w-full border-red-500/40 text-red-400 hover:bg-red-500/10'
                >
                  Discard
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>
      </CaseResolverPageProvider>
    </CaseResolverRuntimeProvider>
  );
}

import type { AiNode } from '@/shared/contracts/case-resolver/../ai-paths-core';
import type { CaseResolverEdge } from '@/shared/contracts/case-resolver/graph';
import type { CaseResolverAssetFile, CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverRelationEdgeMeta, CaseResolverRelationGraph, CaseResolverRelationNodeMeta } from '@/shared/contracts/case-resolver/relations';
import { typeStyles } from '@/shared/lib/ai-paths/core/constants';
import { isObjectRecord } from '@/shared/utils/object-utils';

import { parseCanonicalCaseResolverEdge } from '../settings.edge-validation';

const isCaseResolverFile = (value: unknown): value is CaseResolverFile =>
  isObjectRecord(value) &&
  typeof value['id'] === 'string' &&
  typeof value['name'] === 'string' &&
  typeof value['fileType'] === 'string' &&
  typeof value['folder'] === 'string';

const isCaseResolverAssetFile = (value: unknown): value is CaseResolverAssetFile =>
  isObjectRecord(value) &&
  typeof value['id'] === 'string' &&
  typeof value['name'] === 'string' &&
  typeof value['folder'] === 'string' &&
  typeof value['kind'] === 'string';

const readWorkspaceFolders = (value: unknown): string[] =>
  Array.isArray(value)
    ? value.filter((entry: unknown): entry is string => typeof entry === 'string')
    : [];

const readWorkspaceFiles = (value: unknown): CaseResolverFile[] =>
  Array.isArray(value) ? value.filter(isCaseResolverFile) : [];

const readWorkspaceAssets = (value: unknown): CaseResolverAssetFile[] =>
  Array.isArray(value) ? value.filter(isCaseResolverAssetFile) : [];

export const readWorkspaceSnapshot = (
  workspace: unknown
): {
  relationGraphSource: unknown;
  folders: string[];
  files: CaseResolverFile[];
  assets: CaseResolverAssetFile[];
} => {
  if (!isObjectRecord(workspace)) {
    return {
      relationGraphSource: {},
      folders: [],
      files: [],
      assets: [],
    };
  }
  return {
    relationGraphSource: workspace['relationGraph'],
    folders: readWorkspaceFolders(workspace['folders']),
    files: readWorkspaceFiles(workspace['files']),
    assets: readWorkspaceAssets(workspace['assets']),
  };
};

const hasKnownNodeType = (value: string): value is AiNode['type'] =>
  Object.prototype.hasOwnProperty.call(typeStyles, value);

const normalizeFocusedCaseId = (value: string | null | undefined): string | null => {
  const normalized = value?.trim() ?? '';
  return normalized || null;
};

export const resolveFocusedCaseId = (
  activeFileId: string | null | undefined,
  activeCaseId: string | null | undefined
): string | null => normalizeFocusedCaseId(activeFileId) ?? normalizeFocusedCaseId(activeCaseId);

const readRuntimePorts = (value: unknown, fallbackPort: string): string[] => {
  const ports = Array.isArray(value)
    ? value.filter((port: unknown): port is string => typeof port === 'string' && port.trim().length > 0)
    : [];
  return ports.length > 0 ? ports : [fallbackPort];
};

const readRuntimeNodeCoordinate = (
  positionRecord: Record<string, unknown>,
  key: 'x' | 'y'
): number => {
  const value = positionRecord[key];
  return typeof value === 'number' && Number.isFinite(value) ? value : 0;
};

const toRuntimeNode = (node: CaseResolverRelationGraph['nodes'][number]): AiNode | null => {
  if (!isObjectRecord(node)) return null;
  const id = typeof node['id'] === 'string' ? node['id'].trim() : '';
  if (!id) return null;
  const title = typeof node['title'] === 'string' ? node['title'] : id;
  const description = typeof node['description'] === 'string' ? node['description'] : '';
  const rawType = typeof node['type'] === 'string' ? node['type'].trim() : '';
  const type = rawType && hasKnownNodeType(rawType) ? rawType : 'template';
  const positionRecord = isObjectRecord(node['position'])
    ? node['position']
    : ({} as Record<string, unknown>);
  const config =
    node['config'] && typeof node['config'] === 'object' && !Array.isArray(node['config'])
      ? (node['config'] as AiNode['config'])
      : undefined;
  const createdAt =
    (typeof node['createdAt'] === 'string' ? node['createdAt'] : undefined) ??
    new Date().toISOString();
  const updatedAt =
    (typeof node['updatedAt'] === 'string' ? node['updatedAt'] : undefined) ?? createdAt;
  const data =
    node['data'] && typeof node['data'] === 'object' && !Array.isArray(node['data'])
      ? node['data']
      : {};
  return {
    id,
    createdAt,
    updatedAt,
    type,
    title,
    description,
    inputs: readRuntimePorts(node['inputs'], 'in'),
    outputs: readRuntimePorts(node['outputs'], 'out'),
    position: {
      x: readRuntimeNodeCoordinate(positionRecord, 'x'),
      y: readRuntimeNodeCoordinate(positionRecord, 'y'),
    },
    data,
    ...(config ? { config } : {}),
  };
};

export const toRuntimeNodes = (nodes: CaseResolverRelationGraph['nodes']): AiNode[] =>
  nodes.map(toRuntimeNode).filter((node): node is AiNode => node !== null);

export const toStrictEdges = (inputEdges: CaseResolverEdge[]): CaseResolverRelationGraph['edges'] =>
  inputEdges
    .map((edge: CaseResolverEdge): CaseResolverRelationGraph['edges'][number] => {
      const canonicalEdge = parseCanonicalCaseResolverEdge(edge, 'case_resolver.relations_workspace');
      return {
        id: canonicalEdge.id,
        source: canonicalEdge.source ?? '',
        target: canonicalEdge.target ?? '',
        ...(typeof canonicalEdge.label === 'string' ? { label: canonicalEdge.label } : {}),
        ...(typeof canonicalEdge.sourceHandle === 'string'
          ? { sourceHandle: canonicalEdge.sourceHandle }
          : {}),
        ...(typeof canonicalEdge.targetHandle === 'string'
          ? { targetHandle: canonicalEdge.targetHandle }
          : {}),
      };
    })
    .filter(
      (edge): edge is CaseResolverRelationGraph['edges'][number] =>
        typeof edge.source === 'string' &&
        edge.source.trim().length > 0 &&
        typeof edge.target === 'string' &&
        edge.target.trim().length > 0
    );

export const readRelationNodeMetaMap = (
  graph: CaseResolverRelationGraph
): Record<string, CaseResolverRelationNodeMeta> => {
  const value = (graph as Record<string, unknown>)['nodeMeta'];
  return isObjectRecord(value) ? (value as Record<string, CaseResolverRelationNodeMeta>) : {};
};

export const readRelationEdgeMetaMap = (
  graph: CaseResolverRelationGraph
): Record<string, CaseResolverRelationEdgeMeta> => {
  const value = (graph as Record<string, unknown>)['edgeMeta'];
  return isObjectRecord(value) ? (value as Record<string, CaseResolverRelationEdgeMeta>) : {};
};

const isCaseRelationNode = (
  nodeId: string,
  nodeMetaMap: Record<string, CaseResolverRelationNodeMeta>
): boolean => {
  const nodeMeta = nodeMetaMap[nodeId];
  if (nodeMeta && typeof nodeMeta.entityType === 'string') {
    return nodeMeta.entityType === 'case';
  }
  return nodeId.startsWith('case:');
};

const readEdgeEndpoints = (
  edge: unknown
): { id: string; source: string; target: string } | null => {
  if (!isObjectRecord(edge)) return null;
  const id = typeof edge['id'] === 'string' ? edge['id'].trim() : '';
  const source = typeof edge['source'] === 'string' ? edge['source'].trim() : '';
  const target = typeof edge['target'] === 'string' ? edge['target'].trim() : '';
  if (!id || !source || !target) return null;
  return { id, source, target };
};

export const projectCaseOnlyRelationGraph = (
  graph: CaseResolverRelationGraph
): CaseResolverRelationGraph => {
  const relationNodeMeta = readRelationNodeMetaMap(graph);
  const caseNodeIds = new Set<string>();

  const caseNodes = graph.nodes.filter((node): boolean => {
    if (!isObjectRecord(node)) return false;
    const nodeId = typeof node['id'] === 'string' ? node['id'].trim() : '';
    if (!nodeId) return false;
    if (!isCaseRelationNode(nodeId, relationNodeMeta)) return false;
    caseNodeIds.add(nodeId);
    return true;
  });

  const caseEdges = toStrictEdges(graph.edges).filter((edge): boolean => {
    const endpoints = readEdgeEndpoints(edge);
    if (!endpoints) return false;
    return caseNodeIds.has(endpoints.source) && caseNodeIds.has(endpoints.target);
  });

  const caseNodeMeta: Record<string, CaseResolverRelationNodeMeta> = {};
  caseNodeIds.forEach((nodeId: string): void => {
    const meta = relationNodeMeta[nodeId];
    if (meta) {
      caseNodeMeta[nodeId] = meta;
    }
  });

  const relationEdgeMeta = readRelationEdgeMetaMap(graph);
  const caseEdgeIds = new Set<string>();
  caseEdges.forEach((edge: CaseResolverRelationGraph['edges'][number]): void => {
    const endpoints = readEdgeEndpoints(edge);
    if (!endpoints) return;
    caseEdgeIds.add(endpoints.id);
  });
  const caseEdgeMeta: Record<string, CaseResolverRelationEdgeMeta> = {};
  Object.entries(relationEdgeMeta).forEach(
    ([edgeId, meta]: [string, CaseResolverRelationEdgeMeta]): void => {
      if (!caseEdgeIds.has(edgeId)) return;
      caseEdgeMeta[edgeId] = meta;
    }
  );

  return {
    nodes: caseNodes,
    edges: caseEdges,
    nodeMeta: caseNodeMeta,
    edgeMeta: caseEdgeMeta,
  };
};

