'use client';

import React from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import type {
  CaseResolverCaptureDocumentDateAction,
  CaseResolverCaptureProposalState,
} from '@/features/case-resolver/capture/public';
import { type CaseResolverCaptureAction } from '@/features/case-resolver/capture/public';
import { encodeFilemakerPartyReference } from '@/features/filemaker/public';
import { Badge, Button } from '@/shared/ui/primitives.public';
import { FormField, SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { DetailModal } from '@/shared/ui/templates/modals/DetailModal';

import {
  type PromptExploderCaptureMappingModalRuntimeValue,
  useOptionalPromptExploderCaptureMappingModalRuntime,
} from './PromptExploderCaptureMappingModalRuntimeContext';

type PromptExploderCaptureMappingModalProps = PromptExploderCaptureMappingModalRuntimeValue;

export function PromptExploderCaptureMappingModal(
  props: Partial<PromptExploderCaptureMappingModalProps> = {}
): React.JSX.Element {
  const runtime = useOptionalPromptExploderCaptureMappingModalRuntime();
  const resolvedProps =
    props.onUpdateAction !== undefined
      ? (props as PromptExploderCaptureMappingModalProps)
      : runtime;

  if (!resolvedProps) {
    throw new Error(
      'PromptExploderCaptureMappingModal must be used within PromptExploderCaptureMappingModalRuntimeProvider or receive explicit props'
    );
  }

  const {
    open,
    draft,
    applying,
    targetFileName,
    partyOptions,
    onClose,
    onApply,
    onUpdateAction,
    onUpdateReference,
    onUpdateDateAction,
    resolveMatchedPartyLabel,
    diagnostics,
  } = resolvedProps;

  const [closeConfirmOpen, setCloseConfirmOpen] = React.useState(false);

  const resolveActionOptions = (
    proposal: NonNullable<CaseResolverCaptureProposalState['addresser']>
  ): Array<LabeledOptionDto<CaseResolverCaptureAction>> => {
    if (proposal.matchKind === 'party' || proposal.matchKind === 'party_and_address') {
      return [
        { value: 'useMatched', label: 'Use matched Filemaker record' },
        { value: 'keepText', label: 'Keep as text only' },
        { value: 'ignore', label: 'Ignore this capture' },
      ];
    }
    return [
      { value: 'createInFilemaker', label: 'Add to Filemaker database' },
      { value: 'keepText', label: 'Keep as text only' },
      { value: 'ignore', label: 'Ignore this capture' },
    ];
  };

  const resolveMatchBadgeLabel = (
    proposal: NonNullable<CaseResolverCaptureProposalState['addresser']>
  ): string => {
    if (proposal.matchKind === 'party_and_address') return 'Matched in Filemaker';
    if (proposal.matchKind === 'party') return 'Matched party';
    if (proposal.matchKind === 'address') return 'Matched address only';
    return proposal.hasAddressCandidate ? 'Address found, not matched' : 'No match';
  };

  const dateActionOptions: Array<LabeledOptionDto<CaseResolverCaptureDocumentDateAction>> = [
    {
      value: 'useDetectedDate',
      label: 'Use detected date and remove it from text',
    },
    {
      value: 'keepText',
      label: 'Keep date in text only',
    },
    {
      value: 'ignore',
      label: 'Ignore date capture',
    },
  ];

  return (
    <>
      <DetailModal
        isOpen={open && draft !== null}
        onClose={onClose}
        title='Prompt Exploder Capture Mapping'
        subtitle='Review and edit addresser/addressee mapping before it updates this document.'
        size='lg'
        showClose={false}
        closeOnOutside={false}
        closeOnEscape={false}
        onInteractOutside={(): void => {
          setCloseConfirmOpen(true);
        }}
        onEscapeKeyDown={(): void => {
          setCloseConfirmOpen(true);
        }}
        footer={
          <div className='flex w-full justify-end gap-2'>
            <Button type='button' variant='outline' onClick={onClose} disabled={applying} size='sm'>
              Dismiss (No Mapping)
            </Button>
            <Button type='button' onClick={onApply} disabled={!draft || applying} size='sm'>
              {applying ? 'Applying...' : 'Apply Mapping'}
            </Button>
          </div>
        }
      >
        {draft ? (
          <div className='space-y-4'>
            <div className='rounded border border-border/60 bg-card/30 px-3 py-2 text-xs text-gray-300'>
              Target File: <span className='font-medium text-gray-100'>{targetFileName}</span>
            </div>
            {diagnostics ? (
              <div className='rounded border border-border/60 bg-card/20 px-3 py-2 text-[11px] text-gray-300'>
                <div>
                  Apply status:{' '}
                  <span className='font-medium text-gray-100'>{diagnostics.status}</span>
                  {diagnostics.stage ? ` (${diagnostics.stage})` : ''}
                </div>
                <div className='mt-0.5'>{diagnostics.message}</div>
                <div className='mt-0.5 text-gray-400'>
                  target: {diagnostics.targetFileId ?? '(none)'} · resolved:{' '}
                  {diagnostics.resolvedTargetFileId ?? '(none)'} · rev:{' '}
                  {diagnostics.workspaceRevision} · attempts: {diagnostics.attempts}
                </div>
                {(diagnostics.cleanupDurationMs !== null &&
                  diagnostics.cleanupDurationMs !== undefined) ||
                (diagnostics.mutationDurationMs !== null &&
                  diagnostics.mutationDurationMs !== undefined) ||
                (diagnostics.totalDurationMs !== null &&
                  diagnostics.totalDurationMs !== undefined) ? (
                    <div className='mt-0.5 text-gray-500'>
                    cleanup: {diagnostics.cleanupDurationMs ?? '-'}ms · mutation:{' '}
                      {diagnostics.mutationDurationMs ?? '-'}ms · total:{' '}
                      {diagnostics.totalDurationMs ?? '-'}ms
                    </div>
                  ) : null}
              </div>
            ) : null}

            {draft.documentDate ? (
              <div className='space-y-3 rounded border border-border/60 bg-card/25 p-3'>
                <div className='flex items-center justify-between gap-3'>
                  <div className='flex items-center gap-2'>
                    <div className='text-sm font-semibold text-gray-100'>Document Date</div>
                    <Badge variant='outline' className='px-1.5 py-0 text-[10px]'>
                      Source: {draft.documentDate.source === 'metadata' ? 'Metadata' : 'Text'}
                    </Badge>
                  </div>
                </div>
                <div className='rounded border border-border/60 bg-card/30 p-2 text-xs text-gray-200'>
                  <div>
                    Detected date: <span className='font-medium'>{draft.documentDate.isoDate}</span>
                  </div>
                  {draft.documentDate.city ? (
                    <div className='mt-1'>
                      Captured city: <span className='font-medium'>{draft.documentDate.city}</span>
                    </div>
                  ) : null}
                  {draft.documentDate.sourceLine ? (
                    <div className='mt-1 text-[11px] text-gray-400'>
                      Source line: {draft.documentDate.sourceLine}
                    </div>
                  ) : null}
                </div>
                <FormField label='Date Action'>
                  <SelectSimple
                    size='sm'
                    value={draft.documentDate.action}
                    onValueChange={(value: string): void => {
                      if (
                        value === 'useDetectedDate' ||
                        value === 'keepText' ||
                        value === 'ignore'
                      ) {
                        onUpdateDateAction(value);
                      }
                    }}
                    options={dateActionOptions}
                    triggerClassName='h-9'
                   ariaLabel='Date Action' title='Date Action'/>
                </FormField>
              </div>
            ) : (
              <div className='rounded border border-dashed border-border/60 bg-card/20 px-3 py-3 text-sm text-gray-400'>
                No captured document date in this Prompt Exploder payload.
              </div>
            )}

            {(['addresser', 'addressee'] as const).map((role) => {
              const proposal = draft[role];
              const roleLabel = role === 'addresser' ? 'Addresser' : 'Addressee';
              if (!proposal) {
                return (
                  <div
                    key={role}
                    className='rounded border border-dashed border-border/60 bg-card/20 px-3 py-3 text-sm text-gray-400'
                  >
                    No captured {roleLabel.toLowerCase()} candidate in this Prompt Exploder payload.
                  </div>
                );
              }

              const matchedPartyLabel = proposal.existingReference
                ? resolveMatchedPartyLabel(proposal.existingReference)
                : 'None';
              const actionOptions = resolveActionOptions(proposal);
              const selectedAction = actionOptions.some(
                (option) => option.value === proposal.action
              )
                ? proposal.action
                : (actionOptions[0]?.value ?? 'ignore');
              const shouldShowMatchedPartySelector = selectedAction === 'useMatched';

              return (
                <div
                  key={role}
                  className='space-y-3 rounded border border-border/60 bg-card/25 p-3'
                >
                  <div className='flex items-center justify-between gap-3'>
                    <div className='flex items-center gap-2'>
                      <div className='text-sm font-semibold text-gray-100'>{roleLabel}</div>
                      <Badge variant='outline' className='px-1.5 py-0 text-[10px]'>
                        {resolveMatchBadgeLabel(proposal)}
                      </Badge>
                    </div>
                    <div className='text-[11px] text-gray-400'>
                      Source role: {proposal.sourceRole}
                    </div>
                  </div>

                  <div className='rounded border border-border/60 bg-card/30 p-2'>
                    <div className='text-[11px] uppercase tracking-wide text-gray-500'>
                      Captured Text
                    </div>
                    <div className='mt-1 whitespace-pre-wrap text-xs text-gray-200'>
                      {proposal.candidate.rawText ||
                        proposal.candidate.displayName ||
                        'No captured text.'}
                    </div>
                  </div>

                  <div className='grid gap-3 md:grid-cols-2'>
                    <FormField label='Action'>
                      <SelectSimple
                        size='sm'
                        value={selectedAction}
                        onValueChange={(value: string): void => {
                          if (
                            value === 'useMatched' ||
                            value === 'createInFilemaker' ||
                            value === 'keepText' ||
                            value === 'ignore'
                          ) {
                            onUpdateAction(role, value);
                          }
                        }}
                        options={actionOptions}
                        triggerClassName='h-9'
                       ariaLabel='Action' title='Action'/>
                    </FormField>

                    {shouldShowMatchedPartySelector ? (
                      <FormField label='Database Party'>
                        <SelectSimple
                          size='sm'
                          value={encodeFilemakerPartyReference(proposal.existingReference)}
                          onValueChange={(value: string): void => {
                            onUpdateReference(role, value);
                          }}
                          options={partyOptions}
                          triggerClassName='h-9'
                         ariaLabel='Database Party' title='Database Party'/>
                      </FormField>
                    ) : (
                      <FormField label='Matched Party'>
                        <div className='h-9 rounded border border-border/60 bg-card/30 px-3 py-2 text-xs text-gray-300'>
                          {matchedPartyLabel}
                        </div>
                      </FormField>
                    )}
                  </div>

                  {proposal.existingAddressId ? (
                    <div className='text-[11px] text-gray-500'>
                      Matched address ID: {proposal.existingAddressId}
                    </div>
                  ) : proposal.hasAddressCandidate ? (
                    <div className='text-[11px] text-gray-500'>
                      Address candidate detected (not matched in Filemaker).
                    </div>
                  ) : null}
                </div>
              );
            })}
          </div>
        ) : null}
      </DetailModal>
      <ConfirmModal
        isOpen={closeConfirmOpen}
        onClose={(): void => {
          setCloseConfirmOpen(false);
        }}
        title='Apply capture mapping?'
        message='Apply the capture mapping to the document, or cancel to return to the mapping review.'
        confirmText='Apply Mapping'
        cancelText='Cancel'
        loading={applying}
        onConfirm={(): void => {
          setCloseConfirmOpen(false);
          onApply();
        }}
      />
    </>
  );
}

import { type Edge as AiEdge, type AiNode, type NodeDefinition } from '@/shared/contracts/ai-paths';
import { DEFAULT_CASE_RESOLVER_EDGE_META, DEFAULT_CASE_RESOLVER_NODE_META, resolveCaseResolverPdfExtractionTemplate } from '@/shared/contracts/case-resolver/constants';
import { type CaseResolverPdfExtractRequest, type CaseResolverPdfExtractResponse, type CaseResolverEdgeMeta, type CaseResolverFile, type CaseResolverGraph, type CaseResolverNodeMeta, type CaseResolverPdfExtractionPresetId, type CaseResolverDroppedAsset, type CaseResolverDroppedDocument } from '@/shared/contracts/case-resolver';
import type { Toast } from '@/shared/contracts/ui/base';
import { palette } from '@/shared/lib/ai-paths/core/definitions';

import {
  DOCUMENT_PLAINTEXT_CONTENT_PORT,
  buildCanvasNodeFileTemplate,
  buildNode,
  buildPromptTemplateFromDroppedDocumentFile,
  clampCanvasPosition,
  createEdgeId,
  createNodeId,
  ensureDocumentPromptPorts,
  normalizeExtractedPdfText,
  resolvePromptConfig,
} from './case-resolver-canvas-utils';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

type CreateCaseResolverCanvasDropHandlersInput = {
  addNode: (node: AiNode) => void;
  addEdge: (edge: AiEdge) => void;
  updateNode: (id: string, patch: Partial<AiNode>) => void;
  selectNode: (nodeId: string) => void;
  focusNodeInCanvas: (nodeId: string, position: { x: number; y: number }) => void;
  onGraphChange: (graph: CaseResolverGraph) => void;
  nodes: AiNode[];
  edges: AiEdge[];
  normalizedNodeMeta: Record<string, CaseResolverNodeMeta>;
  normalizedEdgeMeta: Record<string, CaseResolverEdgeMeta>;
  normalizedDocumentFileLinksByNode: Record<string, string[]>;
  normalizedDocumentDropNodeId: string | null;
  normalizedDocumentSourceFileIdByNode: Record<string, string>;
  pdfExtractionPresetId: CaseResolverPdfExtractionPresetId;
  availableFileIds: Set<string>;
  availableFilesById: Map<string, CaseResolverFile>;
  toast: Toast;
};

export const createCaseResolverCanvasDropHandlers = ({
  addNode,
  addEdge,
  updateNode,
  selectNode,
  focusNodeInCanvas,
  onGraphChange,
  nodes,
  edges,
  normalizedNodeMeta,
  normalizedEdgeMeta,
  normalizedDocumentFileLinksByNode,
  normalizedDocumentDropNodeId,
  normalizedDocumentSourceFileIdByNode,
  pdfExtractionPresetId,
  availableFileIds,
  availableFilesById,
  toast,
}: CreateCaseResolverCanvasDropHandlersInput): {
  addDroppedAssetNode: (
    asset: CaseResolverDroppedAsset,
    dropPosition: { x: number; y: number },
    indexOffset?: number
  ) => Promise<void>;
  handleDroppedDocuments: (
    droppedDocuments: CaseResolverDroppedDocument[],
    dropPosition: { x: number; y: number }
  ) => void;
  showDocumentNodeInCanvas: (fileId: string, preferredNodeId?: string | null) => void;
} => {
  const toCaseResolverEdge = (edge: AiEdge): CaseResolverGraph['edges'][number] | null => {
    if (!edge.source || !edge.target) return null;
    return {
      id: edge.id,
      source: edge.source,
      target: edge.target,
      ...(edge.label ? { label: edge.label } : {}),
      ...(edge.sourceHandle ? { sourceHandle: edge.sourceHandle } : {}),
      ...(edge.targetHandle ? { targetHandle: edge.targetHandle } : {}),
    };
  };
  const toCanvasEdge = (edge: CaseResolverGraph['edges'][number]): AiEdge => ({
    id: edge.id,
    source: edge.source ?? '',
    target: edge.target ?? '',
    type: 'default',
    data: {},
    createdAt: new Date().toISOString(),
    updatedAt: null,
    ...(edge.sourceHandle ? { sourceHandle: edge.sourceHandle } : {}),
    ...(edge.targetHandle ? { targetHandle: edge.targetHandle } : {}),
  });
  const existingEdges: CaseResolverGraph['edges'] = edges
    .map(toCaseResolverEdge)
    .filter((edge): edge is CaseResolverGraph['edges'][number] => edge !== null);

  const extractPdfText = async (filepath: string): Promise<string> => {
    try {
      const request: CaseResolverPdfExtractRequest = { filepath };
      const response = await fetch('/api/case-resolver/assets/extract-pdf', {
        method: 'POST',
        headers: {
          'content-type': 'application/json',
        },
        body: JSON.stringify(request),
      });
      if (!response.ok) {
        const fallbackMessage = `Failed to extract PDF (${response.status})`;
        let detail = fallbackMessage;
        try {
          const payload = (await response.json()) as { error?: string | { message?: string } };
          if (typeof payload.error === 'string') {
            detail = payload.error;
          } else if (payload.error && typeof payload.error.message === 'string') {
            detail = payload.error.message;
          }
        } catch (error) {
          logClientError(error);
          detail = fallbackMessage;
        }
        throw new Error(detail);
      }
      const payload = (await response.json()) as CaseResolverPdfExtractResponse;
      return typeof payload.text === 'string' ? payload.text : '';
    } catch (error) {
      logClientError(error);
      throw new Error(
        `PDF extraction failed: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  };

  const addPdfExtractionPipeline = async (
    asset: CaseResolverDroppedAsset,
    dropPosition: { x: number; y: number },
    indexOffset = 0
  ): Promise<void> => {
    try {
      const promptDefinition = palette.find((entry: NodeDefinition) => entry.type === 'prompt');
      const modelDefinition = palette.find((entry: NodeDefinition) => entry.type === 'model');
      if (!promptDefinition || !modelDefinition) {
        toast('Missing Prompt/Model node definitions for PDF flow.', { variant: 'error' });
        return;
      }

      let extractedText = normalizeExtractedPdfText(asset.textContent);
      if (!extractedText && asset.filepath) {
        try {
          extractedText = normalizeExtractedPdfText(await extractPdfText(asset.filepath));
        } catch (error: unknown) {
          logClientError(error);
          toast(
            error instanceof Error
              ? `${error.message}. PDF node will use file path only.`
              : 'Failed to extract PDF text. PDF node will use file path only.',
            { variant: 'warning' }
          );
        }
      }

      const basePosition = clampCanvasPosition({
        x: dropPosition.x + indexOffset * 36,
        y: dropPosition.y + indexOffset * 36,
      });
      const extractionPromptPosition = clampCanvasPosition({
        x: basePosition.x + 380,
        y: basePosition.y,
      });
      const modelPosition = clampCanvasPosition({
        x: extractionPromptPosition.x + 380,
        y: extractionPromptPosition.y,
      });
      const outputPosition = clampCanvasPosition({
        x: modelPosition.x + 380,
        y: modelPosition.y,
      });

      const pdfNodeId = createNodeId();
      const extractionPromptId = createNodeId();
      const modelNodeId = createNodeId();
      const outputNodeId = createNodeId();

      const pdfSourceTemplate = [
        `PDF File: ${asset.name}`,
        ...(asset.filepath ? [`Path: ${asset.filepath}`] : []),
        ...(asset.mimeType ? [`MIME: ${asset.mimeType}`] : []),
        '',
        'PDF_TEXT_BEGIN',
        extractedText || '(No extracted PDF text available. Use the PDF path above as reference.)',
        'PDF_TEXT_END',
      ].join('\n');

      const pdfNodeBase = buildNode(
        promptDefinition,
        basePosition,
        pdfNodeId,
        `PDF Source: ${asset.name}`
      );
      const pdfNodePromptConfig = resolvePromptConfig(pdfNodeBase);
      const pdfNode: AiNode = {
        ...pdfNodeBase,
        config: {
          ...(pdfNodeBase.config ?? {}),
          prompt: {
            ...pdfNodePromptConfig,
            template: pdfSourceTemplate,
          },
        },
      };

      const extractionPromptBase = buildNode(
        promptDefinition,
        extractionPromptPosition,
        extractionPromptId,
        `Prompt: Extract ${asset.name}`
      );
      const extractionPromptConfig = resolvePromptConfig(extractionPromptBase);
      const extractionPromptNode: AiNode = {
        ...extractionPromptBase,
        config: {
          ...(extractionPromptBase.config ?? {}),
          prompt: {
            ...extractionPromptConfig,
            template: resolveCaseResolverPdfExtractionTemplate(pdfExtractionPresetId),
          },
        },
      };

      const modelNode = buildNode(
        modelDefinition,
        modelPosition,
        modelNodeId,
        `AI Model: ${asset.name}`
      );

      const outputPromptBase = buildNode(
        promptDefinition,
        outputPosition,
        outputNodeId,
        `WYSIWYG Output: ${asset.name}`
      );
      const outputPromptConfig = resolvePromptConfig(outputPromptBase);
      const outputNode: AiNode = ensureDocumentPromptPorts({
        ...outputPromptBase,
        config: {
          ...(outputPromptBase.config ?? {}),
          prompt: {
            ...outputPromptConfig,
            template: '<p>{{result}}</p>',
          },
        },
      });

      const edgePdfToPrompt: CaseResolverGraph['edges'][number] = {
        id: createEdgeId(),
        source: pdfNodeId,
        target: extractionPromptId,
        sourceHandle: 'prompt',
        targetHandle: 'result',
      };
      const edgePromptToModel: CaseResolverGraph['edges'][number] = {
        id: createEdgeId(),
        source: extractionPromptId,
        target: modelNodeId,
        sourceHandle: 'prompt',
        targetHandle: 'prompt',
      };
      const edgeModelToOutput: CaseResolverGraph['edges'][number] = {
        id: createEdgeId(),
        source: modelNodeId,
        target: outputNodeId,
        sourceHandle: 'result',
        targetHandle: DOCUMENT_PLAINTEXT_CONTENT_PORT,
      };

      addNode(pdfNode);
      addNode(extractionPromptNode);
      addNode(modelNode);
      addNode(outputNode);
      addEdge(toCanvasEdge(edgePdfToPrompt));
      addEdge(toCanvasEdge(edgePromptToModel));
      addEdge(toCanvasEdge(edgeModelToOutput));
      selectNode(outputNodeId);

      onGraphChange({
        nodes: [...nodes, pdfNode, extractionPromptNode, modelNode, outputNode],
        edges: [...existingEdges, edgePdfToPrompt, edgePromptToModel, edgeModelToOutput],
        nodeMeta: {
          ...normalizedNodeMeta,
          [extractionPromptId]: {
            ...DEFAULT_CASE_RESOLVER_NODE_META,
            role: 'ai_prompt',
            includeInOutput: false,
            quoteMode: 'none',
            surroundPrefix: '',
            surroundSuffix: '',
          },
          [outputNodeId]: {
            ...DEFAULT_CASE_RESOLVER_NODE_META,
            role: 'text_note',
            includeInOutput: true,
            quoteMode: 'none',
            surroundPrefix: '',
            surroundSuffix: '',
          },
        },
        edgeMeta: {
          ...normalizedEdgeMeta,
          [edgePdfToPrompt.id]: { ...DEFAULT_CASE_RESOLVER_EDGE_META },
          [edgePromptToModel.id]: { ...DEFAULT_CASE_RESOLVER_EDGE_META },
          [edgeModelToOutput.id]: { ...DEFAULT_CASE_RESOLVER_EDGE_META },
        },
        pdfExtractionPresetId,
        documentFileLinksByNode: normalizedDocumentFileLinksByNode,
        documentDropNodeId: normalizedDocumentDropNodeId,
        documentSourceFileIdByNode: normalizedDocumentSourceFileIdByNode,
      });
    } catch (error) {
      logClientError(error);
      toast(
        error instanceof Error
          ? `PDF pipeline creation failed: ${error.message}`
          : 'An unknown error occurred in the PDF pipeline.',
        { variant: 'error' }
      );
    }
  };

  const addDroppedAssetNode = async (
    asset: CaseResolverDroppedAsset,
    dropPosition: { x: number; y: number },
    indexOffset = 0
  ): Promise<void> => {
    if (asset.kind === 'pdf') {
      await addPdfExtractionPipeline(asset, dropPosition, indexOffset);
      return;
    }

    const position = clampCanvasPosition({
      x: dropPosition.x + indexOffset * 28,
      y: dropPosition.y + indexOffset * 28,
    });
    const promptDefinition = palette.find((entry: NodeDefinition) => entry.type === 'prompt');

    if (!promptDefinition) return;
    const id = createNodeId();
    const node = buildNode(promptDefinition, position, id, `File: ${asset.name}`);
    const promptConfig = resolvePromptConfig(node);
    const summaryParts = [
      `Asset: ${asset.name}`,
      `Kind: ${asset.kind}`,
      ...(asset.filepath ? [`Path: ${asset.filepath}`] : []),
      ...(asset.mimeType ? [`MIME: ${asset.mimeType}`] : []),
      ...(asset.size !== null ? [`Size: ${asset.size} bytes`] : []),
      ...(asset.description.trim().length > 0 ? [`Description: ${asset.description}`] : []),
    ];
    addNode({
      ...node,
      config: {
        ...(node.config ?? {}),
        prompt: {
          ...promptConfig,
          template: summaryParts.join('\n'),
        },
      },
    });
    selectNode(id);
  };

  const handleDroppedDocuments = (
    droppedDocuments: CaseResolverDroppedDocument[],
    dropPosition: { x: number; y: number }
  ): void => {
    if (droppedDocuments.length === 0) return;

    const normalizedFileIds = Array.from(
      new Set(
        droppedDocuments
          .map((entry: CaseResolverDroppedDocument) => entry.id.trim())
          .filter((fileId: string) => fileId.length > 0 && availableFileIds.has(fileId))
      )
    );
    if (normalizedFileIds.length === 0) {
      toast('Dropped document is not available in this workspace.', { variant: 'warning' });
      return;
    }

    const droppedFiles = normalizedFileIds
      .map((fileId: string): CaseResolverFile | null => availableFilesById.get(fileId) ?? null)
      .filter((file: CaseResolverFile | null): file is CaseResolverFile => file !== null);

    const droppedDocumentFiles = droppedFiles.filter(
      (file: CaseResolverFile): boolean => file.fileType !== 'case'
    );
    if (droppedDocumentFiles.length > 0) {
      const promptDefinition = palette.find((entry: NodeDefinition) => entry.type === 'prompt');
      if (!promptDefinition) {
        toast('Prompt node definition is missing.', { variant: 'error' });
        return;
      }

      let nextNodes = [...nodes];
      const nextNodeMeta = { ...normalizedNodeMeta };
      const nextDocumentSourceFileIdByNode = { ...normalizedDocumentSourceFileIdByNode };
      let lastCreatedNodeId: string | null = null;
      let lastCreatedNodePosition: { x: number; y: number } | null = null;

      droppedDocumentFiles.forEach((file: CaseResolverFile, index: number): void => {
        const id = createNodeId();
        const position = clampCanvasPosition({
          x: dropPosition.x + index * 28,
          y: dropPosition.y + index * 28,
        });
        const node = buildNode(promptDefinition, position, id, `Document: ${file.name}`);
        const promptConfig = resolvePromptConfig(node);
        const promptNode = ensureDocumentPromptPorts({
          ...node,
          config: {
            ...(node.config ?? {}),
            prompt: {
              ...promptConfig,
              template: buildPromptTemplateFromDroppedDocumentFile(file),
            },
          },
        });
        addNode(promptNode);
        nextNodes = [...nextNodes, promptNode];
        nextNodeMeta[id] = {
          ...DEFAULT_CASE_RESOLVER_NODE_META,
          role: 'text_note',
          includeInOutput: true,
          quoteMode: 'none',
          surroundPrefix: '',
          surroundSuffix: '',
        };
        nextDocumentSourceFileIdByNode[id] = file.id;
        lastCreatedNodeId = id;
        lastCreatedNodePosition = position;
      });

      if (lastCreatedNodeId && lastCreatedNodePosition) {
        focusNodeInCanvas(lastCreatedNodeId, lastCreatedNodePosition);
      }

      onGraphChange({
        nodes: nextNodes,
        edges: existingEdges,
        nodeMeta: nextNodeMeta,
        edgeMeta: normalizedEdgeMeta,
        pdfExtractionPresetId,
        documentFileLinksByNode: normalizedDocumentFileLinksByNode,
        documentDropNodeId: normalizedDocumentDropNodeId,
        documentSourceFileIdByNode: nextDocumentSourceFileIdByNode,
      });

      toast(
        droppedDocumentFiles.length === 1
          ? 'Created document text node. Use Node Inspector for quote/surround options.'
          : `Created ${droppedDocumentFiles.length} document text nodes.`,
        { variant: 'success' }
      );
      return;
    }

    const promptDefinition = palette.find((entry: NodeDefinition) => entry.type === 'prompt');
    if (!promptDefinition) {
      toast('Prompt node definition is missing.', { variant: 'error' });
      return;
    }

    let nextNodes = nodes;
    let targetNodeId = normalizedDocumentDropNodeId;

    if (!targetNodeId) {
      const id = createNodeId();
      const node = buildNode(
        promptDefinition,
        clampCanvasPosition(dropPosition),
        id,
        'Canvas Node File'
      );
      targetNodeId = id;
      nextNodes = [...nextNodes, node];
      addNode(node);
      focusNodeInCanvas(id, node.position);
    }

    const existingLinkedFileIds = normalizedDocumentFileLinksByNode[targetNodeId] ?? [];
    const nextLinkedFileIds = Array.from(new Set([...existingLinkedFileIds, ...normalizedFileIds]));
    const nextDocumentFileLinksByNode = {
      ...normalizedDocumentFileLinksByNode,
      [targetNodeId]: nextLinkedFileIds,
    };

    const targetNode = nextNodes.find((node: AiNode) => node.id === targetNodeId);
    if (!targetNode) {
      toast('Failed to resolve Canvas Node File target.', { variant: 'error' });
      return;
    }
    if (targetNode.type !== 'prompt') {
      toast('Canvas Node File must use prompt node type.', { variant: 'error' });
      return;
    }
    const promptConfig = resolvePromptConfig(targetNode);
    const nextTemplate = buildCanvasNodeFileTemplate(nextLinkedFileIds, availableFilesById);

    const nextTargetNode: AiNode = {
      ...targetNode,
      title: 'Canvas Node File',
      config: {
        ...(targetNode.config ?? {}),
        prompt: {
          ...promptConfig,
          template: nextTemplate,
        },
      },
    };
    nextNodes = nextNodes.map((node: AiNode) => (node.id === targetNodeId ? nextTargetNode : node));
    updateNode(targetNodeId, {
      title: 'Canvas Node File',
      config: nextTargetNode.config,
    });

    onGraphChange({
      nodes: nextNodes,
      edges: existingEdges,
      nodeMeta: normalizedNodeMeta,
      edgeMeta: normalizedEdgeMeta,
      pdfExtractionPresetId,
      documentFileLinksByNode: nextDocumentFileLinksByNode,
      documentDropNodeId: targetNodeId,
      documentSourceFileIdByNode: normalizedDocumentSourceFileIdByNode,
    });

    toast(
      normalizedFileIds.length === 1
        ? 'Document linked to Canvas Node File.'
        : `${normalizedFileIds.length} documents linked to Canvas Node File.`,
      { variant: 'success' }
    );
  };

  const showDocumentNodeInCanvas = (fileId: string, preferredNodeId?: string | null): void => {
    const normalizedFileId = fileId.trim();
    if (!normalizedFileId) return;

    const isLinkedNode = (node: AiNode): boolean =>
      normalizedDocumentSourceFileIdByNode[node.id] === normalizedFileId;

    let targetNode: AiNode | null = null;
    if (preferredNodeId) {
      const preferred = nodes.find((node: AiNode): boolean => node.id === preferredNodeId) ?? null;
      if (preferred && isLinkedNode(preferred)) {
        targetNode = preferred;
      }
    }

    if (!targetNode) {
      const reverseNodes = [...nodes].reverse();
      targetNode = reverseNodes.find(isLinkedNode) ?? null;
    }

    if (!targetNode) {
      toast('Document node is no longer on canvas.', { variant: 'warning' });
      return;
    }

    focusNodeInCanvas(targetNode.id, targetNode.position);
  };

  return {
    addDroppedAssetNode,
    handleDroppedDocuments,
    showDocumentNodeInCanvas,
  };
};

import { CASE_RESOLVER_DOCUMENT_NODE_INPUT_PORTS, CASE_RESOLVER_DOCUMENT_NODE_OUTPUT_PORTS, CASE_RESOLVER_EXPLANATORY_NODE_INPUT_PORTS, CASE_RESOLVER_EXPLANATORY_NODE_OUTPUT_PORTS, CASE_RESOLVER_EXPLANATORY_WYSIWYG_CONTENT_PORT, DEFAULT_CASE_RESOLVER_EDGE_META, DEFAULT_CASE_RESOLVER_NODE_META } from '@/shared/contracts/case-resolver/constants';
import { type AiNode, type NodeDefinition, type CaseResolverEdgeMeta, type CaseResolverFile, type CaseResolverNodeMeta } from '@/shared/contracts/case-resolver';
import {
  CANVAS_HEIGHT,
  CANVAS_WIDTH,
  NODE_MIN_HEIGHT,
  NODE_WIDTH,
} from '@/shared/lib/ai-paths/core/constants';
import { getDefaultConfigForType } from '@/shared/lib/ai-paths/core/normalization';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const buildNode = (
  definition: NodeDefinition,
  position: { x: number; y: number },
  id: string,
  title: string
): AiNode => {
  const now = new Date().toISOString();
  const defaultConfig = getDefaultConfigForType(
    definition.type,
    definition.outputs,
    definition.inputs
  );
  const mergedConfig = definition.config
    ? {
      ...(defaultConfig ?? {}),
      ...definition.config,
    }
    : defaultConfig;

  return {
    ...definition,
    id,
    createdAt: now,
    updatedAt: now,
    title,
    position,
    data: {},
    ...(mergedConfig ? { config: mergedConfig } : {}),
  };
};

export const ensureDocumentPromptPorts = (
  node: AiNode,
  role: CaseResolverNodeMeta['role'] | null = null
): AiNode => {
  if (node.type !== 'prompt') return node;
  const isExplanatory = role === 'explanatory';
  const nextInputs = isExplanatory
    ? [...CASE_RESOLVER_EXPLANATORY_NODE_INPUT_PORTS]
    : [...CASE_RESOLVER_DOCUMENT_NODE_INPUT_PORTS];
  const nextOutputs = isExplanatory
    ? [...CASE_RESOLVER_EXPLANATORY_NODE_OUTPUT_PORTS]
    : [...CASE_RESOLVER_DOCUMENT_NODE_OUTPUT_PORTS];
  const currentInputs = Array.isArray(node.inputs) ? node.inputs : [];
  const currentOutputs = Array.isArray(node.outputs) ? node.outputs : [];
  const sameInputs =
    nextInputs.length === currentInputs.length &&
    nextInputs.every((port: string, index: number): boolean => port === currentInputs[index]);
  const sameOutputs =
    nextOutputs.length === currentOutputs.length &&
    nextOutputs.every((port: string, index: number): boolean => port === currentOutputs[index]);
  if (sameInputs && sameOutputs) return node;
  return {
    ...node,
    inputs: nextInputs,
    outputs: nextOutputs,
  };
};

export const DOCUMENT_WYSIWYG_TEXT_PORT =
  CASE_RESOLVER_DOCUMENT_NODE_INPUT_PORTS[0] ?? 'wysiwygText';
export const DOCUMENT_PLAINTEXT_CONTENT_PORT =
  CASE_RESOLVER_DOCUMENT_NODE_INPUT_PORTS[1] ?? 'plaintextContent';
export const DOCUMENT_PLAIN_TEXT_PORT = CASE_RESOLVER_DOCUMENT_NODE_INPUT_PORTS[2] ?? 'plainText';
export const DOCUMENT_WYSIWYG_CONTENT_PORT = CASE_RESOLVER_EXPLANATORY_WYSIWYG_CONTENT_PORT;

export const ensureNodeMeta = (
  nodes: AiNode[],
  existing: Record<string, CaseResolverNodeMeta>
): Record<string, CaseResolverNodeMeta> => {
  const nodeIds = new Set(nodes.map((node: AiNode) => node.id));
  const next: Record<string, CaseResolverNodeMeta> = {};

  Object.entries(existing).forEach(([nodeId, meta]: [string, CaseResolverNodeMeta]) => {
    if (!nodeIds.has(nodeId)) return;
    next[nodeId] = meta;
  });

  nodes.forEach((node: AiNode) => {
    if (node.type !== 'prompt') return;
    if (!next[node.id]) {
      next[node.id] = {
        ...DEFAULT_CASE_RESOLVER_NODE_META,
        role: 'ai_prompt',
        includeInOutput: false,
      };
    }
  });

  return next;
};

export const ensureEdgeMeta = (
  edges: Array<{ id: string }>,
  existing: Record<string, CaseResolverEdgeMeta>
): Record<string, CaseResolverEdgeMeta> => {
  const edgeIds = new Set(edges.map((edge) => edge.id));
  const next: Record<string, CaseResolverEdgeMeta> = {};

  Object.entries(existing).forEach(([edgeId, meta]: [string, CaseResolverEdgeMeta]) => {
    if (!edgeIds.has(edgeId)) return;
    next[edgeId] = meta;
  });

  edges.forEach((edge) => {
    if (!next[edge.id]) {
      next[edge.id] = { ...DEFAULT_CASE_RESOLVER_EDGE_META };
    }
  });

  return next;
};

export const ensureDocumentLinksByNode = (
  nodes: AiNode[],
  existing: Record<string, string[]>,
  validFileIds: Set<string>
): Record<string, string[]> => {
  const nodeIds = new Set(nodes.map((node: AiNode) => node.id));
  const next: Record<string, string[]> = {};

  Object.entries(existing).forEach(([nodeId, links]: [string, string[]]) => {
    if (!nodeIds.has(nodeId)) return;
    if (!Array.isArray(links)) return;
    const unique = new Set<string>();
    links.forEach((fileId: string) => {
      if (typeof fileId !== 'string') return;
      const normalized = fileId.trim();
      if (!normalized) return;
      if (!validFileIds.has(normalized)) return;
      unique.add(normalized);
    });
    next[nodeId] = Array.from(unique);
  });

  return next;
};

export const ensureDocumentSourceFileByNode = (
  nodes: AiNode[],
  existing: Record<string, string>,
  validFileIds: Set<string>
): Record<string, string> => {
  const nodeIds = new Set(nodes.map((node: AiNode) => node.id));
  const next: Record<string, string> = {};

  Object.entries(existing).forEach(([nodeId, fileId]: [string, string]) => {
    if (!nodeIds.has(nodeId)) return;
    if (typeof fileId !== 'string') return;
    const normalizedFileId = fileId.trim();
    if (!normalizedFileId || !validFileIds.has(normalizedFileId)) return;
    next[nodeId] = normalizedFileId;
  });

  return next;
};

export const resolveDocumentDropNodeId = (
  candidate: string | null,
  nodes: AiNode[]
): string | null => {
  if (!candidate) return null;
  return nodes.some((node: AiNode) => node.id === candidate) ? candidate : null;
};

export const buildCanvasNodeFileTemplate = (
  linkedFileIds: string[],
  availableFilesById: Map<string, CaseResolverFile>
): string => {
  const lines = ['Canvas Node File', 'Linked Documents:'];
  if (linkedFileIds.length === 0) {
    lines.push('- (none)');
    return lines.join('\n');
  }

  linkedFileIds.forEach((fileId: string, index: number) => {
    const file = availableFilesById.get(fileId);
    const label = file ? file.name : fileId;
    const folderLabel = file ? file.folder || '(root)' : '(unknown)';
    lines.push(`${index + 1}. ${label} [${folderLabel}]`);
  });

  return lines.join('\n');
};

export const resolvePromptConfig = (node: AiNode): { template: string } => {
  const template = node.config?.prompt?.template;
  return {
    template: typeof template === 'string' ? template : '',
  };
};

const escapeHtml = (value: string): string =>
  value
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

const toHtmlParagraph = (value: string): string => {
  const trimmed = value.trim();
  if (!trimmed) return '';
  return `<p>${escapeHtml(trimmed).replace(/\n/g, '<br/>')}</p>`;
};

const hasHtmlMarkup = (value: string): boolean => /<\/?[a-z][^>]*>/i.test(value);

const decodeBasicHtmlEntities = (value: string): string =>
  value
    .replace(/&nbsp;/gi, ' ')
    .replace(/&apos;|&#39;/gi, '\'')
    .replace(/&quot;/gi, '"')
    .replace(/&gt;/gi, '>')
    .replace(/&lt;/gi, '<')
    .replace(/&amp;/gi, '&');

const decodeHtmlEntity = (value: string): string => {
  const basicDecoded = decodeBasicHtmlEntities(value);
  try {
    if (typeof window === 'undefined') return basicDecoded;
    const textarea = document.createElement('textarea');
    textarea.innerHTML = basicDecoded;
    return decodeBasicHtmlEntities(textarea.value);
  } catch (error) {
    logClientError(error);
    return basicDecoded;
  }
};

const stripHtmlTagsPreserveBreaks = (value: string): string =>
  value
    .replace(/<br\s*\/?\s*>/gi, '\n')
    .replace(/<\/(p|div|h1|h2|h3|h4|h5|h6|li|blockquote)>/gi, '\n')
    .replace(/<li>/gi, '• ')
    .replace(/<\/?[a-z][^>]*>/gi, '');

export const stripHtmlToPlainText = (html: string): string => {
  const decoded = decodeHtmlEntity(html);
  const stripped = stripHtmlTagsPreserveBreaks(decoded);
  const normalized = stripHtmlTagsPreserveBreaks(decodeHtmlEntity(stripped));
  return normalized
    .split('\n')
    .map((line: string) => line.trim())
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
};

export const renderPromptNodeTextPreview = (
  node: AiNode,
  nodeMeta: CaseResolverNodeMeta
): string => {
  const normalizedNodeMeta: CaseResolverNodeMeta = {
    ...DEFAULT_CASE_RESOLVER_NODE_META,
    ...nodeMeta,
  };
  const promptTemplate = node.config?.prompt?.template;
  const raw = typeof promptTemplate === 'string' ? promptTemplate : '';
  const plainText = stripHtmlToPlainText(raw);
  if (!plainText) return '';
  const quoted =
    normalizedNodeMeta.quoteMode === 'double'
      ? `"${plainText}"`
      : normalizedNodeMeta.quoteMode === 'single'
        ? `'${plainText}'`
        : plainText;
  return `${normalizedNodeMeta.surroundPrefix}${quoted}${normalizedNodeMeta.surroundSuffix}${
    normalizedNodeMeta.appendTrailingNewline ? '\n' : ''
  }`;
};

export const buildPromptTemplateFromDroppedDocumentFile = (file: CaseResolverFile): string => {
  if (file.fileType === 'scanfile') {
    const scanMarkdown = file.documentContentMarkdown.trim();
    if (scanMarkdown.length > 0) {
      return toHtmlParagraph(scanMarkdown);
    }
    const scanPlainText = file.documentContentPlainText.trim();
    if (scanPlainText.length > 0) {
      return toHtmlParagraph(scanPlainText);
    }
    const scanStoredContent = file.documentContent.trim();
    if (scanStoredContent.length > 0) {
      const normalizedScanContent = stripHtmlToPlainText(scanStoredContent) || scanStoredContent;
      return toHtmlParagraph(normalizedScanContent);
    }
    const scanSlotText = file.scanSlots
      .map((slot): string => (slot.ocrText ?? '').trim())
      .filter((value: string): boolean => value.length > 0)
      .join('\n\n');
    if (scanSlotText.length > 0) {
      return toHtmlParagraph(scanSlotText);
    }
    const topLevelOcrText = (file.ocrText ?? '').trim();
    if (topLevelOcrText.length > 0) {
      return toHtmlParagraph(topLevelOcrText);
    }
  }
  const sourceHtml = file.documentContentHtml.trim();
  if (sourceHtml.length > 0) {
    return sourceHtml;
  }
  const sourcePlainText = file.documentContentPlainText.trim();
  if (sourcePlainText.length > 0) {
    return toHtmlParagraph(sourcePlainText);
  }
  const sourceMarkdown = file.documentContentMarkdown.trim();
  if (sourceMarkdown.length > 0) {
    return toHtmlParagraph(sourceMarkdown);
  }
  const sourceContent = file.documentContent.trim();
  if (sourceContent.length > 0) {
    return hasHtmlMarkup(sourceContent) ? sourceContent : toHtmlParagraph(sourceContent);
  }
  return toHtmlParagraph(`Document: ${file.name}`);
};

export const resolvePromptNodeStaticOutputs = (
  node: AiNode,
  nodeMeta: CaseResolverNodeMeta
): {
  wysiwygText: string;
  plaintextContent: string;
  plainText: string;
  wysiwygContent: string;
} => {
  const promptTemplate = resolvePromptConfig(node).template;
  const wysiwygText = stripHtmlToPlainText(promptTemplate);
  const plaintextContent = renderPromptNodeTextPreview(node, nodeMeta) || wysiwygText;
  const plainText = stripHtmlToPlainText(plaintextContent || wysiwygText);
  const wysiwygContent = nodeMeta.role === 'explanatory' ? promptTemplate : '';
  return {
    wysiwygText,
    plaintextContent,
    plainText,
    wysiwygContent,
  };
};

export const clampCanvasPosition = (position: {
  x: number;
  y: number;
}): { x: number; y: number } => ({
  x: Math.min(Math.max(position.x, 16), CANVAS_WIDTH - NODE_WIDTH - 16),
  y: Math.min(Math.max(position.y, 16), CANVAS_HEIGHT - NODE_MIN_HEIGHT - 16),
});

