      {isNodeFileMode ? (
        <CaseResolverNodeFileWorkspace />
      ) : showCaseOverviewWorkspace ? (
        <CaseResolverCaseOverviewWorkspace />
      ) : workspaceView === 'relations' ? (
        <CaseResolverRelationsWorkspace />
