        <CaseResolverFileViewer />
      ) : editingDocumentDraft?.fileType === 'scanfile' ? (
        <CaseResolverScanFileEditor />
      ) : editingDocumentDraft ? (
        <CaseResolverDocumentEditor />
      ) : activeFile ? (
