import {
  type AiNode,
  type CaseResolverJoinMode,
  type CaseResolverNodeMeta,
} from '@/shared/contracts/case-resolver';
import { DEFAULT_CASE_RESOLVER_EDGE_META } from '@/shared/contracts/case-resolver/constants';
import { stripHtml } from './utils/text-sanitization';
import { appendWithJoin } from './composer-utils';

export type NodeOutput = {
  wysiwygText: string;
  plaintextContent: string;
  plainText: string;
  wysiwygContent: string;
};

export const computeNodeOutput = (
  node: AiNode,
  meta: CaseResolverNodeMeta,
  incoming: {
    plainText: { value: string; firstJoinMode: CaseResolverJoinMode };
    plaintextContent: { value: string; firstJoinMode: CaseResolverJoinMode };
    wysiwygContent: { value: string; firstJoinMode: CaseResolverJoinMode };
  },
  transform: ((input: any) => string) | undefined
): NodeOutput => {
  const nodeText = ''; // Placeholder for actual text resolution logic
  const nodeWysiwygText = ''; // Placeholder

  const plainTextOutput = transform 
    ? transform({ nodeId: node.id, nodeMeta: meta, output: 'plainText', value: nodeText })
    : stripHtml(nodeText);

  let plaintextContentOutput = meta.role === 'explanatory' ? incoming.plainText.value : incoming.plaintextContent.value;

  if (meta.includeInOutput && nodeText.trim().length > 0) {
    const joinMode = (meta.role === 'explanatory' ? incoming.plainText.firstJoinMode : incoming.plaintextContent.firstJoinMode) || (DEFAULT_CASE_RESOLVER_EDGE_META.joinMode ?? 'newline');
    plaintextContentOutput = appendWithJoin(plaintextContentOutput, nodeText, joinMode);
  }

  if (meta.role === 'explanatory' && !transform) {
    plaintextContentOutput = stripHtml(plaintextContentOutput);
  }

  let wysiwygContentOutput = meta.role === 'explanatory' ? incoming.wysiwygContent.value : '';
  if (meta.role === 'explanatory' && meta.includeInOutput && nodeWysiwygText.trim().length > 0) {
    const joinMode = (incoming.wysiwygContent.firstJoinMode || DEFAULT_CASE_RESOLVER_EDGE_META.joinMode || 'newline');
    wysiwygContentOutput = appendWithJoin(wysiwygContentOutput, nodeWysiwygText, joinMode);
  }

  return {
    wysiwygText: '', // Placeholder
    plaintextContent: plaintextContentOutput,
    plainText: plainTextOutput,
    wysiwygContent: wysiwygContentOutput,
  };
};

import { type AiNode, type CaseResolverGraph, type CaseResolverJoinMode, type CaseResolverNodeMeta } from '@/shared/contracts/case-resolver';
import type { CaseResolverCompiledSegment } from '@/shared/contracts/case-resolver/capture';
import { stripHtml } from './utils/text-sanitization';
import {
  appendWithJoin,
  resolveEdgeMeta,
  resolveNodeMeta,
  resolveNodeText,
  resolveSourceOutputValue,
  sortEdgesBySourcePosition,
  wrapByQuoteMode,
  wrapByQuoteModeWithoutColor,
} from './composer-utils';
import {
  type GraphContext,
  type NodeOutputs,
  isAcceptedPort,
} from './composer-graph';

export type CaseResolverPlainTextTransformInput = {
  nodeId: string;
  nodeMeta: CaseResolverNodeMeta;
  output: 'plainText' | 'plaintextContent';
  value: string;
};

export type CaseResolverCompileOptions = {
  transformPlainTextOutput?: (input: CaseResolverPlainTextTransformInput) => string;
};

export interface CollectIncomingParams {
  nodeId: string;
  type: keyof NodeOutputs;
  context: GraphContext;
  outputsByNode: Record<string, NodeOutputs>;
  graph: CaseResolverGraph;
}

export const collectIncoming = ({
  nodeId,
  type,
  context,
  outputsByNode,
  graph
}: CollectIncomingParams): { value: string; firstJoinMode: CaseResolverJoinMode | null } => {
  let value = '';
  let firstJoinMode: CaseResolverJoinMode | null = null;
  const incomingEdges = sortEdgesBySourcePosition(context.incomingByNode.get(nodeId) ?? [], context.nodeById);

  incomingEdges.forEach((edge): void => {
    const targetHandle = edge.targetHandle;
    const isAccepted = isAcceptedPort(type, targetHandle);
    if (!isAccepted || edge.source === undefined) return;

    const sourceOutputs = outputsByNode[edge.source];
    if (sourceOutputs === undefined) return;


    const rawSourceValue = resolveSourceOutputValue(sourceOutputs, edge.sourceHandle, type);
    const sourceValue = type === 'plainText' ? stripHtml(rawSourceValue) : rawSourceValue;
    if (sourceValue.length === 0) return;

    const edgeJoinMode = resolveEdgeMeta(edge.id, graph.edgeMeta || {}).joinMode ?? 'newline';
    if (firstJoinMode === null) {
      firstJoinMode = edgeJoinMode;
    }
    value = appendWithJoin(value, sourceValue, edgeJoinMode);
  });

  return { value, firstJoinMode };
};


export const resolveIncomingText = (
  meta: CaseResolverNodeMeta,
  wysiwyg: { value: string; firstJoinMode: CaseResolverJoinMode | null },
  plain: { value: string; firstJoinMode: CaseResolverJoinMode | null },
  plainContent: { value: string; firstJoinMode: CaseResolverJoinMode | null }
): { text: string; joinMode: CaseResolverJoinMode } => {
  if (wysiwyg.value.trim().length > 0) {
    return { text: wysiwyg.value, joinMode: wysiwyg.firstJoinMode ?? 'newline' };
  }
  if (plain.value.trim().length > 0) {
    return { text: plain.value, joinMode: plain.firstJoinMode ?? 'newline' };
  }
  if (meta.role === 'explanatory' && plainContent.value.trim().length > 0) {
    return { text: plainContent.value, joinMode: plainContent.firstJoinMode ?? 'newline' };
  }
  return { text: '', joinMode: 'newline' };
};

export const resolveResolvedWysiwygText = (
  meta: CaseResolverNodeMeta,
  incomingText: string,
  nodeText: string,
  incomingTextJoinMode: CaseResolverJoinMode
): string => {
  if (meta.role === 'explanatory' && incomingText.trim().length > 0 && nodeText.trim().length > 0) {
    return appendWithJoin(incomingText, nodeText, incomingTextJoinMode);
  }
  return incomingText.trim().length > 0 ? incomingText : nodeText;
};

export const resolvePlainTextOutput = (
  nodeId: string,
  meta: CaseResolverNodeMeta,
  value: string,
  options: CaseResolverCompileOptions
): string => {
  const wrapped = wrapByQuoteModeWithoutColor(value, meta);
  if (options.transformPlainTextOutput === undefined) {
    return stripHtml(wrapped);
  }
  return options.transformPlainTextOutput({
    nodeId,
    nodeMeta: meta,
    output: 'plainText',
    value: wrapped,
  });
};

export const resolvePlaintextContentOutput = (
  nodeId: string,
  meta: CaseResolverNodeMeta,
  options: CaseResolverCompileOptions,
  params: {
    isExplanatory: boolean;
    plainTextValue: string;
    plaintextContentValue: string;
    plainTextJoinMode: CaseResolverJoinMode | null;
    plaintextContentJoinMode: CaseResolverJoinMode | null;
    wrappedSecondaryText: string;
  }
): string => {
  let output = params.isExplanatory ? params.plainTextValue : params.plaintextContentValue;
  const includeInOutput = meta.includeInOutput ?? false;

  if (includeInOutput && params.wrappedSecondaryText.trim().length > 0) {
    const joinMode = (params.isExplanatory ? params.plainTextJoinMode : params.plaintextContentJoinMode) ?? 'newline';
    output = appendWithJoin(output, params.wrappedSecondaryText, joinMode);
  }

  if (meta.role === 'explanatory') {
    if (options.transformPlainTextOutput !== undefined) {
      output = options.transformPlainTextOutput({
        nodeId,
        nodeMeta: meta,
        output: 'plaintextContent',
        value: output,
      });
    } else {
      output = stripHtml(output);
    }
  }
  return output;
};

export const resolveNodeOutputChannels = (
  nodeId: string,
  meta: CaseResolverNodeMeta,
  options: CaseResolverCompileOptions,
  inputs: {
    resolvedWysiwygText: string;
    nodeText: string;
    incomingPlainText: { value: string; firstJoinMode: CaseResolverJoinMode | null };
    incomingPlaintextContent: { value: string; firstJoinMode: CaseResolverJoinMode | null };
  }
): NodeOutputs => {
  const isExplanatory = meta.role === 'explanatory';
  const hasIncomingPlainText = inputs.incomingPlainText.value.trim().length > 0;
  const isExplanatoryPlainTextInputFlow = isExplanatory && hasIncomingPlainText;

  const plainTextOutput = resolvePlainTextOutput(
    nodeId, meta, isExplanatoryPlainTextInputFlow ? inputs.nodeText : inputs.resolvedWysiwygText, options
  );

  const secondaryTextSeed = isExplanatoryPlainTextInputFlow ? inputs.nodeText : inputs.resolvedWysiwygText;
  const wrappedSecondaryText = wrapByQuoteMode(secondaryTextSeed, meta);

  const plaintextContentOutput = resolvePlaintextContentOutput(nodeId, meta, options, {
    isExplanatory: isExplanatoryPlainTextInputFlow,
    plainTextValue: inputs.incomingPlainText.value,
    plaintextContentValue: inputs.incomingPlaintextContent.value,
    plainTextJoinMode: inputs.incomingPlainText.firstJoinMode,
    plaintextContentJoinMode: inputs.incomingPlaintextContent.firstJoinMode,
    wrappedSecondaryText,
  });

  return {
    wysiwygText: wrapByQuoteModeWithoutColor(inputs.resolvedWysiwygText, meta),
    plaintextContent: plaintextContentOutput,
    plainText: plainTextOutput,
    wysiwygContent: '', // Placeholder
  };
};

export const processNode = (
  node: AiNode,
  graph: CaseResolverGraph,
  context: GraphContext,
  outputsByNode: Record<string, NodeOutputs>,
  options: CaseResolverCompileOptions
): { output: NodeOutputs; segment: CaseResolverCompiledSegment } => {
  const meta = resolveNodeMeta(node.id, graph.nodeMeta || {});
  const nodeText = resolveNodeText(node);

  const incomingWysiwygText = collectIncoming({ nodeId: node.id, type: 'wysiwygText', context, outputsByNode, graph });
  const incomingPlaintextContent = collectIncoming({ nodeId: node.id, type: 'plaintextContent', context, outputsByNode, graph });
  const incomingPlainText = collectIncoming({ nodeId: node.id, type: 'plainText', context, outputsByNode, graph });

  const { text: incomingText, joinMode: incomingTextJoinMode } = resolveIncomingText(
    meta, incomingWysiwygText, incomingPlainText, incomingPlaintextContent
  );

  const resolvedWysiwygText = resolveResolvedWysiwygText(meta, incomingText, nodeText, incomingTextJoinMode);
  const wrappedText = wrapByQuoteMode(resolvedWysiwygText, meta);

  const output = resolveNodeOutputChannels(node.id, meta, options, {
    resolvedWysiwygText,
    nodeText,
    incomingPlainText,
    incomingPlaintextContent,
  });

  return {
    output,
    segment: {
      id: `seg-${node.id}`,
      nodeId: node.id,
      role: meta.role ?? '',
      content: wrappedText,
      title: node.title ?? '',
      text: wrappedText,
      includeInOutput: meta.includeInOutput ?? false,
      metadata: {
        title: node.title,
        includeInOutput: meta.includeInOutput,
      },
    },
  };
};

import {
  type AiNode,
  type CaseResolverNodeMeta,
  type CaseResolverCompiledSegment,
} from '@/shared/contracts/case-resolver';
import { resolveNodeMeta } from './composer-utils';
import { computeNodeOutput, type NodeOutput } from './composer-compiler';

export type CompilationState = {
  outputsByNode: Record<string, NodeOutput>;
  segments: CaseResolverCompiledSegment[];
};

export const processNode = (
  node: AiNode,
  nodeMeta: Record<string, CaseResolverNodeMeta>,
  incoming: {
    plainText: { value: string; firstJoinMode: any };
    plaintextContent: { value: string; firstJoinMode: any };
    wysiwygContent: { value: string; firstJoinMode: any };
  },
  transform: ((input: any) => string) | undefined
): { output: NodeOutput, segment: CaseResolverCompiledSegment } => {
  const meta = resolveNodeMeta(node.id, nodeMeta, { role: 'text_note', includeInOutput: true, quoteMode: 'none', surroundPrefix: '', surroundSuffix: '', appendTrailingNewline: false });

  const nodeOutput = computeNodeOutput(node, meta, incoming, transform);

  const segment: CaseResolverCompiledSegment = {
    id: `seg-${node.id}`,
    nodeId: node.id,
    role: meta.role || '',
    content: nodeOutput.wysiwygText,
    title: node.title || '',
    text: nodeOutput.plainText,
    includeInOutput: meta.includeInOutput,
    metadata: {
      title: node.title,
      includeInOutput: meta.includeInOutput,
    },
  };

  return { output: nodeOutput, segment };
};

import { type CaseResolverEdge } from '@/shared/contracts/case-resolver';
import { type NodeOutput } from './composer-compiler';

export const resolveLeafNodePrompt = (
  visitOrder: { nodeId: string }[],
  outgoingByNode: Map<string, CaseResolverEdge[]>,
  visitedNodeIds: Set<string>,
  outputsByNode: Record<string, NodeOutput>
): string => {
  const leafNodeIds = visitOrder
    .map((entry) => entry.nodeId)
    .filter((nodeId) => {
      const outgoing = outgoingByNode.get(nodeId) ?? [];
      return !outgoing.some((edge) => typeof edge.target === 'string' && visitedNodeIds.has(edge.target));
    });

  const dedupedLeafOutputs: string[] = [];
  const seenLeafOutputs = new Set<string>();

  leafNodeIds.forEach((nodeId) => {
    const output = outputsByNode[nodeId]?.plaintextContent?.trim();
    if (output && !seenLeafOutputs.has(output)) {
      seenLeafOutputs.add(output);
      dedupedLeafOutputs.push(output);
    }
  });

  return dedupedLeafOutputs.join('\n\n').trim();
};

import {
  type CaseResolverJoinMode,
  type AiNode,
  type CaseResolverEdge,
  type CaseResolverNodeMeta,
  type CaseResolverEdgeMeta,
} from '@/shared/contracts/case-resolver';
import {
  DEFAULT_CASE_RESOLVER_EDGE_META,
  DEFAULT_CASE_RESOLVER_NODE_META,
} from '@/shared/contracts/case-resolver/constants';
import { stripHtml } from './utils/text-sanitization';

type CaseResolverOutputChannels = {
  wysiwygText: string;
  plaintextContent: string;
  plainText: string;
  wysiwygContent: string;
};

export const JOIN_VALUE_MAP: Record<CaseResolverJoinMode, string> = {
  newline: '\n',
  none: '',
  space: ' ',
  tab: '\t',
};

export const resolveNodeMeta = (
  nodeId: string,
  nodeMeta: Record<string, CaseResolverNodeMeta>,
  fallback: CaseResolverNodeMeta = DEFAULT_CASE_RESOLVER_NODE_META
): CaseResolverNodeMeta => ({
  ...fallback,
  ...(nodeMeta[nodeId] ?? {}),
});

export const resolveEdgeMeta = (
  edgeId: string,
  edgeMeta: Record<string, CaseResolverEdgeMeta>
): CaseResolverEdgeMeta => ({
  ...DEFAULT_CASE_RESOLVER_EDGE_META,
  ...(edgeMeta[edgeId] ?? {}),
});

export const resolveSourceOutputValue = (
  outputs: CaseResolverOutputChannels | undefined,
  sourceHandle: string | null | undefined,
  fallbackType: keyof CaseResolverOutputChannels
): string => {
  if (outputs === undefined) return '';
  if (sourceHandle === 'wysiwygText') return outputs.wysiwygText;
  if (sourceHandle === 'plaintextContent') return outputs.plaintextContent;
  if (sourceHandle === 'plainText') return outputs.plainText;
  if (sourceHandle === 'wysiwygContent') return outputs.wysiwygContent;
  return outputs[fallbackType];
};

export const resolveNodeText = (node: AiNode): string => {
  const promptTemplate = node.config?.prompt?.template;
  if (typeof promptTemplate === 'string' && promptTemplate.trim().length > 0) {
    return stripHtml(promptTemplate);
  }
  const noteText = node.config?.notes?.text;
  if (typeof noteText === 'string' && noteText.trim().length > 0) {
    return stripHtml(noteText);
  }
  return '';
};

export const resolveNodeWysiwygText = (node: AiNode): string => {
  const promptTemplate = node.config?.prompt?.template;
  if (typeof promptTemplate === 'string' && promptTemplate.trim().length > 0) {
    return promptTemplate;
  }
  const noteText = node.config?.notes?.text;
  if (typeof noteText === 'string' && noteText.trim().length > 0) {
    return noteText;
  }
  return '';
};

export const wrapByQuoteMode = (value: string, meta: CaseResolverNodeMeta): string => {
  const wrappedValue = wrapByQuoteModeWithoutColor(value, meta);
  if (!wrappedValue) return wrappedValue;
  const canApplyHtmlColorWrapper = meta.role !== 'explanatory';
  const normalizedColor =
    canApplyHtmlColorWrapper &&
    typeof meta.textColor === 'string' &&
    /^#(?:[0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(meta.textColor.trim())
      ? meta.textColor.trim()
      : '';
  if (!normalizedColor) return wrappedValue;
  return `<span style="color: ${normalizedColor};">${wrappedValue}</span>`;
};

export const wrapByQuoteModeWithoutColor = (value: string, meta: CaseResolverNodeMeta): string => {
  if (!value) return value;
  const quotedValue =
    meta.quoteMode === 'double' ? `"${value}"` : meta.quoteMode === 'single' ? `'${value}'` : value;
  return `${meta.surroundPrefix}${quotedValue}${meta.surroundSuffix}${
    meta.appendTrailingNewline ? '\n' : ''
  }`;
};

export const sortNodeIdsByPosition = (nodes: AiNode[]): string[] =>
  [...nodes]
    .sort((left: AiNode, right: AiNode) => {
      if (left.position.y !== right.position.y) return left.position.y - right.position.y;
      if (left.position.x !== right.position.x) return left.position.x - right.position.x;
      return left.id.localeCompare(right.id);
    })
    .map((node: AiNode) => node.id);

export const appendWithJoin = (current: string, value: string, joinMode: CaseResolverJoinMode): string => {
  if (!value) return current;
  if (!current) return value;
  return `${current}${JOIN_VALUE_MAP[joinMode]}${value}`;
};

export const sortEdgesBySourcePosition = (edges: CaseResolverEdge[], nodeById: Map<string, AiNode>): CaseResolverEdge[] => {
  return [...edges].sort((left: CaseResolverEdge, right: CaseResolverEdge) => {
    const leftNode = left.source ? nodeById.get(left.source) : undefined;
    const rightNode = right.source ? nodeById.get(right.source) : undefined;
    if (leftNode && rightNode) {
      if (leftNode.position.y !== rightNode.position.y) {
        return leftNode.position.y - rightNode.position.y;
      }
      if (leftNode.position.x !== rightNode.position.x) {
        return leftNode.position.x - rightNode.position.x;
      }
      if (leftNode.id !== rightNode.id) {
        return leftNode.id.localeCompare(rightNode.id);
      }
    } else if (leftNode || rightNode) {
      return leftNode ? -1 : 1;
    }
    return left.id.localeCompare(right.id);
  });
};

