const createUniqueAssetName = ({
  assets,
  folder,
  baseName,
}: {
  assets: CaseResolverAssetFile[];
  folder: string;
  baseName: string;
}): string => {
  const normalizedBaseName = baseName.trim() || 'New Asset';
  const existingNames = new Set(
    assets
      .filter((asset: CaseResolverAssetFile): boolean => asset.folder === folder)
      .map((asset: CaseResolverAssetFile): string => asset.name.trim().toLowerCase())
  );
  if (!existingNames.has(normalizedBaseName.toLowerCase())) {
    return normalizedBaseName;
  }
  let index = 2;
  while (index < 10000) {
    const candidate = `${normalizedBaseName} ${index}`;
    if (!existingNames.has(candidate.toLowerCase())) {
      return candidate;
    }
    index += 1;
  }
  return `${normalizedBaseName} ${Date.now()}`;
};

export function useCaseResolverStateCreationActions({
  workspace: _workspace,
  updateWorkspace,
  setWorkspace,
  syncPersistedWorkspaceTracking,
  requestedFileId,
  selectedFileId,
  requestedCaseStatus,
  setRequestedCaseStatus,
  activeCaseId,
  canCreateInActiveCase,
  defaultTagId,
  defaultCaseIdentifierId,
  defaultCategoryId,
  setSelectedFileId,
  setSelectedAssetId,
  setSelectedFolderPath,
  settingsStoreRef,
  toast,
}: {
  workspace: CaseResolverWorkspace;
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: {
      persistToast?: string;
      persistNow?: boolean;
      mutationId?: string;
      source?: string;
      skipNormalization?: boolean;
    }
  ) => void;
  setWorkspace: React.Dispatch<React.SetStateAction<CaseResolverWorkspace>>;
  syncPersistedWorkspaceTracking: (workspace: CaseResolverWorkspace) => void;
  requestedFileId: string | null;
  selectedFileId: string | null;
  requestedCaseStatus: CaseResolverRequestedCaseStatus;
  setRequestedCaseStatus: (status: CaseResolverRequestedCaseStatus) => void;
  activeCaseId: string | null;
  canCreateInActiveCase: boolean;
  defaultTagId: string | null;
  defaultCaseIdentifierId: string | null;
  defaultCategoryId: string | null;
  setSelectedFileId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedAssetId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedFolderPath: React.Dispatch<React.SetStateAction<string | null>>;
  settingsStoreRef: React.MutableRefObject<SettingsStoreValue>;
  toast: Toast;
}) {
  const createContextRecoveryInFlightRef = useRef(false);

  const resolveCaseIdForWorkspace = useCallback(
    (targetWorkspace: CaseResolverWorkspace): string | null => {
      const targetFilesById = new Map<string, CaseResolverFile>(
        targetWorkspace.files.map((file: CaseResolverFile): [string, CaseResolverFile] => [
          file.id,
          file,
        ])
      );
      const targetRequestedCaseContainerId = resolveCaseContainerIdForFileId(
        targetFilesById,
        requestedFileId
      );
      const targetContextFileId = selectedFileId ?? targetWorkspace.activeFileId;
      const targetSelectedCaseContainerId = resolveCaseContainerIdForFileId(
        targetFilesById,
        targetContextFileId
      );
      return resolveCaseResolverActiveCaseId({
        requestedFileId,
        requestedCaseContainerId: targetRequestedCaseContainerId,
        selectedCaseContainerId: targetSelectedCaseContainerId,
        files: targetWorkspace.files,
      });
    },
    [requestedFileId, selectedFileId]
  );

  const recoverCreateContextCaseId = useCallback(
    async (source: string): Promise<string | null> => {
      if (createContextRecoveryInFlightRef.current) return null;
      if (!requestedFileId) return null;

      createContextRecoveryInFlightRef.current = true;
      try {
        const refreshedWorkspace = await fetchCaseResolverWorkspaceSnapshot(source);
        if (!refreshedWorkspace) return null;
        const recoveredCaseId = resolveCaseIdForWorkspace(refreshedWorkspace);
        if (!recoveredCaseId) return null;

        syncPersistedWorkspaceTracking(refreshedWorkspace);
        // Note: we can't easily clear queued refs from here if they are in useCaseResolverState
        // but we can pass them in if needed. For now, let's assume we handle the core recovery.

        setWorkspace(refreshedWorkspace);
        setRequestedCaseStatus('ready');

        settingsStoreRef.current.refetch();
        logCaseResolverWorkspaceEvent({
          source,
          action: 'create_context_recovered',
          workspaceRevision: getCaseResolverWorkspaceRevision(refreshedWorkspace),
        });
        return recoveredCaseId;
      } finally {
        createContextRecoveryInFlightRef.current = false;
      }
    },
    [
      requestedFileId,
      resolveCaseIdForWorkspace,
      syncPersistedWorkspaceTracking,
      setWorkspace,
      setRequestedCaseStatus,
      settingsStoreRef,
    ]
  );

  const createFolderForCase = useCallback(
    (ownerCaseId: string, targetFolderPath: string | null): void => {
      updateWorkspace(
        (current) => {
          const normalizedTargetFolder = resolveCaseScopedFolderTarget({
            targetFolderPath,
            ownerCaseId,
            folderRecords: current.folderRecords,
          });
          const existingFoldersForOwner = normalizeFolderRecords(current.folderRecords)
            .filter(
              (record: CaseResolverFolderRecord): boolean => record.ownerCaseId === ownerCaseId
            )
            .map((record: CaseResolverFolderRecord): string => record.path);
          const nextPath = createUniqueFolderPath(existingFoldersForOwner, normalizedTargetFolder);
          const currentFolderRecords = normalizeFolderRecords(current.folderRecords);
          const ownedRecordExists = currentFolderRecords.some(
            (record: CaseResolverFolderRecord): boolean =>
              record.path === nextPath && (record.ownerCaseId ?? null) === ownerCaseId
          );
          if (ownedRecordExists) return current;
          return {
            ...current,
            folders: normalizeFolderPaths([...current.folders, nextPath]),
            folderRecords: appendOwnedFolderRecords({
              records: current.folderRecords,
              folderPath: nextPath,
              ownerCaseId,
            }),
          };
        },
        { persistToast: 'Case Resolver tree changes saved.' }
      );
    },
    [updateWorkspace]
  );

  const createDocumentForCase = useCallback(
    ({
      ownerCaseId,
      targetFolderPath,
    }: {
      ownerCaseId: string;
      targetFolderPath: string | null;
    }): void => {
      let createdDocumentId: string | null = null;
      updateWorkspace(
        (current) => {
          const folder = resolveCaseScopedFolderTarget({
            targetFolderPath,
            ownerCaseId,
            folderRecords: current.folderRecords,
          });
          const name = createUniqueCaseFileName({
            files: current.files,
            folder,
            baseName: 'New Document',
          });
          const file = createCaseResolverFile({
            id: createId('case-file'),
            fileType: 'document',
            name,
            folder,
            parentCaseId: ownerCaseId,
            editorType: 'document',
            tagId: defaultTagId,
            caseIdentifierId: defaultCaseIdentifierId,
            categoryId: defaultCategoryId,
          });
          createdDocumentId = file.id;

          return {
            ...current,
            files: [...current.files, file],
            folders: normalizeFolderPaths([...current.folders, folder]),
            folderRecords: appendOwnedFolderRecords({
              records: current.folderRecords,
              folderPath: folder,
              ownerCaseId,
            }),
          };
        },
        { persistToast: 'Case Resolver tree changes saved.' }
      );
      setSelectedAssetId(null);
      setSelectedFolderPath(null);
      if (createdDocumentId) {
        setSelectedFileId(createdDocumentId);
      }
    },
    [
      defaultCaseIdentifierId,
      defaultCategoryId,
      defaultTagId,
      setSelectedAssetId,
      setSelectedFileId,
      setSelectedFolderPath,
      updateWorkspace,
    ]
  );

  const createNodeFileForCase = useCallback(
    ({
      ownerCaseId,
      targetFolderPath,
    }: {
      ownerCaseId: string;
      targetFolderPath: string | null;
    }): void => {
      let createdAssetId: string | null = null;
      updateWorkspace(
        (current) => {
          const folder = resolveCaseScopedFolderTarget({
            targetFolderPath,
            ownerCaseId,
            folderRecords: current.folderRecords,
          });
          const asset = createCaseResolverAssetFile({
            id: createId('asset'),
            workspaceId: current.id,
            name: createUniqueAssetName({
              assets: current.assets,
              folder,
              baseName: 'New Node File',
            }),
            folder,
            kind: 'node_file',
            metadata: {
              ownerCaseId,
            },
          });
          createdAssetId = asset.id;
          return {
            ...current,
            assets: [...current.assets, asset],
            folders: normalizeFolderPaths([...current.folders, folder]),
            folderRecords: appendOwnedFolderRecords({
              records: current.folderRecords,
              folderPath: folder,
              ownerCaseId,
            }),
          };
        },
        { persistToast: 'Case Resolver tree changes saved.' }
      );
      setSelectedFileId(null);
      setSelectedFolderPath(null);
      if (createdAssetId) {
        setSelectedAssetId(createdAssetId);
      }
    },
    [setSelectedAssetId, setSelectedFileId, setSelectedFolderPath, updateWorkspace]
  );

  const handleCreateFolder = useCallback(
    (targetFolderPath: string | null): void => {
      if (activeCaseId && canCreateInActiveCase) {
        createFolderForCase(activeCaseId, targetFolderPath);
        return;
      }
      if (requestedCaseStatus === 'loading' || createContextRecoveryInFlightRef.current) {
        toast('Case context is still loading. Please wait.', { variant: 'warning' });
        return;
      }
      if (requestedFileId) {
        setRequestedCaseStatus('loading');
        void (async (): Promise<void> => {
          const recoveredCaseId = await recoverCreateContextCaseId(
            'case_view_create_folder_recover'
          );
          if (recoveredCaseId) {
            createFolderForCase(recoveredCaseId, targetFolderPath);
            return;
          }
          setRequestedCaseStatus('missing');
          logCaseResolverWorkspaceEvent({
            source: 'case_view',
            action: 'create_folder_blocked',
            message: 'No active case context is available after refresh.',
          });
          toast('Cannot create folder without a selected case.', { variant: 'warning' });
        })();
        return;
      }
      logCaseResolverWorkspaceEvent({
        source: 'case_view',
        action: 'create_folder_blocked',
        message: 'No active case context is available.',
      });
      toast('Cannot create folder without a selected case.', { variant: 'warning' });
    },
    [
      activeCaseId,
      canCreateInActiveCase,
      createFolderForCase,
      recoverCreateContextCaseId,
      requestedCaseStatus,
      requestedFileId,
      toast,
      setRequestedCaseStatus,
    ]
  );

  const handleCreateFile = useCallback(
    (targetFolderPath: string | null): void => {
      if (activeCaseId && canCreateInActiveCase) {
        createDocumentForCase({
          ownerCaseId: activeCaseId,
          targetFolderPath,
        });
        return;
      }
      if (requestedCaseStatus === 'loading' || createContextRecoveryInFlightRef.current) {
        toast('Case context is still loading. Please wait.', { variant: 'warning' });
        return;
      }
      if (requestedFileId) {
        setRequestedCaseStatus('loading');
        void (async (): Promise<void> => {
          const recoveredCaseId = await recoverCreateContextCaseId('case_view_create_file_recover');
          if (recoveredCaseId) {
            createDocumentForCase({
              ownerCaseId: recoveredCaseId,
              targetFolderPath,
            });
            return;
          }
          setRequestedCaseStatus('missing');
          logCaseResolverWorkspaceEvent({
            source: 'case_view',
            action: 'create_file_blocked',
            message: 'No active case context is available after refresh.',
          });
          toast('Cannot create document without a selected case.', { variant: 'warning' });
        })();
        return;
      }
      logCaseResolverWorkspaceEvent({
        source: 'case_view',
        action: 'create_file_blocked',
        message: 'No active case context is available.',
      });
      toast('Cannot create document without a selected case.', { variant: 'warning' });
    },
    [
      activeCaseId,
      canCreateInActiveCase,
      createDocumentForCase,
      recoverCreateContextCaseId,
      requestedCaseStatus,
      requestedFileId,
      setRequestedCaseStatus,
      toast,
    ]
  );

  const handleCreateNodeFile = useCallback(
    (targetFolderPath: string | null): void => {
      if (activeCaseId && canCreateInActiveCase) {
        createNodeFileForCase({
          ownerCaseId: activeCaseId,
          targetFolderPath,
        });
        return;
      }
      if (requestedCaseStatus === 'loading' || createContextRecoveryInFlightRef.current) {
        toast('Case context is still loading. Please wait.', { variant: 'warning' });
        return;
      }
      if (requestedFileId) {
        setRequestedCaseStatus('loading');
        void (async (): Promise<void> => {
          const recoveredCaseId = await recoverCreateContextCaseId(
            'case_view_create_node_file_recover'
          );
          if (recoveredCaseId) {
            createNodeFileForCase({
              ownerCaseId: recoveredCaseId,
              targetFolderPath,
            });
            return;
          }
          setRequestedCaseStatus('missing');
          logCaseResolverWorkspaceEvent({
            source: 'case_view',
            action: 'create_node_file_blocked',
            message: 'No active case context is available after refresh.',
          });
          toast('Cannot create node file without a selected case.', { variant: 'warning' });
        })();
        return;
      }
      logCaseResolverWorkspaceEvent({
        source: 'case_view',
        action: 'create_node_file_blocked',
        message: 'No active case context is available.',
      });
      toast('Cannot create node file without a selected case.', { variant: 'warning' });
    },
    [
      activeCaseId,
      canCreateInActiveCase,
      createNodeFileForCase,
      recoverCreateContextCaseId,
      requestedCaseStatus,
      requestedFileId,
      setRequestedCaseStatus,
      toast,
    ]
  );

  return {
    handleCreateFolder,
    handleCreateFile,
    handleCreateNodeFile,
    recoverCreateContextCaseId,
  };
}

'use client';

import { useCallback } from 'react';

import {
  buildFileEditDraft,
  createCaseResolverHistorySnapshotEntry,
} from '@/features/case-resolver/utils/caseResolverUtils';
import {
  deriveDocumentContentSync,
  ensureHtmlForPreview,
  hasHtmlMarkup,
  ensureSafeDocumentHtml,
  stripHtmlToPlainText,
  toStorageDocumentValue,
} from '@/shared/lib/document-editor/public';
import type { CaseResolverEditorNodeContext, CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { Toast } from '@/shared/contracts/ui/base';

import { createCaseResolverFile } from '../settings';
import { type CaseResolverFileEditDraft } from '../types';
import {
  CASE_RESOLVER_DOCUMENT_HISTORY_LIMIT,
  buildCaseResolverDraftCanonicalState,
  canCaseResolverDraftPerformInitialManualSave,
  clearStoredEditorDraft,
  hasCaseResolverDraftMeaningfulChanges,
} from './useCaseResolverState.helpers';
type CaseResolverOpenFileEditorOptions = {
  nodeContext?: CaseResolverEditorNodeContext | null;
};

export function useCaseResolverStateEditorActions({
  workspace,
  updateWorkspace,
  editingDocumentDraft,
  setEditingDocumentDraft,
  setEditingDocumentNodeContext,
  setSelectedFileId,
  setSelectedAssetId,
  setSelectedFolderPath,
  setWorkspace,
  toast,
}: {
  workspace: CaseResolverWorkspace;
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: {
      persistToast?: string;
      persistNow?: boolean;
      mutationId?: string;
      source?: string;
      skipNormalization?: boolean;
    }
  ) => void;
  editingDocumentDraft: CaseResolverFileEditDraft | null;
  setEditingDocumentDraft: React.Dispatch<React.SetStateAction<CaseResolverFileEditDraft | null>>;
  setEditingDocumentNodeContext: React.Dispatch<
    React.SetStateAction<CaseResolverEditorNodeContext | null>
  >;
  setSelectedFileId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedAssetId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedFolderPath: React.Dispatch<React.SetStateAction<string | null>>;
  setWorkspace: React.Dispatch<React.SetStateAction<CaseResolverWorkspace>>;
  toast: Toast;
}) {
  const handleOpenFileEditor = useCallback(
    (fileId: string, options?: CaseResolverOpenFileEditorOptions): void => {
      const target = workspace.files.find((file) => file.id === fileId);
      if (!target) {
        setEditingDocumentNodeContext(null);
        toast('File not found.', { variant: 'warning' });
        return;
      }
      if (target.fileType === 'case') {
        setEditingDocumentNodeContext(null);
        toast('Cases are edited in the Cases list. Select a document to edit.', {
          variant: 'info',
        });
        return;
      }
      const baseDraft = buildFileEditDraft(target);
      const mergedDraft: CaseResolverFileEditDraft = {
        ...baseDraft,
        documentHistory: baseDraft.documentHistory ?? [],
      };
      const canonicalDraft = (() => {
        if (mergedDraft.fileType === 'scanfile') {
          const resolvedDraftMarkdown = (() => {
            if (
              typeof mergedDraft.documentContentMarkdown === 'string' &&
              mergedDraft.documentContentMarkdown.trim().length > 0
            ) {
              return mergedDraft.documentContentMarkdown;
            }
            if (
              typeof mergedDraft.documentContentPlainText === 'string' &&
              mergedDraft.documentContentPlainText.trim().length > 0
            ) {
              return mergedDraft.documentContentPlainText;
            }
            const fallbackContent = mergedDraft.documentContent ?? '';
            if (fallbackContent.trim().length > 0) {
              return hasHtmlMarkup(fallbackContent)
                ? stripHtmlToPlainText(fallbackContent)
                : fallbackContent;
            }
            if (
              typeof mergedDraft.documentContentHtml === 'string' &&
              mergedDraft.documentContentHtml.trim().length > 0
            ) {
              return stripHtmlToPlainText(mergedDraft.documentContentHtml);
            }
            return '';
          })();
          return deriveDocumentContentSync({
            mode: 'markdown',
            value: resolvedDraftMarkdown,
            previousHtml: mergedDraft.documentContentHtml,
            previousMarkdown: mergedDraft.documentContentMarkdown,
          });
        }

        const resolvedDraftHtml = (() => {
          if (
            typeof mergedDraft.documentContentHtml === 'string' &&
            mergedDraft.documentContentHtml.trim().length > 0
          ) {
            return mergedDraft.documentContentHtml;
          }
          if (
            typeof mergedDraft.documentContentMarkdown === 'string' &&
            mergedDraft.documentContentMarkdown.trim().length > 0
          ) {
            return ensureHtmlForPreview(mergedDraft.documentContentMarkdown, 'markdown');
          }
          return ensureSafeDocumentHtml(mergedDraft.documentContent ?? '');
        })();
        return deriveDocumentContentSync({
          mode: 'wysiwyg',
          value: resolvedDraftHtml,
          previousHtml: mergedDraft.documentContentHtml,
          previousMarkdown: mergedDraft.documentContentMarkdown,
        });
      })();
      const nextDraft: CaseResolverFileEditDraft = {
        ...mergedDraft,
        editorType: mergedDraft.fileType === 'scanfile' ? 'markdown' : 'wysiwyg',
        documentContentFormatVersion: 1,
        documentContent: toStorageDocumentValue(canonicalDraft),
        documentContentMarkdown: canonicalDraft.markdown,
        documentContentHtml: canonicalDraft.html,
        documentContentPlainText: canonicalDraft.plainText,
        documentConversionWarnings: canonicalDraft.warnings,
      };
      clearStoredEditorDraft(fileId);
      setEditingDocumentDraft(nextDraft);
      setEditingDocumentNodeContext(options?.nodeContext ?? null);
      setSelectedFileId(fileId);
      setSelectedAssetId(null);
      setSelectedFolderPath(null);
      setWorkspace((current) =>
        current.activeFileId === fileId
          ? current
          : {
            ...current,
            activeFileId: fileId,
          }
      );
    },
    [
      workspace.files,
      toast,
      setEditingDocumentNodeContext,
      setEditingDocumentDraft,
      setSelectedFileId,
      setSelectedAssetId,
      setSelectedFolderPath,
      setWorkspace,
    ]
  );

  const handleSaveFileEditor = useCallback((): void => {
    if (!editingDocumentDraft) return;
    const currentFile = workspace.files.find(
      (file: CaseResolverFile): boolean => file.id === editingDocumentDraft.id
    );
    if (!currentFile) {
      toast('Document no longer exists. Please refresh list.', { variant: 'warning' });
      return;
    }
    if (currentFile.isLocked) {
      setEditingDocumentDraft((current) =>
        current?.id === currentFile.id ? buildFileEditDraft(currentFile) : current
      );
      toast('Document is locked. Unlock it in Case Resolver before saving.', {
        variant: 'warning',
      });
      return;
    }
    const hasVersionDrift =
      currentFile.documentContentVersion !== editingDocumentDraft.baseDocumentContentVersion;
    const canonicalState = buildCaseResolverDraftCanonicalState(editingDocumentDraft);
    const nextStoredContent = canonicalState.storedContent;
    const nextOriginalDocumentContent = canonicalState.originalDocumentContent;
    const nextExplodedDocumentContent = canonicalState.explodedDocumentContent;
    const hasContentChanges =
      currentFile.activeDocumentVersion !== editingDocumentDraft.activeDocumentVersion ||
      currentFile.editorType !== canonicalState.mode ||
      currentFile.documentContent !== nextStoredContent ||
      currentFile.documentContentMarkdown !== canonicalState.markdown ||
      currentFile.documentContentHtml !== canonicalState.html ||
      currentFile.documentContentPlainText !== canonicalState.plainText ||
      JSON.stringify(currentFile.documentConversionWarnings) !==
        JSON.stringify(canonicalState.warnings) ||
      currentFile.originalDocumentContent !== nextOriginalDocumentContent ||
      currentFile.explodedDocumentContent !== nextExplodedDocumentContent;
    const hasMeaningfulChanges = hasCaseResolverDraftMeaningfulChanges({
      draft: editingDocumentDraft,
      file: currentFile,
      canonicalState,
    });
    const canSavePristineInitialDocument = canCaseResolverDraftPerformInitialManualSave({
      draft: editingDocumentDraft,
      file: currentFile,
      canonicalState,
    });

    if (!hasMeaningfulChanges && !canSavePristineInitialDocument) {
      clearStoredEditorDraft(editingDocumentDraft.id);
      if (hasVersionDrift) {
        setEditingDocumentDraft((current) =>
          current?.id === editingDocumentDraft.id ? buildFileEditDraft(currentFile) : current
        );
        toast('Document is already synced with the latest version. No changes to save.', {
          variant: 'info',
        });
        return;
      }
      toast('No document changes to save.', { variant: 'info' });
      return;
    }
    if (hasVersionDrift) {
      toast('Document changed while editor was open. Saving on top of latest version.', {
        variant: 'warning',
      });
    }
    const now = new Date().toISOString();
    const nextDocumentContentVersion = currentFile.documentContentVersion + 1;
    const currentSnapshot = hasContentChanges
      ? createCaseResolverHistorySnapshotEntry({
        savedAt: now,
        documentContentVersion: currentFile.documentContentVersion,
        activeDocumentVersion: currentFile.activeDocumentVersion,
        editorType: currentFile.editorType,
        documentContent: currentFile.documentContent,
        documentContentMarkdown: currentFile.documentContentMarkdown,
        documentContentHtml: currentFile.documentContentHtml,
        documentContentPlainText: currentFile.documentContentPlainText,
      })
      : null;
    const nextDocumentHistory = currentSnapshot
      ? [currentSnapshot, ...currentFile.documentHistory].slice(
        0,
        CASE_RESOLVER_DOCUMENT_HISTORY_LIMIT
      )
      : currentFile.documentHistory;
    const nextParentCaseId =
      editingDocumentDraft.parentCaseId === undefined
        ? currentFile.parentCaseId
        : editingDocumentDraft.parentCaseId;
    const nextSavedFile = createCaseResolverFile({
      ...currentFile,
      ...editingDocumentDraft,
      parentCaseId: nextParentCaseId,
      editorType: canonicalState.mode,
      documentContentFormatVersion: 1,
      documentContentVersion: nextDocumentContentVersion,
      documentContent: nextStoredContent,
      documentContentMarkdown: canonicalState.markdown,
      documentContentHtml: canonicalState.html,
      documentContentPlainText: canonicalState.plainText,
      documentHistory: nextDocumentHistory,
      documentConversionWarnings: canonicalState.warnings,
      lastContentConversionAt: now,
      originalDocumentContent: nextOriginalDocumentContent,
      explodedDocumentContent: nextExplodedDocumentContent,
      createdAt: editingDocumentDraft.createdAt || currentFile.createdAt || now,
      updatedAt: now,
    });
    updateWorkspace(
      (current) => ({
        ...current,
        files: current.files.map((file) =>
          file.id === editingDocumentDraft.id ? nextSavedFile : file
        ),
      }),
      {
        persistToast: 'Document changes saved.',
        source: 'case_view_document_save',
      }
    );
    clearStoredEditorDraft(editingDocumentDraft.id);
    setEditingDocumentDraft((current) => {
      if (current?.id !== editingDocumentDraft.id) return current;
      return buildFileEditDraft(nextSavedFile);
    });
  }, [editingDocumentDraft, toast, updateWorkspace, workspace.files, setEditingDocumentDraft]);

  const handleDiscardFileEditorDraft = useCallback((): void => {
    if (editingDocumentDraft) {
      clearStoredEditorDraft(editingDocumentDraft.id);
    }
    setEditingDocumentDraft(null);
    setEditingDocumentNodeContext(null);
  }, [editingDocumentDraft, setEditingDocumentDraft, setEditingDocumentNodeContext]);

  return {
    handleOpenFileEditor,
    handleSaveFileEditor,
    handleDiscardFileEditorDraft,
  };
}

'use client';

import { useCallback } from 'react';

import { isPathWithinFolder } from '@/features/case-resolver/utils/caseResolverUtils';
import type { CaseResolverAssetFile, CaseResolverFile, CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { Toast as CaseResolverToast } from '@/shared/contracts/ui/base';
import type { ConfirmConfig } from '@/shared/hooks/ui/useConfirm';

import { normalizeFolderPath, normalizeFolderPaths, renameFolderPath } from '../settings';
import { deleteCaseResolverNodeFileSnapshot } from '../workspace-persistence';
import type { UseCaseResolverWorkspaceMutationsValue } from './useCaseResolverState.workspace-mutations';
import {
  collectCaseScopeIds,
  removeOwnedFolderRecordsWithinPath,
  renameOwnedFolderRecordsWithinPath,
} from './useCaseResolverState.helpers';

type UseCaseResolverStateFolderActionsInput = {
  confirm: (config: ConfirmConfig) => void;
  toast: CaseResolverToast;
  updateWorkspace: UseCaseResolverWorkspaceMutationsValue['updateWorkspace'];
  workspace: CaseResolverWorkspace;
  selectedCaseScopeIds: Set<string> | null;
  selectedCaseContainerId: string | null;
  setSelectedFileId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedAssetId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedFolderPath: React.Dispatch<React.SetStateAction<string | null>>;
  setEditingDocumentDraft: React.Dispatch<React.SetStateAction<CaseResolverFileEditDraft | null>>;
  treeSaveToast: string;
};

export type UseCaseResolverStateFolderActionsResult = {
  handleDeleteFolder: (folderPath: string) => void;
  handleMoveFile: (fileId: string, targetFolder: string) => Promise<void>;
  handleMoveAsset: (assetId: string, targetFolder: string) => Promise<void>;
  handleRenameFile: (fileId: string, nextName: string) => Promise<void>;
  handleRenameAsset: (assetId: string, nextName: string) => Promise<void>;
  handleRenameFolder: (folderPath: string, nextFolderPath: string) => Promise<void>;
};

export const useCaseResolverStateFolderActions = ({
  confirm,
  toast,
  updateWorkspace,
  workspace,
  selectedCaseScopeIds,
  selectedCaseContainerId,
  setSelectedFileId,
  setSelectedAssetId,
  setSelectedFolderPath,
  setEditingDocumentDraft,
  treeSaveToast,
}: UseCaseResolverStateFolderActionsInput): UseCaseResolverStateFolderActionsResult => {
  const isLockedEditableFile = useCallback(
    (file: CaseResolverFile): boolean => file.fileType !== 'case' && file.isLocked === true,
    []
  );

  const handleDeleteFolder = useCallback(
    (folderPath: string): void => {
      const normalizedFolder = normalizeFolderPath(folderPath);
      if (!normalizedFolder) return;
      const scopedCaseIds = selectedCaseScopeIds;
      const scopedFileIds = scopedCaseIds
        ? new Set<string>(
          workspace.files
            .filter(
              (file: CaseResolverFile): boolean =>
                file.fileType !== 'case' &&
                  Boolean(file.parentCaseId && scopedCaseIds.has(file.parentCaseId))
            )
            .map((file: CaseResolverFile): string => file.id)
        )
        : null;
      const hasLockedFilesInFolder = workspace.files.some(
        (file: CaseResolverFile): boolean =>
          isLockedEditableFile(file) &&
          isPathWithinFolder(file.folder, normalizedFolder) &&
          (!scopedCaseIds || Boolean(file.parentCaseId && scopedCaseIds.has(file.parentCaseId)))
      );
      if (hasLockedFilesInFolder) {
        toast('Folder contains locked documents. Unlock them before deleting this folder.', {
          variant: 'warning',
        });
        return;
      }

      confirm({
        title: 'Delete Folder?',
        message: `Are you sure you want to delete folder "${normalizedFolder}" and all nested content? This action cannot be undone.`,
        confirmText: 'Delete Folder',
        isDangerous: true,
        onConfirm: () => {
          const filesInDeletedFolder = workspace.files.filter(
            (file: CaseResolverFile): boolean =>
              file.fileType !== 'case' &&
              isPathWithinFolder(file.folder, normalizedFolder) &&
              (!scopedCaseIds || Boolean(file.parentCaseId && scopedCaseIds.has(file.parentCaseId)))
          );
          const assetsInDeletedFolder = workspace.assets.filter(
            (asset: CaseResolverAssetFile): boolean =>
              isPathWithinFolder(asset.folder, normalizedFolder) &&
              (!scopedFileIds ||
                Boolean(asset.sourceFileId && scopedFileIds.has(asset.sourceFileId)))
          );
          const removedFileIds = new Set<string>(
            filesInDeletedFolder.map((file: CaseResolverFile): string => file.id)
          );
          const removedAssetIds = new Set<string>(
            assetsInDeletedFolder.map((asset: CaseResolverAssetFile): string => asset.id)
          );
          const removedNodeFileAssetIds = assetsInDeletedFolder
            .filter((asset: CaseResolverAssetFile): boolean => asset.kind === 'node_file')
            .map((asset: CaseResolverAssetFile): string => asset.id);

          updateWorkspace(
            (current) => {
              const currentScopeCaseIds = collectCaseScopeIds(
                current.files,
                selectedCaseContainerId
              );
              const currentHasLockedFilesInFolder = current.files.some(
                (file: CaseResolverFile): boolean =>
                  isLockedEditableFile(file) &&
                  isPathWithinFolder(file.folder, normalizedFolder) &&
                  (!currentScopeCaseIds ||
                    Boolean(file.parentCaseId && currentScopeCaseIds.has(file.parentCaseId)))
              );
              if (currentHasLockedFilesInFolder) return current;
              const currentScopeFileIds = currentScopeCaseIds
                ? new Set<string>(
                  current.files
                    .filter(
                      (file: CaseResolverFile): boolean =>
                        file.fileType !== 'case' &&
                          Boolean(file.parentCaseId && currentScopeCaseIds.has(file.parentCaseId))
                    )
                    .map((file: CaseResolverFile): string => file.id)
                )
                : null;
              const currentRemovedFileIds = new Set(
                current.files
                  .filter(
                    (file: CaseResolverFile): boolean =>
                      file.fileType !== 'case' &&
                      isPathWithinFolder(file.folder, normalizedFolder) &&
                      (!currentScopeCaseIds ||
                        Boolean(file.parentCaseId && currentScopeCaseIds.has(file.parentCaseId)))
                  )
                  .map((file: CaseResolverFile): string => file.id)
              );
              const nextFiles = current.files.filter(
                (file: CaseResolverFile): boolean =>
                  file.fileType === 'case' ||
                  !isPathWithinFolder(file.folder, normalizedFolder) ||
                  (currentScopeCaseIds !== null &&
                    (!file.parentCaseId || !currentScopeCaseIds.has(file.parentCaseId)))
              );
              const nextAssets = current.assets.filter(
                (asset: CaseResolverAssetFile): boolean =>
                  !isPathWithinFolder(asset.folder, normalizedFolder) ||
                  (currentScopeFileIds !== null &&
                    (!asset.sourceFileId || !currentScopeFileIds.has(asset.sourceFileId)))
              );
              const fallbackCaseId = (() => {
                if (!current.activeFileId || !currentRemovedFileIds.has(current.activeFileId)) {
                  return null;
                }
                const removedActiveFile =
                  current.files.find(
                    (file: CaseResolverFile): boolean => file.id === current.activeFileId
                  ) ?? null;
                if (!removedActiveFile?.parentCaseId) return null;
                const parentCase =
                  current.files.find(
                    (file: CaseResolverFile): boolean => file.id === removedActiveFile.parentCaseId
                  ) ?? null;
                return parentCase?.fileType === 'case' ? parentCase.id : null;
              })();
              const fallbackFileId =
                nextFiles.find((file: CaseResolverFile): boolean => file.fileType !== 'case')?.id ??
                nextFiles.find((file: CaseResolverFile): boolean => file.fileType === 'case')?.id ??
                null;

              return {
                ...current,
                folders: current.folders.filter(
                  (path: string): boolean => !isPathWithinFolder(path, normalizedFolder)
                ),
                folderRecords: removeOwnedFolderRecordsWithinPath({
                  records: current.folderRecords,
                  folderPath: normalizedFolder,
                  ownerCaseIds: currentScopeCaseIds,
                }),
                files: nextFiles,
                assets: nextAssets,
                activeFileId:
                  current.activeFileId && currentRemovedFileIds.has(current.activeFileId)
                    ? (fallbackCaseId ?? fallbackFileId)
                    : current.activeFileId,
              };
            },
            { persistToast: treeSaveToast }
          );

          setSelectedFileId((current: string | null): string | null => {
            if (!current || !removedFileIds.has(current)) return current;
            const removedSelectedFile =
              workspace.files.find((file: CaseResolverFile): boolean => file.id === current) ??
              null;
            if (!removedSelectedFile?.parentCaseId) return null;
            const parentCase =
              workspace.files.find(
                (file: CaseResolverFile): boolean =>
                  file.id === removedSelectedFile.parentCaseId && file.fileType === 'case'
              ) ?? null;
            return parentCase?.id ?? null;
          });
          setSelectedAssetId((current: string | null): string | null =>
            current && removedAssetIds.has(current) ? null : current
          );
          setSelectedFolderPath((current: string | null): string | null =>
            current && isPathWithinFolder(current, normalizedFolder) ? null : current
          );
          if (removedNodeFileAssetIds.length > 0) {
            void Promise.allSettled(
              removedNodeFileAssetIds.map((assetId: string) =>
                deleteCaseResolverNodeFileSnapshot(assetId, 'case_view_folder_delete')
              )
            );
          }
        },
      });
    },
    [
      confirm,
      isLockedEditableFile,
      selectedCaseContainerId,
      selectedCaseScopeIds,
      setSelectedAssetId,
      setSelectedFileId,
      setSelectedFolderPath,
      toast,
      treeSaveToast,
      updateWorkspace,
      workspace.assets,
      workspace.files,
    ]
  );

  const handleMoveFile = useCallback(
    async (fileId: string, targetFolder: string): Promise<void> => {
      const targetFile = workspace.files.find(
        (file: CaseResolverFile): boolean => file.id === fileId
      );
      if (targetFile && isLockedEditableFile(targetFile)) {
        toast('Document is locked. Unlock it before moving.', { variant: 'warning' });
        return;
      }
      const normalizedTarget = normalizeFolderPath(targetFolder);
      updateWorkspace(
        (current) => {
          const currentTargetFile = current.files.find(
            (file: CaseResolverFile): boolean => file.id === fileId
          );
          if (currentTargetFile && isLockedEditableFile(currentTargetFile)) return current;
          return {
            ...current,
            files: current.files.map((file: CaseResolverFile) =>
              file.id === fileId
                ? { ...file, folder: normalizedTarget, updatedAt: new Date().toISOString() }
                : file
            ),
            folders: normalizeFolderPaths(
              normalizedTarget ? [...current.folders, normalizedTarget] : current.folders
            ),
          };
        },
        { persistToast: treeSaveToast }
      );
      setEditingDocumentDraft((current: CaseResolverFileEditDraft | null) => {
        if (current?.id !== fileId) return current;
        return {
          ...current,
          folder: normalizedTarget,
          updatedAt: new Date().toISOString(),
        };
      });
    },
    [
      isLockedEditableFile,
      setEditingDocumentDraft,
      toast,
      treeSaveToast,
      updateWorkspace,
      workspace.files,
    ]
  );

  const handleMoveAsset = useCallback(
    async (assetId: string, targetFolder: string): Promise<void> => {
      const normalizedTarget = normalizeFolderPath(targetFolder);
      updateWorkspace(
        (current) => ({
          ...current,
          assets: current.assets.map((asset: CaseResolverAssetFile) =>
            asset.id === assetId
              ? { ...asset, folder: normalizedTarget, updatedAt: new Date().toISOString() }
              : asset
          ),
          folders: normalizeFolderPaths(
            normalizedTarget ? [...current.folders, normalizedTarget] : current.folders
          ),
        }),
        { persistToast: treeSaveToast }
      );
    },
    [treeSaveToast, updateWorkspace]
  );

  const handleRenameFile = useCallback(
    async (fileId: string, nextName: string): Promise<void> => {
      const trimmedName = nextName.trim();
      if (!trimmedName) return;
      const targetFile = workspace.files.find(
        (file: CaseResolverFile): boolean => file.id === fileId
      );
      if (targetFile && isLockedEditableFile(targetFile)) {
        toast('Document is locked. Unlock it before renaming.', { variant: 'warning' });
        return;
      }
      updateWorkspace(
        (current) => {
          const currentTargetFile = current.files.find(
            (file: CaseResolverFile): boolean => file.id === fileId
          );
          if (currentTargetFile && isLockedEditableFile(currentTargetFile)) return current;
          return {
            ...current,
            files: current.files.map((file: CaseResolverFile) =>
              file.id === fileId
                ? { ...file, name: trimmedName, updatedAt: new Date().toISOString() }
                : file
            ),
          };
        },
        { persistToast: treeSaveToast }
      );
      setEditingDocumentDraft((current: CaseResolverFileEditDraft | null) => {
        if (current?.id !== fileId) return current;
        return {
          ...current,
          name: trimmedName,
          updatedAt: new Date().toISOString(),
        };
      });
    },
    [
      isLockedEditableFile,
      setEditingDocumentDraft,
      toast,
      treeSaveToast,
      updateWorkspace,
      workspace.files,
    ]
  );

  const handleRenameAsset = useCallback(
    async (assetId: string, nextName: string): Promise<void> => {
      const trimmedName = nextName.trim();
      if (!trimmedName) return;
      updateWorkspace(
        (current) => ({
          ...current,
          assets: current.assets.map((asset: CaseResolverAssetFile) =>
            asset.id === assetId
              ? { ...asset, name: trimmedName, updatedAt: new Date().toISOString() }
              : asset
          ),
        }),
        { persistToast: treeSaveToast }
      );
    },
    [treeSaveToast, updateWorkspace]
  );

  const handleRenameFolder = useCallback(
    async (folderPath: string, nextFolderPath: string): Promise<void> => {
      const normalizedSource = normalizeFolderPath(folderPath);
      const normalizedTarget = normalizeFolderPath(nextFolderPath);
      if (!normalizedSource || !normalizedTarget) return;
      if (normalizedSource === normalizedTarget) return;
      const hasLockedFilesInFolder = workspace.files.some(
        (file: CaseResolverFile): boolean =>
          isLockedEditableFile(file) &&
          isPathWithinFolder(file.folder, normalizedSource) &&
          (!selectedCaseScopeIds ||
            Boolean(file.parentCaseId && selectedCaseScopeIds.has(file.parentCaseId)))
      );
      if (hasLockedFilesInFolder) {
        toast('Folder contains locked documents. Unlock them before renaming this folder.', {
          variant: 'warning',
        });
        return;
      }

      updateWorkspace(
        (current) => {
          const now = new Date().toISOString();
          const rename = (value: string): string =>
            renameFolderPath(value, normalizedSource, normalizedTarget);
          const currentScopeCaseIds = collectCaseScopeIds(current.files, selectedCaseContainerId);
          const currentHasLockedFilesInFolder = current.files.some(
            (file: CaseResolverFile): boolean =>
              isLockedEditableFile(file) &&
              isPathWithinFolder(file.folder, normalizedSource) &&
              (!currentScopeCaseIds ||
                Boolean(file.parentCaseId && currentScopeCaseIds.has(file.parentCaseId)))
          );
          if (currentHasLockedFilesInFolder) return current;
          const currentScopeFileIds = currentScopeCaseIds
            ? new Set<string>(
              current.files
                .filter(
                  (file: CaseResolverFile): boolean =>
                    file.fileType !== 'case' &&
                      Boolean(file.parentCaseId && currentScopeCaseIds.has(file.parentCaseId))
                )
                .map((file: CaseResolverFile): string => file.id)
            )
            : null;

          return {
            ...current,
            folders: normalizeFolderPaths(current.folders.map(rename)),
            folderRecords: renameOwnedFolderRecordsWithinPath({
              records: current.folderRecords,
              sourceFolderPath: normalizedSource,
              targetFolderPath: normalizedTarget,
              ownerCaseIds: currentScopeCaseIds,
            }),
            folderTimestamps: Object.fromEntries(
              Object.entries(current.folderTimestamps ?? {}).map(([path, timestamps]) => [
                rename(path),
                timestamps,
              ])
            ),
            files: current.files.map((file: CaseResolverFile) => {
              const shouldRename =
                isPathWithinFolder(file.folder, normalizedSource) &&
                (!currentScopeCaseIds ||
                  (file.fileType === 'case'
                    ? currentScopeCaseIds.has(file.id)
                    : Boolean(file.parentCaseId && currentScopeCaseIds.has(file.parentCaseId))));
              if (!shouldRename) return file;
              const nextFolder = rename(file.folder);
              if (nextFolder === file.folder) return file;
              return { ...file, folder: nextFolder, updatedAt: now };
            }),
            assets: current.assets.map((asset: CaseResolverAssetFile) => {
              const shouldRename =
                isPathWithinFolder(asset.folder, normalizedSource) &&
                (!currentScopeFileIds ||
                  Boolean(asset.sourceFileId && currentScopeFileIds.has(asset.sourceFileId)));
              if (!shouldRename) return asset;
              const nextFolder = rename(asset.folder);
              if (nextFolder === asset.folder) return asset;
              return { ...asset, folder: nextFolder, updatedAt: now };
            }),
          };
        },
        { persistToast: treeSaveToast }
      );

      setSelectedFolderPath((current) => {
        if (!current || !isPathWithinFolder(current, normalizedSource)) return current;
        return renameFolderPath(current, normalizedSource, normalizedTarget);
      });
      setEditingDocumentDraft((current: CaseResolverFileEditDraft | null) => {
        if (!current || !isPathWithinFolder(current.folder, normalizedSource)) return current;
        return {
          ...current,
          folder: renameFolderPath(current.folder, normalizedSource, normalizedTarget),
          updatedAt: new Date().toISOString(),
        };
      });
    },
    [
      isLockedEditableFile,
      selectedCaseContainerId,
      selectedCaseScopeIds,
      setEditingDocumentDraft,
      setSelectedFolderPath,
      toast,
      treeSaveToast,
      updateWorkspace,
      workspace.files,
    ]
  );

  return {
    handleDeleteFolder,
    handleMoveFile,
    handleMoveAsset,
    handleRenameFile,
    handleRenameAsset,
    handleRenameFolder,
  };
};

import { buildFileEditDraft } from '@/features/case-resolver/utils/caseResolverUtils';
import {
  deriveDocumentContentSync,
  ensureHtmlForPreview,
  hasHtmlMarkup,
  ensureSafeDocumentHtml,
  stripHtmlToPlainText,
  toStorageDocumentValue,
  type DocumentContentCanonical,
} from '@/shared/lib/document-editor/public';
import type { CaseResolverFile, CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import { stableStringify } from '@/shared/lib/ai-paths/core/utils';

export type CaseResolverDraftCanonicalState = {
  mode: 'markdown' | 'wysiwyg';
  storedContent: string;
  markdown: string;
  html: string;
  plainText: string;
  warnings: string[];
  originalDocumentContent: string;
  explodedDocumentContent: string;
};

const toComparableCanonicalState = (
  fileType: CaseResolverFile['fileType'] | CaseResolverFileEditDraft['fileType'],
  canonicalState: CaseResolverDraftCanonicalState
): CaseResolverDraftCanonicalState => {
  if (fileType !== 'scanfile') return canonicalState;
  return {
    ...canonicalState,
    // Scan files are markdown-authoritative. HTML and version mirrors are derived views.
    html: '',
    originalDocumentContent: '',
    explodedDocumentContent: '',
  };
};

const normalizeSemanticallyEmptyCanonicalContent = (
  canonical: DocumentContentCanonical
): DocumentContentCanonical => {
  if (canonical.plainText.trim().length > 0) return canonical;
  if (
    canonical.html.length === 0 &&
    canonical.markdown.length === 0 &&
    canonical.plainText.length === 0
  ) {
    return canonical;
  }
  return {
    ...canonical,
    html: '',
    markdown: '',
    plainText: '',
  };
};

export const buildCaseResolverDraftCanonicalState = (
  draft: CaseResolverFileEditDraft
): CaseResolverDraftCanonicalState => {
  const resolvedMode: 'markdown' | 'wysiwyg' =
    draft.fileType === 'scanfile' ? 'markdown' : 'wysiwyg';
  const resolvedCanonicalSource = (() => {
    if (resolvedMode === 'markdown') {
      if (
        typeof draft.documentContentMarkdown === 'string' &&
        draft.documentContentMarkdown.trim().length > 0
      ) {
        return draft.documentContentMarkdown;
      }
      if (
        typeof draft.documentContentPlainText === 'string' &&
        draft.documentContentPlainText.trim().length > 0
      ) {
        return draft.documentContentPlainText;
      }
      const fallbackContent = draft.documentContent ?? '';
      if (fallbackContent.trim().length > 0) {
        return hasHtmlMarkup(fallbackContent)
          ? stripHtmlToPlainText(fallbackContent)
          : fallbackContent;
      }
      if (
        typeof draft.documentContentHtml === 'string' &&
        draft.documentContentHtml.trim().length > 0
      ) {
        return stripHtmlToPlainText(draft.documentContentHtml);
      }
      return '';
    }
    if (
      typeof draft.documentContentHtml === 'string' &&
      draft.documentContentHtml.trim().length > 0
    ) {
      return draft.documentContentHtml;
    }
    if (
      typeof draft.documentContentMarkdown === 'string' &&
      draft.documentContentMarkdown.trim().length > 0
    ) {
      return ensureHtmlForPreview(draft.documentContentMarkdown, 'markdown');
    }
    return ensureSafeDocumentHtml(draft.documentContent ?? '');
  })();
  const canonical = normalizeSemanticallyEmptyCanonicalContent(
    deriveDocumentContentSync({
      mode: resolvedMode,
      value: resolvedCanonicalSource,
      previousHtml: draft.documentContentHtml ?? '',
      previousMarkdown: draft.documentContentMarkdown ?? '',
    })
  );
  const storedContent = toStorageDocumentValue(canonical);
  const originalDocumentContent =
    draft.activeDocumentVersion === 'original'
      ? storedContent
      : (draft.originalDocumentContent ?? '');
  const explodedDocumentContent =
    draft.activeDocumentVersion === 'exploded'
      ? storedContent
      : (draft.explodedDocumentContent ?? '');
  return {
    mode: resolvedMode,
    storedContent,
    markdown: canonical.markdown,
    html: canonical.html,
    plainText: canonical.plainText,
    warnings: [...canonical.warnings],
    originalDocumentContent,
    explodedDocumentContent,
  };
};

const normalizeComparableReferenceCaseIds = (value: string[] | null | undefined): string[] =>
  [...(value ?? [])].sort();

const normalizeComparableWarnings = (value: string[] | null | undefined): string[] => [
  ...(value ?? []),
];

const normalizeComparablePartyReference = (
  value: CaseResolverFileEditDraft['addresser'] | null | undefined
): { kind: 'person' | 'organization'; id: string } | null => {
  if (!value || typeof value !== 'object') return null;
  const normalizedKind =
    value.kind === 'person' || value.kind === 'organization' ? value.kind : null;
  const normalizedId = typeof value.id === 'string' ? value.id.trim() : '';
  if (!normalizedKind || !normalizedId) return null;
  return {
    kind: normalizedKind,
    id: normalizedId,
  };
};

type CaseResolverComparableDocumentSnapshot = {
  id: string;
  name: string;
  folder: string;
  parentCaseId: string | null;
  referenceCaseIds: string[];
  documentDate: CaseResolverFileEditDraft['documentDate'];
  documentCity: string | null;
  isSent: boolean;
  tagId: string | null;
  caseIdentifierId: string | null;
  categoryId: string | null;
  scanOcrModel: string;
  scanOcrPrompt: string;
  addresser: CaseResolverFileEditDraft['addresser'];
  addressee: CaseResolverFileEditDraft['addressee'];
  activeDocumentVersion: CaseResolverFileEditDraft['activeDocumentVersion'];
  editorType: CaseResolverFileEditDraft['editorType'];
  documentContentFormatVersion: 1;
  documentContent: string;
  documentContentMarkdown: string;
  documentContentHtml: string;
  documentContentPlainText: string;
  documentConversionWarnings: string[];
  originalDocumentContent: string;
  explodedDocumentContent: string;
};

const buildCaseResolverFileComparableSnapshot = (
  file: CaseResolverFile
): CaseResolverComparableDocumentSnapshot => {
  const canonicalDraft = buildFileEditDraft(file);
  const canonicalState = toComparableCanonicalState(
    file.fileType,
    buildCaseResolverDraftCanonicalState(canonicalDraft)
  );
  return {
    id: file.id,
    name: file.name,
    folder: file.folder,
    parentCaseId: file.parentCaseId ?? null,
    referenceCaseIds: normalizeComparableReferenceCaseIds(file.referenceCaseIds),
    documentDate: canonicalDraft.documentDate,
    documentCity:
      typeof canonicalDraft.documentCity === 'string'
        ? canonicalDraft.documentCity.trim() || null
        : null,
    isSent: file.isSent === true,
    tagId: file.tagId ?? null,
    caseIdentifierId: file.caseIdentifierId ?? null,
    categoryId: file.categoryId ?? null,
    scanOcrModel: file.scanOcrModel ?? '',
    scanOcrPrompt: file.scanOcrPrompt ?? '',
    addresser: normalizeComparablePartyReference(file.addresser),
    addressee: normalizeComparablePartyReference(file.addressee),
    activeDocumentVersion: canonicalDraft.activeDocumentVersion,
    editorType: canonicalState.mode,
    documentContentFormatVersion: 1,
    documentContent: canonicalState.storedContent,
    documentContentMarkdown: canonicalState.markdown,
    documentContentHtml: canonicalState.html,
    documentContentPlainText: canonicalState.plainText,
    documentConversionWarnings: normalizeComparableWarnings(canonicalState.warnings),
    originalDocumentContent: canonicalState.originalDocumentContent ?? '',
    explodedDocumentContent: canonicalState.explodedDocumentContent ?? '',
  };
};

const buildCaseResolverDraftComparableSnapshot = (
  draft: CaseResolverFileEditDraft,
  canonicalState: CaseResolverDraftCanonicalState
): CaseResolverComparableDocumentSnapshot => {
  const comparableCanonicalState = toComparableCanonicalState(draft.fileType, canonicalState);
  return {
    id: draft.id,
    name: draft.name,
    folder: draft.folder,
    parentCaseId: draft.parentCaseId ?? null,
    referenceCaseIds: normalizeComparableReferenceCaseIds(draft.referenceCaseIds),
    documentDate: draft.documentDate,
    documentCity: typeof draft.documentCity === 'string' ? draft.documentCity.trim() || null : null,
    isSent: draft.isSent === true,
    tagId: draft.tagId ?? null,
    caseIdentifierId: draft.caseIdentifierId ?? null,
    categoryId: draft.categoryId ?? null,
    scanOcrModel: draft.scanOcrModel ?? '',
    scanOcrPrompt: draft.scanOcrPrompt ?? '',
    addresser: normalizeComparablePartyReference(draft.addresser),
    addressee: normalizeComparablePartyReference(draft.addressee),
    activeDocumentVersion: draft.activeDocumentVersion,
    editorType: comparableCanonicalState.mode,
    documentContentFormatVersion: 1,
    documentContent: comparableCanonicalState.storedContent,
    documentContentMarkdown: comparableCanonicalState.markdown,
    documentContentHtml: comparableCanonicalState.html,
    documentContentPlainText: comparableCanonicalState.plainText,
    documentConversionWarnings: normalizeComparableWarnings(comparableCanonicalState.warnings),
    originalDocumentContent: comparableCanonicalState.originalDocumentContent ?? '',
    explodedDocumentContent: comparableCanonicalState.explodedDocumentContent ?? '',
  };
};

export const buildCaseResolverFileComparableFingerprint = (file: CaseResolverFile): string =>
  stableStringify(buildCaseResolverFileComparableSnapshot(file));

export const buildCaseResolverDraftComparableFingerprint = (
  draft: CaseResolverFileEditDraft,
  canonicalState?: CaseResolverDraftCanonicalState
): string =>
  stableStringify(
    buildCaseResolverDraftComparableSnapshot(
      draft,
      canonicalState ?? buildCaseResolverDraftCanonicalState(draft)
    )
  );

export const hasCaseResolverDraftMeaningfulChanges = ({
  draft,
  file,
  canonicalState,
}: {
  draft: CaseResolverFileEditDraft;
  file: CaseResolverFile;
  canonicalState?: CaseResolverDraftCanonicalState;
}): boolean =>
  buildCaseResolverDraftComparableFingerprint(draft, canonicalState) !==
  buildCaseResolverFileComparableFingerprint(file);

export const canCaseResolverDraftPerformInitialManualSave = ({
  draft,
  file,
  canonicalState,
}: {
  draft: CaseResolverFileEditDraft;
  file: CaseResolverFile;
  canonicalState?: CaseResolverDraftCanonicalState;
}): boolean => {
  if (draft.id !== file.id) return false;
  if (draft.fileType !== 'document' || file.fileType !== 'document') return false;
  if ((file.documentHistory?.length ?? 0) > 0) return false;
  if (file.documentContentVersion > 1) return false;
  if (file.updatedAt !== file.createdAt) return false;

  const resolvedCanonicalState = canonicalState ?? buildCaseResolverDraftCanonicalState(draft);
  if (
    hasCaseResolverDraftMeaningfulChanges({
      draft,
      file,
      canonicalState: resolvedCanonicalState,
    })
  ) {
    return false;
  }

  const hasAnyTextContent =
    resolvedCanonicalState.plainText.trim().length > 0 ||
    resolvedCanonicalState.markdown.trim().length > 0 ||
    resolvedCanonicalState.originalDocumentContent.trim().length > 0 ||
    resolvedCanonicalState.explodedDocumentContent.trim().length > 0;
  return !hasAnyTextContent;
};

import { isPathWithinFolder } from '@/features/case-resolver/utils/caseResolverUtils';
import type { CaseResolverFile, CaseResolverFolderRecord } from '@/shared/contracts/case-resolver/file';

import { expandFolderPath, normalizeFolderPath, renameFolderPath } from '../settings';

const buildFolderRecordKey = (path: string, ownerCaseId: string | null): string =>
  `${ownerCaseId ?? '__none__'}::${path}`;

export const normalizeFolderRecords = (
  source: CaseResolverFolderRecord[] | null | undefined
): CaseResolverFolderRecord[] => {
  if (!Array.isArray(source)) return [];
  const byKey = new Map<string, CaseResolverFolderRecord>();
  source.forEach((record: CaseResolverFolderRecord): void => {
    const normalizedPath = normalizeFolderPath(record.path);
    if (!normalizedPath) return;
    const ownerCaseId =
      typeof record.ownerCaseId === 'string' && record.ownerCaseId.trim().length > 0
        ? record.ownerCaseId.trim()
        : null;
    const key = buildFolderRecordKey(normalizedPath, ownerCaseId);
    if (byKey.has(key)) return;
    byKey.set(key, {
      path: normalizedPath,
      ownerCaseId,
    });
  });
  return Array.from(byKey.values()).sort(
    (left: CaseResolverFolderRecord, right: CaseResolverFolderRecord) => {
      const pathDelta = left.path.localeCompare(right.path);
      if (pathDelta !== 0) return pathDelta;
      return (left.ownerCaseId ?? '').localeCompare(right.ownerCaseId ?? '');
    }
  );
};

export const appendOwnedFolderRecords = ({
  records,
  folderPath,
  ownerCaseId,
}: {
  records: CaseResolverFolderRecord[] | null | undefined;
  folderPath: string;
  ownerCaseId: string | null;
}): CaseResolverFolderRecord[] => {
  const normalizedPath = normalizeFolderPath(folderPath);
  if (!normalizedPath) return normalizeFolderRecords(records);
  const current = normalizeFolderRecords(records);
  const byKey = new Map<string, CaseResolverFolderRecord>(
    current.map((record: CaseResolverFolderRecord): [string, CaseResolverFolderRecord] => [
      buildFolderRecordKey(record.path, record.ownerCaseId ?? null),
      record,
    ])
  );
  expandFolderPath(normalizedPath).forEach((path: string): void => {
    const key = buildFolderRecordKey(path, ownerCaseId);
    if (byKey.has(key)) return;
    byKey.set(key, { path, ownerCaseId });
  });
  return normalizeFolderRecords(Array.from(byKey.values()));
};

export const removeOwnedFolderRecordsWithinPath = ({
  records,
  folderPath,
  ownerCaseIds,
}: {
  records: CaseResolverFolderRecord[] | null | undefined;
  folderPath: string;
  ownerCaseIds: Set<string> | null;
}): CaseResolverFolderRecord[] => {
  const normalizedPath = normalizeFolderPath(folderPath);
  if (!normalizedPath) return normalizeFolderRecords(records);
  const current = normalizeFolderRecords(records);
  const filtered = current.filter((record: CaseResolverFolderRecord): boolean => {
    if (!isPathWithinFolder(record.path, normalizedPath)) return true;
    if (!ownerCaseIds || ownerCaseIds.size === 0) return false;
    if (!record.ownerCaseId) return true;
    return !ownerCaseIds.has(record.ownerCaseId);
  });
  return normalizeFolderRecords(filtered);
};

export const renameOwnedFolderRecordsWithinPath = ({
  records,
  sourceFolderPath,
  targetFolderPath,
  ownerCaseIds,
}: {
  records: CaseResolverFolderRecord[] | null | undefined;
  sourceFolderPath: string;
  targetFolderPath: string;
  ownerCaseIds: Set<string> | null;
}): CaseResolverFolderRecord[] => {
  const normalizedSource = normalizeFolderPath(sourceFolderPath);
  const normalizedTarget = normalizeFolderPath(targetFolderPath);
  if (!normalizedSource || !normalizedTarget) return normalizeFolderRecords(records);
  const current = normalizeFolderRecords(records);
  const renamed = current.map((record: CaseResolverFolderRecord): CaseResolverFolderRecord => {
    if (!isPathWithinFolder(record.path, normalizedSource)) return record;
    if (ownerCaseIds && ownerCaseIds.size > 0) {
      if (!record.ownerCaseId || !ownerCaseIds.has(record.ownerCaseId)) {
        return record;
      }
    }
    return {
      ...record,
      path: renameFolderPath(record.path, normalizedSource, normalizedTarget),
    };
  });
  return normalizeFolderRecords(renamed);
};

export const collectCaseScopeIds = (
  files: CaseResolverFile[],
  rootCaseId: string | null
): Set<string> | null => {
  if (!rootCaseId) return null;
  const fileById = new Map<string, CaseResolverFile>(
    files.map((file: CaseResolverFile): [string, CaseResolverFile] => [file.id, file])
  );
  if (fileById.get(rootCaseId)?.fileType !== 'case') return null;

  const childCaseIdsByParentId = new Map<string, string[]>();
  files.forEach((file: CaseResolverFile): void => {
    if (file.fileType !== 'case') return;
    const parentCaseId = file.parentCaseId;
    if (!parentCaseId || parentCaseId === file.id) return;
    const parentFile = fileById.get(parentCaseId);
    if (parentFile?.fileType !== 'case') return;
    const currentChildren = childCaseIdsByParentId.get(parentCaseId) ?? [];
    currentChildren.push(file.id);
    childCaseIdsByParentId.set(parentCaseId, currentChildren);
  });

  const scopedCaseIds = new Set<string>();
  const visitCase = (caseId: string): void => {
    if (!caseId || scopedCaseIds.has(caseId)) return;
    const caseFile = fileById.get(caseId);
    if (caseFile?.fileType !== 'case') return;
    scopedCaseIds.add(caseId);
    const children = childCaseIdsByParentId.get(caseId) ?? [];
    children.forEach((childId: string): void => visitCase(childId));
  };
  visitCase(rootCaseId);
  return scopedCaseIds.size > 0 ? scopedCaseIds : null;
};

export const resolveCaseContainerIdForFileId = (
  filesById: Map<string, CaseResolverFile>,
  fileId: string | null
): string | null => {
  if (!fileId) return null;
  const contextFile = filesById.get(fileId) ?? null;
  if (!contextFile) return null;
  if (contextFile.fileType === 'case') return contextFile.id;
  if (!contextFile.parentCaseId) return null;
  const parentFile = filesById.get(contextFile.parentCaseId) ?? null;
  return parentFile?.fileType === 'case' ? parentFile.id : null;
};

export const resolveCaseContainerIdForFolderPath = ({
  filesById,
  folderRecords,
  folderPath,
}: {
  filesById: Map<string, CaseResolverFile>;
  folderRecords: CaseResolverFolderRecord[] | null | undefined;
  folderPath: string | null;
}): string | null => {
  const normalizedFolderPath = normalizeFolderPath(folderPath ?? '');
  if (!normalizedFolderPath) return null;

  const ownerCaseIds = normalizeFolderRecords(folderRecords)
    .filter((record: CaseResolverFolderRecord): boolean => record.path === normalizedFolderPath)
    .map((record: CaseResolverFolderRecord): string => record.ownerCaseId?.trim() ?? '')
    .filter((ownerCaseId: string): boolean => {
      if (!ownerCaseId) return false;
      return filesById.get(ownerCaseId)?.fileType === 'case';
    });
  const uniqueOwnerCaseIds = Array.from(new Set(ownerCaseIds));
  return uniqueOwnerCaseIds.length === 1 ? (uniqueOwnerCaseIds[0] ?? null) : null;
};

export const resolveCaseResolverActiveCaseId = ({
  requestedFileId,
  requestedCaseContainerId,
  selectedCaseContainerId,
  selectedFolderCaseContainerId,
  files: _files,
}: {
  requestedFileId: string | null;
  requestedCaseContainerId: string | null;
  selectedCaseContainerId: string | null;
  selectedFolderCaseContainerId?: string | null;
  files: CaseResolverFile[];
}): string | null => {
  if (requestedFileId) return requestedCaseContainerId;
  if (selectedCaseContainerId) return selectedCaseContainerId;
  if (selectedFolderCaseContainerId) return selectedFolderCaseContainerId;
  return null;
};

export const resolveCaseScopedFolderTarget = ({
  targetFolderPath,
  ownerCaseId,
  folderRecords,
}: {
  targetFolderPath: string | null;
  ownerCaseId: string;
  folderRecords: CaseResolverFolderRecord[] | null | undefined;
}): string => {
  const normalizedTarget = normalizeFolderPath(targetFolderPath ?? '');
  if (!normalizedTarget) return '';

  const normalizedRecords = normalizeFolderRecords(folderRecords);
  const ownerPaths = new Set<string>(
    normalizedRecords
      .filter((record: CaseResolverFolderRecord): boolean => record.ownerCaseId === ownerCaseId)
      .map((record: CaseResolverFolderRecord): string => record.path)
  );

  // If the folder path already belongs to this case, keep it.
  if (ownerPaths.has(normalizedTarget)) {
    return normalizedTarget;
  }

  // If it does not belong to this case, reset to root to avoid leaking create actions
  // into a folder selected in another case.
  return '';
};

import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { getCaseResolverWorkspaceRevision } from '../workspace-persistence';

export type CaseResolverWorkspaceHydrationDecisionReason =
  | 'incoming_newer_revision'
  | 'requested_file_missing_in_current'
  | 'equal_revision_current_placeholder'
  | 'current_default_placeholder'
  | 'keep_current';

export type CaseResolverWorkspaceHydrationDecision = {
  adopt: boolean;
  reason: CaseResolverWorkspaceHydrationDecisionReason;
};

export type CaseResolverWorkspaceHydrationSource = 'store' | 'navigation' | 'heavy' | 'none';

export type CaseResolverWorkspaceHydrationSourceReason =
  | CaseResolverWorkspaceHydrationDecisionReason
  | 'navigation_newer_revision'
  | 'store_only'
  | 'navigation_requested_file_fallback'
  | 'navigation_only'
  | 'heavy_only'
  | 'store_preferred'
  | 'no_workspace_source';

export type CaseResolverWorkspaceHydrationSourceSelection = {
  workspace: CaseResolverWorkspace;
  source: CaseResolverWorkspaceHydrationSource;
  reason: CaseResolverWorkspaceHydrationSourceReason;
};

type CaseResolverWorkspaceHydrationDecisionResolver = (input: {
  current: CaseResolverWorkspace;
  incoming: CaseResolverWorkspace;
  requestedFileId: string | null;
}) => CaseResolverWorkspaceHydrationDecision | null;

type PreferredCaseResolverWorkspaceSelectionContext = {
  storeWorkspace: CaseResolverWorkspace;
  resolvedNavigationWorkspace: CaseResolverWorkspace;
  hasStoreWorkspace: boolean;
  hasNavigationWorkspace: boolean;
  normalizedRequestedFileId: string;
  hasRequestedFileId: boolean;
  navigationHasRequestedFile: boolean;
  storeHasRequestedFile: boolean;
  navigationRevision: number;
  storeRevision: number;
};

const normalizeRequestedFileId = (value: string | null | undefined): string =>
  typeof value === 'string' ? value.trim() : '';

const hasRequestedFile = (workspace: CaseResolverWorkspace, requestedFileId: string): boolean =>
  workspace.files.some((file): boolean => file.id === requestedFileId);

const resolveRequestedFileSatisfied = ({
  requestedFileId,
  workspace,
}: {
  requestedFileId: string;
  workspace: CaseResolverWorkspace;
}): boolean => {
  if (requestedFileId.length === 0) return true;
  return hasRequestedFile(workspace, requestedFileId);
};

const isPlaceholderWorkspace = (workspace: CaseResolverWorkspace): boolean => {
  const hasContent =
    workspace.files.length > 0 ||
    workspace.assets.length > 0 ||
    workspace.folders.length > 0 ||
    (workspace.folderRecords?.length ?? 0) > 0;
  if (hasContent) return false;
  const normalizedWorkspaceId = workspace.id.trim().toLowerCase();
  return normalizedWorkspaceId === '' || normalizedWorkspaceId === 'empty';
};

const resolveIncomingRevisionDecision = ({
  current,
  incoming,
}: {
  current: CaseResolverWorkspace;
  incoming: CaseResolverWorkspace;
}): CaseResolverWorkspaceHydrationDecision | null => {
  const currentRevision = getCaseResolverWorkspaceRevision(current);
  const incomingRevision = getCaseResolverWorkspaceRevision(incoming);
  return incomingRevision > currentRevision
    ? { adopt: true, reason: 'incoming_newer_revision' }
    : null;
};

const resolvePlaceholderWorkspaceDecision = ({
  current,
  incoming,
}: {
  current: CaseResolverWorkspace;
  incoming: CaseResolverWorkspace;
}): CaseResolverWorkspaceHydrationDecision | null => {
  const currentRevision = getCaseResolverWorkspaceRevision(current);
  const incomingRevision = getCaseResolverWorkspaceRevision(incoming);
  const currentIsPlaceholder = isPlaceholderWorkspace(current);
  const incomingIsPlaceholder = isPlaceholderWorkspace(incoming);

  if (incomingRevision === currentRevision && currentIsPlaceholder && !incomingIsPlaceholder) {
    return { adopt: true, reason: 'equal_revision_current_placeholder' };
  }

  return currentIsPlaceholder && !incomingIsPlaceholder
    ? { adopt: true, reason: 'current_default_placeholder' }
    : null;
};

const resolveRequestedFileWorkspaceDecision = ({
  current,
  incoming,
  requestedFileId,
}: {
  current: CaseResolverWorkspace;
  incoming: CaseResolverWorkspace;
  requestedFileId: string | null;
}): CaseResolverWorkspaceHydrationDecision | null => {
  const normalizedRequestedFileId = normalizeRequestedFileId(requestedFileId);
  if (!normalizedRequestedFileId) {
    return null;
  }

  const currentHasRequested = hasRequestedFile(current, normalizedRequestedFileId);
  const incomingHasRequested = hasRequestedFile(incoming, normalizedRequestedFileId);
  return !currentHasRequested && incomingHasRequested
    ? { adopt: true, reason: 'requested_file_missing_in_current' }
    : null;
};

const HYDRATION_DECISION_RESOLVERS: CaseResolverWorkspaceHydrationDecisionResolver[] = [
  resolveIncomingRevisionDecision,
  resolvePlaceholderWorkspaceDecision,
  resolveRequestedFileWorkspaceDecision,
];

const resolveWorkspaceHydrationDecision = (input: {
  current: CaseResolverWorkspace;
  incoming: CaseResolverWorkspace;
  requestedFileId: string | null;
}): CaseResolverWorkspaceHydrationDecision | null => {
  for (const resolver of HYDRATION_DECISION_RESOLVERS) {
    const decision = resolver(input);
    if (decision) {
      return decision;
    }
  }
  return null;
};

const buildHydrationSourceSelection = (
  workspace: CaseResolverWorkspace,
  source: CaseResolverWorkspaceHydrationSource,
  reason: CaseResolverWorkspaceHydrationSourceReason
): CaseResolverWorkspaceHydrationSourceSelection => ({
  workspace,
  source,
  reason,
});

const buildPreferredCaseResolverWorkspaceSelectionContext = ({
  storeWorkspace,
  navigationWorkspace,
  hasStoreWorkspace,
  hasNavigationWorkspace,
  requestedFileId,
}: {
  storeWorkspace: CaseResolverWorkspace;
  navigationWorkspace?: CaseResolverWorkspace;
  hasStoreWorkspace: boolean;
  hasNavigationWorkspace?: boolean;
  requestedFileId: string | null;
}): PreferredCaseResolverWorkspaceSelectionContext => {
  const normalizedRequestedFileId = normalizeRequestedFileId(requestedFileId);
  const hasRequestedFileId = normalizedRequestedFileId.length > 0;
  const resolvedNavigationWorkspace = navigationWorkspace ?? storeWorkspace;
  return {
    storeWorkspace,
    resolvedNavigationWorkspace,
    hasStoreWorkspace,
    hasNavigationWorkspace: hasNavigationWorkspace === true,
    normalizedRequestedFileId,
    hasRequestedFileId,
    navigationHasRequestedFile:
      hasRequestedFileId && hasRequestedFile(resolvedNavigationWorkspace, normalizedRequestedFileId),
    storeHasRequestedFile:
      hasRequestedFileId && hasRequestedFile(storeWorkspace, normalizedRequestedFileId),
    navigationRevision: getCaseResolverWorkspaceRevision(resolvedNavigationWorkspace),
    storeRevision: getCaseResolverWorkspaceRevision(storeWorkspace),
  };
};

const resolveNavigationRequestedFileFallbackSelection = (
  context: PreferredCaseResolverWorkspaceSelectionContext
): CaseResolverWorkspaceHydrationSourceSelection | null =>
  context.hasRequestedFileId &&
  context.hasNavigationWorkspace &&
  context.navigationHasRequestedFile &&
  !context.storeHasRequestedFile
    ? buildHydrationSourceSelection(
        context.resolvedNavigationWorkspace,
        'navigation',
        'navigation_requested_file_fallback'
      )
    : null;

const resolveNewerNavigationWorkspaceSelection = (
  context: PreferredCaseResolverWorkspaceSelectionContext
): CaseResolverWorkspaceHydrationSourceSelection | null =>
  context.hasNavigationWorkspace &&
  context.navigationRevision > context.storeRevision &&
  resolveRequestedFileSatisfied({
    requestedFileId: context.normalizedRequestedFileId,
    workspace: context.resolvedNavigationWorkspace,
  })
    ? buildHydrationSourceSelection(
        context.resolvedNavigationWorkspace,
        'navigation',
        'navigation_newer_revision'
      )
    : null;

const resolveStorePreferredWorkspaceSelection = (
  context: PreferredCaseResolverWorkspaceSelectionContext
): CaseResolverWorkspaceHydrationSourceSelection | null => {
  if (!context.hasStoreWorkspace) {
    return null;
  }

  return (
    resolveNavigationRequestedFileFallbackSelection(context) ??
    resolveNewerNavigationWorkspaceSelection(context) ??
    buildHydrationSourceSelection(context.storeWorkspace, 'store', 'store_only')
  );
};

const resolveNavigationOnlyWorkspaceSelection = (
  context: PreferredCaseResolverWorkspaceSelectionContext
): CaseResolverWorkspaceHydrationSourceSelection | null =>
  context.hasNavigationWorkspace && context.navigationHasRequestedFile
    ? buildHydrationSourceSelection(
        context.resolvedNavigationWorkspace,
        'navigation',
        'navigation_only'
      )
    : null;

export const shouldAdoptIncomingWorkspace = ({
  current,
  incoming,
  requestedFileId,
}: {
  current: CaseResolverWorkspace;
  incoming: CaseResolverWorkspace;
  requestedFileId: string | null;
}): CaseResolverWorkspaceHydrationDecision => {
  return (
    resolveWorkspaceHydrationDecision({
      current,
      incoming,
      requestedFileId,
    }) ?? { adopt: false, reason: 'keep_current' }
  );
};

export const shouldRefetchSettingsStoreForRequestedFile = ({
  requestedFileId,
  requestedFileResolvedInWorkspace,
  requestedFileResolvedInStore,
  isStoreLoading,
  isStoreFetching,
  lastRefetchedFileId,
}: {
  requestedFileId: string | null;
  requestedFileResolvedInWorkspace: boolean;
  requestedFileResolvedInStore: boolean;
  isStoreLoading: boolean;
  isStoreFetching: boolean;
  lastRefetchedFileId: string | null;
}): boolean => {
  const normalizedRequestedFileId = normalizeRequestedFileId(requestedFileId);
  if (!normalizedRequestedFileId) return false;
  if (requestedFileResolvedInWorkspace || requestedFileResolvedInStore) return false;
  if (isStoreLoading || isStoreFetching) return false;
  return lastRefetchedFileId !== normalizedRequestedFileId;
};

export const resolvePreferredCaseResolverWorkspace = ({
  storeWorkspace,
  navigationWorkspace,
  hasStoreWorkspace,
  hasNavigationWorkspace,
  requestedFileId,
}: {
  storeWorkspace: CaseResolverWorkspace;
  navigationWorkspace?: CaseResolverWorkspace;
  heavyWorkspace?: CaseResolverWorkspace;
  hasStoreWorkspace: boolean;
  hasNavigationWorkspace?: boolean;
  hasHeavyWorkspace?: boolean;
  requestedFileId: string | null;
}): CaseResolverWorkspaceHydrationSourceSelection => {
  const context = buildPreferredCaseResolverWorkspaceSelectionContext({
    storeWorkspace,
    navigationWorkspace,
    hasStoreWorkspace,
    hasNavigationWorkspace,
    requestedFileId,
  });

  return (
    resolveStorePreferredWorkspaceSelection(context) ??
    resolveNavigationOnlyWorkspaceSelection(context) ??
    buildHydrationSourceSelection(storeWorkspace, 'none', 'no_workspace_source')
  );
};

import { buildFileEditDraft } from '@/features/case-resolver/utils/caseResolverUtils';
import type { CaseResolverFile, CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverRequestedCaseStatus } from '@/shared/contracts/case-resolver/base';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { createCaseResolverFile } from '../settings';
import { buildCaseResolverFileComparableFingerprint } from './useCaseResolverState.helpers.canonical';
import type {
  CaseResolverWorkspaceUpdateOptions,
  UseCaseResolverWorkspaceMutationsValue,
} from './useCaseResolverState.workspace-mutations';

export type { CaseResolverRequestedCaseStatus };

export const isCaseResolverCreateContextReady = ({
  activeCaseId,
  requestedFileId,
  requestedCaseStatus,
}: {
  activeCaseId: string | null;
  requestedFileId: string | null;
  requestedCaseStatus: CaseResolverRequestedCaseStatus;
}): boolean => {
  if (!activeCaseId) return false;
  if (!requestedFileId) return true;
  return requestedCaseStatus === 'ready';
};

const normalizeCaseResolverFileId = (value: string | null | undefined): string =>
  typeof value === 'string' ? value.trim() : '';

const idsMatchByNormalization = (
  left: string | null | undefined,
  right: string | null | undefined
): boolean => {
  const normalizedLeft = normalizeCaseResolverFileId(left);
  const normalizedRight = normalizeCaseResolverFileId(right);
  return Boolean(normalizedLeft && normalizedRight && normalizedLeft === normalizedRight);
};

export const resolveCaseResolverFileById = (
  files: CaseResolverWorkspace['files'],
  candidateId: string | null | undefined
): CaseResolverFile | null => {
  const normalizedCandidateId = normalizeCaseResolverFileId(candidateId);
  if (!normalizedCandidateId) return null;
  return (
    files.find((file: CaseResolverFile): boolean => file.id === candidateId) ??
    files.find(
      (file: CaseResolverFile): boolean =>
        normalizeCaseResolverFileId(file.id) === normalizedCandidateId
    ) ??
    null
  );
};

export type CaseResolverCaptureTargetResolution =
  | 'proposal_target'
  | 'context_target'
  | 'editing_draft'
  | 'unresolved';

export const resolveCaptureTargetFile = ({
  workspaceFiles,
  proposalTargetFileId,
  contextFileId = null,
  editingDraftFileId = null,
}: {
  workspaceFiles: CaseResolverWorkspace['files'];
  proposalTargetFileId: string | null | undefined;
  contextFileId?: string | null;
  editingDraftFileId?: string | null;
}): {
  file: CaseResolverFile | null;
  resolution: CaseResolverCaptureTargetResolution;
  resolvedTargetFileId: string | null;
} => {
  const proposalTarget = resolveCaseResolverFileById(workspaceFiles, proposalTargetFileId);
  if (proposalTarget) {
    return {
      file: proposalTarget,
      resolution: 'proposal_target',
      resolvedTargetFileId: proposalTarget.id,
    };
  }

  const contextTarget = resolveCaseResolverFileById(workspaceFiles, contextFileId);
  if (contextTarget) {
    return {
      file: contextTarget,
      resolution: 'context_target',
      resolvedTargetFileId: contextTarget.id,
    };
  }

  const editingDraftTarget = resolveCaseResolverFileById(workspaceFiles, editingDraftFileId);
  if (editingDraftTarget) {
    return {
      file: editingDraftTarget,
      resolution: 'editing_draft',
      resolvedTargetFileId: editingDraftTarget.id,
    };
  }

  return {
    file: null,
    resolution: 'unresolved',
    resolvedTargetFileId: null,
  };
};

export type CaseResolverFileMutationStage = 'precheck' | 'mutation' | null;

type CaseResolverWorkspaceUpdater = UseCaseResolverWorkspaceMutationsValue['updateWorkspace'];

type CaseResolverEditingDraftUpdater = React.Dispatch<
  React.SetStateAction<CaseResolverFileEditDraft | null>
>;

const applyCaseResolverFilePatch = ({
  baseFile,
  patch,
}: {
  baseFile: CaseResolverFile;
  patch: Partial<CaseResolverFile>;
}): CaseResolverFile =>
  createCaseResolverFile({
    ...baseFile,
    ...patch,
    parentCaseId: patch.parentCaseId === undefined ? baseFile.parentCaseId : patch.parentCaseId,
    createdAt:
      typeof patch.createdAt === 'string'
        ? patch.createdAt
        : baseFile.createdAt || new Date().toISOString(),
    updatedAt:
      typeof patch.updatedAt === 'string'
        ? patch.updatedAt
        : typeof baseFile.updatedAt === 'string'
          ? baseFile.updatedAt
          : baseFile.createdAt || new Date().toISOString(),
  });

export const applyCaseResolverFileMutationAndRebaseDraft = ({
  fileId,
  updateWorkspace,
  setEditingDocumentDraft,
  mutate,
  source,
  persistToast,
  activateFile = false,
  skipNormalization = false,
  fallbackFileOnMissing = null,
  allowFallbackOnMissing = true,
  precheckWorkspaceFiles = null,
}: {
  fileId: string;
  updateWorkspace: CaseResolverWorkspaceUpdater;
  setEditingDocumentDraft: CaseResolverEditingDraftUpdater;
  mutate: (file: CaseResolverFile) => Partial<CaseResolverFile> | null;
  source: string;
  persistToast?: string;
  activateFile?: boolean;
  skipNormalization?: boolean;
  fallbackFileOnMissing?: CaseResolverFile | null;
  allowFallbackOnMissing?: boolean;
  precheckWorkspaceFiles?: CaseResolverWorkspace['files'] | null;
}): {
  ok: boolean;
  stage: CaseResolverFileMutationStage;
  fileFound: boolean;
  changed: boolean;
  nextFile: CaseResolverFile | null;
  resolvedTargetFileId: string | null;
} => {
  const precheckTarget = precheckWorkspaceFiles
    ? resolveCaseResolverFileById(precheckWorkspaceFiles, fileId)
    : null;
  if (precheckWorkspaceFiles && !precheckTarget) {
    return {
      ok: false,
      stage: 'precheck',
      fileFound: false,
      changed: false,
      nextFile: null,
      resolvedTargetFileId: null,
    };
  }

  let fileFound = false;
  let changed = false;
  let nextFile: CaseResolverFile | null = null;
  let resolvedTargetFileId: string | null = precheckTarget?.id ?? null;

  const mutationOptions: CaseResolverWorkspaceUpdateOptions = {
    source,
    ...(persistToast ? { persistToast } : {}),
    ...(skipNormalization ? { skipNormalization: true } : {}),
  };
  const matchesTargetFileId = (candidateId: string): boolean =>
    idsMatchByNormalization(candidateId, resolvedTargetFileId ?? fileId);

  updateWorkspace((current) => {
    let localFileFound = false;
    let localChanged = false;
    let localNextFile: CaseResolverFile | null = null;
    const mutationTarget = resolveCaseResolverFileById(
      current.files,
      resolvedTargetFileId ?? fileId
    );
    let matchedFileId: string | null = mutationTarget?.id ?? null;
    let nextFiles = current.files;

    if (mutationTarget) {
      localFileFound = true;
      const patch = mutate(mutationTarget);
      if (patch) {
        const normalizedNextFile = applyCaseResolverFilePatch({
          baseFile: mutationTarget,
          patch,
        });
        if (
          buildCaseResolverFileComparableFingerprint(mutationTarget) !==
          buildCaseResolverFileComparableFingerprint(normalizedNextFile)
        ) {
          localChanged = true;
          localNextFile = normalizedNextFile;
          nextFiles = current.files.map(
            (file: CaseResolverFile): CaseResolverFile =>
              file.id === mutationTarget.id ? normalizedNextFile : file
          );
        }
      }
    }

    if (
      !localFileFound &&
      allowFallbackOnMissing &&
      fallbackFileOnMissing &&
      matchesTargetFileId(fallbackFileOnMissing.id)
    ) {
      localFileFound = true;
      matchedFileId = fallbackFileOnMissing.id;
      const patch = mutate(fallbackFileOnMissing);
      if (patch) {
        const normalizedNextFile = applyCaseResolverFilePatch({
          baseFile: fallbackFileOnMissing,
          patch,
        });
        localChanged = true;
        localNextFile = normalizedNextFile;
        nextFiles = [...current.files, normalizedNextFile];
      }
    }

    fileFound = localFileFound;
    changed = localChanged;
    nextFile = localNextFile;
    if (matchedFileId) {
      resolvedTargetFileId = matchedFileId;
    }

    if (!localFileFound) return current;
    const activeTargetFileId = matchedFileId ?? fileId;
    const nextActiveFileId =
      activateFile && current.activeFileId !== activeTargetFileId
        ? activeTargetFileId
        : current.activeFileId;
    const activeFileChanged = nextActiveFileId !== current.activeFileId;
    if (!localChanged && !activeFileChanged) return current;
    return {
      ...current,
      activeFileId: nextActiveFileId,
      files: localChanged ? nextFiles : current.files,
    };
  }, mutationOptions);

  const nextFileSnapshot = nextFile;
  if (nextFileSnapshot !== null) {
    setEditingDocumentDraft((current: CaseResolverFileEditDraft | null) => {
      if (!current) return current;
      const currentDraft = current;
      const nextSnapshot: CaseResolverFile = nextFileSnapshot;
      if (
        currentDraft.id !== nextSnapshot.id &&
        !idsMatchByNormalization(currentDraft.id, resolvedTargetFileId ?? fileId)
      ) {
        return current;
      }
      const rebasedBase = nextSnapshot;
      const rebasedDraft = buildFileEditDraft(rebasedBase);
      return {
        ...rebasedDraft,
      };
    });
  }

  if (!fileFound) {
    return {
      ok: false,
      stage: 'mutation',
      fileFound: false,
      changed: false,
      nextFile: null,
      resolvedTargetFileId,
    };
  }

  return {
    ok: true,
    stage: null,
    fileFound,
    changed,
    nextFile,
    resolvedTargetFileId,
  };
};

import { createId } from '@/features/case-resolver/utils/caseResolverUtils';
import type { CaseResolverAssetFile, CaseResolverFile } from '@/shared/contracts/case-resolver/file';

import { normalizeFolderPath } from '../settings';

export const createPlaceholderAssetName = ({
  assets,
  folder,
  baseName,
}: {
  assets: CaseResolverAssetFile[];
  folder: string;
  baseName: string;
}): string => {
  const normalizedBase = baseName.trim() || 'Untitled Asset';
  const normalizedFolder = normalizeFolderPath(folder);
  const namesInFolder = new Set(
    assets
      .filter((asset: CaseResolverAssetFile): boolean => asset.folder === normalizedFolder)
      .map((asset: CaseResolverAssetFile): string => asset.name.trim().toLowerCase())
  );
  if (!namesInFolder.has(normalizedBase.toLowerCase())) return normalizedBase;
  let index = 2;
  while (index < 10_000) {
    const candidate = `${normalizedBase} ${index}`;
    if (!namesInFolder.has(candidate.toLowerCase())) {
      return candidate;
    }
    index += 1;
  }
  return `${normalizedBase}-${createId('dup')}`;
};

export const createUniqueCaseFileName = ({
  files,
  folder,
  baseName,
}: {
  files: CaseResolverFile[];
  folder: string;
  baseName: string;
}): string => {
  const normalizedBase = baseName.trim() || 'Untitled File';
  const normalizedFolder = normalizeFolderPath(folder);
  const namesInFolder = new Set(
    files
      .filter((file: CaseResolverFile): boolean => file.folder === normalizedFolder)
      .map((file: CaseResolverFile): string => file.name.trim().toLowerCase())
  );
  if (!namesInFolder.has(normalizedBase.toLowerCase())) return normalizedBase;
  let index = 2;
  while (index < 10_000) {
    const candidate = `${normalizedBase} ${index}`;
    if (!namesInFolder.has(candidate.toLowerCase())) {
      return candidate;
    }
    index += 1;
  }
  return `${normalizedBase}-${createId('dup')}`;
};

export type CaseResolverWorkspacePersistQueueStatus = 'idle' | 'queued' | 'saving' | 'retry_wait';

export type CaseResolverWorkspacePersistQueueState = {
  queuedSerializedWorkspace: string | null;
  queuedExpectedRevision: number | null;
  queuedMutationId: string | null;
  inFlightSerializedWorkspace: string | null;
  inFlightExpectedRevision: number | null;
  inFlightMutationId: string | null;
  conflictAutoRetryCount: number;
  retryScheduled: boolean;
};

export type BeginCaseResolverWorkspacePersistAttemptInput = {
  state: CaseResolverWorkspacePersistQueueState;
  lastPersistedSerialized: string;
  lastPersistedRevision: number;
  fallbackMutationId: string;
};

export type BeginCaseResolverWorkspacePersistAttemptResult = {
  nextState: CaseResolverWorkspacePersistQueueState;
  attempt: {
    serializedWorkspace: string;
    expectedRevision: number;
    mutationId: string;
  } | null;
};

export type CompleteCaseResolverWorkspacePersistConflictInput = {
  state: CaseResolverWorkspacePersistQueueState;
  serverRevision: number;
  maxAutoRetryCount: number;
};

export type CompleteCaseResolverWorkspacePersistConflictResult = {
  nextState: CaseResolverWorkspacePersistQueueState;
  exhausted: boolean;
  retryCount: number;
};

const normalizeRevision = (value: number | null | undefined): number =>
  Number.isFinite(value) && (value ?? 0) >= 0 ? Math.floor(value ?? 0) : 0;

export const createCaseResolverWorkspacePersistQueueState =
  (): CaseResolverWorkspacePersistQueueState => ({
    queuedSerializedWorkspace: null,
    queuedExpectedRevision: null,
    queuedMutationId: null,
    inFlightSerializedWorkspace: null,
    inFlightExpectedRevision: null,
    inFlightMutationId: null,
    conflictAutoRetryCount: 0,
    retryScheduled: false,
  });

export const resolveCaseResolverWorkspacePersistQueueStatus = (
  state: CaseResolverWorkspacePersistQueueState
): CaseResolverWorkspacePersistQueueStatus => {
  if (state.inFlightSerializedWorkspace) return 'saving';
  if (state.retryScheduled && state.queuedSerializedWorkspace) return 'retry_wait';
  if (state.queuedSerializedWorkspace) return 'queued';
  return 'idle';
};

export const enqueueCaseResolverWorkspacePersistMutation = (
  state: CaseResolverWorkspacePersistQueueState,
  input: {
    serializedWorkspace: string;
    expectedRevision: number;
    mutationId: string;
  }
): CaseResolverWorkspacePersistQueueState => ({
  ...state,
  queuedSerializedWorkspace: input.serializedWorkspace,
  queuedExpectedRevision: normalizeRevision(input.expectedRevision),
  queuedMutationId: input.mutationId.trim() || null,
  retryScheduled: false,
});

export const clearCaseResolverWorkspacePersistQueue = (
  state: CaseResolverWorkspacePersistQueueState
): CaseResolverWorkspacePersistQueueState => ({
  ...state,
  queuedSerializedWorkspace: null,
  queuedExpectedRevision: null,
  queuedMutationId: null,
  retryScheduled: false,
});

export const beginCaseResolverWorkspacePersistAttempt = ({
  state,
  lastPersistedSerialized,
  lastPersistedRevision,
  fallbackMutationId,
}: BeginCaseResolverWorkspacePersistAttemptInput): BeginCaseResolverWorkspacePersistAttemptResult => {
  if (state.inFlightSerializedWorkspace) {
    return {
      nextState: state,
      attempt: null,
    };
  }

  const queuedSerializedWorkspace = state.queuedSerializedWorkspace;
  if (!queuedSerializedWorkspace || queuedSerializedWorkspace === lastPersistedSerialized) {
    return {
      nextState: clearCaseResolverWorkspacePersistQueue({
        ...state,
        conflictAutoRetryCount: 0,
      }),
      attempt: null,
    };
  }

  const expectedRevision =
    state.queuedExpectedRevision === null
      ? normalizeRevision(lastPersistedRevision)
      : normalizeRevision(state.queuedExpectedRevision);
  const mutationId = state.queuedMutationId?.trim() || fallbackMutationId;
  return {
    nextState: {
      ...state,
      queuedSerializedWorkspace: null,
      queuedExpectedRevision: null,
      queuedMutationId: null,
      inFlightSerializedWorkspace: queuedSerializedWorkspace,
      inFlightExpectedRevision: expectedRevision,
      inFlightMutationId: mutationId,
      retryScheduled: false,
    },
    attempt: {
      serializedWorkspace: queuedSerializedWorkspace,
      expectedRevision,
      mutationId,
    },
  };
};

export const completeCaseResolverWorkspacePersistAttemptSuccess = (
  state: CaseResolverWorkspacePersistQueueState,
  input: { persistedRevision: number }
): CaseResolverWorkspacePersistQueueState => {
  const hasQueuedMutation = Boolean(state.queuedSerializedWorkspace);
  return {
    ...state,
    inFlightSerializedWorkspace: null,
    inFlightExpectedRevision: null,
    inFlightMutationId: null,
    queuedExpectedRevision: hasQueuedMutation
      ? normalizeRevision(input.persistedRevision)
      : state.queuedExpectedRevision,
    conflictAutoRetryCount: 0,
    retryScheduled: false,
  };
};

export const completeCaseResolverWorkspacePersistAttemptConflict = ({
  state,
  serverRevision,
  maxAutoRetryCount,
}: CompleteCaseResolverWorkspacePersistConflictInput): CompleteCaseResolverWorkspacePersistConflictResult => {
  const nextRetryCount = state.conflictAutoRetryCount + 1;
  const exhausted = nextRetryCount > maxAutoRetryCount;
  if (exhausted) {
    return {
      nextState: {
        ...state,
        inFlightSerializedWorkspace: null,
        inFlightExpectedRevision: null,
        inFlightMutationId: null,
        conflictAutoRetryCount: 0,
        retryScheduled: false,
      },
      exhausted: true,
      retryCount: nextRetryCount,
    };
  }

  const retrySerializedWorkspace =
    state.queuedSerializedWorkspace ?? state.inFlightSerializedWorkspace;
  const retryMutationId =
    (state.queuedMutationId?.trim() || null) ?? (state.inFlightMutationId?.trim() || null);

  return {
    nextState: {
      ...state,
      queuedSerializedWorkspace: retrySerializedWorkspace ?? null,
      queuedExpectedRevision: normalizeRevision(serverRevision),
      queuedMutationId: retryMutationId,
      inFlightSerializedWorkspace: null,
      inFlightExpectedRevision: null,
      inFlightMutationId: null,
      conflictAutoRetryCount: nextRetryCount,
      retryScheduled: true,
    },
    exhausted: false,
    retryCount: nextRetryCount,
  };
};

export const completeCaseResolverWorkspacePersistAttemptFailure = (
  state: CaseResolverWorkspacePersistQueueState
): CaseResolverWorkspacePersistQueueState => ({
  ...state,
  inFlightSerializedWorkspace: null,
  inFlightExpectedRevision: null,
  inFlightMutationId: null,
  conflictAutoRetryCount: 0,
  retryScheduled: false,
});

import type { CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const CASE_RESOLVER_EDITOR_DRAFT_STORAGE_PREFIX = 'case-resolver-editor-draft-v1';

export type StoredCaseResolverEditorDraft = {
  fileId: string;
  baseDocumentContentVersion: number;
  updatedAt: string;
  draft: Partial<CaseResolverFileEditDraft>;
};

export type WriteStoredEditorDraftResult =
  | { ok: true }
  | { ok: false; reason: 'quota' | 'storage-unavailable' };

const buildEditorDraftStorageKey = (fileId: string): string =>
  `${CASE_RESOLVER_EDITOR_DRAFT_STORAGE_PREFIX}:${fileId}`;

export const readStoredEditorDraft = (fileId: string): StoredCaseResolverEditorDraft | null => {
  if (typeof window === 'undefined') return null;
  try {
    const raw = window.localStorage.getItem(buildEditorDraftStorageKey(fileId));
    if (!raw) return null;
    const parsed = JSON.parse(raw) as StoredCaseResolverEditorDraft | null;
    if (!parsed || typeof parsed !== 'object') return null;
    if (parsed.fileId !== fileId) return null;
    if (!parsed.draft || typeof parsed.draft !== 'object') return null;
    return parsed;
  } catch (error) {
    logClientError(error);
    return null;
  }
};

const isQuotaExceededStorageError = (error: unknown): boolean => {
  if (!error || typeof error !== 'object') return false;
  const record = error as { name?: unknown; code?: unknown };
  const errorName = typeof record.name === 'string' ? record.name : '';
  const errorCode = typeof record.code === 'number' ? record.code : null;
  return (
    errorName === 'QuotaExceededError' ||
    errorName === 'NS_ERROR_DOM_QUOTA_REACHED' ||
    errorCode === 22 ||
    errorCode === 1014
  );
};

const buildStoredEditorDraftPatch = (
  draft: CaseResolverFileEditDraft,
  mode: 'primary' | 'minimal'
): Partial<CaseResolverFileEditDraft> => {
  const primaryContentPatch: Partial<CaseResolverFileEditDraft> =
    draft.editorType === 'wysiwyg'
      ? {
        documentContentHtml: draft.documentContentHtml ?? '',
      }
      : {
        documentContentMarkdown: draft.documentContentMarkdown ?? '',
      };

  const patch = Object.fromEntries(
    Object.entries({
      name: draft.name,
      folder: draft.folder,
      parentCaseId: draft.parentCaseId,
      referenceCaseIds: [...(draft.referenceCaseIds ?? [])],
      updatedAt: draft.updatedAt,
      documentDate: draft.documentDate,
      documentCity: draft.documentCity,
      isSent: draft.isSent === true,
      activeDocumentVersion: draft.activeDocumentVersion,
      editorType: draft.editorType,
      documentContentFormatVersion: draft.documentContentFormatVersion,
      documentContentVersion: draft.documentContentVersion,
      documentConversionWarnings: [...(draft.documentConversionWarnings ?? [])],
      lastContentConversionAt: draft.lastContentConversionAt,
      scanOcrModel: draft.scanOcrModel,
      scanOcrPrompt: draft.scanOcrPrompt,
      addresser: draft.addresser,
      addressee: draft.addressee,
      tagId: draft.tagId,
      caseIdentifierId: draft.caseIdentifierId,
      categoryId: draft.categoryId,
      // Persist scan slot topology only; OCR text can be very large and quickly exhaust quota.
      scanSlots: (draft.scanSlots ?? []).map((slot) => ({
        ...slot,
        ocrText: '',
      })),
    }).filter(([, value]) => value !== undefined)
  ) as Partial<CaseResolverFileEditDraft>;
  if (mode === 'minimal') return patch;
  return {
    ...patch,
    ...primaryContentPatch,
    originalDocumentContent: draft.originalDocumentContent ?? '',
    explodedDocumentContent: draft.explodedDocumentContent ?? '',
  };
};

const buildStoredEditorDraftPayload = (
  fileId: string,
  draft: CaseResolverFileEditDraft,
  mode: 'primary' | 'minimal'
): StoredCaseResolverEditorDraft => ({
  fileId,
  baseDocumentContentVersion: draft.baseDocumentContentVersion ?? 0,
  updatedAt: new Date().toISOString(),
  draft: buildStoredEditorDraftPatch(draft, mode),
});

const collectStoredEditorDraftKeys = (storage: Storage, keepKey: string): string[] => {
  const keys: string[] = [];
  for (let index = 0; index < storage.length; index += 1) {
    const entryKey = storage.key(index);
    if (!entryKey) continue;
    if (!entryKey.startsWith(`${CASE_RESOLVER_EDITOR_DRAFT_STORAGE_PREFIX}:`)) continue;
    if (entryKey === keepKey) continue;
    keys.push(entryKey);
  }
  return keys;
};

const removeStoredEditorDraftsExcept = (storage: Storage, keepKey: string): void => {
  const removableKeys = collectStoredEditorDraftKeys(storage, keepKey);
  removableKeys.forEach((entryKey) => {
    try {
      storage.removeItem(entryKey);
    } catch (error) {
      logClientError(error);

      // Ignore cleanup errors; we still attempt to persist the latest draft.
    }
  });
};

const tryWriteEditorDraftPayload = (
  storage: Storage,
  key: string,
  payload: StoredCaseResolverEditorDraft
): WriteStoredEditorDraftResult => {
  try {
    storage.setItem(key, JSON.stringify(payload));
    return { ok: true };
  } catch (error) {
    logClientError(error);
    if (isQuotaExceededStorageError(error)) {
      return { ok: false, reason: 'quota' };
    }
    return { ok: false, reason: 'storage-unavailable' };
  }
};

export const writeStoredEditorDraft = (
  fileId: string,
  draft: CaseResolverFileEditDraft
): WriteStoredEditorDraftResult => {
  if (typeof window === 'undefined') return { ok: true };
  const storage = window.localStorage;
  const key = buildEditorDraftStorageKey(fileId);

  const primaryWrite = tryWriteEditorDraftPayload(
    storage,
    key,
    buildStoredEditorDraftPayload(fileId, draft, 'primary')
  );
  if (primaryWrite.ok) return primaryWrite;

  if (primaryWrite.reason !== 'quota') return primaryWrite;
  removeStoredEditorDraftsExcept(storage, key);

  const retryPrimaryWrite = tryWriteEditorDraftPayload(
    storage,
    key,
    buildStoredEditorDraftPayload(fileId, draft, 'primary')
  );
  if (retryPrimaryWrite.ok) return retryPrimaryWrite;
  if (retryPrimaryWrite.reason !== 'quota') return retryPrimaryWrite;

  const minimalWrite = tryWriteEditorDraftPayload(
    storage,
    key,
    buildStoredEditorDraftPayload(fileId, draft, 'minimal')
  );
  if (minimalWrite.ok) return minimalWrite;
  return { ok: false, reason: 'quota' };
};

export const clearStoredEditorDraft = (fileId: string): void => {
  if (typeof window === 'undefined') return;
  try {
    window.localStorage.removeItem(buildEditorDraftStorageKey(fileId));
  } catch (error) {
    logClientError(error);

    // Ignore storage cleanup errors.
  }
};

import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverRequestedCaseIssue } from '@/shared/contracts/case-resolver/base';

const normalizeRequestedFileId = (value: string | null | undefined): string =>
  typeof value === 'string' ? value.trim() : '';

export const hasRequestedCaseFile = (
  files: CaseResolverFile[],
  requestedFileId: string | null | undefined
): boolean => {
  const normalizedRequestedFileId = normalizeRequestedFileId(requestedFileId);
  if (!normalizedRequestedFileId) return false;
  return files.some((file: CaseResolverFile): boolean => file.id === normalizedRequestedFileId);
};

export const resolveRequestedCaseIssueAfterRefresh = ({
  refreshSucceeded,
  hasRequestedFileAfterRefresh,
}: {
  refreshSucceeded: boolean;
  hasRequestedFileAfterRefresh: boolean;
}): CaseResolverRequestedCaseIssue | null => {
  if (!refreshSucceeded) return 'workspace_unavailable';
  if (hasRequestedFileAfterRefresh) return null;
  return 'requested_file_missing';
};

export const stripCaseContextQueryParams = (search: string): string => {
  const normalizedSearch = search.startsWith('?') ? search.slice(1) : search;
  const params = new URLSearchParams(normalizedSearch);
  params.delete('fileId');
  params.delete('openEditor');
  params.delete('promptExploderSessionId');
  return params.toString();
};

export const buildRequestedContextRequestKey = (
  requestedFileId: string,
  retryTick: number
): string => `${requestedFileId.trim()}|${retryTick}`;

export const shouldStartRequestedContextFetch = ({
  currentRequestKey,
  attemptedRequestKey,
  inFlightRequestKey,
  currentStatus,
}: {
  currentRequestKey: string;
  attemptedRequestKey: string | null;
  inFlightRequestKey: string | null;
  currentStatus: 'loading' | 'ready' | 'missing';
}): boolean => {
  if (!currentRequestKey.trim()) return false;
  if (attemptedRequestKey !== currentRequestKey) return true;
  if (inFlightRequestKey === currentRequestKey) return false;
  return currentStatus === 'loading';
};

export const hasValidRequestedContextInFlight = ({
  currentRequestKey,
  inFlightRequestKey,
  startedAtMs,
  nowMs,
  watchdogMs,
}: {
  currentRequestKey: string;
  inFlightRequestKey: string | null;
  startedAtMs: number | null;
  nowMs: number;
  watchdogMs: number;
}): boolean => {
  if (inFlightRequestKey !== currentRequestKey) return false;
  if (typeof startedAtMs !== 'number' || !Number.isFinite(startedAtMs)) return false;
  if (startedAtMs <= 0) return false;
  return nowMs - startedAtMs <= watchdogMs;
};

export const shouldQueueRequestedContextAutoClear = ({
  requestedFileId,
  requestedCaseStatus,
  requestedCaseIssue,
  requestKey,
  lastQueuedRequestKey,
}: {
  requestedFileId: string | null | undefined;
  requestedCaseStatus: 'loading' | 'ready' | 'missing';
  requestedCaseIssue: CaseResolverRequestedCaseIssue | null;
  requestKey: string | null | undefined;
  lastQueuedRequestKey: string | null;
}): boolean => {
  const normalizedRequestedFileId = normalizeRequestedFileId(requestedFileId);
  const normalizedRequestKey = typeof requestKey === 'string' ? requestKey.trim() : '';
  if (!normalizedRequestedFileId || !normalizedRequestKey) return false;
  if (requestedCaseStatus !== 'missing' || requestedCaseIssue !== 'requested_file_missing') {
    return false;
  }
  return normalizedRequestKey !== lastQueuedRequestKey;
};

import type { CaseResolverAssetKind, CaseResolverUploadedFile } from '@/shared/contracts/case-resolver/base';

export type { CaseResolverUploadedFile };
import { inferCaseResolverAssetKind, normalizeFolderPath } from '../settings';

export const normalizeUploadedCaseResolverFile = (
  payload: unknown,
  fallbackFile: File,
  fallbackFolder: string
): CaseResolverUploadedFile => {
  const record =
    payload && typeof payload === 'object' && !Array.isArray(payload)
      ? (payload as Record<string, unknown>)
      : {};
  const originalName =
    typeof record['originalName'] === 'string' && record['originalName'].trim().length > 0
      ? record['originalName'].trim()
      : fallbackFile.name.trim() || 'Scan';
  const filepath =
    typeof record['filepath'] === 'string' && record['filepath'].trim().length > 0
      ? record['filepath'].trim()
      : null;
  const mimetype =
    typeof record['mimetype'] === 'string' && record['mimetype'].trim().length > 0
      ? record['mimetype'].trim()
      : fallbackFile.type.trim() || null;
  const size =
    typeof record['size'] === 'number' && Number.isFinite(record['size']) && record['size'] >= 0
      ? Math.round(record['size'])
      : Number.isFinite(fallbackFile.size) && fallbackFile.size >= 0
        ? Math.round(fallbackFile.size)
        : null;
  const folder =
    typeof record['folder'] === 'string' && record['folder'].trim().length > 0
      ? record['folder'].trim()
      : fallbackFolder;
  const kind = inferCaseResolverAssetKind({
    kind: typeof record['kind'] === 'string' ? record['kind'] : null,
    mimeType: typeof record['mimetype'] === 'string' ? record['mimetype'] : fallbackFile.type,
    name:
      typeof record['originalName'] === 'string' && record['originalName'].trim().length > 0
        ? record['originalName']
        : fallbackFile.name,
  });
  return {
    id:
      typeof record['id'] === 'string' && record['id'].trim().length > 0
        ? record['id'].trim()
        : null,
    originalName,
    kind,
    filepath,
    mimetype,
    size,
    folder,
  };
};

const resolveUploadBucketForAssetKind = (
  kind: CaseResolverAssetKind
): 'images' | 'pdfs' | 'files' => {
  if (kind === 'image') return 'images';
  if (kind === 'pdf') return 'pdfs';
  return 'files';
};

export const resolveUploadBaseFolder = (folder: string, kind: CaseResolverAssetKind): string => {
  const normalizedFolder = normalizeFolderPath(folder);
  if (!normalizedFolder) return '';
  const bucket = resolveUploadBucketForAssetKind(kind);
  if (normalizedFolder === bucket) return '';
  const suffix = `/${bucket}`;
  if (normalizedFolder.endsWith(suffix)) {
    return normalizedFolder.slice(0, -suffix.length);
  }
  return normalizedFolder;
};

