import type { CaseResolverFile, CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverScanSlot } from '@/shared/contracts/case-resolver/ocr';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { Toast } from '@/shared/contracts/ui/base';
import type { SettingsStoreValue } from '@/shared/providers/SettingsStoreProvider';

import {
  CASE_RESOLVER_SETTINGS_KEY,
  DEFAULT_CASE_RESOLVER_OCR_PROMPT,
  parseCaseResolverSettings,
} from '../settings';
import {
  CASE_RESOLVER_OCR_JOB_POLL_INTERVAL_MS,
  CASE_RESOLVER_OCR_JOB_TIMEOUT_MS,
  sleep,
} from './useCaseResolverState.helpers';
import { logClientError } from '@/shared/utils/observability/client-error-logger';



export function useCaseResolverStateOcrActions({
  settingsStoreRef,
  toast,
  updateWorkspace,
  workspace,
  editingDocumentDraft,
  setEditingDocumentDraft,
  setIsUploadingScanDraftFiles,
  setUploadingScanSlotId,
  treeSaveToast,
}: {
  settingsStoreRef: React.MutableRefObject<SettingsStoreValue>;
  toast: Toast;
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: {
      persistToast?: string;
      persistNow?: boolean;
      mutationId?: string;
      source?: string;
      skipNormalization?: boolean;
    }
  ) => void;
  workspace: CaseResolverWorkspace;
  editingDocumentDraft: CaseResolverFileEditDraft | null;
  setEditingDocumentDraft: React.Dispatch<React.SetStateAction<CaseResolverFileEditDraft | null>>;
  setIsUploadingScanDraftFiles: React.Dispatch<React.SetStateAction<boolean>>;
  setUploadingScanSlotId: React.Dispatch<React.SetStateAction<string | null>>;
  treeSaveToast: string;
}) {
  const createCaseResolverOcrCorrelationId = useCallback((): string => {
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
      return `case-resolver-ocr-${crypto.randomUUID()}`;
    }
    return `case-resolver-ocr-${Math.random().toString(36).slice(2, 10)}-${Date.now()}`;
  }, []);

  const resolveRuntimeScanOcrSettings = useCallback(
    (options?: {
      modelOverride?: string | null;
      promptOverride?: string | null;
    }): { model: string; prompt: string } => {
      const runtimeCaseResolverSettings = parseCaseResolverSettings(
        settingsStoreRef.current.get(CASE_RESOLVER_SETTINGS_KEY)
      );
      const modelOverride = options?.modelOverride?.trim() ?? '';
      const promptOverride = options?.promptOverride?.trim() ?? '';
      return {
        model:
          modelOverride ||
          runtimeCaseResolverSettings.ocrModel.trim() ||
          (settingsStoreRef.current.get('openai_model') ?? '').trim(),
        prompt:
          promptOverride ||
          runtimeCaseResolverSettings.ocrPrompt.trim() ||
          DEFAULT_CASE_RESOLVER_OCR_PROMPT,
      };
    },
    [settingsStoreRef]
  );

  const enqueueImageOcrRuntimeJob = useCallback(
    async (input: {
      filepath: string;
      runtime: { model: string; prompt: string };
    }): Promise<string> => {
      const correlationId = createCaseResolverOcrCorrelationId();
      const response = await fetch('/api/case-resolver/ocr/jobs', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Correlation-Id': correlationId,
        },
        body: JSON.stringify({
          filepath: input.filepath,
          model: input.runtime.model,
          prompt: input.runtime.prompt,
          correlationId,
        }),
      });
      if (!response.ok) {
        const fallbackMessage = `Failed to queue OCR runtime job (${response.status})`;
        const errorBody = await response.text();
        throw new Error(errorBody || fallbackMessage);
      }
      const payload = (await response.json()) as {
        job?: { id?: unknown } | null;
      };
      const jobIdRaw = payload.job?.id;
      if (typeof jobIdRaw !== 'string' || jobIdRaw.trim().length === 0) {
        throw new Error('OCR runtime job id was not returned.');
      }
      return jobIdRaw.trim();
    },
    [createCaseResolverOcrCorrelationId]
  );

  const pollImageOcrRuntimeJob = useCallback(async (jobId: string): Promise<string> => {
    const startedAt = Date.now();
    while (Date.now() - startedAt <= CASE_RESOLVER_OCR_JOB_TIMEOUT_MS) {
      const response = await fetch(`/api/case-resolver/ocr/jobs/${encodeURIComponent(jobId)}`, {
        method: 'GET',
        cache: 'no-store',
      });
      if (!response.ok) {
        const fallbackMessage = `Failed to read OCR runtime job (${response.status})`;
        const errorBody = await response.text();
        throw new Error(errorBody || fallbackMessage);
      }

      const payload = (await response.json()) as {
        job?: {
          status?: unknown;
          resultText?: unknown;
          errorMessage?: unknown;
        } | null;
      };
      const status =
        typeof payload.job?.status === 'string' ? payload.job.status.trim().toLowerCase() : '';

      if (status === 'completed') {
        return typeof payload.job?.resultText === 'string' ? payload.job.resultText.trim() : '';
      }
      if (status === 'failed') {
        const errorMessage = payload.job?.errorMessage;
        throw new Error(
          typeof errorMessage === 'string' && errorMessage.trim().length > 0
            ? errorMessage.trim()
            : 'OCR runtime job failed.'
        );
      }

      await sleep(CASE_RESOLVER_OCR_JOB_POLL_INTERVAL_MS);
    }

    throw new Error('OCR runtime job timed out.');
  }, []);

  const handleRunScanFileOcr = useCallback(
    async (fileId: string): Promise<void> => {
      const targetFile = workspace.files.find(
        (file: CaseResolverFile): boolean => file.id === fileId
      );
      if (targetFile?.fileType !== 'scanfile') {
        throw new Error('Scan file no longer exists.');
      }
      if (targetFile.isLocked) {
        throw new Error('Document is locked. Unlock it before running OCR.');
      }
      const draftScanSlots =
        editingDocumentDraft?.id === fileId && editingDocumentDraft.fileType === 'scanfile'
          ? editingDocumentDraft.scanSlots
          : null;
      const scanSlotsForOcr =
        draftScanSlots && draftScanSlots.length > 0 ? draftScanSlots : targetFile.scanSlots;

      if (scanSlotsForOcr.length === 0) {
        toast('Upload at least one image or PDF to this file before running OCR.', {
          variant: 'warning',
        });
        return;
      }

      setIsUploadingScanDraftFiles(true);
      setUploadingScanSlotId('all');

      try {
        const runtime = resolveRuntimeScanOcrSettings();
        const nextSlots: CaseResolverScanSlot[] = [];
        const failedSlots: string[] = [];
        let successfulSlots = 0;

        for (let index = 0; index < scanSlotsForOcr.length; index += 1) {
          const slot = scanSlotsForOcr[index];
          if (!slot) continue;
          setUploadingScanSlotId(slot.id);
          if (!slot.filepath) {
            const missingFilepathMessage = 'Missing file path.';
            nextSlots.push({
              ...slot,
              ocrError: missingFilepathMessage,
            });
            failedSlots.push(`${slot.name || `Slot ${index + 1}`}: ${missingFilepathMessage}`);
            continue;
          }
          try {
            const runtimeJobId = await enqueueImageOcrRuntimeJob({
              filepath: slot.filepath,
              runtime,
            });
            const extractedText = await pollImageOcrRuntimeJob(runtimeJobId);
            nextSlots.push({
              ...slot,
              ocrText: extractedText,
              ocrError: null,
            });
            successfulSlots += 1;
          } catch (error: unknown) {
            logClientError(error);
            const message = error instanceof Error ? error.message : 'OCR failed';
            nextSlots.push(slot);
            failedSlots.push(`${slot.name || `Slot ${index + 1}`}: ${message}`);
            if (nextSlots.length > 0) {
              const lastIndex = nextSlots.length - 1;
              const currentSlot = nextSlots[lastIndex];
              if (currentSlot) {
                nextSlots[lastIndex] = {
                  ...currentSlot,
                  ocrError: message,
                };
              }
            }
          }
        }

        if (successfulSlots > 0) {
          let didPersistOcrResult = false;
          let ocrPersistBlockedByLock = false;
          updateWorkspace(
            (current: CaseResolverWorkspace) => {
              const now = new Date().toISOString();
              let didUpdate = false;
              const nextFiles = current.files.map((file: CaseResolverFile): CaseResolverFile => {
                if (file.id !== fileId || file.fileType !== 'scanfile') return file;
                if (file.isLocked) {
                  ocrPersistBlockedByLock = true;
                  return file;
                }
                didUpdate = true;
                const mergedText = buildCombinedOcrText(nextSlots);
                const canonicalDocument = deriveDocumentContentSync({
                  mode: 'markdown',
                  value: mergedText,
                });
                const storedDocumentContent = toStorageDocumentValue(canonicalDocument);
                const nextOriginalDocumentContent =
                  file.activeDocumentVersion === 'original'
                    ? storedDocumentContent
                    : file.originalDocumentContent;
                const nextExplodedDocumentContent =
                  file.activeDocumentVersion === 'exploded'
                    ? storedDocumentContent
                    : file.explodedDocumentContent;
                const nextContentVersion =
                  ((): number => {
                    const val = file.documentContentVersion;
                    if (typeof val === 'number') return val;
                    if (typeof val === 'string') {
                      const parsed = Number.parseInt(val, 10);
                      return Number.isNaN(parsed) ? 0 : parsed;
                    }
                    return 0;
                  })() + 1;
                return {
                  ...file,
                  scanSlots: nextSlots,
                  scanOcrModel: runtime.model,
                  scanOcrPrompt: runtime.prompt,
                  editorType: canonicalDocument.mode,
                  documentContentVersion: nextContentVersion,
                  documentContent: storedDocumentContent,
                  documentContentMarkdown: canonicalDocument.markdown,
                  documentContentHtml: canonicalDocument.html,
                  documentContentPlainText: canonicalDocument.plainText,
                  originalDocumentContent: nextOriginalDocumentContent,
                  explodedDocumentContent: nextExplodedDocumentContent,
                  documentConversionWarnings: canonicalDocument.warnings,
                  lastContentConversionAt: now,
                  updatedAt: now,
                };
              });
              didPersistOcrResult = didUpdate;
              if (!didUpdate) return current;
              return {
                ...current,
                files: nextFiles,
              };
            },
            { persistToast: treeSaveToast }
          );
          if (didPersistOcrResult) {
            setEditingDocumentDraft((current) => {
              if (current?.id !== fileId || current?.fileType !== 'scanfile') return current;
              if (current.isLocked) return current;
              const now = new Date().toISOString();
              const mergedText = buildCombinedOcrText(nextSlots);
              const canonicalDocument = deriveDocumentContentSync({
                mode: 'markdown',
                value: mergedText,
              });
              const storedDocumentContent = toStorageDocumentValue(canonicalDocument);
              const nextOriginalDocumentContent: string =
                current.activeDocumentVersion === 'original'
                  ? storedDocumentContent
                  : (current.originalDocumentContent ?? '');
              const nextExplodedDocumentContent: string =
                current.activeDocumentVersion === 'exploded'
                  ? storedDocumentContent
                  : (current.explodedDocumentContent ?? '');
              const nextBaseVersion =
                ((): number => {
                  const val = current.baseDocumentContentVersion;
                  if (typeof val === 'number') return val;
                  if (typeof val === 'string') {
                    const parsed = Number.parseInt(val, 10);
                    return Number.isNaN(parsed) ? 0 : parsed;
                  }
                  return 0;
                })() + 1;
              const nextContentVersion =
                ((): number => {
                  const val = current.documentContentVersion;
                  if (typeof val === 'number') return val;
                  if (typeof val === 'string') {
                    const parsed = Number.parseInt(val, 10);
                    return Number.isNaN(parsed) ? 0 : parsed;
                  }
                  return 0;
                })() + 1;
              return {
                ...current,
                scanSlots: nextSlots,
                scanOcrModel: runtime.model,
                scanOcrPrompt: runtime.prompt,
                editorType: canonicalDocument.mode,
                baseDocumentContentVersion: nextBaseVersion,
                documentContentVersion: nextContentVersion,
                documentContent: storedDocumentContent,
                documentContentMarkdown: canonicalDocument.markdown,
                documentContentHtml: canonicalDocument.html,
                documentContentPlainText: canonicalDocument.plainText,
                originalDocumentContent: nextOriginalDocumentContent,
                explodedDocumentContent: nextExplodedDocumentContent,
                documentConversionWarnings: canonicalDocument.warnings,
                lastContentConversionAt: now,
                updatedAt: now,
              };
            });
            toast('OCR finished.', { variant: 'success' });
          } else if (ocrPersistBlockedByLock) {
            toast('Document was locked before OCR output could be applied.', {
              variant: 'warning',
            });
          }
        }

        if (failedSlots.length > 0) {
          toast(
            failedSlots.length === 1
              ? (failedSlots[0] ?? 'OCR failed for one file.')
              : `${failedSlots.length} files failed during OCR.`,
            { variant: 'error' }
          );
        }
      } finally {
        setUploadingScanSlotId(null);
        setIsUploadingScanDraftFiles(false);
      }
    },
    [
      editingDocumentDraft,
      enqueueImageOcrRuntimeJob,
      pollImageOcrRuntimeJob,
      resolveRuntimeScanOcrSettings,
      setEditingDocumentDraft,
      setIsUploadingScanDraftFiles,
      setUploadingScanSlotId,
      toast,
      treeSaveToast,
      updateWorkspace,
      workspace.files,
    ]
  );

  return {
    handleRunScanFileOcr,
    resolveRuntimeScanOcrSettings,
    enqueueImageOcrRuntimeJob,
    pollImageOcrRuntimeJob,
  };
}

'use client';

import { useCallback, useRef, useState } from 'react';

import { safeSetTimeout, safeClearTimeout, type SafeTimerId } from '@/shared/lib/timers';

import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import { type Toast } from '@/shared/contracts/ui';
import { type SettingsStoreValue } from '@/shared/providers/SettingsStoreProvider';

import { parseCaseResolverWorkspace } from '../settings';
import {
  computeCaseResolverConflictRetryDelayMs,
  createCaseResolverWorkspaceMutationId,
  getCaseResolverWorkspaceRevision,
  logCaseResolverWorkspaceEvent,
  persistCaseResolverWorkspaceSnapshot,
} from '../workspace-persistence';
import { serializeWorkspaceForUnsavedChangesCheck } from './useCaseResolverState.helpers';
import {
  beginCaseResolverWorkspacePersistAttempt,
  clearCaseResolverWorkspacePersistQueue,
  completeCaseResolverWorkspacePersistAttemptConflict,
  completeCaseResolverWorkspacePersistAttemptFailure,
  completeCaseResolverWorkspacePersistAttemptSuccess,
  createCaseResolverWorkspacePersistQueueState,
  enqueueCaseResolverWorkspacePersistMutation,
  type CaseResolverWorkspacePersistQueueState,
} from './useCaseResolverState.helpers.persist-queue';

const CASE_RESOLVER_WORKSPACE_CONFLICT_AUTO_RETRY_LIMIT = 5;

export type WorkspaceSaveStatus = 'idle' | 'dirty' | 'saving' | 'saved' | 'conflict' | 'error';

export interface UseCaseResolverPersistenceValue {
  isWorkspaceSaving: boolean;
  workspaceSaveStatus: WorkspaceSaveStatus;
  workspaceSaveError: string | null;
  setWorkspaceSaveStatus: React.Dispatch<React.SetStateAction<WorkspaceSaveStatus>>;
  setWorkspaceSaveError: React.Dispatch<React.SetStateAction<string | null>>;
  lastPersistedValueRef: React.MutableRefObject<string>;
  lastPersistedRevisionRef: React.MutableRefObject<number>;
  pendingSaveToastRef: React.MutableRefObject<string | null>;
  queuedSerializedWorkspaceRef: React.MutableRefObject<string | null>;
  queuedExpectedRevisionRef: React.MutableRefObject<number | null>;
  queuedMutationIdRef: React.MutableRefObject<string | null>;
  conflictRetryTimerRef: React.MutableRefObject<SafeTimerId | null>;
  persistWorkspaceTimerRef: React.MutableRefObject<SafeTimerId | null>;
  persistWorkspaceInFlightRef: React.MutableRefObject<boolean>;
  workspaceConflictAutoRetryCountRef: React.MutableRefObject<number>;
  syncPersistedWorkspaceTracking: (nextWorkspace: CaseResolverWorkspace) => void;
  enqueueWorkspacePersistMutation: (input: {
    serializedWorkspace: string;
    expectedRevision: number;
    mutationId: string;
  }) => void;
  clearQueuedWorkspacePersistMutation: () => void;
  clearConflictRetryTimer: () => void;
  flushWorkspacePersist: () => void;
}


export function useCaseResolverPersistence({
  initialWorkspaceState,
  settingsStoreRef,
  toast,
  setPersistedWorkspaceSnapshot,
  setPersistedWorkspaceComparableSnapshot,
}: {
  initialWorkspaceState: CaseResolverWorkspace;
  settingsStoreRef: React.MutableRefObject<SettingsStoreValue>;
  toast: Toast;
  setPersistedWorkspaceSnapshot: (val: string) => void;
  setPersistedWorkspaceComparableSnapshot: (val: string) => void;
}): UseCaseResolverPersistenceValue {
  const [isWorkspaceSaving, setIsWorkspaceSaving] = useState(false);
  const [workspaceSaveStatus, setWorkspaceSaveStatus] = useState<WorkspaceSaveStatus>('idle');
  const [workspaceSaveError, setWorkspaceSaveError] = useState<string | null>(null);

  const lastPersistedValueRef = useRef<string>(JSON.stringify(initialWorkspaceState));
  const lastPersistedRevisionRef = useRef<number>(
    getCaseResolverWorkspaceRevision(initialWorkspaceState)
  );
  const pendingSaveToastRef = useRef<string | null>(null);
  const queuedSerializedWorkspaceRef = useRef<string | null>(null);
  const queuedExpectedRevisionRef = useRef<number | null>(null);
  const queuedMutationIdRef = useRef<string | null>(null);
  const queueStateRef = useRef<CaseResolverWorkspacePersistQueueState>(
    createCaseResolverWorkspacePersistQueueState()
  );
  const conflictRetryTimerRef = useRef<SafeTimerId | null>(null);
  const persistWorkspaceTimerRef = useRef<SafeTimerId | null>(null);
  const persistWorkspaceInFlightRef = useRef(false);
  const workspaceConflictAutoRetryCountRef = useRef(0);

  const applyQueueState = useCallback((nextState: CaseResolverWorkspacePersistQueueState): void => {
    queueStateRef.current = nextState;
    queuedSerializedWorkspaceRef.current = nextState.queuedSerializedWorkspace;
    queuedExpectedRevisionRef.current = nextState.queuedExpectedRevision;
    queuedMutationIdRef.current = nextState.queuedMutationId;
    persistWorkspaceInFlightRef.current = nextState.inFlightSerializedWorkspace !== null;
    workspaceConflictAutoRetryCountRef.current = nextState.conflictAutoRetryCount;
  }, []);

  const syncPersistedWorkspaceTracking = useCallback(
    (nextWorkspace: CaseResolverWorkspace): void => {
      const serialized = JSON.stringify(nextWorkspace);
      lastPersistedValueRef.current = serialized;
      setPersistedWorkspaceSnapshot(serialized);
      setPersistedWorkspaceComparableSnapshot(
        serializeWorkspaceForUnsavedChangesCheck(nextWorkspace)
      );
      lastPersistedRevisionRef.current = getCaseResolverWorkspaceRevision(nextWorkspace);
    },
    [setPersistedWorkspaceSnapshot, setPersistedWorkspaceComparableSnapshot]
  );

  const enqueueWorkspacePersistMutation = useCallback(
    (input: {
      serializedWorkspace: string;
      expectedRevision: number;
      mutationId: string;
    }): void => {
      applyQueueState(enqueueCaseResolverWorkspacePersistMutation(queueStateRef.current, input));
    },
    [applyQueueState]
  );

  const clearQueuedWorkspacePersistMutation = useCallback((): void => {
    applyQueueState(clearCaseResolverWorkspacePersistQueue(queueStateRef.current));
  }, [applyQueueState]);

  const clearConflictRetryTimer = useCallback((): void => {
    if (conflictRetryTimerRef.current === null) return;
    safeClearTimeout(conflictRetryTimerRef.current);
    conflictRetryTimerRef.current = null;
  }, []);

  const flushWorkspacePersist = useCallback((): void => {
    if (persistWorkspaceInFlightRef.current) return;
    clearConflictRetryTimer();

    if (settingsStoreRef.current.isFetching) {
      persistWorkspaceTimerRef.current = safeSetTimeout(() => {
        persistWorkspaceTimerRef.current = null;
        flushWorkspacePersist();
      }, 100);
      return;
    }

    const persistAttemptResult = beginCaseResolverWorkspacePersistAttempt({
      state: queueStateRef.current,
      lastPersistedSerialized: lastPersistedValueRef.current,
      lastPersistedRevision: lastPersistedRevisionRef.current,
      fallbackMutationId: createCaseResolverWorkspaceMutationId('case-resolver-workspace-manual'),
    });
    applyQueueState(persistAttemptResult.nextState);
    const persistAttempt = persistAttemptResult.attempt;
    if (!persistAttempt) {
      setIsWorkspaceSaving(false);
      setWorkspaceSaveStatus('saved');
      setWorkspaceSaveError(null);
      return;
    }
    const {
      serializedWorkspace: nextSerializedWorkspace,
      expectedRevision,
      mutationId,
    } = persistAttempt;
    const parsedWorkspaceForPersist = parseCaseResolverWorkspace(nextSerializedWorkspace);

    setIsWorkspaceSaving(true);
    setWorkspaceSaveStatus('saving');
    setWorkspaceSaveError(null);
    let shouldContinuePersistQueue = true;

    void persistCaseResolverWorkspaceSnapshot({
      workspace: parsedWorkspaceForPersist,
      expectedRevision,
      mutationId,
      source: 'case_view',
    })
      .then((result) => {
        if (result.ok) {
          clearConflictRetryTimer();
          const persistedWorkspace = result.workspace;
          syncPersistedWorkspaceTracking(persistedWorkspace);
          applyQueueState(
            completeCaseResolverWorkspacePersistAttemptSuccess(queueStateRef.current, {
              persistedRevision: getCaseResolverWorkspaceRevision(persistedWorkspace),
            })
          );
          logCaseResolverWorkspaceEvent({
            source: 'case_view',
            action: 'manual_save_success',
            mutationId,
            expectedRevision,
            workspaceRevision: getCaseResolverWorkspaceRevision(persistedWorkspace),
          });
          settingsStoreRef.current.refetch();
          if (pendingSaveToastRef.current) {
            toast(pendingSaveToastRef.current, { variant: 'success' });
            pendingSaveToastRef.current = null;
          }
          setWorkspaceSaveStatus('saved');
          setWorkspaceSaveError(null);
          return;
        }

        if (!result.ok && result.conflict) {
          const serverWorkspace = result.workspace;
          const serverRevision = getCaseResolverWorkspaceRevision(serverWorkspace);
          syncPersistedWorkspaceTracking(serverWorkspace);
          logCaseResolverWorkspaceEvent({
            source: 'case_view',
            action: 'manual_save_conflict',
            mutationId,
            expectedRevision,
            workspaceRevision: serverRevision,
          });
          const conflictResult = completeCaseResolverWorkspacePersistAttemptConflict({
            state: queueStateRef.current,
            serverRevision,
            maxAutoRetryCount: CASE_RESOLVER_WORKSPACE_CONFLICT_AUTO_RETRY_LIMIT,
          });
          applyQueueState(conflictResult.nextState);
          if (conflictResult.exhausted) {
            clearConflictRetryTimer();
            shouldContinuePersistQueue = false;
            pendingSaveToastRef.current = null;
            const retryErrorMessage =
              'Could not save Case Resolver changes because workspace kept changing. Please try again.';
            logCaseResolverWorkspaceEvent({
              source: 'case_view',
              action: 'manual_save_conflict_retry_exhausted',
              mutationId,
              expectedRevision,
              workspaceRevision: serverRevision,
              message: retryErrorMessage,
            });
            setWorkspaceSaveStatus('error');
            setWorkspaceSaveError(retryErrorMessage);
            toast(retryErrorMessage, { variant: 'error' });
            return;
          }

          const retryDelayMs = computeCaseResolverConflictRetryDelayMs(conflictResult.retryCount);
          setWorkspaceSaveStatus('saving');
          setWorkspaceSaveError(null);
          clearConflictRetryTimer();
          conflictRetryTimerRef.current = safeSetTimeout((): void => {
            conflictRetryTimerRef.current = null;
            flushWorkspacePersist();
          }, retryDelayMs);
          shouldContinuePersistQueue = false;
          logCaseResolverWorkspaceEvent({
            source: 'case_view',
            action: 'manual_save_conflict_retry',
            mutationId,
            expectedRevision: serverRevision,
            workspaceRevision: serverRevision,
            message: `Auto-retrying save after conflict (${conflictResult.retryCount}/${CASE_RESOLVER_WORKSPACE_CONFLICT_AUTO_RETRY_LIMIT}) in ${retryDelayMs}ms.`,
          });
          return;
        }

        clearConflictRetryTimer();
        applyQueueState(completeCaseResolverWorkspacePersistAttemptFailure(queueStateRef.current));
        if (pendingSaveToastRef.current) {
          pendingSaveToastRef.current = null;
        }
        shouldContinuePersistQueue = false;
        const errorMessage = result.error || 'Failed to save Case Resolver workspace.';
        logCaseResolverWorkspaceEvent({
          source: 'case_view',
          action: 'manual_save_error',
          mutationId,
          expectedRevision,
          message: errorMessage,
        });
        setWorkspaceSaveStatus('error');
        setWorkspaceSaveError(errorMessage);
        toast(errorMessage, { variant: 'error' });
      })
      .finally(() => {
        applyQueueState({
          ...queueStateRef.current,
          inFlightSerializedWorkspace: null,
          inFlightExpectedRevision: null,
          inFlightMutationId: null,
        });
        if (
          shouldContinuePersistQueue &&
          queueStateRef.current.queuedSerializedWorkspace &&
          queueStateRef.current.queuedSerializedWorkspace !== lastPersistedValueRef.current
        ) {
          flushWorkspacePersist();
          return;
        }
        setIsWorkspaceSaving(false);
      });
  }, [
    applyQueueState,
    clearConflictRetryTimer,
    settingsStoreRef,
    syncPersistedWorkspaceTracking,
    toast,
  ]);

  return {
    isWorkspaceSaving,
    workspaceSaveStatus,
    workspaceSaveError,
    setWorkspaceSaveStatus,
    setWorkspaceSaveError,
    lastPersistedValueRef,
    lastPersistedRevisionRef,
    pendingSaveToastRef,
    queuedSerializedWorkspaceRef,
    queuedExpectedRevisionRef,
    queuedMutationIdRef,
    conflictRetryTimerRef,
    persistWorkspaceTimerRef,
    persistWorkspaceInFlightRef,
    workspaceConflictAutoRetryCountRef,
    syncPersistedWorkspaceTracking,
    enqueueWorkspacePersistMutation,
    clearQueuedWorkspacePersistMutation,
    clearConflictRetryTimer,
    flushWorkspacePersist,
  };
}

'use client';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type { CaseResolverCaptureProposalState } from '@/features/case-resolver/capture/public';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverCaptureSettings } from '@/shared/contracts/case-resolver/capture';
import type { FilemakerDatabaseDto as FilemakerDatabase } from '@/shared/contracts/filemaker';
import { type Toast } from '@/shared/contracts/ui';
import {
  PROMPT_EXPLODER_APPLY_TO_STUDIO_KEY,
  PROMPT_EXPLODER_BRIDGE_STORAGE_EVENT,
} from '@/shared/lib/prompt-exploder/bridge';

import { resolveCaseResolverFileById } from './useCaseResolverState.helpers';
import {
  discardPendingCaseResolverPromptExploderPayload,
  readCaseResolverPromptExploderPayloadState,
  resolvePromptExploderPendingPayloadIdentity,
  applyPendingPromptExploderPayloadToCaseResolver,
  type CaseResolverPromptExploderApplyUiDiagnostics,
  type CaseResolverPromptExploderPayloadReadState,
  type CaseResolverPromptExploderPendingPayload,
} from './useCaseResolverState.prompt-exploder-sync';
import { logCaseResolverWorkspaceEvent } from '../workspace-persistence';
import {
  applyPromptExploderTransferLifecycleUpdate,
  type PromptExploderTransferUiStatus,
} from './prompt-exploder-transfer-lifecycle';

import type { CaseResolverFileEditDraft } from '../types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';



import {
  CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_KEY,
  CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_LIMIT,
} from './prompt-exploder/constants';
import type { UseCaseResolverPromptExploderValue } from './prompt-exploder/types';


export function useCaseResolverPromptExploder({
  workspace,
  workspaceRef,
  updateWorkspace,
  setEditingDocumentDraft,
  filemakerDatabase,
  caseResolverCaptureSettings,
  requestedFileId,
  shouldOpenEditorFromQuery,
  requestedPromptExploderSessionId,
  toast,
  flushWorkspacePersist,
}: {
  workspace: CaseResolverWorkspace;
  workspaceRef: React.MutableRefObject<CaseResolverWorkspace>;
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: {
      persistToast?: string;
      persistNow?: boolean;
      mutationId?: string;
      source?: string;
      skipNormalization?: boolean;
    }
  ) => void;
  setEditingDocumentDraft: React.Dispatch<React.SetStateAction<CaseResolverFileEditDraft | null>>;
  filemakerDatabase: FilemakerDatabase;
  caseResolverCaptureSettings: CaseResolverCaptureSettings;
  requestedFileId: string | null;
  shouldOpenEditorFromQuery: boolean;
  requestedPromptExploderSessionId: string;
  toast: Toast;
  flushWorkspacePersist: () => void;
}): UseCaseResolverPromptExploderValue {
  const [promptExploderPartyProposal, setPromptExploderPartyProposal] =
    useState<CaseResolverCaptureProposalState | null>(null);
  const [isPromptExploderPartyProposalOpen, setIsPromptExploderPartyProposalOpen] = useState(false);
  const [isApplyingPromptExploderPartyProposal, setIsApplyingPromptExploderPartyProposalState] =
    useState(false);
  const [promptExploderPayloadRefreshVersion, setPromptExploderPayloadRefreshVersion] = useState(0);
  const [promptExploderApplyDiagnostics, setPromptExploderApplyDiagnostics] =
    useState<CaseResolverPromptExploderApplyUiDiagnostics | null>(null);

  const lastPromptExploderPayloadKeyRef = useRef<string | null>(null);
  const appliedPromptExploderTransferIdsRef = useRef<Set<string>>(new Set());
  const autoApplyPromptTransferKeysRef = useRef<Set<string>>(new Set());
  const autoApplyPromptTransferInFlightKeyRef = useRef<string | null>(null);
  const isApplyingPromptExploderPartyProposalRef = useRef(isApplyingPromptExploderPartyProposal);

  const setIsApplyingPromptExploderPartyProposal = useCallback(
    (value: boolean | ((current: boolean) => boolean)): void => {
      setIsApplyingPromptExploderPartyProposalState((current) => {
        const nextValue =
          typeof value === 'function' ? (value as (current: boolean) => boolean)(current) : value;
        isApplyingPromptExploderPartyProposalRef.current = nextValue;
        return nextValue;
      });
    },
    []
  );

  const transitionPromptExploderApplyDiagnostics = useCallback(
    (input: {
      nextStatus: PromptExploderTransferUiStatus;
      reason?: string | null;
      force?: boolean;
      patch?: Partial<CaseResolverPromptExploderApplyUiDiagnostics>;
    }): void => {
      setPromptExploderApplyDiagnostics(
        (current: CaseResolverPromptExploderApplyUiDiagnostics | null) =>
          applyPromptExploderTransferLifecycleUpdate<CaseResolverPromptExploderApplyUiDiagnostics>(
            current,
            {
              nextStatus: input.nextStatus,
              reason: input.reason ?? null,
              force: input.force ?? false,
              patch: input.patch ?? {},
            }
          )
      );
    },
    []
  );

  const logPromptExploderBindingGuardrailEvent = useCallback(
    (input: {
      mode: 'manual' | 'auto';
      reason: 'document_mismatch' | 'session_mismatch';
      payload: CaseResolverPromptExploderPendingPayload;
      requestedContextFileId: string;
      requestedSessionId: string;
    }): void => {
      logCaseResolverWorkspaceEvent({
        source:
          input.mode === 'manual' ? 'prompt_exploder_apply_manual' : 'prompt_exploder_apply_auto',
        action:
          input.reason === 'document_mismatch'
            ? 'prompt_exploder_binding_block_document_mismatch'
            : 'prompt_exploder_binding_block_session_mismatch',
        message: JSON.stringify({
          reason: input.reason,
          payloadCreatedAt: input.payload.createdAt,
          payloadContextFileId: input.payload.caseResolverContext?.fileId ?? null,
          payloadSessionId: input.payload.caseResolverContext?.sessionId ?? null,
          requestedContextFileId: input.requestedContextFileId || null,
          requestedPromptExploderSessionId: input.requestedSessionId || null,
          openEditorFromQuery: shouldOpenEditorFromQuery,
        }),
      });
    },
    [shouldOpenEditorFromQuery]
  );

  const persistAppliedPromptExploderTransferIds = useCallback((): void => {
    if (typeof window === 'undefined') return;
    try {
      const payload = JSON.stringify(
        Array.from(appliedPromptExploderTransferIdsRef.current).slice(
          -CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_LIMIT
        )
      );
      window.localStorage.setItem(CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_KEY, payload);
    } catch (error) {
      logClientError(error);

      // Ignore storage persistence failures for idempotency cache.
    }
  }, []);

  const markPromptExploderTransferApplied = useCallback(
    (transferId: string | null): void => {
      const normalizedTransferId = transferId?.trim() ?? '';
      if (!normalizedTransferId) return;
      appliedPromptExploderTransferIdsRef.current.add(normalizedTransferId);
      if (
        appliedPromptExploderTransferIdsRef.current.size >
        CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_LIMIT
      ) {
        const values = Array.from(appliedPromptExploderTransferIdsRef.current);
        const trimmed = values.slice(-CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_LIMIT);
        appliedPromptExploderTransferIdsRef.current = new Set(trimmed);
      }
      persistAppliedPromptExploderTransferIds();
    },
    [persistAppliedPromptExploderTransferIds]
  );

  useEffect(() => {
    if (typeof window === 'undefined') return;
    try {
      const raw = window.localStorage.getItem(CASE_RESOLVER_APPLIED_PROMPT_TRANSFER_IDS_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw) as unknown;
      if (!Array.isArray(parsed)) return;
      const next = new Set<string>();
      parsed.forEach((entry: unknown): void => {
        if (typeof entry !== 'string') return;
        const normalized = entry.trim();
        if (!normalized) return;
        next.add(normalized);
      });
      appliedPromptExploderTransferIdsRef.current = next;
    } catch (error) {
      logClientError(error);

      // Ignore idempotency cache restoration issues.
    }
  }, []);

  const refreshPendingPromptExploderPayload = useCallback((): void => {
    setPromptExploderPayloadRefreshVersion((current) => current + 1);
  }, []);

  const promptExploderPayloadReadState = useMemo<CaseResolverPromptExploderPayloadReadState>(
    () => readCaseResolverPromptExploderPayloadState(),
    [promptExploderPayloadRefreshVersion]
  );

  const pendingPromptExploderPayload = promptExploderPayloadReadState.pendingPayload;
  const expiredPromptExploderPayload = promptExploderPayloadReadState.expiredPayload;
  const observedPromptExploderPayload =
    pendingPromptExploderPayload ?? expiredPromptExploderPayload;

  const pendingPromptExploderPayloadKey = useMemo<string | null>(() => {
    if (!pendingPromptExploderPayload) return null;
    return resolvePromptExploderPendingPayloadIdentity(pendingPromptExploderPayload);
  }, [pendingPromptExploderPayload]);

  const workspaceFileIdsSignature = useMemo(
    () => workspace.files.map((file: CaseResolverFile): string => file.id.trim()).join('|'),
    [workspace.files]
  );

  const observedPromptExploderPayloadKey = useMemo<string | null>(() => {
    if (!observedPromptExploderPayload) return null;
    return resolvePromptExploderPendingPayloadIdentity(observedPromptExploderPayload);
  }, [observedPromptExploderPayload]);

  useEffect(() => {
    if (!observedPromptExploderPayload) {
      lastPromptExploderPayloadKeyRef.current = null;
      return;
    }
    if (
      lastPromptExploderPayloadKeyRef.current === observedPromptExploderPayloadKey &&
      observedPromptExploderPayloadKey !== null
    ) {
      setPromptExploderApplyDiagnostics(
        (
          current: CaseResolverPromptExploderApplyUiDiagnostics | null
        ): CaseResolverPromptExploderApplyUiDiagnostics | null =>
          current
            ? { ...current, captureSettingsEnabled: caseResolverCaptureSettings.enabled }
            : current
      );
      return;
    }
    lastPromptExploderPayloadKeyRef.current = observedPromptExploderPayloadKey;
    const payloadContextFileId =
      observedPromptExploderPayload.caseResolverContext?.fileId?.trim() || null;
    const precheckResolvedTargetFileId =
      resolveCaseResolverFileById(workspace.files, payloadContextFileId)?.id ?? null;
    const precheckResolutionStrategy = precheckResolvedTargetFileId ? 'requested_id' : 'unresolved';
    const isExpiredPayload = Boolean(expiredPromptExploderPayload);

    const diagnostics: CaseResolverPromptExploderApplyUiDiagnostics = {
      applyAttemptId: 'pending',
      transferId: observedPromptExploderPayload.transferId?.trim() || null,
      payloadVersion:
        typeof observedPromptExploderPayload.payloadVersion === 'number' &&
        Number.isFinite(observedPromptExploderPayload.payloadVersion)
          ? Math.trunc(observedPromptExploderPayload.payloadVersion)
          : null,
      payloadChecksum: observedPromptExploderPayload.checksum?.trim() || null,
      payloadStatus: observedPromptExploderPayload.status?.trim() || null,
      payloadCreatedAt: observedPromptExploderPayload.createdAt ?? null,
      payloadKey: observedPromptExploderPayloadKey,
      requestedTargetFileId: payloadContextFileId,
      payloadContextFileId,
      fallbackTargetFileId: null,
      precheckResolvedTargetFileId,
      precheckResolutionStrategy,
      precheckWorkspaceFileCount: workspace.files.length,
      mutationResolvedTargetFileId: null,
      mutationResolutionStrategy: 'unresolved',
      mutationWorkspaceFileCount: workspace.files.length,
      resolvedTargetFileId: precheckResolvedTargetFileId,
      resolutionStrategy: precheckResolutionStrategy,
      hasPartiesPayload: Boolean(observedPromptExploderPayload.caseResolverParties),
      hasMetadataPayload: Boolean(observedPromptExploderPayload.caseResolverMetadata?.placeDate),
      captureSettingsEnabled: caseResolverCaptureSettings.enabled,
      proposalBuilt: false,
      proposalReason: caseResolverCaptureSettings.enabled
        ? observedPromptExploderPayload.caseResolverParties ||
          observedPromptExploderPayload.caseResolverMetadata?.placeDate
          ? 'proposal_builder_returned_null'
          : 'no_capture_payload'
        : 'capture_disabled',
      mutationMissingAfterPrecheck: false,
      status: isExpiredPayload ? 'expired' : 'pending',
      reason: isExpiredPayload ? 'payload_expired' : null,
      updatedAt: new Date().toISOString(),
    };
    setPromptExploderApplyDiagnostics(diagnostics);
  }, [
    caseResolverCaptureSettings.enabled,
    expiredPromptExploderPayload,
    observedPromptExploderPayload,
    observedPromptExploderPayloadKey,
    workspaceFileIdsSignature,
    workspace.files,
  ]);

  useEffect(() => {
    refreshPendingPromptExploderPayload();
  }, [refreshPendingPromptExploderPayload, requestedFileId, shouldOpenEditorFromQuery]);

  useEffect(() => {
    const refreshPayload = (): void => {
      refreshPendingPromptExploderPayload();
    };
    const handleStorage = (event: StorageEvent): void => {
      if (event.key !== PROMPT_EXPLODER_APPLY_TO_STUDIO_KEY) return;
      refreshPayload();
    };
    const handleBridgeStorageEvent = (): void => {
      refreshPayload();
    };
    const handleFocus = (): void => {
      refreshPayload();
    };
    const handlePageShow = (): void => {
      refreshPayload();
    };
    const handleVisibilityChange = (): void => {
      if (document.visibilityState !== 'visible') return;
      refreshPayload();
    };

    window.addEventListener('storage', handleStorage);
    window.addEventListener(
      PROMPT_EXPLODER_BRIDGE_STORAGE_EVENT,
      handleBridgeStorageEvent as EventListener
    );
    window.addEventListener('focus', handleFocus);
    window.addEventListener('pageshow', handlePageShow);
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return (): void => {
      window.removeEventListener('storage', handleStorage);
      window.removeEventListener(
        PROMPT_EXPLODER_BRIDGE_STORAGE_EVENT,
        handleBridgeStorageEvent as EventListener
      );
      window.removeEventListener('focus', handleFocus);
      window.removeEventListener('pageshow', handlePageShow);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [refreshPendingPromptExploderPayload]);

  const handleDiscardPendingPromptExploderPayload = useCallback((): void => {
    const discardedPayload = discardPendingCaseResolverPromptExploderPayload();
    if (!discardedPayload) {
      toast('No pending Prompt Exploder output to discard.', { variant: 'info' });
      return;
    }
    const payloadContextFileId = discardedPayload.caseResolverContext?.fileId?.trim() || null;
    const precheckResolvedTargetFileId =
      resolveCaseResolverFileById(workspace.files, payloadContextFileId)?.id ?? null;
    const precheckResolutionStrategy = precheckResolvedTargetFileId ? 'requested_id' : 'unresolved';

    setPromptExploderPartyProposal(null);
    setIsPromptExploderPartyProposalOpen(false);
    setIsApplyingPromptExploderPartyProposal(false);

    const diagnostics: CaseResolverPromptExploderApplyUiDiagnostics = {
      applyAttemptId: 'discarded',
      transferId: discardedPayload.transferId?.trim() || null,
      payloadVersion:
        typeof discardedPayload.payloadVersion === 'number' &&
        Number.isFinite(discardedPayload.payloadVersion)
          ? Math.trunc(discardedPayload.payloadVersion)
          : null,
      payloadChecksum: discardedPayload.checksum?.trim() || null,
      payloadStatus: discardedPayload.status?.trim() || null,
      payloadCreatedAt: discardedPayload.createdAt ?? null,
      payloadKey: [
        discardedPayload.createdAt,
        discardedPayload.caseResolverContext?.fileId ?? '',
        discardedPayload.prompt.length,
      ].join('|'),
      requestedTargetFileId: payloadContextFileId,
      payloadContextFileId,
      fallbackTargetFileId: null,
      precheckResolvedTargetFileId,
      precheckResolutionStrategy,
      precheckWorkspaceFileCount: workspace.files.length,
      mutationResolvedTargetFileId: null,
      mutationResolutionStrategy: 'unresolved',
      mutationWorkspaceFileCount: workspace.files.length,
      resolvedTargetFileId: precheckResolvedTargetFileId,
      resolutionStrategy: precheckResolutionStrategy,
      hasPartiesPayload: Boolean(discardedPayload.caseResolverParties),
      hasMetadataPayload: Boolean(discardedPayload.caseResolverMetadata?.placeDate),
      captureSettingsEnabled: caseResolverCaptureSettings.enabled,
      proposalBuilt: false,
      proposalReason: caseResolverCaptureSettings.enabled
        ? discardedPayload.caseResolverParties || discardedPayload.caseResolverMetadata?.placeDate
          ? 'proposal_builder_returned_null'
          : 'no_capture_payload'
        : 'capture_disabled',
      mutationMissingAfterPrecheck: false,
      status: 'discarded',
      reason: null,
      updatedAt: new Date().toISOString(),
    };
    setPromptExploderApplyDiagnostics(diagnostics);
    refreshPendingPromptExploderPayload();
    toast('Prompt Exploder output discarded.', { variant: 'info' });
  }, [
    caseResolverCaptureSettings.enabled,
    refreshPendingPromptExploderPayload,
    toast,
    workspace.files,
    setIsApplyingPromptExploderPartyProposal,
  ]);

  const handleApplyPendingPromptExploderPayload = useCallback(async (): Promise<boolean> => {
    const payload = pendingPromptExploderPayload;
    if (!payload) {
      if (expiredPromptExploderPayload) {
        transitionPromptExploderApplyDiagnostics({
          nextStatus: 'expired',
          reason: 'payload_expired',
        });
        toast(
          'Pending Prompt Exploder output expired before apply. Discard it and re-send from Prompt Exploder.',
          { variant: 'warning' }
        );
        refreshPendingPromptExploderPayload();
        return false;
      }
      toast('No pending Prompt Exploder output to apply.', { variant: 'info' });
      refreshPendingPromptExploderPayload();
      return false;
    }
    const payloadTransferId = payload.transferId?.trim() ?? '';
    if (
      payloadTransferId.length > 0 &&
      appliedPromptExploderTransferIdsRef.current.has(payloadTransferId)
    ) {
      discardPendingCaseResolverPromptExploderPayload();
      setPromptExploderApplyDiagnostics({
        applyAttemptId: 'already_applied',
        transferId: payloadTransferId,
        payloadVersion:
          typeof payload.payloadVersion === 'number' && Number.isFinite(payload.payloadVersion)
            ? Math.trunc(payload.payloadVersion)
            : null,
        payloadChecksum: payload.checksum?.trim() || null,
        payloadStatus: payload.status?.trim() || null,
        payloadCreatedAt: payload.createdAt ?? null,
        payloadKey: pendingPromptExploderPayloadKey,
        requestedTargetFileId: payload.caseResolverContext?.fileId?.trim() || null,
        payloadContextFileId: payload.caseResolverContext?.fileId?.trim() || null,
        fallbackTargetFileId: null,
        precheckResolvedTargetFileId: null,
        precheckResolutionStrategy: 'unresolved',
        precheckWorkspaceFileCount: workspaceRef.current.files.length,
        mutationResolvedTargetFileId: null,
        mutationResolutionStrategy: 'unresolved',
        mutationWorkspaceFileCount: workspaceRef.current.files.length,
        resolvedTargetFileId: null,
        resolutionStrategy: 'unresolved',
        hasPartiesPayload: Boolean(payload.caseResolverParties),
        hasMetadataPayload: Boolean(payload.caseResolverMetadata?.placeDate),
        captureSettingsEnabled: caseResolverCaptureSettings.enabled,
        proposalBuilt: false,
        proposalReason: caseResolverCaptureSettings.enabled
          ? payload.caseResolverParties || payload.caseResolverMetadata?.placeDate
            ? 'proposal_builder_returned_null'
            : 'no_capture_payload'
          : 'capture_disabled',
        mutationMissingAfterPrecheck: false,
        status: 'applied',
        reason: 'duplicate_transfer_id',
        updatedAt: new Date().toISOString(),
      });
      refreshPendingPromptExploderPayload();
      toast('This Prompt Exploder transfer was already applied. Duplicate payload was discarded.', {
        variant: 'info',
      });
      return true;
    }
    const requestedContextFileId = requestedFileId?.trim() ?? '';
    const payloadContextFileId = payload.caseResolverContext?.fileId?.trim() ?? '';
    if (
      shouldOpenEditorFromQuery &&
      requestedContextFileId.length > 0 &&
      payloadContextFileId.length > 0 &&
      payloadContextFileId !== requestedContextFileId
    ) {
      logPromptExploderBindingGuardrailEvent({
        mode: 'manual',
        reason: 'document_mismatch',
        payload,
        requestedContextFileId,
        requestedSessionId: requestedPromptExploderSessionId,
      });
      toast(
        'Pending Prompt Exploder output belongs to a different document. Reopen Prompt Exploder from this document and apply again.',
        { variant: 'warning' }
      );
      transitionPromptExploderApplyDiagnostics({
        nextStatus: 'blocked',
        reason: 'document_mismatch',
      });
      return false;
    }
    const payloadSessionId = payload.caseResolverContext?.sessionId?.trim() ?? '';
    const hasPromptSessionMismatch =
      requestedPromptExploderSessionId.length > 0 &&
      payloadSessionId !== requestedPromptExploderSessionId;
    if (hasPromptSessionMismatch) {
      logPromptExploderBindingGuardrailEvent({
        mode: 'manual',
        reason: 'session_mismatch',
        payload,
        requestedContextFileId,
        requestedSessionId: requestedPromptExploderSessionId,
      });
      toast(
        'Pending Prompt Exploder output belongs to a different editing session. Reopen Prompt Exploder from this document and apply again.',
        { variant: 'warning' }
      );
      transitionPromptExploderApplyDiagnostics({
        nextStatus: 'blocked',
        reason: 'session_mismatch',
      });
      return false;
    }

    setIsApplyingPromptExploderPartyProposal(true);
    const runApply = (workspaceFilesSnapshot: CaseResolverWorkspace['files']) =>
      applyPendingPromptExploderPayloadToCaseResolver({
        payload,
        workspaceFiles: workspaceFilesSnapshot,
        updateWorkspace,
        setEditingDocumentDraft,
        filemakerDatabase,
        caseResolverCaptureSettings,
      });
    let result: ReturnType<typeof runApply>;
    try {
      result = runApply(workspaceRef.current.files);
    } finally {
      setIsApplyingPromptExploderPartyProposal(false);
    }

    refreshPendingPromptExploderPayload();
    setPromptExploderApplyDiagnostics({
      ...result.diagnostics,
      status: result.applied ? (result.proposalState ? 'capture_review' : 'applied') : 'failed',
      reason: result.applied
        ? result.proposalState
          ? 'awaiting_capture_mapping'
          : null
        : result.reason,
      updatedAt: new Date().toISOString(),
    });

    if (!result.applied) {
      const errorMessages: Record<string, string> = {
        empty_prompt: 'Prompt Exploder output is empty. Reassemble text before applying.',
        target_file_locked:
          'Target document is locked. Unlock it in Case Resolver before applying output.',
        missing_context_file_id: 'Prompt Exploder output is missing a target document context.',
        target_missing_in_live_workspace_after_precheck:
          'Target document was resolved in precheck but is unavailable in the live workspace snapshot.',
        target_file_missing_precheck: 'Cannot resolve target document for Prompt Exploder output.',
        target_file_missing_mutation_snapshot:
          'Cannot resolve target document for Prompt Exploder output.',
      };
      toast(errorMessages[result.reason || ''] || 'No pending Prompt Exploder output to apply.', {
        variant: result.reason ? 'warning' : 'info',
      });
      return false;
    }
    markPromptExploderTransferApplied(result.diagnostics.transferId);

    if (result.proposalState) {
      setPromptExploderPartyProposal(result.proposalState);
      setIsPromptExploderPartyProposalOpen(true);
    } else {
      setPromptExploderPartyProposal(null);
      setIsPromptExploderPartyProposalOpen(false);
      if (result.diagnostics.hasPartiesPayload || result.diagnostics.hasMetadataPayload) {
        if (!result.diagnostics.captureSettingsEnabled) {
          toast('Capture data exists, but Case Resolver Capture is disabled in settings.', {
            variant: 'warning',
          });
        } else {
          toast(
            `Capture data exists, but no mapping proposal was generated (${result.diagnostics.proposalReason}).`,
            { variant: 'warning' }
          );
        }
      } else {
        toast('Applied output has no captured addresser, addressee, or document date.', {
          variant: 'info',
        });
      }
    }

    if (result.workspaceChanged) {
      queueMicrotask((): void => {
        flushWorkspacePersist();
      });
      toast('Prompt Exploder output applied to the bound document.', { variant: 'success' });
    } else {
      toast('Prompt Exploder output already matches the bound document.', { variant: 'info' });
    }
    return true;
  }, [
    caseResolverCaptureSettings,
    expiredPromptExploderPayload,
    filemakerDatabase,
    logPromptExploderBindingGuardrailEvent,
    markPromptExploderTransferApplied,
    pendingPromptExploderPayload,
    pendingPromptExploderPayloadKey,
    refreshPendingPromptExploderPayload,
    requestedFileId,
    requestedPromptExploderSessionId,
    setEditingDocumentDraft,
    shouldOpenEditorFromQuery,
    toast,
    transitionPromptExploderApplyDiagnostics,
    updateWorkspace,
    workspaceRef,
    flushWorkspacePersist,
    setIsApplyingPromptExploderPartyProposal,
  ]);

  useEffect((): void => {
    if (!shouldOpenEditorFromQuery) return;
    const payload = pendingPromptExploderPayload;
    if (!payload) return;
    const requestedContextFileId = requestedFileId?.trim() ?? '';
    const requestedSessionId = requestedPromptExploderSessionId.trim();
    if (!requestedContextFileId || !requestedSessionId) return;
    if (
      !workspace.files.some((file: CaseResolverFile): boolean => file.id === requestedContextFileId)
    ) {
      return;
    }

    const payloadTransferId = payload.transferId?.trim() || '';
    const payloadContextFileId = payload.caseResolverContext?.fileId?.trim() || '';
    const payloadSessionId = payload.caseResolverContext?.sessionId?.trim() || '';
    const autoApplyKey = [
      payloadTransferId || payload.createdAt || 'missing-transfer',
      requestedContextFileId,
      requestedSessionId,
    ].join('|');
    if (autoApplyPromptTransferKeysRef.current.has(autoApplyKey)) return;
    if (autoApplyPromptTransferInFlightKeyRef.current === autoApplyKey) return;

    if (
      payloadContextFileId !== requestedContextFileId ||
      payloadSessionId !== requestedSessionId
    ) {
      autoApplyPromptTransferKeysRef.current.add(autoApplyKey);
      logCaseResolverWorkspaceEvent({
        source: 'prompt_exploder_apply_auto',
        action: 'prompt_exploder_return_auto_apply_skipped',
        message: [
          'reason=binding_mismatch',
          `payload_file_id=${payloadContextFileId || 'none'}`,
          `requested_file_id=${requestedContextFileId}`,
          `payload_session_id=${payloadSessionId || 'none'}`,
          `requested_session_id=${requestedSessionId}`,
        ].join(' '),
      });
      return;
    }

    autoApplyPromptTransferKeysRef.current.add(autoApplyKey);
    autoApplyPromptTransferInFlightKeyRef.current = autoApplyKey;
    logCaseResolverWorkspaceEvent({
      source: 'prompt_exploder_apply_auto',
      action: 'prompt_exploder_return_auto_apply_started',
      message: [
        `transfer_id=${payloadTransferId || 'none'}`,
        `requested_file_id=${requestedContextFileId}`,
      ].join(' '),
    });

    void (async (): Promise<void> => {
      try {
        const applied = await handleApplyPendingPromptExploderPayload();
        logCaseResolverWorkspaceEvent({
          source: 'prompt_exploder_apply_auto',
          action: applied
            ? 'prompt_exploder_return_auto_apply_succeeded'
            : 'prompt_exploder_return_auto_apply_skipped',
          message: `transfer_id=${payloadTransferId || 'none'} applied=${applied ? 'true' : 'false'}`,
        });
      } finally {
        if (autoApplyPromptTransferInFlightKeyRef.current === autoApplyKey) {
          autoApplyPromptTransferInFlightKeyRef.current = null;
        }
      }
    })();
  }, [
    handleApplyPendingPromptExploderPayload,
    pendingPromptExploderPayload,
    requestedFileId,
    requestedPromptExploderSessionId,
    shouldOpenEditorFromQuery,
    workspace.files,
  ]);

  return {
    pendingPromptExploderPayload,
    promptExploderPartyProposal,
    setPromptExploderPartyProposal,
    isPromptExploderPartyProposalOpen,
    setIsPromptExploderPartyProposalOpen,
    isApplyingPromptExploderPartyProposal,
    setIsApplyingPromptExploderPartyProposal,
    promptExploderPayloadRefreshVersion,
    promptExploderApplyDiagnostics,
    setPromptExploderApplyDiagnostics,
    refreshPendingPromptExploderPayload,
    handleDiscardPendingPromptExploderPayload,
    handleApplyPendingPromptExploderPayload,
    transitionPromptExploderApplyDiagnostics,
  };
}

import {
  buildFileEditDraft,
  createCaseResolverHistorySnapshotEntry,
  createId,
} from '@/features/case-resolver/utils/caseResolverUtils';
import {
  buildCaseResolverCaptureProposalState,
  type CaseResolverCaptureProposalState,
} from '@/features/case-resolver/capture/public';
import {
  deriveDocumentContentSync,
  ensureSafeDocumentHtml,
  toStorageDocumentValue,
} from '@/shared/lib/document-editor/public';
import type { CaseResolverFile, CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import {
  clearPromptExploderApplyPayload,
  consumePromptExploderApplyPromptForCaseResolver,
  readPromptExploderApplyPayloadSnapshot,
  savePromptExploderApplyPromptForCaseResolver,
  type PromptExploderBridgePayload,
} from '@/shared/lib/prompt-exploder/bridge';

import { createCaseResolverFile } from '../settings';
import { type PromptExploderTransferUiStatus } from './prompt-exploder-transfer-lifecycle';
import {
  buildCaseResolverFileComparableFingerprint,
  CASE_RESOLVER_DOCUMENT_HISTORY_LIMIT,
} from './useCaseResolverState.helpers';
import type {
  UseCaseResolverWorkspaceMutationsValue,
} from './useCaseResolverState.workspace-mutations';

type SetEditingDocumentDraftFn = React.Dispatch<
  React.SetStateAction<CaseResolverFileEditDraft | null>
>;

type FilemakerDatabase = Parameters<typeof buildCaseResolverCaptureProposalState>[2];
type CaseResolverCaptureSettings = Parameters<typeof buildCaseResolverCaptureProposalState>[3];

const resolveDefaultProposalReason = ({
  captureSettingsEnabled,
  hasPartiesPayload,
  hasMetadataPayload,
}: {
  captureSettingsEnabled: boolean;
  hasPartiesPayload: boolean;
  hasMetadataPayload: boolean;
}): CaseResolverPromptExploderApplyProposalReason => {
  if (!captureSettingsEnabled) return 'capture_disabled';
  if (!hasPartiesPayload && !hasMetadataPayload) return 'no_capture_payload';
  return 'proposal_builder_returned_null';
};

export type CaseResolverPromptExploderPendingPayload = PromptExploderBridgePayload & {
  target: 'case-resolver';
};

export type CaseResolverPromptExploderPayloadReadState = {
  pendingPayload: CaseResolverPromptExploderPendingPayload | null;
  expiredPayload: CaseResolverPromptExploderPendingPayload | null;
  expiresAt: string | null;
};

export type CaseResolverPromptExploderApplyFailureReason =
  | 'no_payload'
  | 'empty_prompt'
  | 'missing_context_file_id'
  | 'target_file_locked'
  | 'target_file_missing_precheck'
  | 'target_file_missing_mutation_snapshot'
  | 'target_missing_in_live_workspace_after_precheck';

export type CaseResolverPromptExploderApplyProposalReason =
  | 'proposal_generated'
  | 'proposal_builder_returned_null'
  | 'no_capture_payload'
  | 'capture_disabled';

export type CaseResolverPromptExploderApplyTargetResolutionStrategy = 'requested_id' | 'unresolved';

export interface CaseResolverPromptExploderApplyDiagnostics {
  applyAttemptId: string;
  transferId: string | null;
  payloadVersion: number | null;
  payloadChecksum: string | null;
  payloadStatus: string | null;
  payloadCreatedAt: string | null;
  payloadKey: string | null;
  requestedTargetFileId: string | null;
  payloadContextFileId: string | null;
  fallbackTargetFileId: string | null;
  precheckResolvedTargetFileId: string | null;
  precheckResolutionStrategy: CaseResolverPromptExploderApplyTargetResolutionStrategy;
  precheckWorkspaceFileCount: number;
  mutationResolvedTargetFileId: string | null;
  mutationResolutionStrategy: CaseResolverPromptExploderApplyTargetResolutionStrategy;
  mutationWorkspaceFileCount: number;
  resolvedTargetFileId: string | null;
  resolutionStrategy: CaseResolverPromptExploderApplyTargetResolutionStrategy;
  hasPartiesPayload: boolean;
  hasMetadataPayload: boolean;
  captureSettingsEnabled: boolean;
  proposalBuilt: boolean;
  proposalReason: CaseResolverPromptExploderApplyProposalReason;
  mutationMissingAfterPrecheck: boolean;
}

export interface CaseResolverPromptExploderApplyUiDiagnostics extends CaseResolverPromptExploderApplyDiagnostics {
  status: PromptExploderTransferUiStatus;
  reason: string | null;
  updatedAt: string;
}

export type CaseResolverPromptExploderApplyResult =
  | {
      applied: true;
      payload: CaseResolverPromptExploderPendingPayload;
      proposalState: CaseResolverCaptureProposalState | null;
      workspaceChanged: boolean;
      diagnostics: CaseResolverPromptExploderApplyDiagnostics;
    }
  | {
      applied: false;
      payload: CaseResolverPromptExploderPendingPayload | null;
      proposalState: null;
      reason: CaseResolverPromptExploderApplyFailureReason;
      diagnostics: CaseResolverPromptExploderApplyDiagnostics;
    };

const normalizeCandidateId = (value: string | null | undefined): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

const resolvePromptExploderApplyTargetFileId = ({
  requestedTargetFileId,
  workspaceFiles,
}: {
  requestedTargetFileId: string | null;
  workspaceFiles: CaseResolverWorkspace['files'];
}): {
  resolvedTargetFileId: string | null;
  resolutionStrategy: CaseResolverPromptExploderApplyTargetResolutionStrategy;
} => {
  const fileIdByNormalizedId = new Map<string, string>();

  workspaceFiles.forEach((file) => {
    const normalizedFileId = normalizeCandidateId(file.id);
    if (normalizedFileId && !fileIdByNormalizedId.has(normalizedFileId)) {
      fileIdByNormalizedId.set(normalizedFileId, file.id);
    }
  });

  const normalizedRequestedId = normalizeCandidateId(requestedTargetFileId);
  if (normalizedRequestedId) {
    const match = fileIdByNormalizedId.get(normalizedRequestedId);
    if (match) {
      return {
        resolvedTargetFileId: match,
        resolutionStrategy: 'requested_id',
      };
    }
  }

  return {
    resolvedTargetFileId: null,
    resolutionStrategy: 'unresolved',
  };
};

const findWorkspaceFileByNormalizedId = (
  files: CaseResolverWorkspace['files'],
  candidateId: string | null
): CaseResolverFile | null => {
  const normalizedCandidateId = normalizeCandidateId(candidateId);
  if (!normalizedCandidateId) return null;
  return (
    files.find(
      (file: CaseResolverFile): boolean => normalizeCandidateId(file.id) === normalizedCandidateId
    ) ?? null
  );
};

const normalizePayloadCreatedAt = (value: string | null | undefined): string =>
  normalizeCandidateId(value) ?? 'missing-created-at';

const buildPromptExploderPayloadKey = (payload: PromptExploderBridgePayload): string =>
  payload.transferId?.trim()
    ? payload.transferId.trim()
    : [
      normalizePayloadCreatedAt(payload.createdAt),
      payload.caseResolverContext?.fileId ?? '',
      payload.prompt,
      JSON.stringify(payload.caseResolverParties ?? null),
      JSON.stringify(payload.caseResolverMetadata ?? null),
    ].join('|');

export const resolvePromptExploderPendingPayloadIdentity = (
  payload: Pick<
    PromptExploderBridgePayload,
    'transferId' | 'createdAt' | 'caseResolverContext' | 'prompt'
  >
): string =>
  [
    payload.transferId?.trim() || '',
    normalizePayloadCreatedAt(payload.createdAt),
    payload.caseResolverContext?.fileId ?? '',
    String(payload.prompt.length),
  ].join('|');

const toCaseResolverPendingPayload = (
  payload: PromptExploderBridgePayload | null
): CaseResolverPromptExploderPendingPayload | null => {
  if (payload?.target !== 'case-resolver') return null;
  return {
    ...payload,
    target: 'case-resolver',
  };
};

export const readCaseResolverPromptExploderPayloadState =
  (): CaseResolverPromptExploderPayloadReadState => {
    const snapshot = readPromptExploderApplyPayloadSnapshot();
    const payload = toCaseResolverPendingPayload(snapshot.payload);
    if (!payload) {
      return {
        pendingPayload: null,
        expiredPayload: null,
        expiresAt: snapshot.expiresAt,
      };
    }
    if (!payload.prompt.trim()) {
      return {
        pendingPayload: null,
        expiredPayload: null,
        expiresAt: snapshot.expiresAt,
      };
    }
    if (snapshot.isExpired) {
      return {
        pendingPayload: null,
        expiredPayload: payload,
        expiresAt: snapshot.expiresAt,
      };
    }
    return {
      pendingPayload: payload,
      expiredPayload: null,
      expiresAt: snapshot.expiresAt,
    };
  };

export const readPendingCaseResolverPromptExploderPayload =
  (): CaseResolverPromptExploderPendingPayload | null => {
    return readCaseResolverPromptExploderPayloadState().pendingPayload;
  };

export const discardPendingCaseResolverPromptExploderPayload =
  (): CaseResolverPromptExploderPendingPayload | null => {
    const snapshot = readPromptExploderApplyPayloadSnapshot();
    const snapshotPayload = toCaseResolverPendingPayload(snapshot.payload);
    if (snapshotPayload && snapshot.isExpired) {
      clearPromptExploderApplyPayload();
      return snapshotPayload;
    }
    const consumed = toCaseResolverPendingPayload(
      consumePromptExploderApplyPromptForCaseResolver()
    );
    if (consumed) return consumed;
    if (!snapshotPayload) return null;
    clearPromptExploderApplyPayload();
    return snapshotPayload;
  };

export const applyPendingPromptExploderPayloadToCaseResolver = ({
  payload,
  workspaceFiles,
  updateWorkspace,
  setEditingDocumentDraft,
  filemakerDatabase,
  caseResolverCaptureSettings,
}: {
  payload?: CaseResolverPromptExploderPendingPayload | null;
  workspaceFiles: CaseResolverWorkspace['files'];
  updateWorkspace: UseCaseResolverWorkspaceMutationsValue['updateWorkspace'];
  setEditingDocumentDraft: SetEditingDocumentDraftFn;
  filemakerDatabase: FilemakerDatabase;
  caseResolverCaptureSettings: CaseResolverCaptureSettings;
}): CaseResolverPromptExploderApplyResult => {
  const applyAttemptId = createId('case-prompt-apply');
  const payloadToApply = payload ?? readPendingCaseResolverPromptExploderPayload();
  const requestedTargetFileId = normalizeCandidateId(payloadToApply?.caseResolverContext?.fileId);
  const payloadContextFileId = payloadToApply?.caseResolverContext?.fileId ?? null;
  const normalizedFallbackTargetFileId: string | null = null;
  const payloadKey = payloadToApply ? buildPromptExploderPayloadKey(payloadToApply) : null;
  const payloadTransferId = payloadToApply?.transferId?.trim() || null;
  const payloadVersion =
    typeof payloadToApply?.payloadVersion === 'number' &&
    Number.isFinite(payloadToApply.payloadVersion)
      ? Math.trunc(payloadToApply.payloadVersion)
      : null;
  const payloadChecksum = payloadToApply?.checksum?.trim() || null;
  const payloadStatus = payloadToApply?.status?.trim() || null;
  const payloadCreatedAt = payloadToApply?.createdAt?.trim() || null;
  const hasPartiesPayload = Boolean(payloadToApply?.caseResolverParties);
  const hasMetadataPayload = Boolean(payloadToApply?.caseResolverMetadata?.placeDate);
  const precheckTargetResolution = resolvePromptExploderApplyTargetFileId({
    requestedTargetFileId,
    workspaceFiles,
  });
  const buildDiagnostics = (
    input: Partial<
      Pick<
        CaseResolverPromptExploderApplyDiagnostics,
        | 'precheckResolvedTargetFileId'
        | 'precheckResolutionStrategy'
        | 'precheckWorkspaceFileCount'
        | 'mutationResolvedTargetFileId'
        | 'mutationResolutionStrategy'
        | 'mutationWorkspaceFileCount'
        | 'resolvedTargetFileId'
        | 'resolutionStrategy'
        | 'proposalBuilt'
        | 'proposalReason'
        | 'mutationMissingAfterPrecheck'
      >
    >
  ): CaseResolverPromptExploderApplyDiagnostics => ({
    applyAttemptId,
    transferId: payloadTransferId,
    payloadVersion,
    payloadChecksum,
    payloadStatus,
    payloadCreatedAt,
    payloadKey,
    requestedTargetFileId,
    payloadContextFileId,
    fallbackTargetFileId: normalizedFallbackTargetFileId,
    precheckResolvedTargetFileId:
      input.precheckResolvedTargetFileId ?? precheckTargetResolution.resolvedTargetFileId ?? null,
    precheckResolutionStrategy:
      input.precheckResolutionStrategy ?? precheckTargetResolution.resolutionStrategy,
    precheckWorkspaceFileCount: input.precheckWorkspaceFileCount ?? workspaceFiles.length,
    mutationResolvedTargetFileId: input.mutationResolvedTargetFileId ?? null,
    mutationResolutionStrategy: input.mutationResolutionStrategy ?? 'unresolved',
    mutationWorkspaceFileCount: input.mutationWorkspaceFileCount ?? workspaceFiles.length,
    resolvedTargetFileId:
      input.resolvedTargetFileId ??
      input.mutationResolvedTargetFileId ??
      precheckTargetResolution.resolvedTargetFileId ??
      null,
    resolutionStrategy:
      input.resolutionStrategy ??
      input.mutationResolutionStrategy ??
      precheckTargetResolution.resolutionStrategy,
    hasPartiesPayload,
    hasMetadataPayload,
    captureSettingsEnabled: caseResolverCaptureSettings.enabled,
    proposalBuilt: input.proposalBuilt ?? false,
    proposalReason:
      input.proposalReason ??
      resolveDefaultProposalReason({
        captureSettingsEnabled: caseResolverCaptureSettings.enabled,
        hasPartiesPayload,
        hasMetadataPayload,
      }),
    mutationMissingAfterPrecheck: input.mutationMissingAfterPrecheck ?? false,
  });

  if (!payloadToApply) {
    return {
      applied: false,
      payload: null,
      proposalState: null,
      reason: 'no_payload',
      diagnostics: buildDiagnostics({}),
    };
  }

  const nextExplodedContent = payloadToApply.prompt;
  if (!nextExplodedContent.trim()) {
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: 'empty_prompt',
      diagnostics: buildDiagnostics({
        resolvedTargetFileId: precheckTargetResolution.resolvedTargetFileId,
        resolutionStrategy: precheckTargetResolution.resolutionStrategy,
      }),
    };
  }
  if (!requestedTargetFileId) {
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: 'missing_context_file_id',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: null,
        mutationResolutionStrategy: 'unresolved',
        mutationWorkspaceFileCount: workspaceFiles.length,
        resolvedTargetFileId: null,
        resolutionStrategy: 'unresolved',
      }),
    };
  }

  const now = new Date().toISOString();
  const canonicalExploded = deriveDocumentContentSync({
    mode: 'wysiwyg',
    value: ensureSafeDocumentHtml(nextExplodedContent),
  });
  const explodedStoredContent = toStorageDocumentValue(canonicalExploded);

  const buildExplodedFile = (file: CaseResolverFile): CaseResolverFile => {
    const currentSnapshot = createCaseResolverHistorySnapshotEntry({
      savedAt: now,
      documentContentVersion: file.documentContentVersion,
      activeDocumentVersion: file.activeDocumentVersion,
      editorType: file.editorType,
      documentContent: file.documentContent,
      documentContentMarkdown: file.documentContentMarkdown,
      documentContentHtml: file.documentContentHtml,
      documentContentPlainText: file.documentContentPlainText,
    });
    const nextDocumentHistory = currentSnapshot
      ? [currentSnapshot, ...file.documentHistory].slice(0, CASE_RESOLVER_DOCUMENT_HISTORY_LIMIT)
      : file.documentHistory;
    return createCaseResolverFile({
      ...file,
      originalDocumentContent: file.originalDocumentContent ?? file.documentContent,

      explodedDocumentContent: explodedStoredContent,
      activeDocumentVersion: 'exploded',
      editorType: canonicalExploded.mode,
      documentContentFormatVersion: 1,
      documentContentVersion: file.documentContentVersion + 1,
      documentContent: explodedStoredContent,
      documentContentMarkdown: canonicalExploded.markdown,
      documentContentHtml: canonicalExploded.html,
      documentContentPlainText: canonicalExploded.plainText,
      documentHistory: nextDocumentHistory,
      documentConversionWarnings: canonicalExploded.warnings,
      lastContentConversionAt: now,
      updatedAt: now,
      createdAt: file.createdAt || now,
    });
  };
  let mutationResolvedTargetFileId = precheckTargetResolution.resolvedTargetFileId;
  const mutationResolutionStrategy = precheckTargetResolution.resolutionStrategy;
  const mutationWorkspaceFileCount = workspaceFiles.length;

  if (!mutationResolvedTargetFileId) {
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: 'target_file_missing_precheck',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: null,
        mutationResolutionStrategy,
        mutationWorkspaceFileCount,
        resolvedTargetFileId: null,
        resolutionStrategy: mutationResolutionStrategy,
      }),
    };
  }

  const mutationSourceFile =
    workspaceFiles.find(
      (file: CaseResolverFile): boolean => file.id === mutationResolvedTargetFileId
    ) ?? findWorkspaceFileByNormalizedId(workspaceFiles, mutationResolvedTargetFileId);

  if (mutationSourceFile?.isLocked) {
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: 'target_file_locked',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: mutationSourceFile.id,
        mutationResolutionStrategy,
        mutationWorkspaceFileCount,
        resolvedTargetFileId: mutationSourceFile.id,
        resolutionStrategy: mutationResolutionStrategy,
      }),
    };
  }

  if (!mutationSourceFile) {
    const missingAfterPrecheck = Boolean(precheckTargetResolution.resolvedTargetFileId);
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: missingAfterPrecheck
        ? 'target_missing_in_live_workspace_after_precheck'
        : 'target_file_missing_mutation_snapshot',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: null,
        mutationResolutionStrategy: 'unresolved',
        mutationWorkspaceFileCount,
        resolvedTargetFileId: null,
        resolutionStrategy: 'unresolved',
        mutationMissingAfterPrecheck: missingAfterPrecheck,
      }),
    };
  }

  mutationResolvedTargetFileId = mutationSourceFile.id;

  const mutationNextFile = buildExplodedFile(mutationSourceFile);
  const mutationChangedFromSnapshot =
    buildCaseResolverFileComparableFingerprint(mutationSourceFile) !==
    buildCaseResolverFileComparableFingerprint(mutationNextFile);
  let liveMutationResolvedTargetFileId: string | null = null;
  let liveMutationResolutionStrategy: CaseResolverPromptExploderApplyTargetResolutionStrategy =
    'unresolved';
  let liveMutationWorkspaceFileCount = mutationWorkspaceFileCount;
  let liveMutationSourceFile: CaseResolverFile | null = null;
  let liveMutationNextFile: CaseResolverFile | null = null;
  let liveMutationChanged = false;
  let liveMutationAttempted = false;
  let liveMutationBlockedByLock = false;

  updateWorkspace(
    (current) => {
      liveMutationAttempted = true;
      const liveTargetFileId = mutationResolvedTargetFileId;
      liveMutationWorkspaceFileCount = current.files.length;
      liveMutationResolutionStrategy = liveTargetFileId ? 'requested_id' : 'unresolved';
      liveMutationResolvedTargetFileId = liveTargetFileId;
      if (!liveTargetFileId) return current;

      const existingTarget =
        current.files.find((file: CaseResolverFile): boolean => file.id === liveTargetFileId) ??
        findWorkspaceFileByNormalizedId(current.files, liveTargetFileId);
      if (!existingTarget) {
        liveMutationResolvedTargetFileId = null;
        liveMutationResolutionStrategy = 'unresolved';
        return current;
      }
      if (existingTarget.isLocked) {
        liveMutationSourceFile = existingTarget;
        liveMutationNextFile = existingTarget;
        liveMutationChanged = false;
        liveMutationBlockedByLock = true;
        return current;
      }
      liveMutationSourceFile = existingTarget;
      const candidate = buildExplodedFile(existingTarget);
      liveMutationNextFile = candidate;

      const existingTargetId = existingTarget.id;
      const fileChangedFromExisting =
        buildCaseResolverFileComparableFingerprint(existingTarget) !==
        buildCaseResolverFileComparableFingerprint(candidate);
      liveMutationChanged = fileChangedFromExisting;

      let fileChanged = false;
      let nextFiles = current.files;
      if (fileChangedFromExisting) {
        nextFiles = current.files.map(
          (file: CaseResolverFile): CaseResolverFile =>
            file.id === existingTargetId ? candidate : file
        );
        fileChanged = true;
      }

      const nextActiveFileId =
        current.activeFileId === liveTargetFileId ? current.activeFileId : liveTargetFileId;
      const activeFileChanged = nextActiveFileId !== current.activeFileId;
      if (!fileChanged && !activeFileChanged) {
        return current;
      }

      return {
        ...current,
        activeFileId: nextActiveFileId,
        files: fileChanged ? nextFiles : current.files,
      };
    },
    {
      source: 'prompt_exploder_apply_manual',
      skipNormalization: true,
    }
  );

  if (liveMutationBlockedByLock && liveMutationResolvedTargetFileId) {
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: 'target_file_locked',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: liveMutationResolvedTargetFileId,
        mutationResolutionStrategy: liveMutationResolutionStrategy,
        mutationWorkspaceFileCount: liveMutationWorkspaceFileCount,
        resolvedTargetFileId: liveMutationResolvedTargetFileId,
        resolutionStrategy: liveMutationResolutionStrategy,
      }),
    };
  }

  if (
    liveMutationAttempted &&
    (!liveMutationResolvedTargetFileId || !liveMutationSourceFile || !liveMutationNextFile)
  ) {
    const missingAfterPrecheck = Boolean(precheckTargetResolution.resolvedTargetFileId);
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: missingAfterPrecheck
        ? 'target_missing_in_live_workspace_after_precheck'
        : 'target_file_missing_mutation_snapshot',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: null,
        mutationResolutionStrategy: 'unresolved',
        mutationWorkspaceFileCount: liveMutationWorkspaceFileCount,
        resolvedTargetFileId: null,
        resolutionStrategy: 'unresolved',
        mutationMissingAfterPrecheck: missingAfterPrecheck,
      }),
    };
  }

  const effectiveMutationSourceFile = liveMutationAttempted
    ? liveMutationSourceFile
    : (liveMutationSourceFile ?? mutationSourceFile);
  const effectiveMutationNextFile = liveMutationAttempted
    ? liveMutationNextFile
    : (liveMutationNextFile ?? mutationNextFile);
  const effectiveMutationResolvedTargetFileId = liveMutationAttempted
    ? liveMutationResolvedTargetFileId
    : (liveMutationResolvedTargetFileId ?? mutationResolvedTargetFileId);
  const effectiveMutationResolutionStrategy = liveMutationAttempted
    ? liveMutationResolutionStrategy
    : liveMutationResolvedTargetFileId
      ? liveMutationResolutionStrategy
      : mutationResolutionStrategy;
  const effectiveMutationWorkspaceFileCount = liveMutationWorkspaceFileCount;

  if (
    !effectiveMutationResolvedTargetFileId ||
    !effectiveMutationSourceFile ||
    !effectiveMutationNextFile
  ) {
    const missingAfterPrecheck = Boolean(precheckTargetResolution.resolvedTargetFileId);
    return {
      applied: false,
      payload: payloadToApply,
      proposalState: null,
      reason: missingAfterPrecheck
        ? 'target_missing_in_live_workspace_after_precheck'
        : 'target_file_missing_mutation_snapshot',
      diagnostics: buildDiagnostics({
        mutationResolvedTargetFileId: null,
        mutationResolutionStrategy: 'unresolved',
        mutationWorkspaceFileCount: effectiveMutationWorkspaceFileCount,
        resolvedTargetFileId: null,
        resolutionStrategy: 'unresolved',
        mutationMissingAfterPrecheck: missingAfterPrecheck,
      }),
    };
  }

  setEditingDocumentDraft(
    (current: CaseResolverFileEditDraft | null): CaseResolverFileEditDraft | null => {
      if (current?.id !== effectiveMutationResolvedTargetFileId) return current;
      return buildFileEditDraft(effectiveMutationNextFile);
    }
  );

  const primaryProposalState = buildCaseResolverCaptureProposalState(
    payloadToApply.caseResolverParties,
    effectiveMutationNextFile.id,
    filemakerDatabase,
    caseResolverCaptureSettings,
    {
      metadata: payloadToApply.caseResolverMetadata,
      sourceText: payloadToApply.prompt,
    }
  );
  const proposalState = primaryProposalState;
  const proposalReason: CaseResolverPromptExploderApplyProposalReason = (() => {
    if (!caseResolverCaptureSettings.enabled) return 'capture_disabled';
    if (!hasPartiesPayload && !hasMetadataPayload) return 'no_capture_payload';
    if (primaryProposalState) return 'proposal_generated';
    return 'proposal_builder_returned_null';
  })();

  const consumedPayload = consumePromptExploderApplyPromptForCaseResolver();
  if (consumedPayload) {
    const consumedPayloadKey = buildPromptExploderPayloadKey(consumedPayload);
    if (consumedPayloadKey !== payloadKey) {
      savePromptExploderApplyPromptForCaseResolver(
        consumedPayload.prompt,
        consumedPayload.caseResolverContext ?? null,
        consumedPayload.caseResolverParties ?? null,
        consumedPayload.caseResolverMetadata ?? null,
        {
          transferId: consumedPayload.transferId ?? null,
          payloadVersion: consumedPayload.payloadVersion ?? null,
          createdAt: consumedPayload.createdAt ?? null,
          expiresAt: consumedPayload.expiresAt ?? null,
          checksum: consumedPayload.checksum ?? null,
          status: consumedPayload.status ?? null,
          appliedAt: consumedPayload.appliedAt ?? null,
        }
      );
    }
  }

  return {
    applied: true,
    payload: payloadToApply,
    proposalState,
    workspaceChanged: liveMutationResolvedTargetFileId
      ? liveMutationChanged
      : mutationChangedFromSnapshot,
    diagnostics: buildDiagnostics({
      mutationResolvedTargetFileId: effectiveMutationResolvedTargetFileId,
      mutationResolutionStrategy: effectiveMutationResolutionStrategy,
      mutationWorkspaceFileCount: effectiveMutationWorkspaceFileCount,
      resolvedTargetFileId: effectiveMutationResolvedTargetFileId,
      resolutionStrategy: effectiveMutationResolutionStrategy,
      proposalBuilt: Boolean(proposalState),
      proposalReason,
    }),
  };
};

'use client';

import { useCallback } from 'react';

import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import { type Toast } from '@/shared/contracts/ui';

export function useCaseResolverStateRelatedFilesActions({
  workspace,
  updateWorkspace,
  toast,
}: {
  workspace: CaseResolverWorkspace;
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: {
      persistToast?: string;
      persistNow?: boolean;
      mutationId?: string;
      source?: string;
      skipNormalization?: boolean;
    }
  ) => void;
  toast: Toast;
}) {
  const handleLinkRelatedFiles = useCallback(
    (fileIdA: string, fileIdB: string): void => {
      const normalizedFileIdA = fileIdA.trim();
      const normalizedFileIdB = fileIdB.trim();
      if (!normalizedFileIdA || !normalizedFileIdB || normalizedFileIdA === normalizedFileIdB) {
        return;
      }

      const fileA = workspace.files.find((f: CaseResolverFile) => f.id === normalizedFileIdA);
      const fileB = workspace.files.find((f: CaseResolverFile) => f.id === normalizedFileIdB);
      if (!fileA || !fileB) {
        toast('Cannot link documents because one of them no longer exists.', {
          variant: 'warning',
        });
        return;
      }
      if (fileA.fileType === 'case' || fileB.fileType === 'case') {
        toast('Only documents can be linked in this panel.', { variant: 'info' });
        return;
      }
      if (fileA.isLocked || fileB.isLocked) {
        toast('Unlock both documents before changing links.', { variant: 'warning' });
        return;
      }

      const linkInA = (fileA.relatedFileIds ?? []).includes(normalizedFileIdB);
      const linkInB = (fileB.relatedFileIds ?? []).includes(normalizedFileIdA);
      if (linkInA && linkInB) {
        toast('These documents are already linked.', { variant: 'info' });
        return;
      }
      const now = new Date().toISOString();
      updateWorkspace(
        (current) => {
          const currentFileA =
            current.files.find(
              (file: CaseResolverFile): boolean => file.id === normalizedFileIdA
            ) ?? null;
          const currentFileB =
            current.files.find(
              (file: CaseResolverFile): boolean => file.id === normalizedFileIdB
            ) ?? null;
          if (!currentFileA || !currentFileB) return current;
          if (
            currentFileA.fileType === 'case' ||
            currentFileB.fileType === 'case' ||
            currentFileA.isLocked ||
            currentFileB.isLocked
          ) {
            return current;
          }
          return {
            ...current,
            files: current.files.map((file: CaseResolverFile) => {
              if (file.id === normalizedFileIdA) {
                const existing = file.relatedFileIds ?? [];
                const next = Array.from(new Set([...existing, normalizedFileIdB])).sort(
                  (left, right) => left.localeCompare(right)
                );
                return { ...file, relatedFileIds: next, updatedAt: now };
              }
              if (file.id === normalizedFileIdB) {
                const existing = file.relatedFileIds ?? [];
                const next = Array.from(new Set([...existing, normalizedFileIdA])).sort(
                  (left, right) => left.localeCompare(right)
                );
                return { ...file, relatedFileIds: next, updatedAt: now };
              }
              return file;
            }),
          };
        },
        { persistNow: true, source: 'case_view_link_related_files' }
      );
      const nameA = fileA?.name ?? fileIdA;
      const nameB = fileB?.name ?? fileIdB;
      toast(
        linkInA || linkInB
          ? `Repaired relation link between "${nameA}" and "${nameB}".`
          : `"${nameA}" linked to "${nameB}".`,
        { variant: 'success' }
      );
    },
    [updateWorkspace, workspace.files, toast]
  );

  const handleUnlinkRelatedFile = useCallback(
    (sourceFileId: string, targetFileId: string): void => {
      const normalizedSourceFileId = sourceFileId.trim();
      const normalizedTargetFileId = targetFileId.trim();
      if (
        !normalizedSourceFileId ||
        !normalizedTargetFileId ||
        normalizedSourceFileId === normalizedTargetFileId
      ) {
        return;
      }
      const sourceFile = workspace.files.find(
        (file: CaseResolverFile) => file.id === normalizedSourceFileId
      );
      const targetFile = workspace.files.find(
        (file: CaseResolverFile) => file.id === normalizedTargetFileId
      );
      if (!sourceFile || !targetFile) {
        toast('Cannot unlink documents because one of them no longer exists.', {
          variant: 'warning',
        });
        return;
      }
      if (sourceFile.isLocked || targetFile.isLocked) {
        toast('Unlock both documents before changing links.', { variant: 'warning' });
        return;
      }
      const now = new Date().toISOString();
      updateWorkspace(
        (current) => {
          const currentSourceFile =
            current.files.find(
              (file: CaseResolverFile): boolean => file.id === normalizedSourceFileId
            ) ?? null;
          const currentTargetFile =
            current.files.find(
              (file: CaseResolverFile): boolean => file.id === normalizedTargetFileId
            ) ?? null;
          if (!currentSourceFile || !currentTargetFile) return current;
          if (currentSourceFile.isLocked || currentTargetFile.isLocked) return current;
          return {
            ...current,
            files: current.files.map((file: CaseResolverFile) => {
              if (file.id === normalizedSourceFileId || file.id === normalizedTargetFileId) {
                const otherId =
                  file.id === normalizedSourceFileId
                    ? normalizedTargetFileId
                    : normalizedSourceFileId;
                const next = (file.relatedFileIds ?? []).filter((id: string) => id !== otherId);
                return {
                  ...file,
                  relatedFileIds: next.length > 0 ? next : undefined,
                  updatedAt: now,
                };
              }
              return file;
            }),
          };
        },
        { persistNow: true, source: 'case_view_unlink_related_files' }
      );
    },
    [toast, updateWorkspace, workspace.files]
  );

  return {
    handleLinkRelatedFiles,
    handleUnlinkRelatedFile,
  };
}

'use client';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
  safeSetInterval,
  safeClearInterval,
  safeSetTimeout,
  safeClearTimeout,
} from '@/shared/lib/timers';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { CaseResolverRequestedCaseIssue, CaseResolverRequestedCaseStatus } from '@/shared/contracts/case-resolver/base';

import {
  fetchCaseResolverWorkspaceRecordDetailed,
  getCaseResolverWorkspaceRevision,
  logCaseResolverWorkspaceEvent,
} from '../workspace-persistence';
import { shouldAdoptIncomingWorkspace } from './useCaseResolverState.helpers.hydration';
import {
  buildRequestedContextRequestKey,
  hasRequestedCaseFile,
  hasValidRequestedContextInFlight,
  resolveRequestedCaseIssueAfterRefresh,
  shouldQueueRequestedContextAutoClear,
  shouldStartRequestedContextFetch,
} from './useCaseResolverState.helpers.requested-context';
import {
  reduceRequestedContextState,
  type CaseResolverRuntimeRequestedContextSlice,
  type RequestedContextEvent,
} from '../runtime';

import {
  CASE_RESOLVER_REQUESTED_CONTEXT_FETCH_ATTEMPT_TIMEOUT_MS,
  CASE_RESOLVER_REQUESTED_CONTEXT_FETCH_MAX_TOTAL_MS,
  CASE_RESOLVER_REQUESTED_CONTEXT_STORE_HYDRATION_GRACE_MS,
  CASE_RESOLVER_REQUESTED_CONTEXT_LOADING_WATCHDOG_MS,
} from './requested-context/constants';
import type { UseCaseResolverRequestedContextValue } from './requested-context/types';
import {
  mapRequestedContextRuntimeToStatus,
  createInitialRequestedContextRuntimeState,
} from './requested-context/utils';

type RequestedContextInFlightState = {
  requestKey: string;
  requestedFileId: string;
  startedAtMs: number;
};

type RequestedContextTransitionResolvedVia =
  | 'none'
  | 'auto_clear'
  | 'manual'
  | 'workspace_presence'
  | 'snapshot_fetch'
  | 'watchdog';

export function useCaseResolverStateRequestedContext({
  requestedFileId,
  workspace,
  workspaceRef,
  setWorkspace,
  isMountedRef,
  handledRequestedFileIdRef,
  syncPersistedWorkspaceTracking,
  clearQueuedWorkspacePersistMutation,
  isStoreLoading,
  isStoreFetching,
  storeWorkspaceHasRequestedFile,
  isPromptExploderReturnFlow,
}: {
  requestedFileId: string | null;
  workspace: CaseResolverWorkspace;
  workspaceRef: React.MutableRefObject<CaseResolverWorkspace>;
  setWorkspace: React.Dispatch<React.SetStateAction<CaseResolverWorkspace>>;
  isMountedRef: React.MutableRefObject<boolean>;
  handledRequestedFileIdRef: React.MutableRefObject<string | null>;
  syncPersistedWorkspaceTracking: (workspace: CaseResolverWorkspace) => void;
  clearQueuedWorkspacePersistMutation: () => void;
  isStoreLoading: boolean;
  isStoreFetching: boolean;
  storeWorkspaceHasRequestedFile: boolean;
  isPromptExploderReturnFlow: boolean;
}): UseCaseResolverRequestedContextValue {
  const initialRequestedContextRuntimeState = useMemo(
    (): CaseResolverRuntimeRequestedContextSlice =>
      createInitialRequestedContextRuntimeState(requestedFileId),
    [requestedFileId]
  );

  const [requestedCaseStatus, setRequestedCaseStatusState] =
    useState<CaseResolverRequestedCaseStatus>(
      mapRequestedContextRuntimeToStatus(initialRequestedContextRuntimeState.status)
    );
  const [requestedCaseIssue, setRequestedCaseIssueState] =
    useState<CaseResolverRequestedCaseIssue | null>(initialRequestedContextRuntimeState.issue);
  const [requestedContextRetryTick, setRequestedContextRetryTick] = useState(
    initialRequestedContextRuntimeState.retryTick
  );
  const [requestedContextAutoClearRequestKey, setRequestedContextAutoClearRequestKey] = useState<
    string | null
  >(null);

  const requestedWorkspaceRefreshFileIdRef = useRef<string | null>(null);
  const requestedWorkspaceMissingFileIdRef = useRef<string | null>(null);
  const requestedCaseStatusRef = useRef<CaseResolverRequestedCaseStatus>(
    mapRequestedContextRuntimeToStatus(initialRequestedContextRuntimeState.status)
  );
  const requestedCaseIssueRef = useRef<CaseResolverRequestedCaseIssue | null>(
    initialRequestedContextRuntimeState.issue
  );
  const requestedContextRetryTickRef = useRef<number>(
    initialRequestedContextRuntimeState.retryTick
  );
  const requestedContextRuntimeStateRef = useRef<CaseResolverRuntimeRequestedContextSlice>(
    initialRequestedContextRuntimeState
  );
  const requestedContextInFlightRef = useRef<RequestedContextInFlightState | null>(null);
  const requestedContextAttemptKeyRef = useRef<string | null>(null);
  const requestedContextStartedAtRef = useRef<number | null>(null);
  const requestedContextAutoClearRequestKeyRef = useRef<string | null>(null);
  const requestedContextLastQueuedAutoClearKeyRef = useRef<string | null>(null);
  const requestedContextStoreHydrationWaitRequestKeyRef = useRef<string | null>(null);
  const lastLoggedRequestedContextSignatureRef = useRef<string>('');

  const setRequestedCaseStatus = useCallback(
    (nextStatus: CaseResolverRequestedCaseStatus): void => {
      if (requestedCaseStatusRef.current === nextStatus) return;
      requestedCaseStatusRef.current = nextStatus;
      setRequestedCaseStatusState(nextStatus);
    },
    []
  );

  const setRequestedCaseIssue = useCallback(
    (nextIssue: CaseResolverRequestedCaseIssue | null): void => {
      if (requestedCaseIssueRef.current === nextIssue) return;
      requestedCaseIssueRef.current = nextIssue;
      setRequestedCaseIssueState(nextIssue);
    },
    []
  );

  const applyRequestedContextEvent = useCallback(
    (event: RequestedContextEvent): CaseResolverRuntimeRequestedContextSlice => {
      const nextState = reduceRequestedContextState(requestedContextRuntimeStateRef.current, event);
      requestedContextRuntimeStateRef.current = nextState;
      setRequestedCaseStatus(mapRequestedContextRuntimeToStatus(nextState.status));
      setRequestedCaseIssue(nextState.issue);
      if (requestedContextRetryTickRef.current !== nextState.retryTick) {
        requestedContextRetryTickRef.current = nextState.retryTick;
        setRequestedContextRetryTick(nextState.retryTick);
      }
      requestedContextAttemptKeyRef.current = nextState.attemptedRequestKey;
      requestedContextStartedAtRef.current = nextState.startedAtMs;
      if (!nextState.inFlightRequestKey) {
        requestedContextInFlightRef.current = null;
      } else {
        requestedContextInFlightRef.current = {
          requestKey: nextState.inFlightRequestKey,
          requestedFileId: nextState.requestedFileId ?? '',
          startedAtMs: nextState.startedAtMs ?? Date.now(),
        };
      }
      return nextState;
    },
    [setRequestedCaseIssue, setRequestedCaseStatus]
  );

  const logRequestedContextTransition = useCallback(
    (
      action: string,
      input?: {
        message?: string;
        requestKey?: string | null;
        resolvedVia?: RequestedContextTransitionResolvedVia;
      }
    ): void => {
      const message = input?.message;
      const requestKey = input?.requestKey ?? null;
      const resolvedVia = input?.resolvedVia ?? 'none';
      const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
      const signature = [
        action,
        normalizedRequestedFileId,
        requestedCaseStatusRef.current,
        requestedCaseIssueRef.current ?? 'none',
        requestKey ?? 'none',
        resolvedVia,
        requestedContextInFlightRef.current?.requestKey ?? 'none',
        requestedContextAttemptKeyRef.current ?? 'none',
        message ?? '',
      ].join('|');
      if (lastLoggedRequestedContextSignatureRef.current === signature) return;
      lastLoggedRequestedContextSignatureRef.current = signature;
      logCaseResolverWorkspaceEvent({
        source: 'case_view',
        action,
        message: [
          normalizedRequestedFileId
            ? `requested_file_id=${normalizedRequestedFileId}`
            : 'requested_file_id=<none>',
          `request_key=${requestKey ?? 'none'}`,
          `in_flight=${requestedContextInFlightRef.current?.requestKey ?? 'none'}`,
          `attempted_key=${requestedContextAttemptKeyRef.current ?? 'none'}`,
          `resolved_via=${resolvedVia}`,
          `requested_case_status=${requestedCaseStatusRef.current}`,
          `requested_case_issue=${requestedCaseIssueRef.current ?? 'none'}`,
          message ?? '',
        ]
          .filter(Boolean)
          .join(' '),
      });
    },
    [requestedFileId]
  );

  const queueRequestedContextAutoClear = useCallback(
    ({
      requestKey,
      issue,
      message,
    }: {
      requestKey: string | null;
      issue: CaseResolverRequestedCaseIssue | null;
      message: string;
    }): void => {
      const normalizedRequestKey = requestKey?.trim() ?? '';
      if (issue === 'workspace_unavailable') {
        logRequestedContextTransition('requested_context_auto_clear_suppressed_unavailable', {
          message: `${message} reason_tag=auto_clear_suppressed_unavailable`,
          requestKey: normalizedRequestKey || requestedContextAttemptKeyRef.current,
          resolvedVia: 'none',
        });
        return;
      }
      if (
        !shouldQueueRequestedContextAutoClear({
          requestedFileId,
          requestedCaseStatus: 'missing',
          requestedCaseIssue: issue,
          requestKey: normalizedRequestKey,
          lastQueuedRequestKey: requestedContextLastQueuedAutoClearKeyRef.current,
        })
      ) {
        return;
      }
      requestedContextLastQueuedAutoClearKeyRef.current = normalizedRequestKey;
      requestedContextAutoClearRequestKeyRef.current = normalizedRequestKey;
      setRequestedContextAutoClearRequestKey(normalizedRequestKey);
      logRequestedContextTransition('requested_context_auto_cleared', {
        message,
        requestKey: normalizedRequestKey,
        resolvedVia: 'auto_clear',
      });
    },
    [logRequestedContextTransition, requestedFileId]
  );

  const handleAcknowledgeRequestedContextAutoClear = useCallback(
    (requestKey: string | null): void => {
      const normalizedRequestKey =
        requestKey?.trim() ?? requestedContextAutoClearRequestKeyRef.current?.trim() ?? '';
      if (!normalizedRequestKey) return;
      requestedContextLastQueuedAutoClearKeyRef.current = normalizedRequestKey;
      if (requestedContextAutoClearRequestKeyRef.current === normalizedRequestKey) {
        requestedContextAutoClearRequestKeyRef.current = null;
      }
      setRequestedContextAutoClearRequestKey((current: string | null): string | null =>
        current === normalizedRequestKey ? null : current
      );
    },
    []
  );

  const resetTransientRefs = useCallback((): void => {
    requestedWorkspaceRefreshFileIdRef.current = null;
    requestedWorkspaceMissingFileIdRef.current = null;
    requestedContextInFlightRef.current = null;
    requestedContextAttemptKeyRef.current = null;
    requestedContextStartedAtRef.current = null;
    requestedContextAutoClearRequestKeyRef.current = null;
    requestedContextLastQueuedAutoClearKeyRef.current = null;
    requestedContextStoreHydrationWaitRequestKeyRef.current = null;
    handledRequestedFileIdRef.current = null;
    setRequestedContextAutoClearRequestKey(null);
  }, [handledRequestedFileIdRef]);

  const handleRetryCaseContext = useCallback((): void => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) {
      applyRequestedContextEvent({
        type: 'query_changed',
        requestedFileId: null,
      });
      return;
    }
    const nextRequestedContextState = applyRequestedContextEvent({
      type: 'retry',
    });
    const nextRequestKey = buildRequestedContextRequestKey(
      normalizedRequestedFileId,
      nextRequestedContextState.retryTick
    );
    resetTransientRefs();
    requestedWorkspaceRefreshFileIdRef.current = normalizedRequestedFileId;
    logRequestedContextTransition('requested_context_loading', {
      message: 'Manual retry requested.',
      requestKey: nextRequestKey,
      resolvedVia: 'manual',
    });
  }, [
    applyRequestedContextEvent,
    logRequestedContextTransition,
    requestedFileId,
    resetTransientRefs,
  ]);

  const resetRequestedContextState = useCallback((): void => {
    resetTransientRefs();
    applyRequestedContextEvent({ type: 'reset' });
    logRequestedContextTransition('requested_context_reset', {
      message: 'Case context reset requested.',
      resolvedVia: 'manual',
    });
  }, [applyRequestedContextEvent, logRequestedContextTransition, resetTransientRefs]);

  useEffect((): void => {
    applyRequestedContextEvent({
      type: 'query_changed',
      requestedFileId,
    });
  }, [applyRequestedContextEvent, requestedFileId]);

  useEffect(() => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) {
      resetTransientRefs();
      applyRequestedContextEvent({
        type: 'query_changed',
        requestedFileId: null,
      });
      logRequestedContextTransition('requested_context_ready', {
        message: 'No requested file in query.',
        resolvedVia: 'none',
      });
      return;
    }

    const hasRequestedFileInWorkspace = hasRequestedCaseFile(
      workspace.files,
      normalizedRequestedFileId
    );
    if (!hasRequestedFileInWorkspace) return;

    if (requestedContextStoreHydrationWaitRequestKeyRef.current) {
      logRequestedContextTransition('requested_context_resolved_after_store_hydration', {
        message: 'Requested file resolved after waiting for store hydration.',
        requestKey: requestedContextStoreHydrationWaitRequestKeyRef.current,
        resolvedVia: 'workspace_presence',
      });
    }

    resetTransientRefs();
    applyRequestedContextEvent({
      type: 'workspace_contains_requested',
    });
    logRequestedContextTransition('requested_context_ready', {
      message: 'Requested file resolved in workspace.',
      resolvedVia: 'workspace_presence',
    });
  }, [
    applyRequestedContextEvent,
    logRequestedContextTransition,
    requestedFileId,
    resetTransientRefs,
    workspace.files,
  ]);

  useEffect(() => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) return;
    if (hasRequestedCaseFile(workspaceRef.current.files, normalizedRequestedFileId)) return;

    const requestKey = buildRequestedContextRequestKey(
      normalizedRequestedFileId,
      requestedContextRetryTick
    );
    const shouldStartFetch = shouldStartRequestedContextFetch({
      currentRequestKey: requestKey,
      attemptedRequestKey: requestedContextAttemptKeyRef.current,
      inFlightRequestKey: requestedContextInFlightRef.current?.requestKey ?? null,
      currentStatus: requestedCaseStatusRef.current,
    });
    if (!shouldStartFetch) return;

    const startedAtMs = Date.now();
    requestedWorkspaceRefreshFileIdRef.current = normalizedRequestedFileId;
    requestedWorkspaceMissingFileIdRef.current = null;
    handledRequestedFileIdRef.current = null;
    applyRequestedContextEvent({
      type: 'refresh_started',
      requestKey,
      startedAtMs,
    });
    logRequestedContextTransition('requested_context_loading', {
      message: 'Refreshing workspace for requested file.',
      requestKey,
      resolvedVia: 'snapshot_fetch',
    });

    void (async (): Promise<void> => {
      const refreshedWorkspaceResult = await fetchCaseResolverWorkspaceRecordDetailed(
        'case_view_requested_context_resolve',
        {
          requiredFileId: normalizedRequestedFileId,
          attemptProfile: 'context_fast',
          maxTotalMs: CASE_RESOLVER_REQUESTED_CONTEXT_FETCH_MAX_TOTAL_MS,
          attemptTimeoutMs: CASE_RESOLVER_REQUESTED_CONTEXT_FETCH_ATTEMPT_TIMEOUT_MS,
          includeDetachedHistory: true,
          includeDetachedDocuments: true,
        }
      );
      if (!isMountedRef.current) return;
      const currentInFlight = requestedContextInFlightRef.current;
      if (currentInFlight?.requestKey !== requestKey) return;

      requestedContextInFlightRef.current = null;
      requestedContextStartedAtRef.current = null;

      const latestRequestedFileId = requestedFileId?.trim() ?? '';
      if (!latestRequestedFileId || latestRequestedFileId !== normalizedRequestedFileId) {
        return;
      }

      if (
        refreshedWorkspaceResult.status === 'unavailable' ||
        refreshedWorkspaceResult.status === 'no_record'
      ) {
        if (
          refreshedWorkspaceResult.status === 'unavailable' &&
          refreshedWorkspaceResult.reason === 'budget_exhausted'
        ) {
          logRequestedContextTransition('requested_context_fetch_budget_exhausted', {
            message: `Fetch chain exhausted budget before resolving context. ${refreshedWorkspaceResult.message}`,
            requestKey,
            resolvedVia: 'snapshot_fetch',
          });
        }
        if (hasRequestedCaseFile(workspaceRef.current.files, normalizedRequestedFileId)) {
          requestedWorkspaceRefreshFileIdRef.current = null;
          requestedWorkspaceMissingFileIdRef.current = null;
          handledRequestedFileIdRef.current = null;
          applyRequestedContextEvent({
            type: 'workspace_contains_requested',
          });
          logRequestedContextTransition('requested_context_ready', {
            message:
              'Workspace refresh failed but requested file resolved from in-memory workspace.',
            requestKey,
            resolvedVia: 'workspace_presence',
          });
          return;
        }
        const shouldWaitForStoreHydration =
          requestedContextStoreHydrationWaitRequestKeyRef.current !== requestKey &&
          (isStoreLoading ||
            isStoreFetching ||
            storeWorkspaceHasRequestedFile ||
            isPromptExploderReturnFlow);
        if (shouldWaitForStoreHydration) {
          requestedContextStoreHydrationWaitRequestKeyRef.current = requestKey;
          requestedWorkspaceRefreshFileIdRef.current = normalizedRequestedFileId;
          requestedWorkspaceMissingFileIdRef.current = null;
          handledRequestedFileIdRef.current = null;
          logRequestedContextTransition('requested_context_waiting_for_store_hydration', {
            message: [
              `store_loading=${isStoreLoading ? 'true' : 'false'}`,
              `store_fetching=${isStoreFetching ? 'true' : 'false'}`,
              `store_has_requested=${storeWorkspaceHasRequestedFile ? 'true' : 'false'}`,
              `prompt_return_flow=${isPromptExploderReturnFlow ? 'true' : 'false'}`,
              `refresh_reason=${
                refreshedWorkspaceResult.status === 'unavailable'
                  ? refreshedWorkspaceResult.reason
                  : refreshedWorkspaceResult.status
              }`,
            ].join(' '),
            requestKey,
            resolvedVia: 'snapshot_fetch',
          });
          safeSetTimeout((): void => {
            if (!isMountedRef.current) return;
            if (requestedCaseStatusRef.current !== 'loading') return;
            if (requestedContextAttemptKeyRef.current !== requestKey) return;
            applyRequestedContextEvent({ type: 'retry' });
          }, CASE_RESOLVER_REQUESTED_CONTEXT_STORE_HYDRATION_GRACE_MS);
          return;
        }
        const requestedIssueAfterRefresh = resolveRequestedCaseIssueAfterRefresh({
          refreshSucceeded: false,
          hasRequestedFileAfterRefresh: false,
        });
        requestedWorkspaceMissingFileIdRef.current = normalizedRequestedFileId;
        requestedWorkspaceRefreshFileIdRef.current = null;
        handledRequestedFileIdRef.current = null;
        applyRequestedContextEvent({
          type: 'refresh_failed',
        });
        logRequestedContextTransition('requested_context_missing_fetch_failed', {
          message: 'Workspace refresh failed while resolving requested file.',
          requestKey,
          resolvedVia: 'snapshot_fetch',
        });
        queueRequestedContextAutoClear({
          requestKey,
          issue: requestedIssueAfterRefresh,
          message: `Auto-cleared stale URL context after refresh failure. ${refreshedWorkspaceResult.message}`,
        });
        return;
      }

      if (refreshedWorkspaceResult.status === 'missing_required_file') {
        requestedWorkspaceMissingFileIdRef.current = normalizedRequestedFileId;
        requestedWorkspaceRefreshFileIdRef.current = null;
        handledRequestedFileIdRef.current = null;
        applyRequestedContextEvent({
          type: 'refresh_succeeded_missing',
        });
        logRequestedContextTransition('requested_context_missing_not_found', {
          message: 'Requested file not found in refreshed workspace record.',
          requestKey,
          resolvedVia: 'snapshot_fetch',
        });
        queueRequestedContextAutoClear({
          requestKey,
          issue: 'requested_file_missing',
          message: 'Auto-cleared stale URL context after requested file was not found.',
        });
        return;
      }

      const refreshedWorkspace = refreshedWorkspaceResult.workspace;

      const refreshedHasRequestedFile = hasRequestedCaseFile(
        refreshedWorkspace.files,
        normalizedRequestedFileId
      );
      const requestedIssueAfterRefresh = resolveRequestedCaseIssueAfterRefresh({
        refreshSucceeded: true,
        hasRequestedFileAfterRefresh: refreshedHasRequestedFile,
      });

      if (requestedIssueAfterRefresh === null) {
        setWorkspace((current: CaseResolverWorkspace): CaseResolverWorkspace => {
          const hydrationDecision = shouldAdoptIncomingWorkspace({
            current,
            incoming: refreshedWorkspace,
            requestedFileId: normalizedRequestedFileId,
          });
          if (!hydrationDecision.adopt) return current;
          if (hydrationDecision.reason === 'equal_revision_current_placeholder') {
            logCaseResolverWorkspaceEvent({
              source: 'case_view_requested_context_resolve',
              action: 'refresh_equal_revision_adopted',
              workspaceRevision: getCaseResolverWorkspaceRevision(refreshedWorkspace),
              message:
                'Adopted equal-revision workspace during requested context resolve because current workspace was placeholder.',
            });
          }
          syncPersistedWorkspaceTracking(refreshedWorkspace);
          clearQueuedWorkspacePersistMutation();
          return refreshedWorkspace;
        });
        requestedWorkspaceRefreshFileIdRef.current = null;
        requestedWorkspaceMissingFileIdRef.current = null;
        handledRequestedFileIdRef.current = null;
        applyRequestedContextEvent({
          type: 'refresh_succeeded_found',
        });
        logRequestedContextTransition('requested_context_ready', {
          message: 'Requested file resolved after workspace refresh.',
          requestKey,
          resolvedVia: 'snapshot_fetch',
        });
        return;
      }

      requestedWorkspaceMissingFileIdRef.current = normalizedRequestedFileId;
      requestedWorkspaceRefreshFileIdRef.current = null;
      handledRequestedFileIdRef.current = null;
      applyRequestedContextEvent({
        type: 'refresh_succeeded_missing',
      });
      logRequestedContextTransition('requested_context_missing_not_found', {
        message: 'Requested file not found after workspace refresh.',
        requestKey,
        resolvedVia: 'snapshot_fetch',
      });
      queueRequestedContextAutoClear({
        requestKey,
        issue: requestedIssueAfterRefresh,
        message: 'Auto-cleared stale URL context after requested file was not found.',
      });
    })();
  }, [
    clearQueuedWorkspacePersistMutation,
    applyRequestedContextEvent,
    handledRequestedFileIdRef,
    isMountedRef,
    queueRequestedContextAutoClear,
    logRequestedContextTransition,
    requestedContextRetryTick,
    requestedFileId,
    setWorkspace,
    syncPersistedWorkspaceTracking,
    workspaceRef,
    isStoreFetching,
    isStoreLoading,
    storeWorkspaceHasRequestedFile,
    isPromptExploderReturnFlow,
  ]);

  useEffect(() => {
    if (requestedCaseStatus !== 'loading') return;
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) return;
    const requestKey = buildRequestedContextRequestKey(
      normalizedRequestedFileId,
      requestedContextRetryTick
    );

    const watchdogTimer = safeSetInterval((): void => {
      const currentStatus = requestedCaseStatusRef.current;
      if (currentStatus !== 'loading') return;
      const hasValidInFlightRequest = hasValidRequestedContextInFlight({
        currentRequestKey: requestKey,
        inFlightRequestKey: requestedContextInFlightRef.current?.requestKey ?? null,
        startedAtMs: requestedContextStartedAtRef.current,
        nowMs: Date.now(),
        watchdogMs: CASE_RESOLVER_REQUESTED_CONTEXT_LOADING_WATCHDOG_MS,
      });
      if (hasValidInFlightRequest) return;
      if (hasRequestedCaseFile(workspaceRef.current.files, normalizedRequestedFileId)) {
        requestedContextInFlightRef.current = null;
        requestedContextStartedAtRef.current = null;
        requestedWorkspaceRefreshFileIdRef.current = null;
        requestedWorkspaceMissingFileIdRef.current = null;
        handledRequestedFileIdRef.current = null;
        applyRequestedContextEvent({
          type: 'workspace_contains_requested',
        });
        logRequestedContextTransition('requested_context_ready', {
          message:
            'Watchdog recovered requested context from in-memory workspace before forcing missing.',
          requestKey,
          resolvedVia: 'workspace_presence',
        });
        return;
      }

      requestedContextInFlightRef.current = null;
      requestedContextStartedAtRef.current = null;
      requestedWorkspaceRefreshFileIdRef.current = null;
      requestedWorkspaceMissingFileIdRef.current = normalizedRequestedFileId;
      handledRequestedFileIdRef.current = null;
      applyRequestedContextEvent({
        type: 'watchdog_timeout',
      });
      logRequestedContextTransition('requested_context_missing_fetch_failed', {
        message: 'Loading watchdog forced missing state after stalled context load.',
        requestKey,
        resolvedVia: 'watchdog',
      });
      queueRequestedContextAutoClear({
        requestKey,
        issue: 'workspace_unavailable',
        message: 'Auto-cleared stale URL context after loading watchdog timeout.',
      });
    }, 500);

    return (): void => {
      safeClearInterval(watchdogTimer);
    };
  }, [
    applyRequestedContextEvent,
    handledRequestedFileIdRef,
    queueRequestedContextAutoClear,
    logRequestedContextTransition,
    requestedCaseStatus,
    requestedContextRetryTick,
    requestedFileId,
    workspaceRef,
  ]);

  useEffect(() => {
    if (requestedCaseStatus !== 'loading') return;
    const deadlockGuardTimer = safeSetTimeout((): void => {
      if (requestedCaseStatusRef.current !== 'loading') return;
      const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
      if (!normalizedRequestedFileId) {
        requestedWorkspaceRefreshFileIdRef.current = null;
        requestedWorkspaceMissingFileIdRef.current = null;
        requestedContextInFlightRef.current = null;
        requestedContextAttemptKeyRef.current = null;
        requestedContextStartedAtRef.current = null;
        handledRequestedFileIdRef.current = null;
        applyRequestedContextEvent({
          type: 'query_changed',
          requestedFileId: null,
        });
        logRequestedContextTransition('requested_context_ready', {
          message: 'Deadlock guard resolved loading state with no requested file.',
          resolvedVia: 'watchdog',
        });
        return;
      }
      if (hasRequestedCaseFile(workspaceRef.current.files, normalizedRequestedFileId)) {
        requestedWorkspaceRefreshFileIdRef.current = null;
        requestedWorkspaceMissingFileIdRef.current = null;
        requestedContextInFlightRef.current = null;
        requestedContextAttemptKeyRef.current = null;
        requestedContextStartedAtRef.current = null;
        handledRequestedFileIdRef.current = null;
        applyRequestedContextEvent({
          type: 'workspace_contains_requested',
        });
        logRequestedContextTransition('requested_context_ready', {
          message: 'Deadlock guard resolved loading state from workspace presence.',
          resolvedVia: 'watchdog',
        });
        return;
      }
      if (requestedContextInFlightRef.current !== null) return;
      requestedWorkspaceRefreshFileIdRef.current = null;
      requestedWorkspaceMissingFileIdRef.current = normalizedRequestedFileId;
      requestedContextStartedAtRef.current = null;
      handledRequestedFileIdRef.current = null;
      applyRequestedContextEvent({
        type: 'watchdog_timeout',
      });
      logRequestedContextTransition('requested_context_missing_fetch_failed', {
        message: 'Deadlock guard forced missing state (loading without in-flight request).',
        requestKey: requestedContextAttemptKeyRef.current,
        resolvedVia: 'watchdog',
      });
      queueRequestedContextAutoClear({
        requestKey: requestedContextAttemptKeyRef.current,
        issue: 'workspace_unavailable',
        message: 'Auto-cleared stale URL context after deadlock guard transition.',
      });
    }, 1_500);

    return (): void => {
      safeClearTimeout(deadlockGuardTimer);
    };
  }, [
    applyRequestedContextEvent,
    handledRequestedFileIdRef,
    queueRequestedContextAutoClear,
    logRequestedContextTransition,
    requestedCaseStatus,
    requestedFileId,
    workspaceRef,
  ]);

  return {
    requestedCaseStatus,
    requestedCaseIssue,
    requestedContextAutoClearRequestKey,
    setRequestedCaseStatus,
    handleAcknowledgeRequestedContextAutoClear,
    handleRetryCaseContext,
    resetRequestedContextState,
  };
}

'use client';

import { useCallback, useMemo } from 'react';

import type { CaseResolverAssetFile, CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { logCaseResolverWorkspaceEvent } from '../workspace-persistence';
import type {
  CaseResolverWorkspaceUpdateOptions,
  UseCaseResolverWorkspaceMutationsValue,
} from './useCaseResolverState.workspace-mutations';

type UseCaseResolverStateSelectionActionsInput = {
  workspace: CaseResolverWorkspace;
  selectedAssetId: string | null;
  updateWorkspace: UseCaseResolverWorkspaceMutationsValue['updateWorkspace'];
  treeSaveToast: string;
};

type UseCaseResolverStateSelectionActionsResult = {
  activeFile: CaseResolverFile | null;
  selectedAsset: CaseResolverAssetFile | null;
  handleUpdateSelectedAsset: (
    patch: Partial<Pick<CaseResolverAssetFile, 'textContent' | 'description' | 'metadata'>>,
    options?: CaseResolverWorkspaceUpdateOptions
  ) => void;
  handleUpdateActiveFileParties: (
    patch: Partial<Pick<CaseResolverFile, 'addresser' | 'addressee' | 'referenceCaseIds'>>
  ) => void;
};

export const useCaseResolverStateSelectionActions = ({
  workspace,
  selectedAssetId,
  updateWorkspace,
  treeSaveToast,
}: UseCaseResolverStateSelectionActionsInput): UseCaseResolverStateSelectionActionsResult => {
  const activeFile = useMemo(
    (): CaseResolverFile | null =>
      workspace.activeFileId
        ? (workspace.files.find((file: CaseResolverFile) => file.id === workspace.activeFileId) ??
          null)
        : null,
    [workspace.activeFileId, workspace.files]
  );

  const selectedAsset = useMemo(
    (): CaseResolverAssetFile | null =>
      selectedAssetId
        ? (workspace.assets.find((asset: CaseResolverAssetFile) => asset.id === selectedAssetId) ??
          null)
        : null,
    [selectedAssetId, workspace.assets]
  );

  const handleUpdateSelectedAsset = useCallback(
    (
      patch: Partial<Pick<CaseResolverAssetFile, 'textContent' | 'description' | 'metadata'>>,
      options?: CaseResolverWorkspaceUpdateOptions
    ): void => {
      if (!selectedAssetId) return;
      const resolvedOptions: CaseResolverWorkspaceUpdateOptions = options ?? {
        persistToast: treeSaveToast,
      };
      updateWorkspace(
        (current: CaseResolverWorkspace) => ({
          ...current,
          assets: current.assets.map((asset: CaseResolverAssetFile) =>
            asset.id === selectedAssetId
              ? {
                ...asset,
                ...patch,
                updatedAt: new Date().toISOString(),
              }
              : asset
          ),
        }),
        resolvedOptions
      );
      if (resolvedOptions.source === 'node_file_manual_save') {
        logCaseResolverWorkspaceEvent({
          source: resolvedOptions.source,
          action: 'node_file_snapshot_manual_save',
          message: `asset_id=${selectedAssetId} persist_now=${resolvedOptions.persistNow === true ? 'true' : 'false'}`,
        });
      }
    },
    [selectedAssetId, treeSaveToast, updateWorkspace]
  );

  const handleUpdateActiveFileParties = useCallback(
    (
      patch: Partial<Pick<CaseResolverFile, 'addresser' | 'addressee' | 'referenceCaseIds'>>
    ): void => {
      if (!workspace.activeFileId) return;
      updateWorkspace(
        (current: CaseResolverWorkspace) => {
          const activeFile =
            current.files.find((file: CaseResolverFile) => file.id === current.activeFileId) ??
            null;
          if (activeFile?.isLocked) return current;
          return {
            ...current,
            files: current.files.map((file: CaseResolverFile) =>
              file.id === current.activeFileId
                ? { ...file, ...patch, updatedAt: new Date().toISOString() }
                : file
            ),
          };
        },
        { persistToast: 'Parties updated.' }
      );
    },
    [updateWorkspace, workspace.activeFileId]
  );

  return {
    activeFile,
    selectedAsset,
    handleUpdateSelectedAsset,
    handleUpdateActiveFileParties,
  };
};

/**
 * Case Resolver State Management Hook
 * 
 * Comprehensive state management for case resolution workflows.
 * Provides:
 * - URL parameter synchronization for case state
 * - Capture settings management and persistence
 * - Real-time state updates and validation
 * - Integration with case resolver capture system
 * - Client-side state coordination
 */

'use client';

import { useSearchParams } from 'next/navigation';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
  CASE_RESOLVER_CAPTURE_SETTINGS_KEY,
  parseCaseResolverCaptureSettings,
  type CaseResolverCaptureSettings as CaseResolverCaptureSettingsType,
} from '@/features/case-resolver/capture/public';
import {
  FILEMAKER_DATABASE_KEY,
  parseFilemakerDatabase,
} from '@/features/filemaker/public';
import type { CaseResolverCategory, CaseResolverIdentifier, CaseResolverTag } from '@/shared/contracts/case-resolver/relations';
import type { CaseResolverEditorNodeContext, CaseResolverWorkspace, CaseResolverSettings } from '@/shared/contracts/case-resolver/workspace';
import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import { useConfirm } from '@/shared/hooks/ui/useConfirm';
import { usePrompt } from '@/shared/hooks/ui/usePrompt';
import { useCountries } from '@/shared/hooks/use-i18n-queries';
import {
  useAdminLayoutActions,
  useAdminLayoutState,
} from '@/shared/providers/AdminLayoutProvider';
import { useSettingsStore } from '@/shared/providers/SettingsStoreProvider';
import { useToast } from '@/shared/ui/primitives.public';

import {
  fromCaseResolverCaseContentFileNodeId,
  fromCaseResolverCaseNodeId,
  fromCaseResolverFileNodeId,
} from '../master-tree';
import {
  CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_KEY,
  CASE_RESOLVER_CATEGORIES_KEY,
  CASE_RESOLVER_IDENTIFIERS_KEY,
  CASE_RESOLVER_SETTINGS_KEY,
  CASE_RESOLVER_TAGS_KEY,
  CASE_RESOLVER_WORKSPACE_KEY,
  getCaseResolverWorkspaceSafeParseDiagnostics,
  hasCaseResolverWorkspaceFilesArray,
  parseCaseResolverCategories,
  parseCaseResolverDefaultDocumentFormat,
  parseCaseResolverIdentifiers,
  parseCaseResolverSettings,
  parseCaseResolverTags,
  safeParseCaseResolverWorkspace,
} from '../settings';
import { type CaseResolverFileEditDraft, type CaseResolverStateValue } from '../types';
import {
  logCaseResolverWorkspaceEvent,
  readCaseResolverNavigationWorkspace,
  getCaseResolverWorkspaceRevision,
} from '../workspace-persistence';
import { useCaseResolverStateAssetActions } from './useCaseResolverState.asset-actions';
import { useCaseResolverStateCreationActions } from './useCaseResolverState.creation-actions';
import { useCaseResolverStateEditorActions } from './useCaseResolverState.editor-actions';
import { useCaseResolverStateFolderActions } from './useCaseResolverState.folder-actions';
import { serializeWorkspaceForUnsavedChangesCheck } from './useCaseResolverState.helpers';
import {
  resolvePreferredCaseResolverWorkspace,
  shouldRefetchSettingsStoreForRequestedFile,
} from './useCaseResolverState.helpers.hydration';
import {
  useCaseResolverPersistence,
  type UseCaseResolverPersistenceValue,
} from './useCaseResolverState.persistence-actions';
import { useCaseResolverPromptExploder } from './useCaseResolverState.prompt-exploder-actions';
import type { UseCaseResolverPromptExploderValue } from './prompt-exploder/types';
import { useCaseResolverStateRelatedFilesActions } from './useCaseResolverState.related-files-actions';
import { useCaseResolverStateRequestedContext } from './useCaseResolverState.requested-context';
import { useCaseResolverStateSelectionActions } from './useCaseResolverState.selection-actions';
import { useCaseResolverStateViewState } from './useCaseResolverState.view-state';
import { useCaseResolverStateWorkspaceDiagnostics } from './useCaseResolverState.workspace-diagnostics';
import { useCaseResolverStateWorkspaceHydration } from './useCaseResolverState.workspace-hydration';
import { useCaseResolverStateWorkspaceMutations } from './useCaseResolverState.workspace-mutations';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const CASE_RESOLVER_TREE_SAVE_TOAST = 'Case Resolver tree changes saved.';

/**
 * Custom hook to manage the complex state and logic of the Case Resolver page.
 */
export function useCaseResolverState(): CaseResolverStateValue {
  const settingsStore = useSettingsStore();
  const settingsStoreRef = useRef(settingsStore);
  settingsStoreRef.current = settingsStore;
  const { toast } = useToast();
  const { confirm, ConfirmationModal } = useConfirm();
  const { PromptInputModal } = usePrompt();
  const { isMenuCollapsed } = useAdminLayoutState();
  const { setIsMenuCollapsed } = useAdminLayoutActions();
  const searchParams = useSearchParams();
  const requestedFileIdRaw = searchParams.get('fileId');
  const requestedFileId = useMemo((): string | null => {
    const rawRequestedFileId = requestedFileIdRaw?.trim() ?? '';
    if (!rawRequestedFileId) return null;

    const resolveNodeIdReference = (value: string): string | null => {
      const decodedCaseNodeId = fromCaseResolverCaseNodeId(value);
      if (decodedCaseNodeId) return decodedCaseNodeId;
      const decodedFileNodeId = fromCaseResolverFileNodeId(value);
      if (decodedFileNodeId) return decodedFileNodeId;
      const decodedCaseContentFileNode = fromCaseResolverCaseContentFileNodeId(value);
      if (decodedCaseContentFileNode?.fileId) return decodedCaseContentFileNode.fileId;
      return null;
    };

    const directResolved = resolveNodeIdReference(rawRequestedFileId);
    if (directResolved) return directResolved;

    let normalizedRequestedFileId = rawRequestedFileId;
    for (let attempt = 0; attempt < 2; attempt += 1) {
      try {
        const decodedCandidate = decodeURIComponent(normalizedRequestedFileId).trim();
        if (!decodedCandidate || decodedCandidate === normalizedRequestedFileId) break;
        const decodedResolved = resolveNodeIdReference(decodedCandidate);
        if (decodedResolved) return decodedResolved;
        normalizedRequestedFileId = decodedCandidate;
      } catch (error) {
        logClientError(error);
        break;
      }
    }

    return normalizedRequestedFileId;
  }, [requestedFileIdRaw]);
  const shouldOpenEditorFromQuery = searchParams.get('openEditor') === '1';
  const requestedPromptExploderSessionId =
    searchParams.get('promptExploderSessionId')?.trim() ?? '';
  const isPromptExploderReturnFlow =
    shouldOpenEditorFromQuery &&
    requestedPromptExploderSessionId.length > 0 &&
    (requestedFileId?.trim() ?? '').length > 0;

  const rawWorkspaceFromStore = settingsStore.get(CASE_RESOLVER_WORKSPACE_KEY) ?? null;
  const rawCaseResolverTags = settingsStore.get(CASE_RESOLVER_TAGS_KEY);
  const rawCaseResolverIdentifiers = settingsStore.get(CASE_RESOLVER_IDENTIFIERS_KEY);
  const rawCaseResolverCategories = settingsStore.get(CASE_RESOLVER_CATEGORIES_KEY);
  const rawCaseResolverSettings = settingsStore.get(CASE_RESOLVER_SETTINGS_KEY);
  const rawCaseResolverDefaultDocumentFormat = settingsStore.get(
    CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_KEY
  );
  const rawCaseResolverCaptureSettings = settingsStore.get(CASE_RESOLVER_CAPTURE_SETTINGS_KEY);
  const rawFilemakerPayload = settingsStore.get(FILEMAKER_DATABASE_KEY);

  const hasWorkspaceFromStore = useMemo(
    (): boolean => hasCaseResolverWorkspaceFilesArray(rawWorkspaceFromStore),
    [rawWorkspaceFromStore]
  );
  const parsedWorkspaceFromStore = useMemo(
    (): CaseResolverWorkspace => safeParseCaseResolverWorkspace(rawWorkspaceFromStore),
    [rawWorkspaceFromStore]
  );
  const workspaceSafeParseDiagnostics = useMemo(
    () => getCaseResolverWorkspaceSafeParseDiagnostics(parsedWorkspaceFromStore),
    [parsedWorkspaceFromStore]
  );
  const storeWorkspaceHasRequestedFile = useMemo((): boolean => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) return false;
    return parsedWorkspaceFromStore.files.some(
      (file: CaseResolverFile): boolean => file.id === normalizedRequestedFileId
    );
  }, [parsedWorkspaceFromStore.files, requestedFileId]);
  const navigationWorkspace = useMemo(
    (): CaseResolverWorkspace | null => readCaseResolverNavigationWorkspace(),
    [requestedFileId]
  );
  const hasNavigationWorkspace = useMemo(
    (): boolean =>
      Boolean(
        navigationWorkspace &&
        (navigationWorkspace.files.length > 0 ||
          navigationWorkspace.assets.length > 0 ||
          navigationWorkspace.folders.length > 0)
      ),
    [navigationWorkspace]
  );
  const preferredWorkspaceSelection = useMemo(
    () =>
      resolvePreferredCaseResolverWorkspace({
        storeWorkspace: parsedWorkspaceFromStore,
        navigationWorkspace: navigationWorkspace ?? undefined,
        hasStoreWorkspace: hasWorkspaceFromStore,
        hasNavigationWorkspace,
        requestedFileId,
      }),
    [
      hasNavigationWorkspace,
      hasWorkspaceFromStore,
      navigationWorkspace,
      parsedWorkspaceFromStore,
      requestedFileId,
    ]
  );
  const parsedWorkspace = preferredWorkspaceSelection.workspace;
  const canHydrateWorkspaceFromStore = preferredWorkspaceSelection.source !== 'none';
  const caseResolverTags = useMemo(
    (): CaseResolverTag[] => parseCaseResolverTags(rawCaseResolverTags),
    [rawCaseResolverTags]
  );
  const caseResolverIdentifiers = useMemo(
    (): CaseResolverIdentifier[] => parseCaseResolverIdentifiers(rawCaseResolverIdentifiers),
    [rawCaseResolverIdentifiers]
  );
  const caseResolverCategories = useMemo(
    (): CaseResolverCategory[] => parseCaseResolverCategories(rawCaseResolverCategories),
    [rawCaseResolverCategories]
  );
  const caseResolverSettings = useMemo((): CaseResolverSettings => {
    const parsed = parseCaseResolverSettings(rawCaseResolverSettings);
    const defaultDocumentFormat = parseCaseResolverDefaultDocumentFormat(
      rawCaseResolverDefaultDocumentFormat,
      parsed.defaultDocumentFormat
    );
    if (defaultDocumentFormat === parsed.defaultDocumentFormat) return parsed;
    return {
      ...parsed,
      defaultDocumentFormat,
    };
  }, [rawCaseResolverDefaultDocumentFormat, rawCaseResolverSettings]);
  const filemakerDatabase = useMemo(
    () => parseFilemakerDatabase(rawFilemakerPayload),
    [rawFilemakerPayload]
  );
  const caseResolverCaptureSettings = useMemo(
    (): CaseResolverCaptureSettingsType =>
      parseCaseResolverCaptureSettings(rawCaseResolverCaptureSettings),
    [rawCaseResolverCaptureSettings]
  );

  const countriesQuery = useCountries();
  const countries = countriesQuery.data ?? [];

  const initialWorkspaceState = useMemo((): CaseResolverWorkspace => {
    if (!requestedFileId) return parsedWorkspace;
    const hasRequestedFile = parsedWorkspace.files.some(
      (file: CaseResolverFile): boolean => file.id === requestedFileId
    );
    if (hasRequestedFile) {
      if (parsedWorkspace.activeFileId === requestedFileId) return parsedWorkspace;
      return {
        ...parsedWorkspace,
        activeFileId: requestedFileId,
      };
    }
    if (parsedWorkspace.activeFileId === null) return parsedWorkspace;
    return {
      ...parsedWorkspace,
      activeFileId: null,
    };
  }, [parsedWorkspace, requestedFileId]);

  const [workspace, setWorkspace] = useState<CaseResolverWorkspace>(initialWorkspaceState);
  const workspaceRef = useRef<CaseResolverWorkspace>(initialWorkspaceState);
  const [editingDocumentDraft, setEditingDocumentDraft] =
    useState<CaseResolverFileEditDraft | null>(null);
  const [editingDocumentNodeContext, setEditingDocumentNodeContext] =
    useState<CaseResolverEditorNodeContext | null>(null);
  const [isUploadingScanDraftFiles, setIsUploadingScanDraftFiles] = useState(false);
  const [uploadingScanSlotId, setUploadingScanSlotId] = useState<string | null>(null);

  const [, setPersistedWorkspaceSnapshot] = useState<string>(JSON.stringify(initialWorkspaceState));
  const [persistedWorkspaceComparableSnapshot, setPersistedWorkspaceComparableSnapshot] =
    useState<string>(() => serializeWorkspaceForUnsavedChangesCheck(initialWorkspaceState));

  const handledRequestedFileIdRef = useRef<string | null>(null);
  const requestedStoreRefreshFileIdRef = useRef<string | null>(null);
  const requestedUnavailableAutoRetryFileIdRef = useRef<string | null>(null);
  const lastWorkspaceParseFallbackSignatureRef = useRef<string>('');

  const persistence: UseCaseResolverPersistenceValue = useCaseResolverPersistence({
    initialWorkspaceState,
    settingsStoreRef,
    toast,
    setPersistedWorkspaceSnapshot,
    setPersistedWorkspaceComparableSnapshot,
  });
  const syncPersistedWorkspaceTracking = persistence.syncPersistedWorkspaceTracking;
  const clearQueuedWorkspacePersistMutation = persistence.clearQueuedWorkspacePersistMutation;
  const isMountedRef = useRef(true);
  const requestedContext = useCaseResolverStateRequestedContext({
    requestedFileId,
    workspace,
    workspaceRef,
    setWorkspace,
    isMountedRef,
    handledRequestedFileIdRef,
    syncPersistedWorkspaceTracking,
    clearQueuedWorkspacePersistMutation,
    isStoreLoading: settingsStore.isLoading,
    isStoreFetching: settingsStore.isFetching,
    storeWorkspaceHasRequestedFile,
    isPromptExploderReturnFlow,
  });
  const {
    requestedCaseStatus,
    requestedCaseIssue,
    requestedContextAutoClearRequestKey,
    setRequestedCaseStatus,
    handleAcknowledgeRequestedContextAutoClear,
    handleRetryCaseContext,
    resetRequestedContextState,
  } = requestedContext;

  const viewState = useCaseResolverStateViewState({
    workspace,
    setWorkspace,
    requestedFileId,
    requestedCaseStatus,
    initialWorkspaceState,
    syncPersistedWorkspaceTracking: persistence.syncPersistedWorkspaceTracking,
    clearQueuedWorkspacePersistMutation: persistence.clearQueuedWorkspacePersistMutation,
    handledRequestedFileIdRef,
  });
  const { setSelectedFileId, setSelectedAssetId, setSelectedFolderPath } = viewState;
  const workspaceDiagnostics = useCaseResolverStateWorkspaceDiagnostics({
    workspace,
    activeCaseId: viewState.activeCaseId,
    selectedFileId: viewState.selectedFileId,
    requestedFileId,
    toast,
  });
  const {
    selectedCaseScopeIds,
    workspaceIndexes,
    workspaceNormalizationDiagnostics,
    treeWorkspace,
  } = workspaceDiagnostics;
  const { updateWorkspace } = useCaseResolverStateWorkspaceMutations({
    workspace,
    setWorkspace,
    persistedWorkspaceComparableSnapshot,
    persistence,
  });

  const promptExploder: UseCaseResolverPromptExploderValue = useCaseResolverPromptExploder({
    workspace,
    workspaceRef,
    updateWorkspace,
    setEditingDocumentDraft,
    filemakerDatabase,
    caseResolverCaptureSettings,
    requestedFileId,
    shouldOpenEditorFromQuery,
    requestedPromptExploderSessionId,
    toast,
    flushWorkspacePersist: persistence.flushWorkspacePersist,
  });

  useCaseResolverStateWorkspaceHydration({
    workspaceRef,
    setWorkspace,
    isMountedRef,
    requestedFileId,
    canHydrateWorkspaceFromStore,
    preferredWorkspaceSource: preferredWorkspaceSelection.source,
    preferredWorkspaceReason: preferredWorkspaceSelection.reason,
    hasWorkspaceFromStore,
    parsedWorkspace,
    isApplyingPromptExploderPartyProposal: promptExploder.isApplyingPromptExploderPartyProposal,
    syncPersistedWorkspaceTracking,
    clearQueuedWorkspacePersistMutation,
    isPromptExploderReturnFlow,
  });

  const editorActions = useCaseResolverStateEditorActions({
    workspace,
    updateWorkspace,
    editingDocumentDraft,
    setEditingDocumentDraft,
    setEditingDocumentNodeContext,
    setSelectedFileId: viewState.setSelectedFileId,
    setSelectedAssetId: viewState.setSelectedAssetId,
    setSelectedFolderPath: viewState.setSelectedFolderPath,
    setWorkspace,
    toast,
  });

  const relatedFilesActions = useCaseResolverStateRelatedFilesActions({
    workspace,
    updateWorkspace,
    toast,
  });

  const defaultTagId = caseResolverTags[0]?.id ?? null;
  const defaultCaseIdentifierId = caseResolverIdentifiers[0]?.id ?? null;
  const defaultCategoryId = caseResolverCategories[0]?.id ?? null;

  const refetchSettingsStore = useCallback((): void => {
    settingsStoreRef.current.refetch();
  }, []);

  useEffect(() => {
    return (): void => {
      isMountedRef.current = false;
    };
  }, []);

  useEffect(() => {
    const fallbackApplied = workspaceSafeParseDiagnostics.parseFallbackApplied;
    if (!fallbackApplied) {
      return;
    }
    const signature = [
      rawWorkspaceFromStore ?? '<null>',
      fallbackApplied ? 'fallback:1' : 'fallback:0',
      workspaceSafeParseDiagnostics.parseFallbackReason ?? 'none',
    ].join('|');
    if (lastWorkspaceParseFallbackSignatureRef.current === signature) return;
    lastWorkspaceParseFallbackSignatureRef.current = signature;
    logCaseResolverWorkspaceEvent({
      source: 'case_view',
      action: 'workspace_parse_fallback_applied',
      workspaceRevision: getCaseResolverWorkspaceRevision(parsedWorkspaceFromStore),
      message: [
        `fallback=${fallbackApplied ? 'true' : 'false'}`,
        `reason=${workspaceSafeParseDiagnostics.parseFallbackReason ?? 'none'}`,
      ].join(' '),
    });
  }, [
    parsedWorkspaceFromStore,
    rawWorkspaceFromStore,
    workspaceSafeParseDiagnostics.parseFallbackApplied,
    workspaceSafeParseDiagnostics.parseFallbackReason,
  ]);

  useEffect(() => {
    workspaceRef.current = workspace;
  }, [workspace]);

  useEffect((): void => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) {
      requestedStoreRefreshFileIdRef.current = null;
      requestedUnavailableAutoRetryFileIdRef.current = null;
      return;
    }

    const requestedFileResolvedInWorkspace = workspace.files.some(
      (file: CaseResolverFile): boolean => file.id === normalizedRequestedFileId
    );
    const requestedFileResolvedInStore = parsedWorkspaceFromStore.files.some(
      (file: CaseResolverFile): boolean => file.id === normalizedRequestedFileId
    );
    if (requestedFileResolvedInWorkspace || requestedFileResolvedInStore) {
      requestedStoreRefreshFileIdRef.current = null;
      return;
    }

    if (
      !shouldRefetchSettingsStoreForRequestedFile({
        requestedFileId: normalizedRequestedFileId,
        requestedFileResolvedInWorkspace,
        requestedFileResolvedInStore,
        isStoreLoading: settingsStore.isLoading,
        isStoreFetching: settingsStore.isFetching,
        lastRefetchedFileId: requestedStoreRefreshFileIdRef.current,
      })
    ) {
      return;
    }

    requestedStoreRefreshFileIdRef.current = normalizedRequestedFileId;
    logCaseResolverWorkspaceEvent({
      source: 'case_view',
      action: 'requested_context_store_refetch',
      message: `requested_file_id=${normalizedRequestedFileId} reason=missing_from_store_snapshot`,
    });
    settingsStoreRef.current.refetch();
  }, [
    parsedWorkspaceFromStore,
    requestedFileId,
    settingsStore.isFetching,
    settingsStore.isLoading,
    workspace.files,
  ]);

  useEffect((): void => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    if (!normalizedRequestedFileId) {
      requestedUnavailableAutoRetryFileIdRef.current = null;
      return;
    }
    const canAutoRetry =
      requestedCaseStatus === 'missing' &&
      requestedCaseIssue === 'workspace_unavailable' &&
      requestedUnavailableAutoRetryFileIdRef.current !== normalizedRequestedFileId;
    if (!canAutoRetry) return;

    requestedUnavailableAutoRetryFileIdRef.current = normalizedRequestedFileId;
    logCaseResolverWorkspaceEvent({
      source: 'case_view',
      action: 'requested_context_auto_retry_after_unavailable',
      message: `requested_file_id=${normalizedRequestedFileId}`,
    });
    settingsStoreRef.current.refetch();
    queueMicrotask((): void => {
      handleRetryCaseContext();
    });
  }, [handleRetryCaseContext, requestedCaseIssue, requestedCaseStatus, requestedFileId]);

  const creationActions = useCaseResolverStateCreationActions({
    workspace,
    updateWorkspace,
    setWorkspace,
    syncPersistedWorkspaceTracking: persistence.syncPersistedWorkspaceTracking,
    requestedFileId,
    selectedFileId: viewState.selectedFileId,
    requestedCaseStatus,
    setRequestedCaseStatus,
    activeCaseId: viewState.activeCaseId,
    canCreateInActiveCase: viewState.canCreateInActiveCase,
    defaultTagId,
    defaultCaseIdentifierId,
    defaultCategoryId,
    setSelectedFileId: viewState.setSelectedFileId,
    setSelectedAssetId: viewState.setSelectedAssetId,
    setSelectedFolderPath: viewState.setSelectedFolderPath,
    settingsStoreRef,
    toast,
  });

  const handleResetCaseContext = useCallback((): void => {
    resetRequestedContextState();
    setSelectedFileId(null);
    setSelectedAssetId(null);
    setSelectedFolderPath(null);
    setWorkspace(
      (current: CaseResolverWorkspace): CaseResolverWorkspace =>
        current.activeFileId === null
          ? current
          : {
            ...current,
            activeFileId: null,
          }
    );
  }, [
    resetRequestedContextState,
    setWorkspace,
    setSelectedAssetId,
    setSelectedFileId,
    setSelectedFolderPath,
  ]);

  const assetActions = useCaseResolverStateAssetActions({
    settingsStore,
    toast,
    updateWorkspace,
    workspace,
    editingDocumentDraft,
    setEditingDocumentDraft,
    setIsUploadingScanDraftFiles,
    setUploadingScanSlotId,
    defaultTagId,
    defaultCaseIdentifierId,
    defaultCategoryId,
    activeCaseId: viewState.activeCaseId,
    requestedCaseStatus,
    setSelectedFileId: viewState.setSelectedFileId,
    setSelectedFolderPath: viewState.setSelectedFolderPath,
    setSelectedAssetId: viewState.setSelectedAssetId,
    treeSaveToast: CASE_RESOLVER_TREE_SAVE_TOAST,
  });

  const folderActions = useCaseResolverStateFolderActions({
    confirm,
    toast,
    updateWorkspace,
    workspace,
    selectedCaseScopeIds,
    selectedCaseContainerId: viewState.activeCaseId,
    setSelectedFileId: viewState.setSelectedFileId,
    setSelectedAssetId: viewState.setSelectedAssetId,
    setSelectedFolderPath: viewState.setSelectedFolderPath,
    setEditingDocumentDraft,
    treeSaveToast: CASE_RESOLVER_TREE_SAVE_TOAST,
  });

  const selectionActions = useCaseResolverStateSelectionActions({
    workspace,
    selectedAssetId: viewState.selectedAssetId,
    updateWorkspace,
    treeSaveToast: CASE_RESOLVER_TREE_SAVE_TOAST,
  });

  return {
    workspace: treeWorkspace,
    workspaceRef,
    setWorkspace,
    updateWorkspace,
    workspaceIndexes,
    workspaceNormalizationDiagnostics,
    ...viewState,
    editingDocumentDraft,
    editingDocumentNodeContext,
    setEditingDocumentDraft,
    setEditingDocumentNodeContext,
    isUploadingScanDraftFiles,
    setIsUploadingScanDraftFiles,
    uploadingScanSlotId,
    setUploadingScanSlotId,
    caseResolverTags,
    caseResolverIdentifiers,
    caseResolverCategories,
    caseResolverSettings,
    countries,
    isMenuCollapsed,
    setIsMenuCollapsed,
    requestedFileId,
    requestedPromptExploderSessionId,
    requestedCaseStatus,
    requestedCaseIssue,
    requestedContextAutoClearRequestKey,
    shouldOpenEditorFromQuery,
    handleAcknowledgeRequestedContextAutoClear,
    handleRetryCaseContext,
    handleResetCaseContext,
    handleCreateFolder: creationActions.handleCreateFolder,
    handleCreateFile: creationActions.handleCreateFile,
    handleCreateScanFile: assetActions.handleCreateScanFile,
    handleCreateNodeFile: creationActions.handleCreateNodeFile,
    handleCreateImageAsset: assetActions.handleCreateImageAsset,
    handleCreateDocumentFromText: assetActions.handleCreateDocumentFromText,
    handleUploadScanFiles: assetActions.handleUploadScanFiles,
    handleRunScanFileOcr: assetActions.handleRunScanFileOcr,
    handleUploadAssets: assetActions.handleUploadAssets,
    handleAttachAssetFile: assetActions.handleAttachAssetFile,
    handleDeleteFolder: folderActions.handleDeleteFolder,
    handleMoveFile: folderActions.handleMoveFile,
    handleMoveAsset: folderActions.handleMoveAsset,
    handleRenameFile: folderActions.handleRenameFile,
    handleRenameAsset: folderActions.handleRenameAsset,
    handleRenameFolder: folderActions.handleRenameFolder,
    handleOpenFileEditor: editorActions.handleOpenFileEditor,
    activeFile: selectionActions.activeFile,
    selectedAsset: selectionActions.selectedAsset,
    handleUpdateSelectedAsset: selectionActions.handleUpdateSelectedAsset,
    handleUpdateActiveFileParties: selectionActions.handleUpdateActiveFileParties,
    handleLinkRelatedFiles: relatedFilesActions.handleLinkRelatedFiles,
    handleUnlinkRelatedFile: relatedFilesActions.handleUnlinkRelatedFile,
    handleSaveFileEditor: editorActions.handleSaveFileEditor,
    handleDiscardFileEditorDraft: editorActions.handleDiscardFileEditorDraft,
    ...promptExploder,
    ...persistence,
    refetchSettingsStore,
    confirmAction: confirm,
    ConfirmationModal,
    PromptInputModal,
    filemakerDatabase,
  };
}

'use client';

import { useCallback } from 'react';

import {
  createId,
  isLikelyImageFile,
  isLikelyScanInputFile,
} from '@/features/case-resolver/utils/caseResolverUtils';
import type { CaseResolverAssetFile, CaseResolverFile, CaseResolverFileEditDraft } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverAssetKind } from '@/shared/contracts/case-resolver/base';
import type { CaseResolverScanSlot } from '@/shared/contracts/case-resolver/ocr';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { Toast } from '@/shared/contracts/ui/base';

import {
  createCaseResolverAssetFile,
  inferCaseResolverAssetKind,
  normalizeFolderPath,
  normalizeFolderPaths,
} from '../settings';
import {
  normalizeUploadedCaseResolverFile,
  resolveUploadBaseFolder,
  type CaseResolverUploadedFile,
} from './useCaseResolverState.helpers';
import { logClientError } from '@/shared/utils/observability/client-error-logger';



export interface UseCaseResolverStateUploadActionsValue {
  handleUploadScanFiles: (fileId: string, files: File[]) => Promise<void>;
  handleUploadAssets: (
    files: File[],
    targetFolderPath: string | null
  ) => Promise<CaseResolverAssetFile[]>;
  handleAttachAssetFile: (
    assetId: string,
    file: File,
    options?: { expectedKind?: CaseResolverAssetKind | null }
  ) => Promise<CaseResolverAssetFile>;
  uploadSourceFileToCaseResolver: (
    sourceFile: File,
    targetFolderPath: string
  ) => Promise<CaseResolverUploadedFile>;
}

export function useCaseResolverStateUploadActions({
  toast,
  updateWorkspace,
  workspace,
  setEditingDocumentDraft,
  setSelectedFileId,
  setSelectedAssetId,
  setSelectedFolderPath,
  treeSaveToast,
}: {
  toast: Toast;
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: {
      persistToast?: string;
      persistNow?: boolean;
      mutationId?: string;
      source?: string;
      skipNormalization?: boolean;
    }
  ) => void;
  workspace: CaseResolverWorkspace;
  setEditingDocumentDraft: React.Dispatch<React.SetStateAction<CaseResolverFileEditDraft | null>>;
  setSelectedFileId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedAssetId: React.Dispatch<React.SetStateAction<string | null>>;
  setSelectedFolderPath: React.Dispatch<React.SetStateAction<string | null>>;
  treeSaveToast: string;
}): UseCaseResolverStateUploadActionsValue {
  const uploadSourceFileToCaseResolver = useCallback(
    async (sourceFile: File, targetFolderPath: string): Promise<CaseResolverUploadedFile> => {
      const uploadFormData = new FormData();
      uploadFormData.append('folder', targetFolderPath);
      uploadFormData.append('file', sourceFile);
      const uploadResponse = await fetch('/api/case-resolver/assets/upload', {
        method: 'POST',
        body: uploadFormData,
      });
      if (!uploadResponse.ok) {
        const fallbackMessage = `Failed to upload file (${uploadResponse.status})`;
        const errorBody = await uploadResponse.text();
        throw new Error(errorBody || fallbackMessage);
      }
      const uploadPayload = (await uploadResponse.json()) as unknown;
      const firstEntry: unknown = Array.isArray(uploadPayload)
        ? (uploadPayload[0] ?? null)
        : uploadPayload;
      return normalizeUploadedCaseResolverFile(firstEntry, sourceFile, targetFolderPath);
    },
    []
  );

  const handleUploadScanFiles = useCallback(
    async (fileId: string, files: File[]): Promise<void> => {
      const targetFile = workspace.files.find(
        (file: CaseResolverFile): boolean => file.id === fileId
      );
      if (targetFile?.fileType !== 'scanfile') {
        throw new Error('Scan file no longer exists.');
      }
      if (targetFile.isLocked) {
        throw new Error('Document is locked. Unlock it before uploading files.');
      }

      const sourceFiles = files.filter(
        (file: File): boolean => file instanceof File && file.size >= 0
      );
      if (sourceFiles.length === 0) return;

      const normalizedFolder = normalizeFolderPath(targetFile.folder);
      const createdSlots: CaseResolverScanSlot[] = [];
      const createdFolders = new Set<string>();
      const failedFiles: string[] = [];

      for (const sourceFile of sourceFiles) {
        if (!isLikelyScanInputFile(sourceFile)) {
          failedFiles.push(`${sourceFile.name || 'file'}: Only image and PDF files are supported.`);
          continue;
        }
        const inferredKind = inferCaseResolverAssetKind({
          mimeType: sourceFile.type,
          name: sourceFile.name,
        });
        if (inferredKind !== 'image' && inferredKind !== 'pdf') {
          failedFiles.push(`${sourceFile.name || 'file'}: Only image and PDF files are supported.`);
          continue;
        }
        try {
          const uploadBaseFolder = resolveUploadBaseFolder(normalizedFolder, inferredKind);
          const uploaded = await uploadSourceFileToCaseResolver(sourceFile, uploadBaseFolder);
          createdSlots.push({
            id: createId('scan-slot'),
            fileId: uploaded.id || '',
            status: 'completed',
            progress: 100,
            name: uploaded.originalName || sourceFile.name || 'file',
            filepath: uploaded.filepath || '',
            sourceFileId: uploaded.id || '',
            mimeType: uploaded.mimetype || sourceFile.type,
            size: uploaded.size || sourceFile.size || 0,
            ocrText: '',
            ocrError: null,
          });
          createdFolders.add(normalizeFolderPath(uploaded.folder || normalizedFolder));
        } catch (error: unknown) {
          logClientError(error);
          failedFiles.push(
            `${sourceFile.name || 'file'}: ${
              error instanceof Error ? error.message : 'Upload failed'
            }`
          );
        }
      }

      if (createdSlots.length > 0) {
        let didAttachSlots = false;
        let attachBlockedByLock = false;
        updateWorkspace(
          (current: CaseResolverWorkspace) => {
            const now = new Date().toISOString();
            let didUpdate = false;
            const nextFiles = current.files.map((file: CaseResolverFile): CaseResolverFile => {
              if (file.id !== fileId || file.fileType !== 'scanfile') return file;
              if (file.isLocked) {
                attachBlockedByLock = true;
                return file;
              }
              didUpdate = true;
              return {
                ...file,
                scanSlots: [...(file.scanSlots ?? []), ...createdSlots],
                updatedAt: now,
              };
            });
            didAttachSlots = didUpdate;
            if (!didUpdate) return current;
            return {
              ...current,
              files: nextFiles,
              folders: normalizeFolderPaths([...current.folders, ...Array.from(createdFolders)]),
            };
          },
          { persistToast: treeSaveToast }
        );
        setEditingDocumentDraft((current) => {
          if (current?.id !== fileId || current?.fileType !== 'scanfile') return current;
          if (current.isLocked) return current;
          return {
            ...current,
            scanSlots: [...(current.scanSlots ?? []), ...createdSlots],
            updatedAt: new Date().toISOString(),
          };
        });
        if (didAttachSlots) {
          toast('Files uploaded.', { variant: 'success' });
        } else if (attachBlockedByLock) {
          toast('Document was locked before uploaded files could be attached.', {
            variant: 'warning',
          });
        }
      }

      if (failedFiles.length > 0) {
        toast(
          failedFiles.length === 1
            ? (failedFiles[0] ?? 'Failed to upload file.')
            : `${failedFiles.length} files failed to upload.`,
          { variant: 'error' }
        );
      }
    },
    [
      toast,
      treeSaveToast,
      updateWorkspace,
      uploadSourceFileToCaseResolver,
      workspace.files,
      setEditingDocumentDraft,
      setSelectedAssetId,
      setSelectedFileId,
      setSelectedFolderPath,
    ]
  );

  const handleUploadAssets = useCallback(
    async (files: File[], targetFolderPath: string | null): Promise<CaseResolverAssetFile[]> => {
      const sourceFiles = files.filter(
        (file: File): boolean => file instanceof File && file.size >= 0
      );
      if (sourceFiles.length === 0) return [];

      const normalizedFolder = normalizeFolderPath(targetFolderPath ?? '');
      const createdAssets: CaseResolverAssetFile[] = [];
      const failedFiles: string[] = [];

      for (const sourceFile of sourceFiles) {
        try {
          const inferredKind = inferCaseResolverAssetKind({
            mimeType: sourceFile.type,
            name: sourceFile.name,
          });
          const uploadBaseFolder = resolveUploadBaseFolder(normalizedFolder, inferredKind);
          const uploaded = await uploadSourceFileToCaseResolver(sourceFile, uploadBaseFolder);
          const fallbackName = sourceFile.name.trim() || `File ${createdAssets.length + 1}`;
          const assetName = uploaded.originalName.trim() || fallbackName;

          createdAssets.push(
            createCaseResolverAssetFile({
              id: createId('asset'),
              name: assetName,
              folder: uploaded.folder || normalizedFolder,
              kind: uploaded.kind,
              filepath: uploaded.filepath,
              sourceFileId: uploaded.id,
              mimeType: uploaded.mimetype,
              size: uploaded.size,
            })
          );
        } catch (error: unknown) {
          logClientError(error);
          failedFiles.push(
            `${sourceFile.name || 'file'}: ${error instanceof Error ? error.message : 'Upload failed'}`
          );
        }
      }

      if (createdAssets.length > 0) {
        updateWorkspace(
          (current: CaseResolverWorkspace) => ({
            ...current,
            assets: [...current.assets, ...createdAssets],
            folders: normalizeFolderPaths([
              ...current.folders,
              ...createdAssets.map((asset: CaseResolverAssetFile): string => asset.folder),
            ]),
          }),
          { persistToast: treeSaveToast }
        );
      }

      if (failedFiles.length > 0) {
        toast(
          failedFiles.length === 1
            ? (failedFiles[0] ?? 'Failed to upload file.')
            : `${failedFiles.length} files failed to upload.`,
          { variant: 'error' }
        );
      }

      if (createdAssets.length === 0 && failedFiles.length > 0) {
        throw new Error(failedFiles[0] ?? 'Failed to upload files.');
      }

      return createdAssets;
    },
    [toast, treeSaveToast, updateWorkspace, uploadSourceFileToCaseResolver]
  );

  const handleAttachAssetFile = useCallback(
    async (
      assetId: string,
      file: File,
      options?: { expectedKind?: CaseResolverAssetKind | null }
    ): Promise<CaseResolverAssetFile> => {
      const currentAsset = workspace.assets.find(
        (asset: CaseResolverAssetFile): boolean => asset.id === assetId
      );
      if (!currentAsset) {
        throw new Error('Asset placeholder no longer exists.');
      }

      const expectedKind = options?.expectedKind ?? currentAsset.kind;
      if (expectedKind === 'image' && !isLikelyImageFile(file)) {
        throw new Error('Please upload an image file for this image placeholder.');
      }

      const uploadFolder = normalizeFolderPath(currentAsset.folder);
      const uploadBaseFolder = resolveUploadBaseFolder(uploadFolder, expectedKind);
      const uploaded = await uploadSourceFileToCaseResolver(file, uploadBaseFolder);
      const uploadedKind = inferCaseResolverAssetKind({
        kind: uploaded.kind,
        mimeType: uploaded.mimetype,
        name: uploaded.originalName,
      });
      if (expectedKind && expectedKind !== 'file' && uploadedKind !== expectedKind) {
        throw new Error(`Uploaded file type does not match this ${expectedKind} placeholder.`);
      }

      const now = new Date().toISOString();
      const resolvedKind = expectedKind && expectedKind !== 'file' ? expectedKind : uploadedKind;
      const updatedAsset: CaseResolverAssetFile = {
        ...currentAsset,
        folder: normalizeFolderPath(uploaded.folder || uploadFolder),
        kind: resolvedKind,
        filepath: uploaded.filepath,
        sourceFileId: uploaded.id,
        mimeType: uploaded.mimetype,
        size: uploaded.size,
        updatedAt: now,
      };
      updateWorkspace(
        (current: CaseResolverWorkspace): CaseResolverWorkspace => {
          let didUpdate = false;
          const nextAssets = current.assets.map(
            (asset: CaseResolverAssetFile): CaseResolverAssetFile => {
              if (asset.id !== assetId) return asset;
              didUpdate = true;
              return updatedAsset;
            }
          );
          if (!didUpdate) return current;
          return {
            ...current,
            assets: nextAssets,
            folders: normalizeFolderPaths([
              ...current.folders,
              normalizeFolderPath(uploaded.folder || uploadFolder) || '',
            ]),
          };
        },
        { persistToast: treeSaveToast }
      );

      setSelectedFileId(null);
      setSelectedFolderPath(null);
      setSelectedAssetId(updatedAsset.id);
      toast('File attached.', { variant: 'success' });
      return updatedAsset;
    },
    [
      setSelectedAssetId,
      setSelectedFileId,
      setSelectedFolderPath,
      toast,
      treeSaveToast,
      updateWorkspace,
      uploadSourceFileToCaseResolver,
      workspace.assets,
    ]
  );

  return {
    handleUploadScanFiles,
    handleUploadAssets,
    handleAttachAssetFile,
    uploadSourceFileToCaseResolver,
  };
}

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';

import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
