export function useCaseResolverStateViewState({
  workspace,
  setWorkspace,
  requestedFileId,
  requestedCaseStatus,
  initialWorkspaceState,
  syncPersistedWorkspaceTracking,
  clearQueuedWorkspacePersistMutation,
  handledRequestedFileIdRef,
}: {
  workspace: CaseResolverWorkspace;
  setWorkspace: React.Dispatch<React.SetStateAction<CaseResolverWorkspace>>;
  requestedFileId: string | null;
  requestedCaseStatus: CaseResolverRequestedCaseStatus;
  initialWorkspaceState: CaseResolverWorkspace;
  syncPersistedWorkspaceTracking: (workspace: CaseResolverWorkspace) => void;
  clearQueuedWorkspacePersistMutation: () => void;
  handledRequestedFileIdRef: React.MutableRefObject<string | null>;
}): UseCaseResolverStateViewStateValue {
  const [selectedFileId, setSelectedFileId] = useState<string | null>(
    requestedFileId ?? initialWorkspaceState.activeFileId
  );
  const [selectedFolderPath, setSelectedFolderPath] = useState<string | null>(null);
  const [selectedAssetId, setSelectedAssetId] = useState<string | null>(null);
  const [folderPanelCollapsed, setFolderPanelCollapsed] = useState(false);
  const [activeMainView, setActiveMainView] = useState<'workspace' | 'search'>('workspace');
  const [isPreviewPageVisible, setIsPreviewPageVisible] = useState(false);
  const [isPartiesModalOpen, setIsPartiesModalOpen] = useState(false);

  const filesById = useMemo(
    () =>
      new Map<string, CaseResolverFile>(
        workspace.files.map((file: CaseResolverFile): [string, CaseResolverFile] => [file.id, file])
      ),
    [workspace.files]
  );

  const requestedCaseContainerId = useMemo(
    (): string | null => resolveCaseContainerIdForFileId(filesById, requestedFileId),
    [filesById, requestedFileId]
  );

  const selectedCaseContainerId = useMemo((): string | null => {
    const contextFileId = selectedFileId ?? workspace.activeFileId;
    return resolveCaseContainerIdForFileId(filesById, contextFileId);
  }, [filesById, selectedFileId, workspace.activeFileId]);

  const selectedFolderCaseContainerId = useMemo(
    (): string | null =>
      resolveCaseContainerIdForFolderPath({
        filesById,
        folderRecords: workspace.folderRecords,
        folderPath: selectedFolderPath,
      }),
    [filesById, selectedFolderPath, workspace.folderRecords]
  );

  const activeCaseId = useMemo(
    (): string | null =>
      resolveCaseResolverActiveCaseId({
        requestedFileId,
        requestedCaseContainerId,
        selectedCaseContainerId,
        selectedFolderCaseContainerId,
        files: workspace.files,
      }),
    [
      requestedCaseContainerId,
      requestedFileId,
      selectedCaseContainerId,
      selectedFolderCaseContainerId,
      workspace.files,
    ]
  );

  const handleSelectFile = useCallback(
    (fileId: string): void => {
      if (selectedFileId === fileId) {
        setSelectedFileId(null);
        setSelectedFolderPath(null);
        setSelectedAssetId(null);
        return;
      }
      setSelectedFileId(fileId);
      setWorkspace(
        (current: CaseResolverWorkspace): CaseResolverWorkspace =>
          current.activeFileId === fileId
            ? current
            : {
              ...current,
              activeFileId: fileId,
            }
      );
      setSelectedFolderPath(null);
      setSelectedAssetId(null);
    },
    [selectedFileId, setWorkspace]
  );

  const handleSelectAsset = useCallback((assetId: string): void => {
    setSelectedFileId(null);
    setSelectedAssetId(assetId);
    setSelectedFolderPath(null);
  }, []);

  const handleSelectFolder = useCallback(
    (folderPath: string | null): void => {
      const preservedCaseId = selectedFolderCaseContainerId ?? activeCaseId;
      if (folderPath !== null && selectedFolderPath === folderPath) {
        setSelectedFileId(null);
        setSelectedFolderPath(null);
        setSelectedAssetId(null);
        if (preservedCaseId) {
          setWorkspace(
            (current: CaseResolverWorkspace): CaseResolverWorkspace =>
              current.activeFileId === preservedCaseId
                ? current
                : {
                  ...current,
                  activeFileId: preservedCaseId,
                }
          );
        }
        return;
      }

      const nextFolderCaseContainerId = resolveCaseContainerIdForFolderPath({
        filesById,
        folderRecords: workspace.folderRecords,
        folderPath,
      });

      setSelectedFileId(null);
      setSelectedFolderPath(folderPath);
      setSelectedAssetId(null);
      const nextActiveCaseId = nextFolderCaseContainerId ?? activeCaseId;
      if (nextActiveCaseId) {
        setWorkspace(
          (current: CaseResolverWorkspace): CaseResolverWorkspace =>
            current.activeFileId === nextActiveCaseId
              ? current
              : {
                ...current,
                activeFileId: nextActiveCaseId,
              }
        );
      }
    },
    [
      activeCaseId,
      filesById,
      selectedFolderCaseContainerId,
      selectedFolderPath,
      setWorkspace,
      workspace.folderRecords,
    ]
  );

  const canCreateInActiveCase = useMemo(
    (): boolean =>
      isCaseResolverCreateContextReady({
        activeCaseId,
        requestedFileId,
        requestedCaseStatus,
      }),
    [activeCaseId, requestedCaseStatus, requestedFileId]
  );

  const requestedFileExists = useMemo(
    (): boolean =>
      Boolean(
        requestedFileId &&
        workspace.files.some((file: CaseResolverFile): boolean => file.id === requestedFileId)
      ),
    [requestedFileId, workspace.files]
  );

  useEffect(() => {
    const resolution = resolveRequestedFileSyncResolution({
      requestedFileId,
      requestedFileExists,
      handledRequestedFileId: handledRequestedFileIdRef.current,
      selectedFileId,
      selectedAssetId,
      selectedFolderPath,
      activeFileId: workspace.activeFileId,
    });

    handledRequestedFileIdRef.current = resolution.nextHandledRequestedFileId;
    if (resolution.nextSelectedFileId !== undefined) {
      setSelectedFileId(resolution.nextSelectedFileId);
    }
    if (resolution.shouldClearSelectedAsset) {
      setSelectedAssetId(null);
    }
    if (resolution.shouldClearSelectedFolder) {
      setSelectedFolderPath(null);
    }
    const nextActiveFileId = resolution.nextActiveFileId;
    if (nextActiveFileId !== undefined) {
      setWorkspace((current: CaseResolverWorkspace): CaseResolverWorkspace => {
        if (current.activeFileId === nextActiveFileId) return current;
        const nextWorkspace = {
          ...current,
          activeFileId: nextActiveFileId,
        };
        syncPersistedWorkspaceTracking(nextWorkspace);
        clearQueuedWorkspacePersistMutation();
        return nextWorkspace;
      });
    }
  }, [
    clearQueuedWorkspacePersistMutation,
    requestedFileExists,
    requestedFileId,
    selectedAssetId,
    selectedFileId,
    selectedFolderPath,
    syncPersistedWorkspaceTracking,
    workspace.activeFileId,
    setWorkspace,
    handledRequestedFileIdRef,
  ]);

  return {
    selectedFileId,
    setSelectedFileId,
    selectedFolderPath,
    setSelectedFolderPath,
    selectedAssetId,
    setSelectedAssetId,
    folderPanelCollapsed,
    setFolderPanelCollapsed,
    activeMainView,
    setActiveMainView,
    isPreviewPageVisible,
    setIsPreviewPageVisible,
    isPartiesModalOpen,
    setIsPartiesModalOpen,
    handleSelectFile,
    handleSelectAsset,
    handleSelectFolder,
    activeCaseId,
    canCreateInActiveCase,
    requestedFileExists,
  };
}

'use client';

import { useEffect, useMemo, useRef } from 'react';

import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { Toast } from '@/shared/contracts/ui/base';

import { collectCaseScopeIds } from './useCaseResolverState.helpers';
import { resolveCaseResolverTreeWorkspace } from '../components/case-resolver-tree-workspace';
import { getCachedCaseResolverRuntimeIndexes } from '../runtime';
import { getCaseResolverWorkspaceNormalizationDiagnostics } from '../settings';
import {
  getCaseResolverWorkspaceRevision,
  logCaseResolverWorkspaceEvent,
} from '../workspace-persistence';

export interface UseCaseResolverWorkspaceDiagnosticsValue {
  treeWorkspace: CaseResolverWorkspace;
  selectedCaseScopeIds: Set<string> | null;
  workspaceIndexes: ReturnType<typeof getCachedCaseResolverRuntimeIndexes>;
  workspaceNormalizationDiagnostics: ReturnType<
    typeof getCaseResolverWorkspaceNormalizationDiagnostics
  >;
}

export function useCaseResolverStateWorkspaceDiagnostics({
  workspace,
  activeCaseId,
  selectedFileId,
  requestedFileId,
  toast,
}: {
  workspace: CaseResolverWorkspace;
  activeCaseId: string | null;
  selectedFileId: string | null;
  requestedFileId: string | null;
  toast: Toast;
}): UseCaseResolverWorkspaceDiagnosticsValue {
  const unresolvedOwnershipWarningShownRef = useRef(false);
  const lastLoggedOwnershipDiagnosticsSignatureRef = useRef<string>('');

  const selectedCaseScopeIds = useMemo(
    (): Set<string> | null => collectCaseScopeIds(workspace.files, activeCaseId),
    [activeCaseId, workspace.files]
  );

  const workspaceIndexes = useMemo(
    () => getCachedCaseResolverRuntimeIndexes(workspace),
    [workspace.assets, workspace.files, workspace.folderRecords, workspace.folders]
  );

  const workspaceNormalizationDiagnostics = useMemo(
    () => getCaseResolverWorkspaceNormalizationDiagnostics(workspace),
    [workspace]
  );

  const treeWorkspace = useMemo(
    (): CaseResolverWorkspace =>
      resolveCaseResolverTreeWorkspace({
        selectedFileId,
        requestedFileId,
        activeCaseId,
        workspace,
        indexes: workspaceIndexes,
      }),
    [activeCaseId, requestedFileId, selectedFileId, workspace, workspaceIndexes]
  );

  const unresolvedOwnershipInActiveScopeCount = useMemo((): number => {
    if (!activeCaseId) return 0;
    const scopedWorkspace = resolveCaseResolverTreeWorkspace({
      selectedFileId: activeCaseId,
      requestedFileId: null,
      activeCaseId,
      workspace,
      includeDescendantCaseScope: true,
      indexes: workspaceIndexes,
    });
    return scopedWorkspace.files.filter(
      (file: CaseResolverFile): boolean => file.fileType !== 'case' && !file.parentCaseId
    ).length;
  }, [activeCaseId, workspace, workspaceIndexes]);

  useEffect((): void => {
    const diagnosticsSignature = [
      getCaseResolverWorkspaceRevision(workspace),
      workspaceNormalizationDiagnostics.ownershipRepairedCount,
      workspaceNormalizationDiagnostics.ownershipUnresolvedCount,
      workspaceNormalizationDiagnostics.droppedDuplicateCount,
    ].join(':');
    if (lastLoggedOwnershipDiagnosticsSignatureRef.current === diagnosticsSignature) return;
    lastLoggedOwnershipDiagnosticsSignatureRef.current = diagnosticsSignature;
    logCaseResolverWorkspaceEvent({
      source: 'case_view',
      action: 'ownership_normalization_state',
      workspaceRevision: getCaseResolverWorkspaceRevision(workspace),
      message: [
        `ownership_repaired_count=${workspaceNormalizationDiagnostics.ownershipRepairedCount}`,
        `ownership_unresolved_count=${workspaceNormalizationDiagnostics.ownershipUnresolvedCount}`,
        `dropped_duplicate_count=${workspaceNormalizationDiagnostics.droppedDuplicateCount}`,
      ].join(' '),
    });
  }, [workspace, workspaceNormalizationDiagnostics]);

  useEffect((): void => {
    if (unresolvedOwnershipInActiveScopeCount <= 0) return;
    if (unresolvedOwnershipWarningShownRef.current) return;
    unresolvedOwnershipWarningShownRef.current = true;
    toast('Some documents have unresolved ownership and appear under Unassigned.', {
      variant: 'warning',
    });
  }, [toast, unresolvedOwnershipInActiveScopeCount]);

  return {
    treeWorkspace,
    selectedCaseScopeIds,
    workspaceIndexes,
    workspaceNormalizationDiagnostics,
  };
}

'use client';

import { useEffect, useRef, useState } from 'react';

import { safeSetTimeout, safeClearTimeout, type SafeTimerId } from '@/shared/lib/timers';

import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { logCaseResolverDurationMetric } from '../runtime/metrics';
import {
  fetchCaseResolverWorkspaceRecord,
  fetchCaseResolverWorkspaceIfStale,
  getCaseResolverWorkspaceRevision,
  logCaseResolverWorkspaceEvent,
} from '../workspace-persistence';
import { shouldAdoptIncomingWorkspace } from './useCaseResolverState.helpers.hydration';

export function useCaseResolverStateWorkspaceHydration({
  workspaceRef,
  setWorkspace,
  isMountedRef,
  requestedFileId,
  canHydrateWorkspaceFromStore,
  preferredWorkspaceSource,
  preferredWorkspaceReason,
  hasWorkspaceFromStore,
  parsedWorkspace,
  isApplyingPromptExploderPartyProposal,
  syncPersistedWorkspaceTracking,
  clearQueuedWorkspacePersistMutation,
  isPromptExploderReturnFlow,
}: {
  workspaceRef: React.MutableRefObject<CaseResolverWorkspace>;
  setWorkspace: React.Dispatch<React.SetStateAction<CaseResolverWorkspace>>;
  isMountedRef: React.MutableRefObject<boolean>;
  requestedFileId: string | null;
  canHydrateWorkspaceFromStore: boolean;
  preferredWorkspaceSource: string;
  preferredWorkspaceReason: string;
  hasWorkspaceFromStore: boolean;
  parsedWorkspace: CaseResolverWorkspace;
  isApplyingPromptExploderPartyProposal: boolean;
  syncPersistedWorkspaceTracking: (workspace: CaseResolverWorkspace) => void;
  clearQueuedWorkspacePersistMutation: () => void;
  isPromptExploderReturnFlow: boolean;
}): void {
  const [bootstrapRefreshRetryTick, setBootstrapRefreshRetryTick] = useState(0);
  const bootstrapRefreshRetryAttemptRef = useRef(0);
  const bootstrapRefreshRetryTimerRef = useRef<SafeTimerId | null>(null);
  const lastWorkspaceSourceSelectionSignatureRef = useRef<string>('');

  useEffect((): void => {
    const selectionSignature = [
      preferredWorkspaceSource,
      preferredWorkspaceReason,
      hasWorkspaceFromStore ? 'store:1' : 'store:0',
      getCaseResolverWorkspaceRevision(parsedWorkspace),
    ].join('|');
    if (lastWorkspaceSourceSelectionSignatureRef.current === selectionSignature) return;
    lastWorkspaceSourceSelectionSignatureRef.current = selectionSignature;
    logCaseResolverWorkspaceEvent({
      source: 'case_view',
      action: 'hydrate_workspace_source_selected',
      workspaceRevision: getCaseResolverWorkspaceRevision(parsedWorkspace),
      message: [
        `source=${preferredWorkspaceSource}`,
        `reason=${preferredWorkspaceReason}`,
        `has_store=${hasWorkspaceFromStore ? 'true' : 'false'}`,
      ].join(' '),
    });
  }, [hasWorkspaceFromStore, parsedWorkspace, preferredWorkspaceReason, preferredWorkspaceSource]);

  useEffect(() => {
    const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
    const workspaceHasTreeData =
      workspaceRef.current.files.length > 0 ||
      workspaceRef.current.assets.length > 0 ||
      workspaceRef.current.folders.length > 0;
    const requestedFileResolvedInWorkspace =
      normalizedRequestedFileId.length === 0
        ? true
        : workspaceRef.current.files.some((file): boolean => file.id === normalizedRequestedFileId);
    if (workspaceHasTreeData && requestedFileResolvedInWorkspace) return;
    const shouldBootstrapRefresh =
      !canHydrateWorkspaceFromStore ||
      preferredWorkspaceSource === 'store' ||
      !requestedFileResolvedInWorkspace;
    if (!shouldBootstrapRefresh) return;
    let cancelled = false;
    void (async (): Promise<void> => {
      const bootstrapStartedAtMs = Date.now();
      const finishBootstrap = (message?: string): void => {
        logCaseResolverDurationMetric('case_open_bootstrap_ms', Date.now() - bootstrapStartedAtMs, {
          source: 'case_view_bootstrap',
          minDurationMs: 1,
          message,
        });
      };
      const currentRevision = getCaseResolverWorkspaceRevision(workspaceRef.current);
      let snapshot: CaseResolverWorkspace | null = null;

      if (isPromptExploderReturnFlow) {
        snapshot = await fetchCaseResolverWorkspaceRecord('case_view_bootstrap', {
          requiredFileId: requestedFileId,
          attemptProfile: 'context_fast',
          maxTotalMs: 6_500,
          attemptTimeoutMs: 2_200,
          includeDetachedHistory: true,
          includeDetachedDocuments: true,
        });
      } else {
        const result = await fetchCaseResolverWorkspaceIfStale(
          'case_view_bootstrap',
          currentRevision,
          {
            includeDetachedHistory: true,
            includeDetachedDocuments: true,
            requiredFileId: requestedFileId,
          }
        );
        if (result.updated) {
          snapshot = result.workspace;
        }
      }
      if (!isMountedRef.current || cancelled) return;
      if (!snapshot) {
        finishBootstrap('snapshot_unavailable');
        if (canHydrateWorkspaceFromStore && requestedFileResolvedInWorkspace) {
          logCaseResolverWorkspaceEvent({
            source: 'case_view_bootstrap',
            action: 'refresh_failed_no_retry',
            message:
              'Bootstrap refresh failed while store snapshot is available; skipping retry loop.',
          });
          return;
        }
        if (bootstrapRefreshRetryTimerRef.current !== null) {
          safeClearTimeout(bootstrapRefreshRetryTimerRef.current);
        }
        const nextAttempt = bootstrapRefreshRetryAttemptRef.current + 1;
        bootstrapRefreshRetryAttemptRef.current = nextAttempt;
        const retryDelayMs = Math.min(10_000, 700 * nextAttempt);
        bootstrapRefreshRetryTimerRef.current = safeSetTimeout((): void => {
          bootstrapRefreshRetryTimerRef.current = null;
          setBootstrapRefreshRetryTick((current: number): number => current + 1);
        }, retryDelayMs);
        logCaseResolverWorkspaceEvent({
          source: 'case_view_bootstrap',
          action: 'refresh_retry_scheduled',
          message: `retry_in_ms=${retryDelayMs} attempt=${nextAttempt}`,
        });
        return;
      }
      finishBootstrap(`snapshot_revision=${getCaseResolverWorkspaceRevision(snapshot)}`);
      bootstrapRefreshRetryAttemptRef.current = 0;
      if (bootstrapRefreshRetryTimerRef.current !== null) {
        safeClearTimeout(bootstrapRefreshRetryTimerRef.current);
        bootstrapRefreshRetryTimerRef.current = null;
      }
      setWorkspace((current: CaseResolverWorkspace): CaseResolverWorkspace => {
        const hydrationDecision = shouldAdoptIncomingWorkspace({
          current,
          incoming: snapshot,
          requestedFileId,
        });
        if (!hydrationDecision.adopt) return current;
        if (hydrationDecision.reason === 'equal_revision_current_placeholder') {
          logCaseResolverWorkspaceEvent({
            source: 'case_view_bootstrap',
            action: 'refresh_equal_revision_adopted',
            workspaceRevision: getCaseResolverWorkspaceRevision(snapshot),
            message:
              'Adopted equal-revision workspace snapshot because current workspace was placeholder.',
          });
        }
        syncPersistedWorkspaceTracking(snapshot);
        clearQueuedWorkspacePersistMutation();
        return snapshot;
      });
    })();
    return (): void => {
      cancelled = true;
    };
  }, [
    bootstrapRefreshRetryTick,
    canHydrateWorkspaceFromStore,
    clearQueuedWorkspacePersistMutation,
    isMountedRef,
    preferredWorkspaceSource,
    requestedFileId,
    setWorkspace,
    syncPersistedWorkspaceTracking,
    workspaceRef,
    isPromptExploderReturnFlow,
  ]);

  useEffect(() => {
    if (!canHydrateWorkspaceFromStore) return;
    if (isApplyingPromptExploderPartyProposal) return;
    setWorkspace((current: CaseResolverWorkspace): CaseResolverWorkspace => {
      const hydrationDecision = shouldAdoptIncomingWorkspace({
        current,
        incoming: parsedWorkspace,
        requestedFileId,
      });
      if (!hydrationDecision.adopt) return current;
      if (hydrationDecision.reason === 'equal_revision_current_placeholder') {
        logCaseResolverWorkspaceEvent({
          source: 'case_view_sync',
          action: 'refresh_equal_revision_adopted',
          workspaceRevision: getCaseResolverWorkspaceRevision(parsedWorkspace),
          message:
            'Adopted equal-revision workspace from settings store because current workspace was placeholder.',
        });
      }

      syncPersistedWorkspaceTracking(parsedWorkspace);
      clearQueuedWorkspacePersistMutation();
      return parsedWorkspace;
    });
  }, [
    canHydrateWorkspaceFromStore,
    clearQueuedWorkspacePersistMutation,
    isApplyingPromptExploderPartyProposal,
    parsedWorkspace,
    requestedFileId,
    setWorkspace,
    syncPersistedWorkspaceTracking,
  ]);

  useEffect(() => {
    return (): void => {
      if (bootstrapRefreshRetryTimerRef.current) {
        safeClearTimeout(bootstrapRefreshRetryTimerRef.current);
        bootstrapRefreshRetryTimerRef.current = null;
      }
    };
  }, []);
}

'use client';

import { useCallback, useEffect, useMemo } from 'react';

import { safeSetTimeout, safeClearTimeout } from '@/shared/lib/timers';

import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { normalizeCaseResolverWorkspace } from '../settings';
import {
  createCaseResolverWorkspaceMutationId,
  getCaseResolverWorkspaceRevision,
  logCaseResolverWorkspaceEvent,
  primeCaseResolverNavigationWorkspace,
  stampCaseResolverWorkspaceMutation,
} from '../workspace-persistence';
import { serializeWorkspaceForUnsavedChangesCheck } from './useCaseResolverState.helpers';

import type { UseCaseResolverPersistenceValue } from './useCaseResolverState.persistence-actions';

export type CaseResolverWorkspaceUpdateOptions = {
  persistToast?: string;
  persistNow?: boolean;
  mutationId?: string;
  source?: string;
  skipNormalization?: boolean;
};

export interface UseCaseResolverWorkspaceMutationsValue {
  updateWorkspace: (
    updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
    options?: CaseResolverWorkspaceUpdateOptions
  ) => void;
}

export function useCaseResolverStateWorkspaceMutations({
  workspace,
  setWorkspace,
  persistedWorkspaceComparableSnapshot,
  persistence,
}: {
  workspace: CaseResolverWorkspace;
  setWorkspace: React.Dispatch<React.SetStateAction<CaseResolverWorkspace>>;
  persistedWorkspaceComparableSnapshot: string;
  persistence: UseCaseResolverPersistenceValue;
}): UseCaseResolverWorkspaceMutationsValue {
  const {
    queuedExpectedRevisionRef,
    lastPersistedRevisionRef,
    pendingSaveToastRef,
    enqueueWorkspacePersistMutation,
    flushWorkspacePersist,
    clearConflictRetryTimer,
    persistWorkspaceTimerRef,
    isWorkspaceSaving,
    setWorkspaceSaveStatus,
    setWorkspaceSaveError,
  } = persistence;

  const updateWorkspace = useCallback(
    (
      updater: (current: CaseResolverWorkspace) => CaseResolverWorkspace,
      options?: CaseResolverWorkspaceUpdateOptions
    ): void => {
      setWorkspace((current: CaseResolverWorkspace) => {
        const baseCurrent = options?.skipNormalization
          ? current
          : normalizeCaseResolverWorkspace(current);
        const updated = updater(baseCurrent);
        if (updated === current || updated === baseCurrent) return current;
        const normalizedUpdated = options?.skipNormalization
          ? updated
          : normalizeCaseResolverWorkspace(updated);
        const mutationId =
          options?.mutationId?.trim() ||
          createCaseResolverWorkspaceMutationId('case-resolver-workspace');
        const stampedWorkspace = stampCaseResolverWorkspaceMutation(normalizedUpdated, {
          baseRevision: getCaseResolverWorkspaceRevision(baseCurrent),
          mutationId,
          normalizeWorkspace: !options?.skipNormalization,
        });
        logCaseResolverWorkspaceEvent({
          source: options?.source ?? 'case_view',
          action: 'mutation_enqueued',
          mutationId,
          expectedRevision: queuedExpectedRevisionRef.current ?? lastPersistedRevisionRef.current,
          workspaceRevision: getCaseResolverWorkspaceRevision(stampedWorkspace),
        });
        primeCaseResolverNavigationWorkspace(stampedWorkspace);
        if (options?.persistToast) {
          pendingSaveToastRef.current = options.persistToast;
        }
        const expectedRevision =
          queuedExpectedRevisionRef.current ?? lastPersistedRevisionRef.current;
        enqueueWorkspacePersistMutation({
          serializedWorkspace: JSON.stringify(stampedWorkspace),
          expectedRevision,
          mutationId,
        });
        return stampedWorkspace;
      });
      if (options?.persistToast || options?.persistNow) {
        safeSetTimeout((): void => {
          flushWorkspacePersist();
        }, 0);
      }
    },
    [
      enqueueWorkspacePersistMutation,
      flushWorkspacePersist,
      lastPersistedRevisionRef,
      pendingSaveToastRef,
      queuedExpectedRevisionRef,
      setWorkspace,
    ]
  );

  useEffect(() => {
    return (): void => {
      clearConflictRetryTimer();
      if (persistWorkspaceTimerRef.current) {
        safeClearTimeout(persistWorkspaceTimerRef.current);
        persistWorkspaceTimerRef.current = null;
      }
    };
  }, [clearConflictRetryTimer, persistWorkspaceTimerRef]);

  const workspaceComparableSnapshot = useMemo(
    (): string => serializeWorkspaceForUnsavedChangesCheck(workspace),
    [workspace]
  );
  const isWorkspaceDirty = useMemo(
    (): boolean => workspaceComparableSnapshot !== persistedWorkspaceComparableSnapshot,
    [persistedWorkspaceComparableSnapshot, workspaceComparableSnapshot]
  );

  useEffect(() => {
    if (isWorkspaceSaving) return;
    if (isWorkspaceDirty) {
      setWorkspaceSaveStatus((current) =>
        current === 'conflict' || current === 'error' ? current : 'dirty'
      );
      return;
    }
    setWorkspaceSaveStatus('saved');
    setWorkspaceSaveError(null);
  }, [isWorkspaceDirty, isWorkspaceSaving, setWorkspaceSaveError, setWorkspaceSaveStatus]);

  return {
    updateWorkspace,
  };
}

'use client';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
  useCanvasActions,
  useCanvasRefs,
  useCanvasState,
  useGraphActions,
  useGraphState,
  useSelectionActions,
  useSelectionState,
} from '@/features/ai/public';
import type { AiNode } from '@/shared/contracts/case-resolver/../ai-paths-core';
import type { CaseResolverNodeMeta, CaseResolverEdgeMeta, CaseResolverNodeFileSnapshot, CaseResolverSnapshotNodeMeta as CaseResolverNodeFileMeta } from '@/shared/contracts/case-resolver/graph';
import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverCompileResult } from '@/shared/contracts/case-resolver/capture';

import {
  useCaseResolverPageActions,
  useCaseResolverPageState,
} from '../context/CaseResolverPageContext';
import { useDocumentRelationSearch } from '../relation-search/hooks/useDocumentRelationSearch';
