  return (
    <AdminCaseResolverPageLayout
      title='Case Resolver Categories'
      current='Categories'
      headerActions={
        <Button
          onClick={(): void => {
            openCreateModal(null);
          }}
          variant='outline'
          className='border-border/70 bg-transparent text-white hover:bg-muted/40'
