const createCaseIdentifierId = (): string => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return `case-identifier-${crypto.randomUUID()}`;
  }
  return `case-identifier-${Math.random().toString(36).slice(2, 10)}`;
};

type CaseIdentifierPathOption = {
  id: string;
  label: string;
  pathIds: string[];
};

const buildCaseIdentifierPathOptions = (
  identifiers: CaseResolverIdentifier[]
): CaseIdentifierPathOption[] => {
  const byId = new Map<string, CaseResolverIdentifier>(
    identifiers.map((identifier: CaseResolverIdentifier): [string, CaseResolverIdentifier] => [
      identifier.id,
      identifier,
    ])
  );
  const cache = new Map<string, { ids: string[]; names: string[] }>();

  const resolvePath = (
    caseIdentifierId: string,
    trail: Set<string>
  ): { ids: string[]; names: string[] } => {
    const cached = cache.get(caseIdentifierId);
    if (cached) return cached;
    const identifier = byId.get(caseIdentifierId);
    if (!identifier) return { ids: [], names: [] };
    if (trail.has(caseIdentifierId)) {
      const fallback = { ids: [identifier.id], names: [identifier.name ?? identifier.value] };
      cache.set(caseIdentifierId, fallback);
      return fallback;
    }

    if (!identifier.parentId || !byId.has(identifier.parentId)) {
      const rootPath = { ids: [identifier.id], names: [identifier.name ?? identifier.value] };
      cache.set(caseIdentifierId, rootPath);
      return rootPath;
    }

    const nextTrail = new Set(trail);
    nextTrail.add(caseIdentifierId);
    const parentPath = resolvePath(identifier.parentId, nextTrail);
    const fullPath = {
      ids: [...parentPath.ids, identifier.id],
      names: [...parentPath.names, identifier.name ?? identifier.value],
    };
    cache.set(caseIdentifierId, fullPath);
    return fullPath;
  };

  return identifiers
    .map((identifier: CaseResolverIdentifier): CaseIdentifierPathOption => {
      const path = resolvePath(identifier.id, new Set<string>());
      return {
        id: identifier.id,
        label: path.names.join(' / '),
        pathIds: path.ids,
      };
    })
    .sort((left: CaseIdentifierPathOption, right: CaseIdentifierPathOption) =>
      left.label.localeCompare(right.label)
    );
};

const collectDescendantCaseIdentifierIds = (
  identifiers: CaseResolverIdentifier[],
  rootCaseIdentifierId: string
): Set<string> => {
  const descendants = new Set<string>([rootCaseIdentifierId]);
  let expanded = true;
  while (expanded) {
    expanded = false;
    identifiers.forEach((identifier: CaseResolverIdentifier): void => {
      if (!identifier.parentId || descendants.has(identifier.id)) return;
      if (!descendants.has(identifier.parentId)) return;
      descendants.add(identifier.id);
      expanded = true;
    });
  }
  return descendants;
};

export function AdminCaseResolverIdentifiersPage(): React.JSX.Element {
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();

  const rawCaseIdentifiers = settingsStore.get(CASE_RESOLVER_IDENTIFIERS_KEY);
  const caseIdentifiers = useMemo(
    (): CaseResolverIdentifier[] => parseCaseResolverIdentifiers(rawCaseIdentifiers),
    [rawCaseIdentifiers]
  );

  const [showModal, setShowModal] = useState(false);
  const [editingCaseIdentifier, setEditingCaseIdentifier] = useState<CaseResolverIdentifier | null>(
    null
  );
  const [caseIdentifierToDelete, setCaseIdentifierToDelete] =
    useState<CaseResolverIdentifier | null>(null);
  const [formData, setFormData] = useState<CaseResolverIdentifierFormData>({
    name: '',
    color: '#f59e0b',
    parentId: null,
  });
  const caseIdentifierPathOptions = useMemo(
    (): CaseIdentifierPathOption[] => buildCaseIdentifierPathOptions(caseIdentifiers),
    [caseIdentifiers]
  );
  const caseIdentifierPathById = useMemo(() => {
    const map = new Map<string, string>();
    caseIdentifierPathOptions.forEach((option: CaseIdentifierPathOption): void => {
      map.set(option.id, option.label);
    });
    return map;
  }, [caseIdentifierPathOptions]);
  const blockedParentIds = useMemo(
    () =>
      editingCaseIdentifier
        ? collectDescendantCaseIdentifierIds(caseIdentifiers, editingCaseIdentifier.id)
        : new Set<string>(),
    [editingCaseIdentifier, caseIdentifiers]
  );
  const parentCaseIdentifierOptions = useMemo(
    () =>
      caseIdentifierPathOptions
        .filter((option: CaseIdentifierPathOption): boolean => !blockedParentIds.has(option.id))
        .map((option: CaseIdentifierPathOption) => ({
          value: option.id,
          label: option.label,
        })),
    [blockedParentIds, caseIdentifierPathOptions]
  );

  const openCreateModal = (): void => {
    setEditingCaseIdentifier(null);
    setFormData({ name: '', color: '#f59e0b', parentId: null });
    setShowModal(true);
  };

  const openEditModal = (caseIdentifier: CaseResolverIdentifier): void => {
    setEditingCaseIdentifier(caseIdentifier);
    setFormData({
      name: caseIdentifier.name ?? caseIdentifier.value,
      color: caseIdentifier.color ?? '',
      parentId: caseIdentifier.parentId ?? null,
    });
    setShowModal(true);
  };

  const handleSave = useCallback(async (): Promise<void> => {
    const normalizedName = formData.name.trim();
    if (!normalizedName) {
      toast('Case identifier name is required.', { variant: 'error' });
      return;
    }

    const now = new Date().toISOString();
    const normalizedParentId =
      formData.parentId && formData.parentId !== editingCaseIdentifier?.id
        ? formData.parentId
        : null;
    const nextCaseIdentifier: CaseResolverIdentifier = editingCaseIdentifier
      ? {
        ...editingCaseIdentifier,
        name: normalizedName,
        parentId: normalizedParentId,
        color: formData.color.trim() || '#f59e0b',
        updatedAt: now,
      }
      : {
        id: createCaseIdentifierId(),
        type: 'custom',
        value: normalizedName,
        name: normalizedName,
        parentId: normalizedParentId,
        color: formData.color.trim() || '#f59e0b',
        createdAt: now,
        updatedAt: now,
      };
    const nextCaseIdentifiers = editingCaseIdentifier
      ? caseIdentifiers.map((caseIdentifier: CaseResolverIdentifier) =>
        caseIdentifier.id === editingCaseIdentifier.id ? nextCaseIdentifier : caseIdentifier
      )
      : [...caseIdentifiers, nextCaseIdentifier];

    try {
      await updateSetting.mutateAsync({
        key: CASE_RESOLVER_IDENTIFIERS_KEY,
        value: serializeSetting(nextCaseIdentifiers),
      });
      toast(editingCaseIdentifier ? 'Case identifier updated.' : 'Case identifier created.', {
        variant: 'success',
      });
      setShowModal(false);
    } catch (error) {
      logClientCatch(error, {
        source: 'AdminCaseResolverIdentifiersPage',
        action: 'saveCaseIdentifier',
        caseIdentifierId: editingCaseIdentifier?.id,
      });
      toast(error instanceof Error ? error.message : 'Failed to save case identifier.', {
        variant: 'error',
      });
    }
  }, [
    caseIdentifiers,
    editingCaseIdentifier,
    formData.color,
    formData.name,
    formData.parentId,
    toast,
    updateSetting,
  ]);

  const handleConfirmDelete = useCallback(async (): Promise<void> => {
    if (!caseIdentifierToDelete) return;
    const now = new Date().toISOString();
    const nextCaseIdentifiers = caseIdentifiers
      .filter(
        (caseIdentifier: CaseResolverIdentifier) => caseIdentifier.id !== caseIdentifierToDelete.id
      )
      .map(
        (caseIdentifier: CaseResolverIdentifier): CaseResolverIdentifier =>
          caseIdentifier.parentId === caseIdentifierToDelete.id
            ? {
              ...caseIdentifier,
              parentId: null,
              updatedAt: now,
            }
            : caseIdentifier
      );
    try {
      await updateSetting.mutateAsync({
        key: CASE_RESOLVER_IDENTIFIERS_KEY,
        value: serializeSetting(nextCaseIdentifiers),
      });
      toast('Case identifier deleted.', { variant: 'success' });
    } catch (error) {
      logClientCatch(error, {
        source: 'AdminCaseResolverIdentifiersPage',
        action: 'deleteCaseIdentifier',
        caseIdentifierId: caseIdentifierToDelete.id,
      });
      toast(error instanceof Error ? error.message : 'Failed to delete case identifier.', {
        variant: 'error',
      });
    } finally {
      setCaseIdentifierToDelete(null);
    }
  }, [caseIdentifierToDelete, caseIdentifiers, toast, updateSetting]);

  return (
    <AdminCaseResolverPageLayout
      title='Case Resolver Case Identifiers'
      current='Case Identifiers'
      headerActions={
        <Button
          onClick={openCreateModal}
          variant='outline'
          className='border-border/70 bg-transparent text-white hover:bg-muted/40'
        >
          <Plus className='mr-2 size-4' />
          Add Case Identifier
        </Button>
      }
      containerClassName='page-section-compact'
    >

      <FormSection title='Case Identifiers' className='p-4'>
        <div className='mt-4'>
          {settingsStore.isLoading ? (
            <div className='space-y-2'>
              <Skeleton className='h-8 w-full' />
              <Skeleton className='h-8 w-full' />
              <Skeleton className='h-8 w-full' />
            </div>
          ) : (
            <SimpleSettingsList
              items={caseIdentifiers.map((id: CaseResolverIdentifier) => ({
                id: id.id,
                title: (
                  <div className='flex items-center gap-2'>
                    <UiTag label={id.name ?? id.value} color={id.color || '#f59e0b'} dot />
                  </div>
                ),
                description: caseIdentifierPathById.get(id.id) ?? id.name,
                original: id,
              }))}
              isLoading={settingsStore.isLoading}
              onEdit={(item) => openEditModal(item.original)}
              onDelete={(item) => setCaseIdentifierToDelete(item.original)}
              emptyMessage='No case identifiers yet. Create case identifiers to classify Case Resolver documents.'
              columns={2}
            />
          )}
        </div>
      </FormSection>

      <ConfirmModal
        isOpen={Boolean(caseIdentifierToDelete)}
        onClose={() => setCaseIdentifierToDelete(null)}
        onConfirm={handleConfirmDelete}
        title='Delete Case Identifier'
        message={`Delete case identifier "${caseIdentifierToDelete?.name ?? ''}"? This action cannot be undone.`}
        confirmText='Delete'
        isDangerous={true}
      />

      <CaseResolverIdentifierModal
        isOpen={showModal}
        onClose={(): void => setShowModal(false)}
        onSuccess={(): void => {}}
        item={editingCaseIdentifier}
        formData={formData}
        setFormData={setFormData}
        parentIdentifierOptions={parentCaseIdentifierOptions}
        isSaving={updateSetting.isPending}
        onSave={(): void => {
          void handleSave();
        }}
      />
    </AdminCaseResolverPageLayout>
  );
}

'use client';

import { ArrowLeft, RefreshCcw, Settings2 } from 'lucide-react';
import Link from 'next/link';
import React, { useEffect, useMemo, useState } from 'react';

import type { LabeledOptionWithDescriptionDto } from '@/shared/contracts/base';
import type { CaseResolverOcrModelsResponse } from '@/shared/contracts/case-resolver/ocr';
import type { CaseResolverSettings } from '@/shared/contracts/case-resolver/workspace';
import { useSettingsMap, useUpdateSettingsBulk } from '@/shared/hooks/use-settings';
import { api } from '@/shared/lib/api-client';
import { useListQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { AdminAiEyebrow, AdminCaseResolverBreadcrumbs } from '@/shared/ui/admin.public';
import { Badge, Button, Input, Textarea, useToast } from '@/shared/ui/primitives.public';
import { FormField, FormSection, SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { SectionHeader } from '@/shared/ui/navigation-and-layout.public';
import { serializeSetting } from '@/shared/utils/settings-json';

import { isLikelyCaseResolverOcrCapableModelId } from '../ocr-models';
import {
  detectCaseResolverOcrProvider,
  resolveCaseResolverOcrProviderLabel,
} from '../ocr-provider';
import {
  CASE_RESOLVER_CONFIRM_DELETE_OPTIONS,
  CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_KEY,
  CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_OPTIONS,
  CASE_RESOLVER_PARTY_SEARCH_KIND_OPTIONS,
  CASE_RESOLVER_SETTINGS_KEY,
  parseCaseResolverDefaultDocumentFormat,
  parseCaseResolverSettings,
} from '../settings';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export function AdminCaseResolverSettingsPage(): React.JSX.Element {
  const { toast } = useToast();
  const settingsQuery = useSettingsMap({ scope: 'light' });
  const updateSettingsBulk = useUpdateSettingsBulk();
  const modelsQuery = useListQueryV2<
    CaseResolverOcrModelsResponse,
    CaseResolverOcrModelsResponse
  >({
    queryKey: QUERY_KEYS.ai.chatbot.caseResolverOcrModels(),
    queryFn: ({ signal }) =>
      api.get<CaseResolverOcrModelsResponse>('/api/case-resolver/ocr/models', { signal }),
    staleTime: 60_000,
    refetchOnMount: false,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    meta: {
      source: 'case-resolver.settings.models-query',
      operation: 'list',
      resource: 'case-resolver.ocr.models',
      domain: 'global',
      tags: ['case-resolver', 'settings', 'ocr-models'],
      description: 'Loads case resolver ocr models.'},
  });

  const [draft, setDraft] = useState<CaseResolverSettings | null>(null);
  const [loadedFrom, setLoadedFrom] = useState<string | null>(null);

  const rawSettings = settingsQuery.data?.get(CASE_RESOLVER_SETTINGS_KEY) ?? null;
  const rawDefaultDocumentFormat =
    settingsQuery.data?.get(CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_KEY) ?? null;
  const openaiModelFallback = (settingsQuery.data?.get('openai_model') ?? '').trim();
  const parsedSettings = useMemo((): CaseResolverSettings => {
    const parsedBase = parseCaseResolverSettings(rawSettings);
    const defaultDocumentFormat = parseCaseResolverDefaultDocumentFormat(
      rawDefaultDocumentFormat,
      parsedBase.defaultDocumentFormat
    );
    const parsed =
      defaultDocumentFormat === parsedBase.defaultDocumentFormat
        ? parsedBase
        : {
          ...parsedBase,
          defaultDocumentFormat,
        };
    if (!parsed.ocrModel && openaiModelFallback) {
      return {
        ...parsed,
        ocrModel: openaiModelFallback,
      };
    }
    return parsed;
  }, [openaiModelFallback, rawDefaultDocumentFormat, rawSettings]);
  const hydrationSignature = `${rawSettings ?? ''}|${rawDefaultDocumentFormat ?? ''}|${openaiModelFallback}`;

  useEffect(() => {
    if (loadedFrom === hydrationSignature && draft) return;
    setDraft(parsedSettings);
    setLoadedFrom(hydrationSignature);
  }, [hydrationSignature, loadedFrom, parsedSettings]);

  const modelOptions = useMemo(() => {
    const options: Array<LabeledOptionWithDescriptionDto<string> & { group: string }> = [];
    const seen = new Set<string>();
    const resolveModelGroup = (modelId: string): string =>
      detectCaseResolverOcrProvider(modelId) === 'ollama' ? 'Ollama models' : 'Other models';
    const append = (values: string[], source: string, group?: string): void => {
      values.forEach((value: string) => {
        const trimmed = value.trim();
        if (!trimmed || seen.has(trimmed)) return;
        if (!isLikelyCaseResolverOcrCapableModelId(trimmed)) return;
        seen.add(trimmed);
        options.push({
          value: trimmed,
          label: trimmed,
          description: source,
          group: group ?? resolveModelGroup(trimmed),
        });
      });
    };

    append(modelsQuery.data?.ollamaModels ?? [], 'local Ollama OCR models', 'Ollama models');
    append(modelsQuery.data?.otherModels ?? [], 'OCR models from API providers', 'Other models');
    append([openaiModelFallback], 'system openai_model');
    if (draft?.ocrModel) {
      append([draft.ocrModel], 'current OCR model');
    }

    return options;
  }, [
    draft?.ocrModel,
    modelsQuery.data?.ollamaModels,
    modelsQuery.data?.otherModels,
    openaiModelFallback,
  ]);

  const ocrKeySourceLabel = useMemo((): string => {
    switch (modelsQuery.data?.keySource) {
      case 'brain':
        return 'Brain OCR model catalog';
      default:
        return 'OCR model source unavailable';
    }
  }, [modelsQuery.data?.keySource]);
  const detectedOcrProviderLabel = useMemo((): string => {
    const model = draft?.ocrModel.trim() ?? '';
    if (!model) return 'Not set';
    return resolveCaseResolverOcrProviderLabel(model);
  }, [draft]);

  const saveDisabled = !draft || settingsQuery.isLoading || updateSettingsBulk.isPending;

  const modelSummary = `${modelOptions.length} OCR-capable model(s) available`;
  const headerBreadcrumb = (
    <AdminCaseResolverBreadcrumbs current='Settings' className='mt-1' />
  );

  const handleSave = async (): Promise<void> => {
    if (!draft) return;
    const settings = draft;
    const nextSettings: CaseResolverSettings = {
      ocrModel: settings.ocrModel.trim(),
      ocrPrompt: settings.ocrPrompt.trim(),
      defaultDocumentFormat: 'wysiwyg',
      confirmDeleteDocument: settings.confirmDeleteDocument !== false,
      defaultAddresserPartyKind: settings.defaultAddresserPartyKind,
      defaultAddresseePartyKind: settings.defaultAddresseePartyKind,
    };
    try {
      await updateSettingsBulk.mutateAsync([
        {
          key: CASE_RESOLVER_SETTINGS_KEY,
          value: serializeSetting(nextSettings),
        },
        {
          key: CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_KEY,
          value: nextSettings.defaultDocumentFormat,
        },
      ]);
      setDraft(nextSettings);
      setLoadedFrom(
        `${serializeSetting(nextSettings)}|${nextSettings.defaultDocumentFormat}|${openaiModelFallback}`
      );
      toast('Case Resolver settings saved.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to save Case Resolver settings.', {
        variant: 'error',
      });
    }
  };

  if (!draft) {
    return (
      <div className='page-section-tight'>
        <SectionHeader
          eyebrow={<AdminAiEyebrow section='Case Resolver' />}
          title='Case Resolver Settings'
          subtitle={headerBreadcrumb}
        />
      </div>
    );
  }

  return (
    <div className='page-section-tight space-y-4'>
      <SectionHeader
        eyebrow={<AdminAiEyebrow section='Case Resolver' />}
        title='Case Resolver Settings'
        subtitle={headerBreadcrumb}
        actions={
          <div className='flex flex-wrap items-center gap-2'>
            <Button
              type='button'
              variant='outline'
              size='xs'
              onClick={(): void => {
                void settingsQuery.refetch();
                void modelsQuery.refetch();
              }}
              disabled={settingsQuery.isLoading || modelsQuery.isFetching}
            >
              <RefreshCcw className='mr-2 size-4' />
              Refresh
            </Button>
            <Button type='button' variant='outline' size='xs' asChild>
              <Link href='/admin/case-resolver'>
                <ArrowLeft className='mr-2 size-4' />
                Back to Case Resolver
              </Link>
            </Button>
          </div>
        }
      />

      <FormSection
        title='OCR Runtime'
        description='Pick the model used for OCR extraction. The dropdown is divided into Ollama models and Other models.'
        variant='subtle'
        className='p-4'
        actions={
          <div className='flex items-center gap-2 text-xs text-gray-400'>
            <Settings2 className='size-3.5' />
            <span>{modelSummary}</span>
          </div>
        }
      >
        <div className='grid gap-3 md:grid-cols-2'>
          <FormField
            label='OCR Model'
            actions={
              <Badge variant='outline' className='px-1.5 py-0 text-[9px] uppercase tracking-wide'>
                {detectedOcrProviderLabel}
              </Badge>
            }
            description={`OpenAI OCR calls use the Brain-managed global OpenAI provider. Model source: ${ocrKeySourceLabel}`}
          >
            <SelectSimple
              value={draft.ocrModel}
              onValueChange={(value: string): void => {
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      ocrModel: value,
                    }
                    : previous
                );
              }}
              options={modelOptions}
              placeholder='Select OCR model'
             ariaLabel='Select OCR model' title='Select OCR model'/>{' '}
            {modelsQuery.data?.warning?.message ? (
              <div className='mt-1 text-[11px] text-amber-300'>
                {modelsQuery.data.warning.message}
              </div>
            ) : null}
          </FormField>

          <FormField
            label='Custom Model ID'
            description='Use this field if your model is not shown in the discovered list.'
          >
            <Input
              value={draft.ocrModel}
              onChange={(event: React.ChangeEvent<HTMLInputElement>): void => {
                const value = event.target.value;
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      ocrModel: value,
                    }
                    : previous
                );
              }}
              placeholder='e.g. gpt-4o-mini or llama3.2-vision'
              className='h-9'
             aria-label='e.g. gpt-4o-mini or llama3.2-vision' title='e.g. gpt-4o-mini or llama3.2-vision'/>
          </FormField>

          <FormField
            label='OCR Prompt Template'
            description='Edit the default OCR instruction sent with uploaded scan images.'
            className='md:col-span-2'
          >
            <Textarea
              value={draft.ocrPrompt}
              onChange={(event: React.ChangeEvent<HTMLTextAreaElement>): void => {
                const value = event.target.value;
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      ocrPrompt: value,
                    }
                    : previous
                );
              }}
              className='min-h-[88px] text-xs'
              placeholder='Instructions used for OCR extraction.'
             aria-label='Instructions used for OCR extraction.' title='Instructions used for OCR extraction.'/>
          </FormField>
        </div>
      </FormSection>

      <FormSection
        title='Document Defaults'
        description='Case Resolver documents always use WYSIWYG format. Markdown mode is disabled.'
        variant='subtle'
        className='p-4'
      >
        <div className='grid gap-3 md:grid-cols-2'>
          <FormField
            label='Default Document Format'
            description='Only canonical WYSIWYG document format is supported.'
          >
            <SelectSimple
              value={draft.defaultDocumentFormat}
              onValueChange={(value: string): void => {
                if (value !== 'wysiwyg') return;
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      defaultDocumentFormat: 'wysiwyg',
                    }
                    : previous
