              }}
              options={CASE_RESOLVER_DEFAULT_DOCUMENT_FORMAT_OPTIONS}
              placeholder='Select default document format'
              disabled
             ariaLabel='Select default document format' title='Select default document format'/>
          </FormField>
          <FormField
            label='Confirm Document Delete'
            description='Applies when deleting documents from Case Resolver tree and Cases list.'
          >
            <SelectSimple
              value={draft.confirmDeleteDocument ? 'on' : 'off'}
              onValueChange={(value: string): void => {
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      confirmDeleteDocument: value !== 'off',
                    }
                    : previous
                );
              }}
              options={CASE_RESOLVER_CONFIRM_DELETE_OPTIONS}
              placeholder='Choose confirmation behavior'
             ariaLabel='Choose confirmation behavior' title='Choose confirmation behavior'/>
          </FormField>
          <FormField
            label='Default Addresser Lookup'
            description='Choose whether addresser dropdown starts in Persons or Organizations mode.'
          >
            <SelectSimple
              value={draft.defaultAddresserPartyKind}
              onValueChange={(value: string): void => {
                if (value !== 'person' && value !== 'organization') return;
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      defaultAddresserPartyKind: value,
                    }
                    : previous
                );
              }}
              options={CASE_RESOLVER_PARTY_SEARCH_KIND_OPTIONS}
              placeholder='Choose default addresser lookup'
             ariaLabel='Choose default addresser lookup' title='Choose default addresser lookup'/>
          </FormField>
          <FormField
            label='Default Addressee Lookup'
            description='Choose whether addressee dropdown starts in Persons or Organizations mode.'
          >
            <SelectSimple
              value={draft.defaultAddresseePartyKind}
              onValueChange={(value: string): void => {
                if (value !== 'person' && value !== 'organization') return;
                setDraft((previous: CaseResolverSettings | null) =>
                  previous
                    ? {
                      ...previous,
                      defaultAddresseePartyKind: value,
                    }
                    : previous
                );
              }}
              options={CASE_RESOLVER_PARTY_SEARCH_KIND_OPTIONS}
              placeholder='Choose default addressee lookup'
             ariaLabel='Choose default addressee lookup' title='Choose default addressee lookup'/>
          </FormField>
        </div>
      </FormSection>

      <div className='flex justify-end'>
        <Button
          type='button'
          onClick={(): void => {
            void handleSave();
          }}
          disabled={saveDisabled}
          className='min-w-[120px]'
        >
          Save Settings
        </Button>
      </div>
    </div>
  );
}

import React from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { CaseResolverTag } from '@/shared/contracts/case-resolver/relations';
import type { SimpleSettingsListItem } from '@/shared/contracts/ui/menus';
import { Tag as UiTag } from '@/shared/ui/forms-and-actions.public';

import type { CaseResolverTagFormData } from '../entity-form-data';

export const DEFAULT_CASE_RESOLVER_TAG_COLOR = '#38bdf8';

export type TagPathOption = {
  id: string;
  label: string;
  pathIds: string[];
};

export type CaseResolverTagListItem = SimpleSettingsListItem & {
  original: CaseResolverTag;
};

export const createCaseResolverTagId = (): string => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return `case-tag-${crypto.randomUUID()}`;
  }
  return `case-tag-${Math.random().toString(36).slice(2, 10)}`;
};

export const createEmptyCaseResolverTagFormData = (): CaseResolverTagFormData => ({
  name: '',
  color: DEFAULT_CASE_RESOLVER_TAG_COLOR,
  parentId: null,
});

export const createCaseResolverTagFormData = (
  tag: CaseResolverTag
): CaseResolverTagFormData => ({
  name: tag.label,
  color: tag.color ?? DEFAULT_CASE_RESOLVER_TAG_COLOR,
  parentId: tag.parentId ?? null,
});

export const buildTagPathOptions = (tags: CaseResolverTag[]): TagPathOption[] => {
  const byId = new Map<string, CaseResolverTag>(
    tags.map((tag: CaseResolverTag): [string, CaseResolverTag] => [tag.id, tag])
  );
  const cache = new Map<string, { ids: string[]; names: string[] }>();

  const resolvePath = (tagId: string, trail: Set<string>): { ids: string[]; names: string[] } => {
    const cached = cache.get(tagId);
    if (cached) return cached;

    const tag = byId.get(tagId);
    if (!tag) return { ids: [], names: [] };

    if (trail.has(tagId)) {
      const fallback = { ids: [tag.id], names: [tag.label] };
      cache.set(tagId, fallback);
      return fallback;
    }

    if (!tag.parentId || !byId.has(tag.parentId)) {
      const rootPath = { ids: [tag.id], names: [tag.label] };
      cache.set(tagId, rootPath);
      return rootPath;
    }

    const nextTrail = new Set(trail);
    nextTrail.add(tagId);
    const parentPath = resolvePath(tag.parentId, nextTrail);
    const fullPath = {
      ids: [...parentPath.ids, tag.id],
      names: [...parentPath.names, tag.label],
    };
    cache.set(tagId, fullPath);
    return fullPath;
  };

  return tags
    .map((tag: CaseResolverTag): TagPathOption => {
      const path = resolvePath(tag.id, new Set<string>());
      return {
        id: tag.id,
        label: path.names.join(' / '),
        pathIds: path.ids,
      };
    })
    .sort((left: TagPathOption, right: TagPathOption) => left.label.localeCompare(right.label));
};

export const buildTagPathLabelMap = (
  tagPathOptions: TagPathOption[]
): Map<string, string> =>
  new Map(tagPathOptions.map((option: TagPathOption): [string, string] => [option.id, option.label]));

export const collectDescendantTagIds = (
  tags: CaseResolverTag[],
  rootTagId: string
): Set<string> => {
  const descendants = new Set<string>([rootTagId]);
  let expanded = true;

  while (expanded) {
    expanded = false;
    tags.forEach((tag: CaseResolverTag): void => {
      if (!tag.parentId || descendants.has(tag.id) || !descendants.has(tag.parentId)) {
        return;
      }

      descendants.add(tag.id);
      expanded = true;
    });
  }

  return descendants;
};

export const buildParentTagOptions = (
  tagPathOptions: TagPathOption[],
  blockedParentIds: Set<string>
): Array<LabeledOptionDto<string>> =>
  tagPathOptions
    .filter((option: TagPathOption): boolean => !blockedParentIds.has(option.id))
    .map((option: TagPathOption) => ({
      value: option.id,
      label: option.label,
    }));

export const buildCaseResolverTagListItems = (
  tags: CaseResolverTag[],
  tagPathById: Map<string, string>
): CaseResolverTagListItem[] =>
  tags.map((tag: CaseResolverTag) => ({
    id: tag.id,
    title: React.createElement(
      'div',
      { className: 'flex items-center gap-2' },
      React.createElement(UiTag, {
        label: tag.label,
        color: tag.color || DEFAULT_CASE_RESOLVER_TAG_COLOR,
        dot: true,
      })
    ),
    description: tagPathById.get(tag.id) ?? tag.label,
    original: tag,
  }));

export const buildNextTagsForSave = (args: {
  editingTag: CaseResolverTag | null;
  formData: CaseResolverTagFormData;
  tags: CaseResolverTag[];
  now: string;
}): CaseResolverTag[] | null => {
  const { editingTag, formData, now, tags } = args;
  const normalizedName = formData.name.trim();
  if (!normalizedName) {
    return null;
  }

  const normalizedParentId =
    formData.parentId && formData.parentId !== editingTag?.id ? formData.parentId : null;
  const color = formData.color.trim() || DEFAULT_CASE_RESOLVER_TAG_COLOR;

  const nextTag: CaseResolverTag = editingTag
    ? {
        ...editingTag,
        label: normalizedName,
        parentId: normalizedParentId,
        color,
        updatedAt: now,
      }
    : {
        id: createCaseResolverTagId(),
        label: normalizedName,
        parentId: normalizedParentId,
        color,
        createdAt: now,
        updatedAt: now,
      };

  return editingTag
    ? tags.map((tag: CaseResolverTag) => (tag.id === editingTag.id ? nextTag : tag))
    : [...tags, nextTag];
};

export const buildNextTagsForDelete = (args: {
  tagToDelete: CaseResolverTag;
  tags: CaseResolverTag[];
  now: string;
}): CaseResolverTag[] => {
  const { now, tagToDelete, tags } = args;

  return tags
    .filter((tag: CaseResolverTag) => tag.id !== tagToDelete.id)
    .map((tag: CaseResolverTag): CaseResolverTag =>
      tag.parentId === tagToDelete.id
        ? {
            ...tag,
            parentId: null,
            updatedAt: now,
          }
        : tag
    );
};

'use client';

import { useCallback, useMemo, useState } from 'react';

import type { CaseResolverTag } from '@/shared/contracts/case-resolver/relations';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useSettingsStore } from '@/shared/providers/SettingsStoreProvider';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';
import { serializeSetting } from '@/shared/utils/settings-json';

import type { CaseResolverTagFormData } from '../entity-form-data';
import { CASE_RESOLVER_TAGS_KEY, parseCaseResolverTags } from '../settings';
import {
  buildNextTagsForDelete,
  buildNextTagsForSave,
  buildParentTagOptions,
  buildTagPathLabelMap,
  buildTagPathOptions,
  collectDescendantTagIds,
  createCaseResolverTagFormData,
  createEmptyCaseResolverTagFormData,
} from './AdminCaseResolverTagsPage.helpers';

export function useAdminCaseResolverTagsPageRuntime() {
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();

  const rawTags = settingsStore.get(CASE_RESOLVER_TAGS_KEY);
  const tags = useMemo((): CaseResolverTag[] => parseCaseResolverTags(rawTags), [rawTags]);

  const [showModal, setShowModal] = useState(false);
  const [editingTag, setEditingTag] = useState<CaseResolverTag | null>(null);
  const [tagToDelete, setTagToDelete] = useState<CaseResolverTag | null>(null);
  const [formData, setFormData] = useState<CaseResolverTagFormData>(createEmptyCaseResolverTagFormData);

  const tagPathOptions = useMemo(() => buildTagPathOptions(tags), [tags]);
  const tagPathById = useMemo(() => buildTagPathLabelMap(tagPathOptions), [tagPathOptions]);
  const blockedParentIds = useMemo(
    () => (editingTag ? collectDescendantTagIds(tags, editingTag.id) : new Set<string>()),
    [editingTag, tags]
  );
  const parentTagOptions = useMemo(
    () => buildParentTagOptions(tagPathOptions, blockedParentIds),
    [blockedParentIds, tagPathOptions]
  );

  const openCreateModal = useCallback((): void => {
    setEditingTag(null);
    setFormData(createEmptyCaseResolverTagFormData());
    setShowModal(true);
  }, []);

  const openEditModal = useCallback((tag: CaseResolverTag): void => {
    setEditingTag(tag);
    setFormData(createCaseResolverTagFormData(tag));
    setShowModal(true);
  }, []);

  const handleSave = useCallback(async (): Promise<void> => {
    const nextTags = buildNextTagsForSave({
      editingTag,
      formData,
      tags,
      now: new Date().toISOString(),
    });
    if (!nextTags) {
      toast('Tag name is required.', { variant: 'error' });
      return;
    }

    try {
      await updateSetting.mutateAsync({
        key: CASE_RESOLVER_TAGS_KEY,
        value: serializeSetting(nextTags),
      });
      toast(editingTag ? 'Tag updated.' : 'Tag created.', { variant: 'success' });
      setShowModal(false);
    } catch (error) {
      logClientCatch(error, {
        source: 'AdminCaseResolverTagsPage',
        action: 'saveTag',
        tagId: editingTag?.id,
      });
      toast(error instanceof Error ? error.message : 'Failed to save tag.', { variant: 'error' });
    }
  }, [editingTag, formData, tags, toast, updateSetting]);

  const handleConfirmDelete = useCallback(async (): Promise<void> => {
    if (!tagToDelete) return;

    try {
      await updateSetting.mutateAsync({
        key: CASE_RESOLVER_TAGS_KEY,
        value: serializeSetting(
          buildNextTagsForDelete({
            tagToDelete,
            tags,
            now: new Date().toISOString(),
          })
        ),
      });
      toast('Tag deleted.', { variant: 'success' });
    } catch (error) {
      logClientCatch(error, {
        source: 'AdminCaseResolverTagsPage',
        action: 'deleteTag',
        tagId: tagToDelete.id,
      });
      toast(error instanceof Error ? error.message : 'Failed to delete tag.', { variant: 'error' });
    } finally {
      setTagToDelete(null);
    }
  }, [tagToDelete, tags, toast, updateSetting]);

  return {
    editingTag,
    formData,
    handleConfirmDelete,
    handleSave,
    openCreateModal,
    openEditModal,
    parentTagOptions,
    setFormData,
    setShowModal,
    setTagToDelete,
    settingsStore,
    showModal,
    tagPathById,
    tagToDelete,
    tags,
    updateSetting,
  };
}

