export const buildPathLabelMap = <
  T extends { id: string; parentId?: string | null | undefined; label?: string; name?: string },
>(
    items: T[]
  ): Map<string, string> => {
  const byId = new Map<string, T>(items.map((item: T): [string, T] => [item.id, item]));
  const cache = new Map<string, string>();

  const resolveLabel = (id: string, visited: Set<string>): string => {
    const cached = cache.get(id);
    if (cached) return cached;
    const item = byId.get(id);
    if (!item) return '';
    const itemLabel = item.label ?? item.name ?? '';
    if (visited.has(id)) {
      cache.set(id, itemLabel);
      return itemLabel;
    }
    if (!item.parentId || !byId.has(item.parentId)) {
      cache.set(id, itemLabel);
      return itemLabel;
    }
    const nextVisited = new Set(visited);
    nextVisited.add(id);
    const parentLabel = resolveLabel(item.parentId, nextVisited);
    const label = `${parentLabel} / ${itemLabel}`;
    cache.set(id, label);
    return label;
  };

  items.forEach((item: T): void => {
    resolveLabel(item.id, new Set<string>());
  });

  return cache;
};

import { type ValidatorPatternList } from '@/shared/contracts/admin';
import { type CaseResolverNodeMeta } from '@/shared/contracts/case-resolver';
import type {
  PromptEngineSettings,
  PromptValidationRule,
  PromptValidationScope,
} from '@/shared/contracts/prompt-engine';
import { formatProgrammaticPrompt } from '@/shared/lib/prompt-engine';
import {
  preparePromptValidationRuntime,
  validateProgrammaticPromptWithRuntime,
} from '@/shared/lib/prompt-engine';

export const CASE_RESOLVER_PLAIN_TEXT_VALIDATOR_SCOPE = 'case-resolver-plain-text' as const;
export const CASE_RESOLVER_PLAIN_TEXT_PROMPT_SCOPE = 'case_resolver_plain_text' as const;

const normalizePromptValidationScopes = (
  scopes: PromptValidationScope[] | null | undefined
): PromptValidationScope[] => {
  if (!Array.isArray(scopes) || scopes.length === 0) {
    return ['global'];
  }
  const deduped: PromptValidationScope[] = [];
  scopes.forEach((scope: PromptValidationScope): void => {
    if (deduped.includes(scope)) return;
    deduped.push(scope);
  });
  return deduped;
};

const ruleAppliesToScope = (rule: PromptValidationRule, scope: PromptValidationScope): boolean => {
  const appliesToScopes = normalizePromptValidationScopes(rule.appliesToScopes);
  return appliesToScopes.includes(scope) || appliesToScopes.includes('global');
};

const resolveScopedRules = (
  settings: PromptEngineSettings
): {
  rules: PromptValidationRule[];
  learnedRules: PromptValidationRule[];
} => {
  const rules = (settings.promptValidation.rules ?? []).filter(
    (rule: PromptValidationRule): boolean =>
      ruleAppliesToScope(rule, CASE_RESOLVER_PLAIN_TEXT_PROMPT_SCOPE)
  );
  const learnedRules = (settings.promptValidation.learnedRules ?? []).filter(
    (rule: PromptValidationRule): boolean =>
      ruleAppliesToScope(rule, CASE_RESOLVER_PLAIN_TEXT_PROMPT_SCOPE)
  );
  return { rules, learnedRules };
};

export const listCaseResolverPlainTextStacks = (
  patternLists: ValidatorPatternList[]
): ValidatorPatternList[] =>
  patternLists.filter(
    (entry: ValidatorPatternList): boolean =>
      entry.scope === CASE_RESOLVER_PLAIN_TEXT_VALIDATOR_SCOPE
  );

export const resolveCaseResolverPlainTextDefaultStackId = (
  patternLists: ValidatorPatternList[]
): string => listCaseResolverPlainTextStacks(patternLists)[0]?.id ?? '';

type ApplyCaseResolverPlainTextValidationArgs = {
  input: string;
  nodeMeta: CaseResolverNodeMeta;
  promptEngineSettings: PromptEngineSettings;
  patternLists: ValidatorPatternList[];
  forceEnabled?: boolean;
  forceFormatterEnabled?: boolean;
};

export const applyCaseResolverPlainTextValidation = (
  args: ApplyCaseResolverPlainTextValidationArgs
): string => {
  const sourceText = typeof args.input === 'string' ? args.input : '';
  if (!sourceText) return sourceText;
  const validationEnabled = args.forceEnabled ?? args.nodeMeta.plainTextValidationEnabled ?? true;
  if (!validationEnabled) return sourceText;

  const formatterEnabled =
    args.forceFormatterEnabled ?? args.nodeMeta.plainTextFormatterEnabled ?? true;
  const stackOptions = listCaseResolverPlainTextStacks(args.patternLists);
  const stackId = args.nodeMeta.plainTextValidationStackId?.trim() ?? '';
  const hasValidStack =
    stackId.length > 0 &&
    stackOptions.some((stack: ValidatorPatternList): boolean => stack.id === stackId);
  if (stackOptions.length > 0 && !hasValidStack) {
    const fallbackStackId = stackOptions[0]?.id?.trim() ?? '';
    if (!fallbackStackId) return sourceText;
  }

  const scopedRules = resolveScopedRules(args.promptEngineSettings);
  if (scopedRules.rules.length === 0 && scopedRules.learnedRules.length === 0) {
    return sourceText;
  }

  const validationSettings = {
    enabled: true,
    rules: scopedRules.rules,
    learnedRules: scopedRules.learnedRules,
  };
  const runtime = preparePromptValidationRuntime(validationSettings, {
    scope: CASE_RESOLVER_PLAIN_TEXT_PROMPT_SCOPE,
  });
  const issuesBefore = validateProgrammaticPromptWithRuntime(sourceText, runtime);
  if (!formatterEnabled || issuesBefore.length === 0) {
    return sourceText;
  }
  const formatted = formatProgrammaticPrompt(
    sourceText,
    validationSettings,
    { scope: CASE_RESOLVER_PLAIN_TEXT_PROMPT_SCOPE },
    {
      preparedRuntime: runtime,
      precomputedIssuesBefore: issuesBefore,
      enableIncrementalValidation: true,
    }
  );
  return formatted.prompt;
};

'use client';

import React from 'react';

import type { DocumentRelationFileTypeFilter, DocumentRelationSortMode } from '@/shared/contracts/case-resolver/base';
import { useFolderTreeProfile } from '@/shared/lib/foldertree/public';
import { cn } from '@/shared/utils/ui-utils';
import { resolveFolderTreeSearchConfig } from '@/shared/utils/folder-tree-profiles-v2';

import {
  DocumentRelationSearchRuntimeContext,
  type DocumentRelationSearchRuntimeValue,
  useDocumentRelationSearchRuntime,
} from './DocumentRelationSearchRuntimeContext';
import {
  DocumentRelationSearchUiProvider,
  type DocumentRelationSearchUiContextValue,
} from './DocumentRelationSearchUiContext';
import { RelationTreeBrowser } from './RelationTreeBrowser';
import {
  RelationTreeBrowserRuntimeContext,
  type RelationTreeBrowserRuntimeValue,
} from './RelationTreeBrowserRuntimeContext';
import { BulkActionBar } from './sections/BulkActionBar';
import { DocumentPreviewDialog } from './sections/DocumentPreviewDialog';
import { FilterBar } from './sections/FilterBar';
import { SearchBar } from './sections/SearchBar';
import { type NodeFileDocumentSearchScope } from '../../components/CaseResolverNodeFileUtils';
import {
  DocumentRelationSearchProvider,
  useDocumentRelationSearchActionsContext,
  useDocumentRelationSearchStateContext,
} from '../context/DocumentRelationSearchContext';
import { RESULT_HEIGHT_MAP } from './sections/document-relation-search-utils';
import { ScopeBar } from './sections/ScopeBar';

import type { RelationTreeInstance } from '../types';

function DocumentRelationSearchInner(): React.JSX.Element {
  const { relationTreeInstance } = useDocumentRelationSearchRuntime();
  const {
    showFiltersBar,
    resultHeight,
    relationTreeNodes,
    relationTreeLookup,
    selectedFileIds,
    isLocked,
    documentSearchQuery,
  } = useDocumentRelationSearchStateContext();
  const { toggleFileSelection, onLinkFile, setPreviewFileId, setDocumentSearchQuery } =
    useDocumentRelationSearchActionsContext();
  const relationTreeProfile = useFolderTreeProfile(relationTreeInstance);
  const relationTreeSearchEnabled = React.useMemo(
    (): boolean => resolveFolderTreeSearchConfig(relationTreeProfile).enabled,
    [relationTreeProfile]
  );

  React.useEffect((): void => {
    if (relationTreeSearchEnabled) return;
    if (documentSearchQuery.length === 0) return;
    setDocumentSearchQuery('');
  }, [documentSearchQuery, relationTreeSearchEnabled, setDocumentSearchQuery]);

  const relationTreeBrowserRuntimeValue = React.useMemo(
    (): RelationTreeBrowserRuntimeValue => ({
      instance: relationTreeInstance,
      nodes: relationTreeNodes,
      lookup: relationTreeLookup,
      isLocked,
      selectedFileIds,
      onToggleFileSelection: toggleFileSelection,
      onLinkFile,
      onPreviewFile: setPreviewFileId,
      searchQuery: relationTreeSearchEnabled ? documentSearchQuery : '',
    }),
    [
      documentSearchQuery,
      isLocked,
      onLinkFile,
      relationTreeInstance,
      relationTreeLookup,
      relationTreeNodes,
      relationTreeSearchEnabled,
      selectedFileIds,
      setPreviewFileId,
      toggleFileSelection,
    ]
  );

  return (
    <DocumentRelationSearchLayout
      showFiltersBar={showFiltersBar}
      resultHeight={resultHeight}
      runtimeValue={relationTreeBrowserRuntimeValue}
    />
  );
}

function DocumentRelationSearchLayout({
  showFiltersBar,
  resultHeight,
  runtimeValue,
}: {
  showFiltersBar: boolean;
  resultHeight: string;
  runtimeValue: RelationTreeBrowserRuntimeValue;
}) {
  return (
    <>
      <div className='flex flex-col overflow-hidden rounded-md border border-border/60 bg-card/20'>
        <ScopeBar />
        {showFiltersBar && <FilterBar />}
        <SearchBar />
        <BulkActionBar />
        <div className={cn('overflow-auto', RESULT_HEIGHT_MAP[resultHeight as keyof typeof RESULT_HEIGHT_MAP])}>
          <RelationTreeBrowserRuntimeContext.Provider value={runtimeValue}>
            <RelationTreeBrowser mode='link_relations' emptyLabel='No matching files' />
          </RelationTreeBrowserRuntimeContext.Provider>
        </div>
      </div>
      <DocumentPreviewDialog />
    </>
  );
}

export type DocumentRelationSearchPanelProps = {
  draftFileId: string;
  isLocked: boolean;
  onLinkFile: (fileId: string) => void;
  /** Folder-tree instance used by relation browser. */
  relationTreeInstance?: RelationTreeInstance | undefined;
  /** Initial scope on first mount (default: 'case_scope') */
  defaultScope?: NodeFileDocumentSearchScope | undefined;
  /** Initial sort mode on first mount (default: 'name_asc') */
  defaultSort?: DocumentRelationSortMode | undefined;
  /** Initial file type filter on first mount (default: 'all') */
  defaultFileType?: DocumentRelationFileTypeFilter | undefined;
  /** Show sort dropdown (default: true) */
  showSortControl?: boolean | undefined;
  /** Show file-type filter chips (default: true) */
  showFileTypeFilter?: boolean | undefined;
};

export function DocumentRelationSearchPanel(
  props: DocumentRelationSearchPanelProps
): React.JSX.Element {
  const {
    draftFileId,
    isLocked,
    onLinkFile,
    relationTreeInstance = 'case_resolver_document_relations',
    defaultScope = 'case_scope',
    defaultSort = 'name_asc',
    defaultFileType = 'all',
    showSortControl = true,
    showFileTypeFilter = true,
  } = props;

  const uiContextValue = React.useMemo(
    (): DocumentRelationSearchUiContextValue => ({
      showSortControl,
      showFileTypeFilter,
    }),
    [showSortControl, showFileTypeFilter]
  );
  const runtimeValue = React.useMemo(
    (): DocumentRelationSearchRuntimeValue => ({
      relationTreeInstance,
    }),
    [relationTreeInstance]
  );

  return (
    <DocumentRelationSearchProvider
      draftFileId={draftFileId}
      isLocked={isLocked}
      onLinkFile={onLinkFile}
      defaultScope={defaultScope}
      defaultSort={defaultSort}
      defaultFileType={defaultFileType}
    >
      <DocumentRelationSearchUiProvider value={uiContextValue}>
        <DocumentRelationSearchRuntimeContext.Provider value={runtimeValue}>
          <DocumentRelationSearchInner />
        </DocumentRelationSearchRuntimeContext.Provider>
      </DocumentRelationSearchUiProvider>
    </DocumentRelationSearchProvider>
  );
}

'use client';

import React, { useCallback, useEffect, useMemo, useRef } from 'react';

import {
  MasterFolderTreeViewport,
  useMasterFolderTreeViewModel,
  useSharedMasterFolderTreeRuntime,
  type FolderTreeViewportRenderNodeInput,
} from '@/shared/lib/foldertree/public';
import type {
  MasterTreeDropPosition,
  MasterTreeNode,
} from '@/shared/utils/master-folder-tree-contract';

import { useOptionalRelationTreeBrowserRuntime } from './RelationTreeBrowserRuntimeContext';
import { RelationTreeNodeItem } from './RelationTreeNodeItem';
import { RelationTreeNodeRuntimeProvider } from './RelationTreeNodeRuntimeContext';
import { logCaseResolverWorkspaceEvent } from '../../workspace-persistence';

import type { RelationBrowserMode, RelationTreeInstance, RelationTreeLookup } from '../types';

const DRAG_FILE_ID_TYPE = 'application/case-resolver-file-id';

type RelationTreeBrowserProps = {
  instance?: RelationTreeInstance | undefined;
  mode: RelationBrowserMode;
  nodes?: MasterTreeNode[] | undefined;
  lookup?: RelationTreeLookup | undefined;
  isLocked?: boolean | undefined;
  selectedFileIds?: Set<string> | undefined;
  onToggleFileSelection?: ((fileId: string) => void) | undefined;
  onLinkFile?: ((fileId: string) => void) | undefined;
  onAddFile?: ((fileId: string) => void) | undefined;
  onPreviewFile?: ((fileId: string) => void) | undefined;
  searchQuery?: string | undefined;
  className?: string | undefined;
  emptyLabel?: string | undefined;
};

const resolveNodeTypeFromMetadata = (
  node: FolderTreeViewportRenderNodeInput['node']
): 'case' | 'folder' | 'file' => {
  const raw = String(node.metadata?.['relationNodeType'] ?? '');
  if (raw === 'file' || raw === 'case' || raw === 'folder') return raw;
  if (node.kind === 'relation_file') return 'file';
  if (node.kind === 'relation_case') return 'case';
  return 'folder';
};

export function RelationTreeBrowser(props: RelationTreeBrowserProps): React.JSX.Element {
  const {
    instance,
    mode,
    nodes,
    lookup,
    isLocked,
    selectedFileIds,
    onToggleFileSelection,
    onLinkFile,
    onAddFile,
    onPreviewFile,
    searchQuery,
    className,
    emptyLabel = 'No files found',
  } = props;
  const browserRuntimeContext = useOptionalRelationTreeBrowserRuntime();
  const resolvedInstance = instance ?? browserRuntimeContext?.instance;
  const resolvedNodes = nodes ?? browserRuntimeContext?.nodes;
  const resolvedLookup = lookup ?? browserRuntimeContext?.lookup;
  const resolvedIsLocked = isLocked ?? browserRuntimeContext?.isLocked ?? false;
  const resolvedSelectedFileIds = selectedFileIds ?? browserRuntimeContext?.selectedFileIds;
  const resolvedOnToggleFileSelection =
    onToggleFileSelection ?? browserRuntimeContext?.onToggleFileSelection;
  const resolvedOnLinkFile = onLinkFile ?? browserRuntimeContext?.onLinkFile;
  const resolvedOnPreviewFile = onPreviewFile ?? browserRuntimeContext?.onPreviewFile;
  const resolvedSearchQuery = searchQuery ?? browserRuntimeContext?.searchQuery ?? '';
  const resolvedOnAddFile = onAddFile ?? browserRuntimeContext?.onAddFile;

  if (!resolvedInstance || !resolvedNodes || !resolvedLookup) {
    throw new Error(
      'RelationTreeBrowser must be used within RelationTreeBrowserRuntimeProvider or receive explicit props'
    );
  }

  const runtime = useSharedMasterFolderTreeRuntime({ bindWindowKeydown: false });
  const tree = useMasterFolderTreeViewModel({
    instance: resolvedInstance,
    nodes: resolvedNodes,
    runtime,
    searchQuery: resolvedSearchQuery,
  });

  const dragArmedFileIdRef = useRef<string | null>(null);
  const dropRejectLoggedRef = useRef<boolean>(false);

  const clearDragHandleArm = useCallback((): void => {
    dragArmedFileIdRef.current = null;
    dropRejectLoggedRef.current = false;
  }, []);

  useEffect(() => {
    const handleClear = (): void => {
      clearDragHandleArm();
    };
    window.addEventListener('pointerup', handleClear);
    window.addEventListener('pointercancel', handleClear);
    window.addEventListener('mouseup', handleClear);
    window.addEventListener('dragend', handleClear);
    window.addEventListener('drop', handleClear);
    window.addEventListener('blur', handleClear);
    return (): void => {
      window.removeEventListener('pointerup', handleClear);
      window.removeEventListener('pointercancel', handleClear);
      window.removeEventListener('mouseup', handleClear);
      window.removeEventListener('dragend', handleClear);
      window.removeEventListener('drop', handleClear);
      window.removeEventListener('blur', handleClear);
    };
  }, [clearDragHandleArm]);

  useEffect(() => {
    logCaseResolverWorkspaceEvent({
      source: 'relation_tree_browser',
      action: 'relation_tree_built',
      message: `instance=${resolvedInstance} mode=${mode} nodes=${resolvedNodes.length}`,
    });
  }, [resolvedInstance, mode, resolvedNodes]);

  useEffect(() => {
    if (!resolvedSearchQuery || resolvedSearchQuery.trim().length === 0) return;
    logCaseResolverWorkspaceEvent({
      source: 'relation_tree_browser',
      action: 'relation_tree_search_applied',
      message: `instance=${resolvedInstance} mode=${mode} query=${resolvedSearchQuery
        .trim()
        .slice(0, 64)}`,
    });
  }, [resolvedInstance, mode, resolvedSearchQuery]);

  const handleArmDragHandle = useCallback(
    (fileId: string): void => {
      if (mode !== 'add_to_node_canvas') return;
      dragArmedFileIdRef.current = fileId;
    },
    [mode]
  );

  const canStartDrag = useCallback(
    ({ node }: { node: FolderTreeViewportRenderNodeInput['node'] }): boolean => {
      if (mode !== 'add_to_node_canvas') return false;
      const nodeType = resolveNodeTypeFromMetadata(node);
      if (nodeType !== 'file') return false;
      const row = resolvedLookup.fileRowByNodeId.get(node.id);
      if (!row) return false;
      const isArmed = dragArmedFileIdRef.current === row.file.id;
      if (!isArmed && !dropRejectLoggedRef.current) {
        dropRejectLoggedRef.current = true;
        logCaseResolverWorkspaceEvent({
          source: 'relation_tree_browser',
          action: 'relation_tree_drop_rejected',
          message: 'drag_start_rejected_not_handle_armed',
        });
      }
      return isArmed;
    },
    [resolvedLookup.fileRowByNodeId, mode]
  );

  const canDrop = useCallback(
    ({
      position,
      targetId,
    }: {
      draggedNodeId: string;
      targetId: string | null;
      position: MasterTreeDropPosition;
      defaultAllowed: boolean;
    }): boolean => {
      if (mode !== 'add_to_node_canvas') return false;
      if (!dropRejectLoggedRef.current) {
        dropRejectLoggedRef.current = true;
        logCaseResolverWorkspaceEvent({
          source: 'relation_tree_browser',
          action: 'relation_tree_drop_rejected',
          message: `target=${targetId ?? 'root'} position=${position}`,
        });
      }
      return false;
    },
    [mode]
  );

  const handleNodeDragStart = useCallback(
    ({
      node,
      event,
    }: {
      node: FolderTreeViewportRenderNodeInput['node'];
      event: React.DragEvent<HTMLDivElement>;
    }): void => {
      if (mode !== 'add_to_node_canvas') return;
      const row = resolvedLookup.fileRowByNodeId.get(node.id);
      if (!row) return;
      event.dataTransfer.effectAllowed = 'copy';
      event.dataTransfer.setData(DRAG_FILE_ID_TYPE, row.file.id);
      logCaseResolverWorkspaceEvent({
        source: 'relation_tree_browser',
        action: 'relation_tree_node_drag_started',
        message: `file_id=${row.file.id}`,
      });
      clearDragHandleArm();
    },
    [clearDragHandleArm, resolvedLookup.fileRowByNodeId, mode]
  );

  const renderNode = useCallback(
    (input: FolderTreeViewportRenderNodeInput): React.JSX.Element => (
      <RelationTreeNodeItem {...input} />
    ),
    []
  );

  const nodeRuntimeContextValue = useMemo(
    () => ({
      mode,
      lookup: resolvedLookup,
      isLocked: resolvedIsLocked,
      selectedFileIds: resolvedSelectedFileIds,
      onToggleFileSelection: resolvedOnToggleFileSelection,
      onLinkFile: (nextFileId: string): void => {
        logCaseResolverWorkspaceEvent({
          source: 'relation_tree_browser',
          action:
            mode === 'link_relations'
              ? 'relation_tree_node_link_clicked'
              : 'relation_tree_node_add_clicked',
          message: `file_id=${nextFileId}`,
        });
        if (mode === 'link_relations') {
          resolvedOnLinkFile?.(nextFileId);
          return;
        }
        resolvedOnAddFile?.(nextFileId);
      },
      onAddFile: resolvedOnAddFile,
      onPreviewFile: resolvedOnPreviewFile,
      onArmDragHandle: handleArmDragHandle,
    }),
    [
      handleArmDragHandle,
      resolvedIsLocked,
      resolvedLookup,
      mode,
      resolvedOnAddFile,
      resolvedOnLinkFile,
      resolvedOnPreviewFile,
      resolvedOnToggleFileSelection,
      resolvedSelectedFileIds,
    ]
  );

  return (
    <RelationTreeNodeRuntimeProvider value={nodeRuntimeContextValue}>
      <MasterFolderTreeViewport
        tree={tree}
        className={className}
        emptyLabel={emptyLabel}
        enableDnd={mode === 'add_to_node_canvas'}
        runtime={runtime}
        canStartDrag={mode === 'add_to_node_canvas' ? canStartDrag : undefined}
        canDrop={mode === 'add_to_node_canvas' ? canDrop : undefined}
        onNodeDragStart={mode === 'add_to_node_canvas' ? handleNodeDragStart : undefined}
        rootDropUi={{ enabled: false }}
        renderNode={renderNode}
      />
    </RelationTreeNodeRuntimeProvider>
  );
}

'use client';

import {
  ChevronDown,
  ChevronRight,
  FileText,
  Folder,
  FolderOpen,
  GripVertical,
  Lock,
  Plus,
  ScanText,
} from 'lucide-react';
import React from 'react';

import type { FolderTreeViewportRenderNodeInput } from '@/shared/lib/foldertree/public';
import { Button, Checkbox, Tooltip } from '@/shared/ui/primitives.public';
import { cn } from '@/shared/utils/ui-utils';

import { useRelationTreeNodeRuntimeContext } from './RelationTreeNodeRuntimeContext';
import { getCaseResolverDocTooltipWithFallback } from '../utils/docs';

type RelationTreeNodeItemProps = FolderTreeViewportRenderNodeInput;

const resolveNodeTypeFromMetadata = (
  node: FolderTreeViewportRenderNodeInput['node']
): 'case' | 'folder' | 'file' => {
  const raw = String(node.metadata?.['relationNodeType'] ?? '');
  if (raw === 'file' || raw === 'case' || raw === 'folder') return raw;
  if (node.kind === 'relation_file') return 'file';
  if (node.kind === 'relation_case') return 'case';
  return 'folder';
};

const renderFileTypeIcon = (fileType: string): React.JSX.Element => {
  if (fileType === 'scanfile') {
    return <ScanText className='size-3.5 shrink-0 text-amber-400/80' />;
  }
  return <FileText className='size-3.5 shrink-0 text-sky-400/80' />;
};

export function RelationTreeNodeItem(props: RelationTreeNodeItemProps): React.JSX.Element {
  const {
    node,
    depth,
    hasChildren,
    isExpanded,
    isDragging,
    isDropTarget,
    dropPosition,
    toggleExpand,
    select,
  } = props;

  const {
    mode,
    lookup,
    isLocked,
    selectedFileIds,
    onToggleFileSelection,
    onLinkFile,
    onAddFile,
    onPreviewFile,
    onArmDragHandle,
  } = useRelationTreeNodeRuntimeContext();
  const nodeType = resolveNodeTypeFromMetadata(node);
  const row = nodeType === 'file' ? (lookup.fileRowByNodeId.get(node.id) ?? null) : null;
  const fileId = row?.file.id ?? '';
  const isFileSelected = fileId.length > 0 && (selectedFileIds?.has(fileId) ?? false);

  const stateClassName =
    dropPosition === 'before'
      ? 'bg-blue-500/10 text-gray-100 ring-1 ring-inset ring-blue-500/60'
      : dropPosition === 'after'
        ? 'bg-blue-500/10 text-gray-100 ring-1 ring-inset ring-cyan-400/60'
        : isDragging
          ? 'opacity-50 text-gray-200'
          : isDropTarget
            ? 'bg-cyan-500/10 text-cyan-100'
            : 'text-gray-300 hover:bg-muted/40';

  if (nodeType !== 'file' || !row) {
    return (
      <div
        className={cn(
          'group flex items-center gap-2 rounded px-2 py-1.5 text-sm transition',
          stateClassName
        )}
        style={{ paddingLeft: `${depth * 16 + 8}px` }}
      >
        {hasChildren ? (
          <Button
            variant='ghost'
            size='sm'
            className='size-4 p-0 text-gray-500 hover:bg-white/10 hover:text-gray-300'
            onClick={(event): void => {
              event.preventDefault();
              event.stopPropagation();
              toggleExpand();
            }}
            aria-label={isExpanded ? 'Collapse' : 'Expand'}
            title={isExpanded ? 'Collapse' : 'Expand'}>
            {isExpanded ? (
              <ChevronDown className='size-3.5' />
            ) : (
              <ChevronRight className='size-3.5' />
            )}
          </Button>
        ) : (
          <span className='inline-flex size-4 items-center justify-center text-xs opacity-40'>
            •
          </span>
        )}
        {isExpanded ? (
          <FolderOpen className='size-4 shrink-0 text-amber-300/70' />
        ) : (
          <Folder className='size-4 shrink-0 text-amber-300/70' />
        )}
        <Button
          variant='link'
          className='h-auto min-w-0 flex-1 justify-start p-0 truncate text-left text-gray-200 hover:text-white hover:no-underline'
          onClick={(event): void => {
            event.preventDefault();
            event.stopPropagation();
            if (hasChildren) {
              toggleExpand();
              return;
            }
            select(event);
          }}
          title={node.name}
        >
          <span className='truncate'>{node.name}</span>
        </Button>
      </div>
    );
  }

  return (
    <div
      className={cn(
        'group flex items-center gap-2 rounded px-2 py-1.5 text-sm transition',
        stateClassName
      )}
      style={{ paddingLeft: `${depth * 16 + 8}px` }}
    >
      <span className='inline-flex size-4 items-center justify-center text-xs opacity-40'>•</span>
      {mode === 'link_relations' ? (
        <Checkbox
          checked={isFileSelected}
          onCheckedChange={() => onToggleFileSelection?.(row.file.id)}
          className='h-3.5 w-3.5 shrink-0'
          aria-label={`Select ${row.file.name}`}
        />
      ) : (
        <Tooltip
          content={getCaseResolverDocTooltipWithFallback(
            'dragToCanvas',
            'Drag from handle to canvas'
          )}
          side='top'
        >
          <button
            type='button'
            data-relation-drag-handle='true'
            className='inline-flex size-5 shrink-0 items-center justify-center rounded border border-border/60 bg-card/40 text-gray-400 transition hover:bg-card/70 hover:text-gray-200'
            onPointerDown={(event): void => {
              event.stopPropagation();
              onArmDragHandle?.(row.file.id);
            }}
            aria-label='Drag handle'
            title={'Drag handle'}>
            <GripVertical className='size-3.5' />
          </button>
        </Tooltip>
      )}

      {renderFileTypeIcon(row.file.fileType)}
      <Button
        variant='link'
        className='h-auto min-w-0 flex-1 justify-start p-0 truncate text-left text-gray-200 hover:text-cyan-300 hover:no-underline'
        onClick={(event): void => {
          event.preventDefault();
          event.stopPropagation();
          onPreviewFile?.(row.file.id);
        }}
        title={row.file.name}
      >
        <span className='truncate'>{row.file.name}</span>
      </Button>
      {row.file.isLocked ? <Lock className='size-3.5 shrink-0 text-amber-400/80' /> : null}
      {mode === 'link_relations' ? (
        <Button
          variant='ghost'
          size='sm'
          disabled={isLocked}
          className='h-7 w-7 shrink-0 p-0 text-gray-400 hover:bg-cyan-500/15 hover:text-cyan-300'
          onClick={(event): void => {
            event.preventDefault();
            event.stopPropagation();
            onLinkFile?.(row.file.id);
          }}
          aria-label={`Link ${row.file.name}`}
          title={`Link ${row.file.name}`}>
          <Plus className='size-3.5' />
        </Button>
      ) : (
        <Button
          variant='ghost'
          size='sm'
          className='h-7 w-7 shrink-0 p-0 text-gray-400 hover:bg-cyan-500/15 hover:text-cyan-300'
          onClick={(event): void => {
            event.preventDefault();
            event.stopPropagation();
            onAddFile?.(row.file.id);
          }}
          aria-label={`Add ${row.file.name} to canvas`}
          title={`Add ${row.file.name} to canvas`}>
          <Plus className='size-3.5' />
        </Button>
      )}
    </div>
  );
}

