export function DocumentPreviewDialog(): React.JSX.Element {
  const { previewFile: file, previewRow, isLocked } = useDocumentRelationSearchStateContext();
  const { onLinkFile, setPreviewFileId } = useDocumentRelationSearchActionsContext();

  const onClose = () => setPreviewFileId(null);
  const onLink = (fileId: string) => {
    onLinkFile(fileId);
    onClose();
  };

  const snippet = file
    ? (file.documentContentPlainText || file.documentContent || '').slice(0, 600)
    : '';

  return (
    <Dialog
      open={file !== null}
      onOpenChange={(open) => {
        if (!open) onClose();
      }}
    >
      <DialogContent className='max-w-xl'>
        {file && (
          <>
            <DialogHeader>
              <DialogTitle className='flex items-center gap-2 text-sm font-semibold'>
                <FileTypeIcon fileType={file.fileType} className='size-4' />
                <span className='min-w-0 truncate'>{file.name}</span>
                {file.isLocked && (
                  <Badge
                    variant='warning'
                    className='ml-auto h-5 px-1.5 text-[10px] font-bold uppercase'
                  >
                    LOCKED
                  </Badge>
                )}
              </DialogTitle>
              <DialogDescription className='sr-only'>
                Document preview for {file.name}
              </DialogDescription>
            </DialogHeader>

            <div className='grid grid-cols-2 gap-x-4 gap-y-1.5 text-xs'>
              <div>
                <span className='text-gray-500'>Folder: </span>
                <span className='text-gray-300'>{file.folder || 'Root'}</span>
              </div>
              <div>
                <span className='text-gray-500'>Date: </span>
                <span className='text-gray-300'>{formatShortDate(file.documentDate?.isoDate)}</span>
              </div>
              {previewRow?.addresserLabel && (
                <div>
                  <span className='text-gray-500'>From: </span>
                  <span className='text-gray-300'>{previewRow.addresserLabel}</span>
                </div>
              )}
              {previewRow?.addresseeLabel && (
                <div>
                  <span className='text-gray-500'>To: </span>
                  <span className='text-gray-300'>{previewRow.addresseeLabel}</span>
                </div>
              )}
              {previewRow?.signatureLabel && (
                <div>
                  <span className='text-gray-500'>Signature: </span>
                  <span className='text-cyan-400/80'>{previewRow.signatureLabel}</span>
                </div>
              )}
              {file.categoryId && (
                <div>
                  <span className='text-gray-500'>Category: </span>
                  <span className='text-gray-300'>{file.categoryId}</span>
                </div>
              )}
            </div>

            <div className='mt-3 max-h-[200px] overflow-auto rounded border border-border/40 bg-card/20 p-3 font-mono text-[11px] leading-relaxed text-gray-400 whitespace-pre-wrap'>
              {snippet || '(No content preview)'}
            </div>

            <DialogFooter>
              <Button variant='outline' size='sm' onClick={onClose} className='h-8 px-3 text-xs'>
                Cancel
              </Button>
              <Button
                disabled={isLocked}
                onClick={() => {
                  onLink(file.id);
                }}
                className='flex items-center gap-1.5 h-8 px-3 text-xs font-medium'
              >
                Link this document
                <ChevronRight className='size-3' />
              </Button>
            </DialogFooter>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}

'use client';

import React, { useMemo } from 'react';

import { FilterPanel } from '@/shared/ui/templates.public';
import type { FilterField } from '@/shared/contracts/ui/panels';

import { TAG_NONE, CAT_NONE } from './document-relation-search-utils';
import {
  useDocumentRelationSearchActionsContext,
  useDocumentRelationSearchStateContext,
} from '../../context/DocumentRelationSearchContext';

export function FilterBar(): React.JSX.Element {
  const {
    caseTagOptions,
    caseCategoryOptions,
    dateFrom,
    dateTo,
    tagIdFilter,
    categoryIdFilter,
  } = useDocumentRelationSearchStateContext();
  const { setDateFrom, setDateTo, setTagIdFilter, setCategoryIdFilter, resetFilters } =
    useDocumentRelationSearchActionsContext();

  const filterFields = useMemo<FilterField[]>(
    () => [
      {
        key: 'dateFrom',
        label: 'From',
        type: 'date',
      },
      {
        key: 'dateTo',
        label: 'To',
        type: 'date',
      },
      {
        key: 'tagId',
        label: 'Tag',
        type: 'select',
        options: [{ value: TAG_NONE, label: 'Any tag' }, ...caseTagOptions],
      },
      {
        key: 'categoryId',
        label: 'Category',
        type: 'select',
        options: [{ value: CAT_NONE, label: 'Any category' }, ...caseCategoryOptions],
      },
    ],
    [caseTagOptions, caseCategoryOptions]
  );

  const filterValues = useMemo(
    () => ({
      dateFrom: dateFrom ?? '',
      dateTo: dateTo ?? '',
      tagId: tagIdFilter ?? TAG_NONE,
      categoryId: categoryIdFilter ?? CAT_NONE,
    }),
    [dateFrom, dateTo, tagIdFilter, categoryIdFilter]
  );

  return (
    <FilterPanel
      filters={filterFields}
      values={filterValues}
      onFilterChange={(key, val) => {
        const value = typeof val === 'string' ? (val.length > 0 ? val : null) : null;
        if (key === 'dateFrom') setDateFrom(value);
        if (key === 'dateTo') setDateTo(value);
        if (key === 'tagId') setTagIdFilter(val === TAG_NONE ? null : (val as string));
        if (key === 'categoryId') setCategoryIdFilter(val === CAT_NONE ? null : (val as string));
      }}
      onReset={resetFilters}
      showHeader={false}
      compact
      className='border-b border-border/40 bg-card/10'
    />
  );
}

