  setShowFiltersBar: React.Dispatch<React.SetStateAction<boolean>>;
  selectedFileIds: Set<string>;
  setSelectedFileIds: React.Dispatch<React.SetStateAction<Set<string>>>;
  previewFileId: string | null;
  setPreviewFileId: (id: string | null) => void;

  // Actions
  onLinkFile: (fileId: string) => void;
  isLocked: boolean;
  handleLinkAll: () => Promise<void>;
  selectAllVisible: () => void;
  clearSelection: () => void;
  toggleFileSelection: (id: string) => void;

  // Computed
  caseTagOptions: SelectOption[];
  caseCategoryOptions: SelectOption[];
  documentSearchRows: NodeFileDocumentSearchRow[];
  visibleDocumentSearchRows: NodeFileDocumentSearchRow[];
  currentDocRows: NodeFileDocumentSearchRow[];
  filtersActiveCount: number;
  allVisibleSelected: boolean;
  someVisibleSelected: boolean;
  previewRow: NodeFileDocumentSearchRow | null;
  previewFile: CaseResolverFile | null;
  relationTreeNodes: MasterTreeNode[];
  relationTreeLookup: RelationTreeLookup;
}

export type DocumentRelationSearchContextValue = DocumentRelationSearchContextType;

type DocumentRelationSearchActionKey =
  | 'setDocumentSearchScope'
  | 'setDocumentSearchQuery'
  | 'setFileTypeFilter'
  | 'setSortMode'
  | 'setDateFrom'
  | 'setDateTo'
  | 'setTagIdFilter'
  | 'setCategoryIdFilter'
  | 'resetFilters'
  | 'setResultHeight'
  | 'setShowFiltersBar'
  | 'setSelectedFileIds'
  | 'setPreviewFileId'
  | 'onLinkFile'
  | 'handleLinkAll'
  | 'selectAllVisible'
  | 'clearSelection'
  | 'toggleFileSelection';

export type DocumentRelationSearchActionsValue = Pick<
  DocumentRelationSearchContextValue,
  DocumentRelationSearchActionKey
>;
export type DocumentRelationSearchStateValue = Omit<
  DocumentRelationSearchContextValue,
  DocumentRelationSearchActionKey
>;

const DocumentRelationSearchStateContext = createContext<DocumentRelationSearchStateValue | null>(
  null
);
const DocumentRelationSearchActionsContext =
  createContext<DocumentRelationSearchActionsValue | null>(null);

export function useDocumentRelationSearchStateContext(): DocumentRelationSearchStateValue {
  const context = useContext(DocumentRelationSearchStateContext);
  if (!context) {
    throw internalError(
      'useDocumentRelationSearchStateContext must be used within a DocumentRelationSearchProvider'
    );
  }
  return context;
}

export function useDocumentRelationSearchActionsContext(): DocumentRelationSearchActionsValue {
  const context = useContext(DocumentRelationSearchActionsContext);
  if (!context) {
    throw internalError(
      'useDocumentRelationSearchActionsContext must be used within a DocumentRelationSearchProvider'
    );
  }
  return context;
}

export interface DocumentRelationSearchProviderProps {
  children: React.ReactNode;
  draftFileId: string;
  onLinkFile: (fileId: string) => void;
  isLocked?: boolean;
  defaultScope?: DocumentSearchScope;
  defaultSort?: DocumentRelationSortMode;
  defaultFileType?: DocumentRelationFileTypeFilter;
}

export function DocumentRelationSearchProvider({
  children,
  draftFileId,
  onLinkFile,
  isLocked = false,
  defaultScope,
  defaultSort,
  defaultFileType,
}: DocumentRelationSearchProviderProps): React.JSX.Element {
  const { state } = useCaseResolverViewStateContext();
  const { workspace, caseResolverIdentifiers, caseResolverTags, caseResolverCategories } = state;
  const draftFile = useMemo(
    () => workspace.files.find((file) => file.id === draftFileId) ?? null,
    [draftFileId, workspace.files]
  );
  const resolvedActiveCaseId = useMemo(() => {
    const activeCaseId = state.activeCaseId?.trim() ?? '';
    if (activeCaseId.length > 0) return activeCaseId;
    const parentCaseId = draftFile?.parentCaseId?.trim() ?? '';
    return parentCaseId.length > 0 ? parentCaseId : null;
  }, [draftFile?.parentCaseId, state.activeCaseId]);

  const [resultHeight, setResultHeight] = useState<ResultHeight>('normal');
  const [showFiltersBar, setShowFiltersBar] = useState(false);
  const [selectedFileIds, setSelectedFileIds] = useState<Set<string>>(new Set());
  const [previewFileId, setPreviewFileId] = useState<string | null>(null);

  const searchProps = useDocumentRelationSearch({
    workspace,
    activeCaseId: resolvedActiveCaseId,
    caseResolverIdentifiers,
    excludeFileIds: [draftFileId],
    initialScope: defaultScope,
    initialSort: defaultSort,
    initialFileType: defaultFileType,
  });

  const {
    documentSearchScope,
    setDocumentSearchScope,
    visibleDocumentSearchRows,
    documentSearchRows,
    documentSearchQuery,
    setDocumentSearchQuery,
    dateFrom,
    setDateFrom,
    dateTo,
    setDateTo,
    tagIdFilter,
    setTagIdFilter,
    categoryIdFilter,
    setCategoryIdFilter,
    fileTypeFilter,
    setFileTypeFilter,
    sortMode,
    setSortMode,
    resetFilters,
    relationTreeNodes,
    relationTreeLookup,
  } = searchProps;

  // Reset selection when scope or filters change
  useEffect(() => {
    setSelectedFileIds(new Set());
  }, [
    documentSearchScope,
    documentSearchQuery,
    dateFrom,
    dateTo,
    tagIdFilter,
    categoryIdFilter,
    fileTypeFilter,
  ]);

  const currentDocRows = visibleDocumentSearchRows;

  const filtersActiveCount = useMemo(() => {
    let count = 0;
    if (dateFrom) count++;
    if (dateTo) count++;
    if (tagIdFilter) count++;
    if (categoryIdFilter) count++;
    if (fileTypeFilter !== 'all') count++;
    return count;
  }, [dateFrom, dateTo, tagIdFilter, categoryIdFilter, fileTypeFilter]);

  const caseTagOptions = useMemo(
    () => caseResolverTags.map((t) => ({ value: t.id, label: t.label })),
    [caseResolverTags]
  );
  const caseCategoryOptions = useMemo(
    () => caseResolverCategories.map((c) => ({ value: c.id, label: c.name })),
    [caseResolverCategories]
  );

  const selectAllVisible = useCallback(() => {
    setSelectedFileIds((prev) => {
      const next = new Set(prev);
      currentDocRows.forEach((row) => next.add(row.file.id));
      return next;
    });
  }, [currentDocRows]);

  const clearSelection = useCallback(() => {
    setSelectedFileIds(new Set());
  }, []);

  const toggleFileSelection = useCallback((id: string) => {
    setSelectedFileIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, []);

  const allVisibleSelected =
    currentDocRows.length > 0 && currentDocRows.every((r) => selectedFileIds.has(r.file.id));
  const someVisibleSelected =
    !allVisibleSelected && currentDocRows.some((r) => selectedFileIds.has(r.file.id));

  const handleLinkAll = useCallback(async () => {
    if (selectedFileIds.size === 0) return;
    const ids = Array.from(selectedFileIds);
    logCaseResolverWorkspaceEvent({
      source: 'document_relation_search',
      action: 'relation_tree_bulk_link_applied',
      message: `count=${ids.length}`,
    });
    for (const id of ids) {
      onLinkFile(id);
    }
    clearSelection();
  }, [selectedFileIds, onLinkFile, clearSelection]);

  const previewRow = useMemo(
    () =>
      previewFileId ? (currentDocRows.find((r) => r.file.id === previewFileId) ?? null) : null,
    [currentDocRows, previewFileId]
  );
  const previewFile = previewRow?.file ?? null;

  const stateValue = useMemo<DocumentRelationSearchStateValue>(
    () => ({
      documentSearchScope,
      documentSearchQuery,
      fileTypeFilter,
      sortMode,
      dateFrom,
      dateTo,
      tagIdFilter,
      categoryIdFilter,
      resultHeight,
      showFiltersBar,
      selectedFileIds,
      previewFileId,
      isLocked,
      caseTagOptions,
      caseCategoryOptions,
      documentSearchRows,
      visibleDocumentSearchRows,
      currentDocRows,
      filtersActiveCount,
      allVisibleSelected,
      someVisibleSelected,
      previewRow,
      previewFile,
      relationTreeNodes,
      relationTreeLookup,
    }),
    [
      documentSearchScope,
      documentSearchQuery,
      fileTypeFilter,
      sortMode,
      dateFrom,
      dateTo,
      tagIdFilter,
      categoryIdFilter,
      resultHeight,
      showFiltersBar,
      selectedFileIds,
      previewFileId,
      isLocked,
      caseTagOptions,
      caseCategoryOptions,
      documentSearchRows,
      visibleDocumentSearchRows,
      currentDocRows,
      filtersActiveCount,
      allVisibleSelected,
      someVisibleSelected,
      previewRow,
      previewFile,
      relationTreeNodes,
      relationTreeLookup,
    ]
  );

  const actionsValue = useMemo<DocumentRelationSearchActionsValue>(
    () => ({
      setDocumentSearchScope,
      setDocumentSearchQuery,
      setFileTypeFilter,
      setSortMode,
      setDateFrom,
      setDateTo,
      setTagIdFilter,
      setCategoryIdFilter,
      resetFilters,
      setResultHeight,
      setShowFiltersBar,
      setSelectedFileIds,
      setPreviewFileId,
      onLinkFile,
      handleLinkAll,
      selectAllVisible,
      clearSelection,
      toggleFileSelection,
    }),
    [
      setDocumentSearchScope,
      setDocumentSearchQuery,
      setFileTypeFilter,
      setSortMode,
      setDateFrom,
      setDateTo,
      setTagIdFilter,
      setCategoryIdFilter,
      resetFilters,
      setResultHeight,
      setShowFiltersBar,
      setSelectedFileIds,
      setPreviewFileId,
      onLinkFile,
      handleLinkAll,
      selectAllVisible,
      clearSelection,
      toggleFileSelection,
    ]
  );

  return (
    <DocumentRelationSearchStateContext.Provider value={stateValue}>
      <DocumentRelationSearchActionsContext.Provider value={actionsValue}>
        {children}
      </DocumentRelationSearchActionsContext.Provider>
    </DocumentRelationSearchStateContext.Provider>
  );
}

'use client';

import { useCallback, useMemo, useState } from 'react';

import type { CaseResolverFile } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverIdentifier } from '@/shared/contracts/case-resolver/relations';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';
import type { DocumentRelationFileTypeFilter, DocumentRelationSortMode } from '@/shared/contracts/case-resolver/base';

export type { DocumentRelationFileTypeFilter, DocumentRelationSortMode };
import {
  collectScopedCaseIds,
  normalizeFolderPathSegments,
  resolveIdentifierSearchLabel,
  resolvePartyReferenceSearchLabel,
  normalizeSearchText,
  type NodeFileDocumentSearchRow,
  type NodeFileDocumentSearchScope,
} from '../../components/CaseResolverNodeFileUtils';
import { buildRelationMasterTree } from '../tree/relation-master-tree';

export type UseDocumentRelationSearchProps = {
  workspace: CaseResolverWorkspace;
  activeCaseId: string | null;
  caseResolverIdentifiers: CaseResolverIdentifier[];
  /** IDs to exclude from results: the current document + already-linked files */
  excludeFileIds: string[];
  /** Initial scope, applied only on first mount */
  initialScope?: NodeFileDocumentSearchScope;
  /** Initial sort mode, applied only on first mount */
  initialSort?: DocumentRelationSortMode;
  /** Initial file type filter, applied only on first mount */
  initialFileType?: DocumentRelationFileTypeFilter;
};

export function useDocumentRelationSearch({
  workspace,
  activeCaseId,
  caseResolverIdentifiers,
  excludeFileIds,
  initialScope = 'case_scope',
  initialSort = 'name_asc',
  initialFileType = 'all',
}: UseDocumentRelationSearchProps) {
  const [documentSearchScope, setDocumentSearchScope] =
    useState<NodeFileDocumentSearchScope>(initialScope);
  const [documentSearchQuery, setDocumentSearchQuery] = useState('');
  const [fileTypeFilter, setFileTypeFilter] =
    useState<DocumentRelationFileTypeFilter>(initialFileType);
  const [sortMode, setSortMode] = useState<DocumentRelationSortMode>(initialSort);
  const [dateFrom, setDateFrom] = useState<string | null>(null);
  const [dateTo, setDateTo] = useState<string | null>(null);
  const [tagIdFilter, setTagIdFilter] = useState<string | null>(null);
  const [categoryIdFilter, setCategoryIdFilter] = useState<string | null>(null);

  const excludeSet = useMemo(() => new Set(excludeFileIds), [excludeFileIds]);

  const caseIdentifierLabelById = useMemo((): Map<string, string> => {
    const labelsById = new Map<string, string>();
    caseResolverIdentifiers.forEach((identifier: CaseResolverIdentifier): void => {
      const id = identifier.id;
      const resolvedLabel = identifier.label || identifier.name || id;
      labelsById.set(id, resolvedLabel);
    });
    return labelsById;
  }, [caseResolverIdentifiers]);

  const scopedCaseIds = useMemo(
    (): Set<string> | null => collectScopedCaseIds(workspace.files, activeCaseId),
    [activeCaseId, workspace.files]
  );

  const allSearchableFiles = useMemo(
    (): CaseResolverFile[] =>
      workspace.files.filter((file: CaseResolverFile): boolean => {
        if (file.fileType === 'case') return false;
        if (excludeSet.has(file.id)) return false;
        if (fileTypeFilter === 'document') return file.fileType === 'document';
        if (fileTypeFilter === 'scanfile') return file.fileType === 'scanfile';
        if (dateFrom !== null && file.documentDate?.isoDate) {
          if (file.documentDate.isoDate < dateFrom) return false;
        }
        if (dateTo !== null && file.documentDate?.isoDate) {
          if (file.documentDate.isoDate > dateTo) return false;
        }
        if (tagIdFilter !== null && (file.tagId ?? null) !== tagIdFilter) return false;
        if (categoryIdFilter !== null && (file.categoryId ?? null) !== categoryIdFilter)
          return false;
        return true;
      }),
    [workspace.files, excludeSet, fileTypeFilter, dateFrom, dateTo, tagIdFilter, categoryIdFilter]
  );

  const caseScopedSearchableFiles = useMemo((): CaseResolverFile[] => {
    if (!activeCaseId || !scopedCaseIds || scopedCaseIds.size === 0) {
      return allSearchableFiles;
    }
    return allSearchableFiles.filter((file: CaseResolverFile): boolean =>
      Boolean(file.parentCaseId && scopedCaseIds.has(file.parentCaseId))
    );
  }, [activeCaseId, allSearchableFiles, scopedCaseIds]);

  const documentSearchRows = useMemo((): NodeFileDocumentSearchRow[] => {
    const sourceFiles =
      documentSearchScope === 'all_cases' ? allSearchableFiles : caseScopedSearchableFiles;
    return sourceFiles.map((file: CaseResolverFile): NodeFileDocumentSearchRow => {
      const folderPath = typeof file.folder === 'string' ? file.folder.trim() : '';
      const folderSegments = normalizeFolderPathSegments(folderPath);
      const signatureLabel = resolveIdentifierSearchLabel(
        file.caseIdentifierId,
        caseIdentifierLabelById
      );
      const addresserLabel = resolvePartyReferenceSearchLabel(file.addresser);
      const addresseeLabel = resolvePartyReferenceSearchLabel(file.addressee);
      const searchable = normalizeSearchText(
        [file.name, file.folder, signatureLabel, addresserLabel, addresseeLabel].join(' ')
      );
      return {
        file,
        signatureLabel,
        addresserLabel,
        addresseeLabel,
        folderPath,
        folderSegments,
        searchable,
      };
    });
  }, [allSearchableFiles, caseIdentifierLabelById, caseScopedSearchableFiles, documentSearchScope]);

  const visibleDocumentSearchRows = useMemo((): NodeFileDocumentSearchRow[] => {
    const rows = [...documentSearchRows];
    if (sortMode === 'name_asc') {
      rows.sort((a, b) => a.file.name.localeCompare(b.file.name));
    } else if (sortMode === 'folder_asc') {
      rows.sort((a, b) => a.folderPath.localeCompare(b.folderPath));
    } else if (sortMode === 'date_desc') {
      rows.sort((a, b) =>
        (b.file.documentDate?.isoDate ?? '').localeCompare(a.file.documentDate?.isoDate ?? '')
      );
    } else if (sortMode === 'date_asc') {
      rows.sort((a, b) =>
        (a.file.documentDate?.isoDate ?? '').localeCompare(b.file.documentDate?.isoDate ?? '')
      );
    }
    return rows;
  }, [documentSearchRows, sortMode]);

  const relationTreeBuildResult = useMemo(
    () =>
      buildRelationMasterTree({
        rows: visibleDocumentSearchRows,
      }),
    [visibleDocumentSearchRows]
  );

  const resetFilters = useCallback((): void => {
    setFileTypeFilter('all');
    setDateFrom(null);
    setDateTo(null);
    setTagIdFilter(null);
    setCategoryIdFilter(null);
  }, []);

  return {
    // State
    documentSearchScope,
    setDocumentSearchScope,
    documentSearchQuery,
    setDocumentSearchQuery,
    fileTypeFilter,
    setFileTypeFilter,
    sortMode,
    setSortMode,
    dateFrom,
    setDateFrom,
    dateTo,
    setDateTo,
    tagIdFilter,
    setTagIdFilter,
    categoryIdFilter,
    setCategoryIdFilter,
    resetFilters,
    // Computed
    caseIdentifierLabelById,
    documentSearchRows,
    visibleDocumentSearchRows,
    totalRowCount: documentSearchRows.length,
    relationTreeNodes: relationTreeBuildResult.nodes,
    relationTreeLookup: relationTreeBuildResult.lookup,
  };
}

import type { CaseResolverRuntimeRequestedContextSlice } from '../types';

export type RequestedContextEvent =
  | { type: 'query_changed'; requestedFileId: string | null }
  | { type: 'workspace_contains_requested' }
  | { type: 'refresh_started'; requestKey: string; startedAtMs: number }
  | { type: 'refresh_succeeded_found' }
  | { type: 'refresh_succeeded_missing' }
  | { type: 'refresh_failed' }
  | { type: 'retry' }
  | { type: 'reset' }
  | { type: 'watchdog_timeout' };

const normalizeRequestedFileId = (value: string | null | undefined): string | null => {
  const normalizedValue = value?.trim() ?? '';
  return normalizedValue.length > 0 ? normalizedValue : null;
};

export const reduceRequestedContextState = (
  currentState: CaseResolverRuntimeRequestedContextSlice,
  event: RequestedContextEvent
): CaseResolverRuntimeRequestedContextSlice => {
  if (event.type === 'reset') {
    return {
      requestedFileId: null,
      retryTick: 0,
      status: 'idle',
      issue: null,
      inFlightRequestKey: null,
      attemptedRequestKey: null,
      startedAtMs: null,
    };
  }

  if (event.type === 'query_changed') {
    const normalizedRequestedFileId = normalizeRequestedFileId(event.requestedFileId);
    if (!normalizedRequestedFileId) {
      return {
        ...currentState,
        requestedFileId: null,
        retryTick: 0,
        status: 'idle',
        issue: null,
        inFlightRequestKey: null,
        attemptedRequestKey: null,
        startedAtMs: null,
      };
    }
    if (normalizedRequestedFileId === currentState.requestedFileId) return currentState;
    return {
      ...currentState,
      requestedFileId: normalizedRequestedFileId,
      retryTick: 0,
      status: 'loading',
      issue: null,
      inFlightRequestKey: null,
      attemptedRequestKey: null,
      startedAtMs: null,
    };
  }

  if (!currentState.requestedFileId) return currentState;

  if (event.type === 'workspace_contains_requested') {
    return {
      ...currentState,
      status: 'ready',
      issue: null,
      inFlightRequestKey: null,
      startedAtMs: null,
    };
  }

  if (event.type === 'refresh_started') {
    return {
      ...currentState,
      status: 'loading',
      issue: null,
      inFlightRequestKey: event.requestKey,
      attemptedRequestKey: event.requestKey,
      startedAtMs: event.startedAtMs,
    };
  }

  if (event.type === 'refresh_succeeded_found') {
    return {
      ...currentState,
      status: 'ready',
      issue: null,
      inFlightRequestKey: null,
      startedAtMs: null,
    };
  }

  if (event.type === 'refresh_succeeded_missing') {
    return {
      ...currentState,
      status: 'missing_not_found',
      issue: 'requested_file_missing',
      inFlightRequestKey: null,
      startedAtMs: null,
    };
  }

  if (event.type === 'refresh_failed' || event.type === 'watchdog_timeout') {
    return {
      ...currentState,
      status: 'missing_unavailable',
      issue: 'workspace_unavailable',
      inFlightRequestKey: null,
      startedAtMs: null,
    };
  }

  if (event.type === 'retry') {
    return {
      ...currentState,
      status: 'loading',
      issue: null,
      retryTick: currentState.retryTick + 1,
      inFlightRequestKey: null,
      startedAtMs: null,
    };
  }

  return currentState;
};

import { logCaseResolverWorkspaceEvent } from '../workspace-persistence';

type CounterMetricName = 'selector_recompute_count' | 'context_state_transition_count';

type DurationMetricName =
  | 'tree_scope_resolve_ms'
  | 'case_open_bootstrap_ms'
  | 'case_open_first_tree_ready_ms'
  | 'case_list_search_index_build_ms'
  | 'case_tree_master_nodes_build_ms'
  | 'case_search_filter_ms'
  | 'editor_dirty_eval_ms';

type CounterState = {
  pending: number;
  lastFlushedAtMs: number;
};

const counterStateByMetric = new Map<CounterMetricName, CounterState>();
const COUNTER_FLUSH_INTERVAL_MS = 1_000;

const nowMs = (): number =>
  typeof performance !== 'undefined' && typeof performance.now === 'function'
    ? performance.now()
    : Date.now();

export const incrementCaseResolverCounterMetric = (
  metric: CounterMetricName,
  options?: {
    count?: number;
    source?: string;
    forceFlush?: boolean;
  }
): void => {
  const step = Math.max(1, Math.floor(options?.count ?? 1));
  const source = options?.source ?? 'case_view';
  const forceFlush = options?.forceFlush === true;
  const currentTimeMs = nowMs();
  const state = counterStateByMetric.get(metric) ?? {
    pending: 0,
    lastFlushedAtMs: currentTimeMs,
  };
  state.pending += step;
  const shouldFlush =
    forceFlush || currentTimeMs - state.lastFlushedAtMs >= COUNTER_FLUSH_INTERVAL_MS;
  if (!shouldFlush) {
    counterStateByMetric.set(metric, state);
    return;
  }

  const count = state.pending;
  state.pending = 0;
  state.lastFlushedAtMs = currentTimeMs;
  counterStateByMetric.set(metric, state);
  logCaseResolverWorkspaceEvent({
    source,
    action: metric,
    message: `count=${count}`,
  });
};

export const logCaseResolverDurationMetric = (
  metric: DurationMetricName,
  durationMs: number,
  options?: {
    source?: string;
    message?: string;
    minDurationMs?: number;
  }
): void => {
  if (!Number.isFinite(durationMs) || durationMs < 0) return;
  const minDurationMs = options?.minDurationMs ?? 0;
  if (durationMs < minDurationMs) return;
  logCaseResolverWorkspaceEvent({
    source: options?.source ?? 'case_view',
    action: metric,
    durationMs,
    message: options?.message,
  });
};

'use client';

import React, { createContext, useContext, useEffect, useMemo, useRef } from 'react';

import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { getCaseResolverWorkspaceRevision } from '../workspace-persistence';
import { useCaseResolverSelector } from './hooks/useCaseResolverStore';
import { incrementCaseResolverCounterMetric } from './metrics';
import { createInitialCaseResolverRuntimeState } from './state';
import { createCaseResolverRuntimeStore } from './store';

import type { CaseResolverRuntimeStore } from './store';
import type { CaseResolverRuntimeSelector } from './types';


type CaseResolverRuntimeProviderProps = {
  workspace: CaseResolverWorkspace;
  selectedFileId: string | null;
  selectedAssetId: string | null;
  selectedFolderPath: string | null;
  activeCaseId: string | null;
  requestedFileId: string | null;
  requestedContextStatus: 'loading' | 'ready' | 'missing';
  requestedContextIssue: 'requested_file_missing' | 'workspace_unavailable' | null;
  children: React.ReactNode;
};

const CaseResolverRuntimeStoreContext = createContext<CaseResolverRuntimeStore | null>(null);

const mapRequestedStatus = (
  requestedContextStatus: 'loading' | 'ready' | 'missing',
  requestedContextIssue: 'requested_file_missing' | 'workspace_unavailable' | null
): 'idle' | 'loading' | 'ready' | 'missing_not_found' | 'missing_unavailable' => {
  if (requestedContextStatus === 'loading') return 'loading';
  if (requestedContextStatus === 'ready') return 'ready';
  if (requestedContextIssue === 'workspace_unavailable') return 'missing_unavailable';
  if (requestedContextIssue === 'requested_file_missing') return 'missing_not_found';
  return 'idle';
};

export function CaseResolverRuntimeProvider(
  props: CaseResolverRuntimeProviderProps
): React.JSX.Element {
  const {
    workspace,
    selectedFileId,
    selectedAssetId,
    selectedFolderPath,
    activeCaseId,
    requestedFileId,
    requestedContextStatus,
    requestedContextIssue,
    children,
  } = props;

  const storeRef = useRef<CaseResolverRuntimeStore | null>(null);
  if (!storeRef.current) {
    storeRef.current = createCaseResolverRuntimeStore(
      createInitialCaseResolverRuntimeState(workspace)
    );
  }
  const store = storeRef.current;

  const workspaceRevision = getCaseResolverWorkspaceRevision(workspace);

  useEffect((): void => {
    store.patchState((currentState) => {
      const nextRequestedStatus = mapRequestedStatus(requestedContextStatus, requestedContextIssue);
      const isWorkspaceChanged =
        currentState.workspace.value !== workspace ||
        currentState.workspace.revision !== workspaceRevision;
      const isSelectionChanged =
        currentState.selection.selectedFileId !== selectedFileId ||
        currentState.selection.selectedAssetId !== selectedAssetId ||
        currentState.selection.selectedFolderPath !== selectedFolderPath ||
        currentState.selection.activeCaseId !== activeCaseId;
      const isRequestedContextChanged =
        currentState.requestedContext.requestedFileId !== requestedFileId ||
        currentState.requestedContext.status !== nextRequestedStatus ||
        currentState.requestedContext.issue !== requestedContextIssue;
      if (!isWorkspaceChanged && !isSelectionChanged && !isRequestedContextChanged) {
        return currentState;
      }
      const transitionCount =
        (isWorkspaceChanged ? 1 : 0) +
        (isSelectionChanged ? 1 : 0) +
        (isRequestedContextChanged ? 1 : 0);
      if (transitionCount > 0) {
        incrementCaseResolverCounterMetric('context_state_transition_count', {
          count: transitionCount,
          source: 'runtime_provider',
        });
      }
      const nextWorkspaceSlice = isWorkspaceChanged
        ? {
          value: workspace,
          revision: workspaceRevision,
          isHydrated: workspace.files.length > 0 || workspace.assets.length > 0,
        }
        : currentState.workspace;
      const nextSelectionSlice = isSelectionChanged
        ? {
          selectedFileId,
          selectedAssetId,
          selectedFolderPath,
          activeCaseId,
        }
        : currentState.selection;
      const nextRequestedContextSlice = isRequestedContextChanged
        ? {
          ...currentState.requestedContext,
          requestedFileId,
          status: nextRequestedStatus,
          issue: requestedContextIssue,
        }
        : currentState.requestedContext;
      return {
        ...currentState,
        workspace: nextWorkspaceSlice,
        selection: nextSelectionSlice,
        requestedContext: nextRequestedContextSlice,
      };
    });
  }, [
    activeCaseId,
    requestedContextIssue,
    requestedContextStatus,
    requestedFileId,
    selectedAssetId,
    selectedFileId,
    selectedFolderPath,
    store,
    workspace,
    workspaceRevision,
  ]);

  const contextValue = useMemo((): CaseResolverRuntimeStore => store, [store]);

  return (
    <CaseResolverRuntimeStoreContext.Provider value={contextValue}>
      {children}
    </CaseResolverRuntimeStoreContext.Provider>
  );
}

function useCaseResolverRuntimeStore(): CaseResolverRuntimeStore {
  const store = useContext(CaseResolverRuntimeStoreContext);
  if (!store) {
    throw new Error('useCaseResolverRuntimeStore must be used within CaseResolverRuntimeProvider');
  }
  return store;
}

export function useCaseResolverRuntimeSelector<T>(
  selector: CaseResolverRuntimeSelector<T>,
  equalityFn?: (left: T, right: T) => boolean
): T {
  const store = useCaseResolverRuntimeStore();
  return useCaseResolverSelector(store, selector, equalityFn);
}

import type { CaseResolverAssetFile, CaseResolverFile, CaseResolverFolderRecord } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { getCaseResolverWorkspaceRevision } from '../../workspace-persistence';

const EMPTY_SET = new Set<string>();

const decodeHtmlEntities = (value: string): string =>
  value
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, '\'');

const stripHtml = (value: string): string =>
  decodeHtmlEntities(value.replace(/<[^>]*>/g, ' '))
    .replace(/\s+/g, ' ')
    .trim();

export const resolveCaseResolverPlainText = (file: CaseResolverFile): string => {
  const plainText = file.documentContentPlainText.trim();
  if (plainText.length > 0) return plainText;
  const markdown = file.documentContentMarkdown.trim();
  if (markdown.length > 0) return markdown;
  return stripHtml(file.documentContent);
};

const forEachFolderPathAncestor = (
  folderPath: string,
  callback: (ancestorPath: string) => void
): void => {
  const normalizedFolderPath = folderPath.trim();
  if (!normalizedFolderPath) return;
  const folderParts = normalizedFolderPath.split('/').filter(Boolean);
  for (let index = 0; index < folderParts.length; index += 1) {
    callback(folderParts.slice(0, index + 1).join('/'));
  }
};

export type CaseResolverRuntimeIndexes = {
  workspaceRevision: number;
  filesById: Map<string, CaseResolverFile>;
  assetsById: Map<string, CaseResolverAssetFile>;
  foldersByPath: Set<string>;
  caseFilesById: Map<string, CaseResolverFile>;
  parentCaseIdByCaseId: Map<string, string | null>;
  childCaseIdsByParentId: Map<string, string[]>;
  subtreeCaseIdsByCaseId: Map<string, Set<string>>;
  nonCaseFilesByOwnerCaseId: Map<string, CaseResolverFile[]>;
  ownerCaseIdBySourceFileId: Map<string, string>;
  assetsByOwnerCaseId: Map<string, CaseResolverAssetFile[]>;
  folderOwnerCaseIdsByPath: Map<string, string[]>;
  relatedFileIdsByFileId: Map<string, string[]>;
  plainTextByFileId: Map<string, string>;
};

const runtimeIndexesCache = new WeakMap<
  CaseResolverWorkspace,
  { revision: number; indexes: CaseResolverRuntimeIndexes }
>();

export const buildCaseResolverRuntimeIndexes = (
  workspace: CaseResolverWorkspace
): CaseResolverRuntimeIndexes => {
  const filesById = new Map<string, CaseResolverFile>();
  const assetsById = new Map<string, CaseResolverAssetFile>();
  const foldersByPath = new Set<string>(workspace.folders);
  const caseFilesById = new Map<string, CaseResolverFile>();
  const parentCaseIdByCaseId = new Map<string, string | null>();
  const childCaseIdsByParentId = new Map<string, string[]>();
  const nonCaseFilesByOwnerCaseId = new Map<string, CaseResolverFile[]>();
  const ownerCaseIdBySourceFileId = new Map<string, string>();
  const relatedFileIdsByFileId = new Map<string, string[]>();
  const plainTextByFileId = new Map<string, string>();

  workspace.files.forEach((file: CaseResolverFile): void => {
    filesById.set(file.id, file);
    foldersByPath.add(file.folder);
    plainTextByFileId.set(file.id, resolveCaseResolverPlainText(file));
    const normalizedRelatedIds = (file.relatedFileIds ?? [])
      .map((relatedFileId: string): string => relatedFileId.trim())
      .filter((relatedFileId: string): boolean => relatedFileId.length > 0);
    relatedFileIdsByFileId.set(file.id, normalizedRelatedIds);

    if (file.fileType === 'case') {
      caseFilesById.set(file.id, file);
      return;
    }

    const normalizedOwnerCaseId = file.parentCaseId?.trim() ?? '';
    if (!normalizedOwnerCaseId) return;
    const caseFiles = nonCaseFilesByOwnerCaseId.get(normalizedOwnerCaseId) ?? [];
    caseFiles.push(file);
    nonCaseFilesByOwnerCaseId.set(normalizedOwnerCaseId, caseFiles);
    ownerCaseIdBySourceFileId.set(file.id, normalizedOwnerCaseId);
  });

  caseFilesById.forEach((caseFile: CaseResolverFile): void => {
    const rawParentCaseId = caseFile.parentCaseId?.trim() ?? '';
    const normalizedParentCaseId =
      rawParentCaseId.length > 0 &&
      rawParentCaseId !== caseFile.id &&
      caseFilesById.has(rawParentCaseId)
        ? rawParentCaseId
        : null;
    parentCaseIdByCaseId.set(caseFile.id, normalizedParentCaseId);
    if (!normalizedParentCaseId) return;
    const childCaseIds = childCaseIdsByParentId.get(normalizedParentCaseId) ?? [];
    childCaseIds.push(caseFile.id);
    childCaseIdsByParentId.set(normalizedParentCaseId, childCaseIds);
  });

  const subtreeCaseIdsByCaseId = new Map<string, Set<string>>();
  const collectCaseSubtree = (caseId: string, stack: Set<string>): Set<string> => {
    const cachedSubtree = subtreeCaseIdsByCaseId.get(caseId);
    if (cachedSubtree) return cachedSubtree;
    const subtreeCaseIds = new Set<string>();
    if (stack.has(caseId)) {
      subtreeCaseIds.add(caseId);
      subtreeCaseIdsByCaseId.set(caseId, subtreeCaseIds);
      return subtreeCaseIds;
    }
    stack.add(caseId);
    subtreeCaseIds.add(caseId);
    const childCaseIds = childCaseIdsByParentId.get(caseId) ?? [];
    childCaseIds.forEach((childCaseId: string): void => {
      const childSubtreeIds = collectCaseSubtree(childCaseId, stack);
      childSubtreeIds.forEach((childSubtreeCaseId: string): void => {
        subtreeCaseIds.add(childSubtreeCaseId);
      });
    });
    stack.delete(caseId);
    subtreeCaseIdsByCaseId.set(caseId, subtreeCaseIds);
    return subtreeCaseIds;
  };
  caseFilesById.forEach((_: CaseResolverFile, caseId: string): void => {
    collectCaseSubtree(caseId, new Set<string>());
  });

  const assetsByOwnerCaseId = new Map<string, CaseResolverAssetFile[]>();
  workspace.assets.forEach((asset: CaseResolverAssetFile): void => {
    assetsById.set(asset.id, asset);
    foldersByPath.add(asset.folder);
    const sourceFileId = asset.sourceFileId?.trim() ?? '';
    if (!sourceFileId) return;
    const ownerCaseId = ownerCaseIdBySourceFileId.get(sourceFileId);
    if (!ownerCaseId) return;
    const assets = assetsByOwnerCaseId.get(ownerCaseId) ?? [];
    assets.push(asset);
    assetsByOwnerCaseId.set(ownerCaseId, assets);
  });

  const folderOwnerIdsByPath = new Map<string, Set<string>>();
  const registerFolderOwner = (folderPath: string, ownerCaseId: string): void => {
    if (!folderPath.trim() || !ownerCaseId.trim()) return;
    forEachFolderPathAncestor(folderPath, (ancestorPath: string): void => {
      const ownerIds = folderOwnerIdsByPath.get(ancestorPath) ?? new Set<string>();
      ownerIds.add(ownerCaseId);
      folderOwnerIdsByPath.set(ancestorPath, ownerIds);
    });
  };

  (workspace.folderRecords ?? []).forEach((folderRecord: CaseResolverFolderRecord): void => {
    const ownerCaseId = folderRecord.ownerCaseId?.trim() ?? '';
    if (!ownerCaseId) return;
    registerFolderOwner(folderRecord.path, ownerCaseId);
  });
  workspace.files.forEach((file: CaseResolverFile): void => {
    if (file.fileType === 'case') return;
    const ownerCaseId = file.parentCaseId?.trim() ?? '';
    if (!ownerCaseId) return;
    registerFolderOwner(file.folder, ownerCaseId);
  });
  workspace.assets.forEach((asset: CaseResolverAssetFile): void => {
    const sourceFileId = asset.sourceFileId?.trim() ?? '';
    if (!sourceFileId) return;
    const ownerCaseId = ownerCaseIdBySourceFileId.get(sourceFileId);
    if (!ownerCaseId) return;
    registerFolderOwner(asset.folder, ownerCaseId);
  });

  const folderOwnerCaseIdsByPath = new Map<string, string[]>();
  folderOwnerIdsByPath.forEach((ownerIds: Set<string>, folderPath: string): void => {
    folderOwnerCaseIdsByPath.set(
      folderPath,
      Array.from(ownerIds).sort((left: string, right: string): number => left.localeCompare(right))
    );
  });

  return {
    workspaceRevision: getCaseResolverWorkspaceRevision(workspace),
    filesById,
    assetsById,
    foldersByPath,
    caseFilesById,
    parentCaseIdByCaseId,
    childCaseIdsByParentId,
    subtreeCaseIdsByCaseId,
    nonCaseFilesByOwnerCaseId,
    ownerCaseIdBySourceFileId,
    assetsByOwnerCaseId,
    folderOwnerCaseIdsByPath,
    relatedFileIdsByFileId,
    plainTextByFileId,
  };
};

export const getCachedCaseResolverRuntimeIndexes = (
  workspace: CaseResolverWorkspace
): CaseResolverRuntimeIndexes => {
  const workspaceRevision = getCaseResolverWorkspaceRevision(workspace);
  const cached = runtimeIndexesCache.get(workspace);
  if (cached?.revision === workspaceRevision) {
    return cached.indexes;
  }
  const indexes = buildCaseResolverRuntimeIndexes(workspace);
  runtimeIndexesCache.set(workspace, {
    revision: workspaceRevision,
    indexes,
  });
  return indexes;
};

export const getCaseSubtreeIds = (
  indexes: CaseResolverRuntimeIndexes,
  caseId: string
): Set<string> => indexes.subtreeCaseIdsByCaseId.get(caseId) ?? EMPTY_SET;

import type { CaseResolverAssetFile, CaseResolverFile, CaseResolverFolderRecord } from '@/shared/contracts/case-resolver/file';
import type { CaseResolverWorkspace } from '@/shared/contracts/case-resolver/workspace';

import { getCachedCaseResolverRuntimeIndexes, type CaseResolverRuntimeIndexes } from './indexes';
import { normalizeFolderPaths } from '../../settings';

type ResolveScopedWorkspaceArgs = {
  workspace: CaseResolverWorkspace;
  selectedFileId: string | null;
  requestedFileId: string | null;
  activeCaseId?: string | null;
  includeDescendantCaseScope?: boolean;
  indexes?: CaseResolverRuntimeIndexes;
};

const resolveCaseContextId = ({
  selectedFileId,
  requestedFileId,
  activeCaseId,
}: {
  selectedFileId: string | null;
  requestedFileId: string | null;
  activeCaseId: string | null;
}): string | null => {
  const normalizedRequestedFileId = requestedFileId?.trim() ?? '';
  if (normalizedRequestedFileId.length > 0) {
    return normalizedRequestedFileId;
  }
  if (selectedFileId) return selectedFileId;
  const normalizedActiveCaseId = activeCaseId?.trim() ?? '';
  return normalizedActiveCaseId.length > 0 ? normalizedActiveCaseId : null;
};

export const resolveScopedCaseResolverWorkspaceWithIndexes = ({
  workspace,
  selectedFileId,
  requestedFileId,
  activeCaseId = null,
  includeDescendantCaseScope = true,
  indexes: providedIndexes,
}: ResolveScopedWorkspaceArgs): CaseResolverWorkspace => {
  const indexes = providedIndexes ?? getCachedCaseResolverRuntimeIndexes(workspace);
  const contextFileId = resolveCaseContextId({
    selectedFileId,
    requestedFileId,
    activeCaseId,
  });
  if (!contextFileId) return workspace;

  const contextFile = indexes.filesById.get(contextFileId) ?? null;
  if (!contextFile) return workspace;

  const scopedRootCaseId =
    contextFile.fileType === 'case'
      ? contextFile.id
      : contextFile.parentCaseId &&
          indexes.caseFilesById.get(contextFile.parentCaseId)?.fileType === 'case'
        ? contextFile.parentCaseId
        : null;
  if (!scopedRootCaseId) return workspace;

  const scopedCaseIds = new Set<string>();
  const visitCase = (caseId: string): void => {
    if (!caseId || scopedCaseIds.has(caseId)) return;
    if (!indexes.caseFilesById.has(caseId)) return;
    scopedCaseIds.add(caseId);
    if (!includeDescendantCaseScope) return;
    const childCaseIds = indexes.childCaseIdsByParentId.get(caseId) ?? [];
    childCaseIds.forEach((childCaseId: string): void => {
      visitCase(childCaseId);
    });
  };
  visitCase(scopedRootCaseId);
  if (scopedCaseIds.size === 0) return workspace;

  const scopedFileIds = new Set<string>();
  workspace.files.forEach((file: CaseResolverFile): void => {
    if (file.fileType === 'case') {
      if (scopedCaseIds.has(file.id)) {
        scopedFileIds.add(file.id);
      }
      return;
    }
    const ownerCaseId = file.parentCaseId?.trim() ?? '';
    if (ownerCaseId && scopedCaseIds.has(ownerCaseId)) {
      scopedFileIds.add(file.id);
    }
  });

  let relationRecovered = true;
  while (relationRecovered) {
    relationRecovered = false;
    workspace.files.forEach((file: CaseResolverFile): void => {
      if (file.fileType === 'case') return;
      if (scopedFileIds.has(file.id)) return;
      const ownerCaseId = file.parentCaseId?.trim() ?? '';
      if (ownerCaseId) return;
      const relatedFileIds = indexes.relatedFileIdsByFileId.get(file.id) ?? [];
      const hasScopedRelation = relatedFileIds.some((relatedFileId: string): boolean =>
        scopedFileIds.has(relatedFileId)
      );
      if (!hasScopedRelation) return;
      scopedFileIds.add(file.id);
      relationRecovered = true;
    });
  }

  const scopedFiles = workspace.files.filter((file: CaseResolverFile): boolean =>
    scopedFileIds.has(file.id)
  );
  if (scopedFiles.length === 0) {
    return workspace;
  }

  const scopedFileIdSet = new Set<string>(
    scopedFiles.map((file: CaseResolverFile): string => file.id)
  );
  const scopedNodeFileAssetIds = new Set<string>();
  scopedFiles.forEach((file: CaseResolverFile): void => {
    const nodeFileAssetIdByNode = file.graph?.nodeFileAssetIdByNode ?? {};
    Object.values(nodeFileAssetIdByNode).forEach((assetId: unknown): void => {
      const normalizedAssetId = typeof assetId === 'string' ? assetId.trim() : '';
      if (!normalizedAssetId) return;
      scopedNodeFileAssetIds.add(normalizedAssetId);
    });
  });

  const isStandaloneNodeFileInScope = (asset: CaseResolverAssetFile): boolean => {
    if (asset.kind !== 'node_file') return false;
    if (scopedNodeFileAssetIds.has(asset.id)) return true;

    const metadataOwnerCaseId =
      asset.metadata &&
      typeof asset.metadata === 'object' &&
      typeof asset.metadata['ownerCaseId'] === 'string'
        ? asset.metadata['ownerCaseId'].trim()
        : '';
    if (metadataOwnerCaseId.length > 0) {
      return scopedCaseIds.has(metadataOwnerCaseId);
    }

    const normalizedFolderPath = asset.folder.trim();
    if (normalizedFolderPath.length === 0) return false;
    const folderOwnerCaseIds = indexes.folderOwnerCaseIdsByPath.get(normalizedFolderPath) ?? [];
    if (folderOwnerCaseIds.length === 0) return false;
    return folderOwnerCaseIds.every((ownerCaseId: string): boolean =>
      scopedCaseIds.has(ownerCaseId)
    );
  };

  const scopedAssets = workspace.assets.filter((asset: CaseResolverAssetFile): boolean => {
    if (asset.sourceFileId && scopedFileIdSet.has(asset.sourceFileId)) return true;
    return isStandaloneNodeFileInScope(asset);
  });

  const scopedFolderRecords = (workspace.folderRecords ?? []).filter(
    (folderRecord: CaseResolverFolderRecord): boolean =>
      Boolean(folderRecord.ownerCaseId && scopedCaseIds.has(folderRecord.ownerCaseId))
  );
  const scopedFolders = normalizeFolderPaths([
    ...scopedFolderRecords.map(
      (folderRecord: CaseResolverFolderRecord): string => folderRecord.path
    ),
    ...scopedFiles.map((file: CaseResolverFile): string => file.folder),
    ...scopedAssets.map((asset): string => asset.folder),
  ]);
  const scopedFolderTimestamps = Object.fromEntries(
    Object.entries(workspace.folderTimestamps ?? {}).filter(
      ([folderPath]: [string, unknown]): boolean => scopedFolders.includes(folderPath)
    )
  );

  const normalizedActiveCaseId = activeCaseId?.trim() ?? '';
  const activeCandidates = [
    selectedFileId,
    normalizedActiveCaseId.length > 0 ? normalizedActiveCaseId : null,
    scopedRootCaseId,
    scopedFiles[0]?.id ?? null,
  ];
  const nextActiveFileId =
    activeCandidates.find(
      (candidate: string | null): candidate is string =>
        typeof candidate === 'string' && scopedFileIdSet.has(candidate)
    ) ?? null;

  return {
    ...workspace,
    folders: scopedFolders,
    folderRecords: scopedFolderRecords,
    folderTimestamps: scopedFolderTimestamps,
    files: scopedFiles,
    assets: scopedAssets,
    activeFileId: nextActiveFileId,
  };
};

import 'server-only';

import type { CaseResolverOcrErrorCategory, CaseResolverOcrJobRecord, CaseResolverOcrObservabilitySnapshot, CaseResolverOcrPercentileSnapshot as PercentileSnapshot } from '@/shared/contracts/case-resolver/ocr';

import { listCaseResolverRecentOcrJobs } from './ocr-runtime-job-store';

const percentile = (values: number[], ratio: number): number => {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const index = Math.min(sorted.length - 1, Math.max(0, Math.floor((sorted.length - 1) * ratio)));
  return sorted[index] ?? 0;
};

const buildPercentileSnapshot = (values: number[]): PercentileSnapshot => {
  return {
    count: values.length,
    p50Ms: percentile(values, 0.5),
    p95Ms: percentile(values, 0.95),
    maxMs: values.length > 0 ? Math.max(...values) : 0,
  };
};

const toTimestamp = (value: string | null): number | null => {
  if (!value) return null;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : null;
};

export const buildCaseResolverOcrObservabilitySnapshot = (
  jobs: CaseResolverOcrJobRecord[],
  nowMs: number = Date.now()
): CaseResolverOcrObservabilitySnapshot => {
  const statuses: Record<CaseResolverOcrJobRecord['status'], number> = {
    queued: 0,
    running: 0,
    completed: 0,
    failed: 0,
  };
  const failureCategories: Record<CaseResolverOcrErrorCategory, number> = {
    timeout: 0,
    rate_limit: 0,
    network: 0,
    provider: 0,
    validation: 0,
    unknown: 0,
  };
  const completionDurationsMs: number[] = [];
  const backlogAgesMs: number[] = [];
  let retryJobs = 0;
  let retryableFailures = 0;
  let totalFailures = 0;
  const correlations = new Set<string>();

  jobs.forEach((job: CaseResolverOcrJobRecord): void => {
    statuses[job.status] += 1;
    if (job.retryOfJobId) retryJobs += 1;
    if (job.correlationId) {
      correlations.add(job.correlationId);
    }

    if (job.status === 'failed') {
      totalFailures += 1;
      if (job.errorCategory) {
        failureCategories[job.errorCategory] += 1;
      } else {
        failureCategories.unknown += 1;
      }
      if (job.retryableError === true) {
        retryableFailures += 1;
      }
      return;
    }

    if (job.status === 'completed') {
      const startedAt = toTimestamp(job.startedAt);
      const finishedAt = toTimestamp(job.finishedAt);
      if (startedAt !== null && finishedAt !== null && finishedAt >= startedAt) {
        completionDurationsMs.push(finishedAt - startedAt);
      }
      return;
    }

    if (job.status === 'queued' || job.status === 'running') {
      const createdAt = toTimestamp(job.createdAt);
      if (createdAt !== null && nowMs >= createdAt) {
        backlogAgesMs.push(nowMs - createdAt);
      }
    }
  });

  const terminalCount = statuses.completed + statuses.failed;
  const successRate = terminalCount > 0 ? statuses.completed / terminalCount : 0;
  const retryRate = jobs.length > 0 ? retryJobs / jobs.length : 0;
  const retryableFailureRate = totalFailures > 0 ? retryableFailures / totalFailures : 0;

  return {
    generatedAt: new Date(nowMs).toISOString(),
    sampleSize: jobs.length,
    statuses,
    successRate,
    retryRate,
    retryableFailureRate,
    failureCategories,
    completionLatencyMs: buildPercentileSnapshot(completionDurationsMs),
    backlogAgeMs: buildPercentileSnapshot(backlogAgesMs),
    distinctCorrelationIds: correlations.size,
  };
};

export const getCaseResolverOcrObservabilitySnapshot = async (options?: {
  limit?: number;
}): Promise<CaseResolverOcrObservabilitySnapshot> => {
  const jobs = await listCaseResolverRecentOcrJobs(options?.limit);
  return buildCaseResolverOcrObservabilitySnapshot(jobs);
};

import 'server-only';

import { randomUUID } from 'crypto';

import type { CaseResolverOcrJobStatus, CaseResolverOcrJobDispatchMode, CaseResolverOcrErrorCategory, CaseResolverOcrJobRecord } from '@/shared/contracts/case-resolver/ocr';
import { getRedisConnection } from '@/shared/lib/queue';
import { ErrorSystem } from '@/shared/utils/observability/error-system';



export type { CaseResolverOcrErrorCategory, CaseResolverOcrJobRecord };

const OCR_RUNTIME_JOB_KEY_PREFIX = 'case-resolver:ocr:job:';
const OCR_RUNTIME_JOB_RECENT_IDS_KEY = 'case-resolver:ocr:job:recent';
const OCR_RUNTIME_JOB_TTL_SECONDS = 60 * 60 * 6;
const OCR_RUNTIME_JOB_TTL_MS = OCR_RUNTIME_JOB_TTL_SECONDS * 1000;
const OCR_RUNTIME_JOB_RECENT_LIMIT = 400;

const inMemoryJobs = new Map<string, { record: CaseResolverOcrJobRecord; expiresAt: number }>();
const inMemoryRecentJobIds: string[] = [];

const nowIso = (): string => new Date().toISOString();

const toRedisKey = (jobId: string): string => `${OCR_RUNTIME_JOB_KEY_PREFIX}${jobId}`;

const isCaseResolverOcrJobStatus = (value: unknown): value is CaseResolverOcrJobStatus => {
  return value === 'queued' || value === 'running' || value === 'completed' || value === 'failed';
};

const isCaseResolverOcrJobDispatchMode = (
  value: unknown
): value is CaseResolverOcrJobDispatchMode => {
  return value === 'queued' || value === 'inline';
};

const isCaseResolverOcrErrorCategory = (value: unknown): value is CaseResolverOcrErrorCategory => {
  return (
    value === 'timeout' ||
    value === 'rate_limit' ||
    value === 'network' ||
    value === 'provider' ||
    value === 'validation' ||
    value === 'unknown'
  );
};

const parseCaseResolverOcrJobRecord = (value: unknown): CaseResolverOcrJobRecord | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  const record = value as Record<string, unknown>;
  const id = typeof record['id'] === 'string' ? record['id'].trim() : '';
  const filepath = typeof record['filepath'] === 'string' ? record['filepath'].trim() : '';
  const status = record['status'];
  if (!id || !filepath || !isCaseResolverOcrJobStatus(status)) return null;
  const model =
    typeof record['model'] === 'string' && record['model'].trim().length > 0
      ? record['model'].trim()
      : null;
  const prompt =
    typeof record['prompt'] === 'string' && record['prompt'].trim().length > 0
      ? record['prompt']
      : null;
  const retryOfJobId =
    typeof record['retryOfJobId'] === 'string' && record['retryOfJobId'].trim().length > 0
      ? record['retryOfJobId'].trim()
      : null;
  const correlationId =
    typeof record['correlationId'] === 'string' && record['correlationId'].trim().length > 0
      ? record['correlationId'].trim()
      : null;
  const attemptsMade =
    typeof record['attemptsMade'] === 'number' && Number.isFinite(record['attemptsMade'])
      ? Math.max(0, Math.floor(record['attemptsMade']))
      : 0;
  const maxAttemptsRaw =
    typeof record['maxAttempts'] === 'number' && Number.isFinite(record['maxAttempts'])
      ? Math.floor(record['maxAttempts'])
      : 1;
  const maxAttempts = Math.max(1, maxAttemptsRaw);

  const dispatchModeRaw = record['dispatchMode'];
  const dispatchMode = isCaseResolverOcrJobDispatchMode(dispatchModeRaw) ? dispatchModeRaw : null;
  const errorCategoryRaw = record['errorCategory'];
  const errorCategory = isCaseResolverOcrErrorCategory(errorCategoryRaw) ? errorCategoryRaw : null;
  const retryableErrorRaw = record['retryableError'];
  const retryableError = typeof retryableErrorRaw === 'boolean' ? retryableErrorRaw : null;
  const createdAt =
    typeof record['createdAt'] === 'string' && record['createdAt'].trim().length > 0
      ? record['createdAt']
      : nowIso();
  const updatedAt =
    typeof record['updatedAt'] === 'string' && record['updatedAt'].trim().length > 0
      ? record['updatedAt']
      : createdAt;

  return {
    id,
    status,
    filepath,
    model,
    prompt,
    retryOfJobId,
    correlationId,
    dispatchMode,
    attemptsMade,
    maxAttempts,
    createdAt,
    updatedAt,
    startedAt:
      typeof record['startedAt'] === 'string' && record['startedAt'].trim().length > 0
        ? record['startedAt']
        : null,
    finishedAt:
      typeof record['finishedAt'] === 'string' && record['finishedAt'].trim().length > 0
        ? record['finishedAt']
        : null,
    resultText: typeof record['resultText'] === 'string' ? record['resultText'] : null,
    errorMessage:
      typeof record['errorMessage'] === 'string' && record['errorMessage'].trim().length > 0
        ? record['errorMessage']
        : null,
    errorCategory,
    retryableError,
  };
};

const cleanupInMemoryJobs = (): void => {
  const now = Date.now();
  for (const [jobId, value] of inMemoryJobs.entries()) {
    if (value.expiresAt > now) continue;
    inMemoryJobs.delete(jobId);
  }
};

const writeInMemoryJob = (record: CaseResolverOcrJobRecord): void => {
  cleanupInMemoryJobs();
  inMemoryJobs.set(record.id, {
    record,
    expiresAt: Date.now() + OCR_RUNTIME_JOB_TTL_MS,
  });
};

const touchInMemoryRecentJobId = (jobId: string): void => {
  const normalizedJobId = jobId.trim();
  if (!normalizedJobId) return;
  const existingIndex = inMemoryRecentJobIds.indexOf(normalizedJobId);
  if (existingIndex >= 0) {
    inMemoryRecentJobIds.splice(existingIndex, 1);
  }
  inMemoryRecentJobIds.unshift(normalizedJobId);
  if (inMemoryRecentJobIds.length > OCR_RUNTIME_JOB_RECENT_LIMIT) {
    inMemoryRecentJobIds.splice(OCR_RUNTIME_JOB_RECENT_LIMIT);
  }
};

const readInMemoryJob = (jobId: string): CaseResolverOcrJobRecord | null => {
  cleanupInMemoryJobs();
  return inMemoryJobs.get(jobId)?.record ?? null;
};

const readInMemoryRecentJobIds = (limit: number): string[] => {
  cleanupInMemoryJobs();
  return inMemoryRecentJobIds.slice(0, limit);
};

const writeRedisJob = async (record: CaseResolverOcrJobRecord): Promise<boolean> => {
  const redis = getRedisConnection();
  if (!redis) return false;
  try {
    await redis.set(
      toRedisKey(record.id),
      JSON.stringify(record),
      'EX',
      OCR_RUNTIME_JOB_TTL_SECONDS
    );
    return true;
  } catch (error) {
    void ErrorSystem.captureException(error);
    return false;
  }
};

const readRedisJob = async (jobId: string): Promise<CaseResolverOcrJobRecord | null> => {
  const redis = getRedisConnection();
  if (!redis) return null;
  try {
    const raw = await redis.get(toRedisKey(jobId));
    if (!raw) return null;
    const parsed = JSON.parse(raw) as unknown;
    return parseCaseResolverOcrJobRecord(parsed);
  } catch (error) {
    void ErrorSystem.captureException(error);
    return null;
  }
};

const persistRecentJobIdInRedis = async (jobId: string): Promise<boolean> => {
  const redis = getRedisConnection();
  if (!redis) return false;
  try {
    await redis
      .multi()
      .lrem(OCR_RUNTIME_JOB_RECENT_IDS_KEY, 0, jobId)
      .lpush(OCR_RUNTIME_JOB_RECENT_IDS_KEY, jobId)
      .ltrim(OCR_RUNTIME_JOB_RECENT_IDS_KEY, 0, OCR_RUNTIME_JOB_RECENT_LIMIT - 1)
      .expire(OCR_RUNTIME_JOB_RECENT_IDS_KEY, OCR_RUNTIME_JOB_TTL_SECONDS)
      .exec();
    return true;
  } catch (error) {
    void ErrorSystem.captureException(error);
    return false;
  }
};

const readRecentJobIdsFromRedis = async (limit: number): Promise<string[] | null> => {
  const redis = getRedisConnection();
  if (!redis) return null;
  try {
    const ids = await redis.lrange(OCR_RUNTIME_JOB_RECENT_IDS_KEY, 0, Math.max(0, limit - 1));
    const normalized = ids
      .map((entry): string => entry.trim())
      .filter((entry): entry is string => entry.length > 0);
    return normalized;
  } catch (error) {
    void ErrorSystem.captureException(error);
    return null;
  }
};

const persistCaseResolverOcrJob = async (
  record: CaseResolverOcrJobRecord
): Promise<CaseResolverOcrJobRecord> => {
  const wroteRedis = await writeRedisJob(record);
  if (!wroteRedis) {
    writeInMemoryJob(record);
  } else {
    inMemoryJobs.delete(record.id);
  }
  touchInMemoryRecentJobId(record.id);
  await persistRecentJobIdInRedis(record.id);
  return record;
};

const updateCaseResolverOcrJob = async (
  jobId: string,
  patch: Partial<Omit<CaseResolverOcrJobRecord, 'id' | 'createdAt'>>,
  options?: { filepath?: string; createIfMissing?: boolean }
): Promise<CaseResolverOcrJobRecord | null> => {
  const normalizedJobId = jobId.trim();
  if (!normalizedJobId) return null;

  let current = await getCaseResolverOcrJobById(normalizedJobId);
  if (!current && options?.createIfMissing) {
    const createdAt = nowIso();
    current = {
      id: normalizedJobId,
      status: 'queued',
      filepath: options.filepath?.trim() || '',
      model: null,
      prompt: null,
      retryOfJobId: null,
      correlationId: null,
      dispatchMode: null,
      attemptsMade: 0,
      maxAttempts: 1,
      createdAt,
      updatedAt: createdAt,
      startedAt: null,
      finishedAt: null,
      resultText: null,
      errorMessage: null,
      errorCategory: null,
      retryableError: null,
    };
  }
  if (!current) return null;

  const updatedAt = nowIso();
  const next: CaseResolverOcrJobRecord = {
    ...current,
    ...patch,
    updatedAt,
  };

  if (next.status === 'running' && !next.startedAt) {
    next.startedAt = updatedAt;
    next.finishedAt = null;
    next.errorMessage = null;
  }

  if (next.status === 'completed') {
    next.finishedAt = next.finishedAt ?? updatedAt;
    next.errorMessage = null;
  }

  if (next.status === 'failed') {
    next.finishedAt = next.finishedAt ?? updatedAt;
  }

  return persistCaseResolverOcrJob(next);
};

export const createCaseResolverOcrJob = async (input: {
  filepath: string;
  model?: string | null;
  prompt?: string | null;
  retryOfJobId?: string | null;
  correlationId?: string | null;
  maxAttempts?: number | null;
}): Promise<CaseResolverOcrJobRecord> => {
  const createdAt = nowIso();
  const normalizedModel = input.model?.trim() ?? null;
  const normalizedPrompt = input.prompt?.trim() || null;
  const normalizedRetryOfJobId = input.retryOfJobId?.trim() || null;
  const normalizedCorrelationId = input.correlationId?.trim() || null;
  const maxAttempts =
    typeof input.maxAttempts === 'number' && Number.isFinite(input.maxAttempts)
      ? Math.max(1, Math.floor(input.maxAttempts))
      : 1;
  const record: CaseResolverOcrJobRecord = {
    id: randomUUID(),
    status: 'queued',
    filepath: input.filepath.trim(),
    model: normalizedModel,
    prompt: normalizedPrompt,
    retryOfJobId: normalizedRetryOfJobId,
    correlationId: normalizedCorrelationId,
    dispatchMode: null,
    attemptsMade: 0,
    maxAttempts,
    createdAt,
    updatedAt: createdAt,
    startedAt: null,
    finishedAt: null,
    resultText: null,
    errorMessage: null,
    errorCategory: null,
    retryableError: null,
  };
  return persistCaseResolverOcrJob(record);
};

export const getCaseResolverOcrJobById = async (
  jobId: string
): Promise<CaseResolverOcrJobRecord | null> => {
  const normalized = jobId.trim();
  if (!normalized) return null;
  const fromRedis = await readRedisJob(normalized);
  if (fromRedis) return fromRedis;
  return readInMemoryJob(normalized);
};

export const setCaseResolverOcrJobDispatchMode = async (
  jobId: string,
  dispatchMode: CaseResolverOcrJobDispatchMode
): Promise<CaseResolverOcrJobRecord | null> => {
  return updateCaseResolverOcrJob(jobId, { dispatchMode });
};

export const markCaseResolverOcrJobRunning = async (
  jobId: string,
  filepath: string,
  options?: { correlationId?: string | null }
): Promise<CaseResolverOcrJobRecord | null> => {
  const normalizedCorrelationId = options?.correlationId?.trim() || null;
  return updateCaseResolverOcrJob(
    jobId,
    {
      status: 'running',
      startedAt: nowIso(),
      finishedAt: null,
      errorMessage: null,
      errorCategory: null,
      retryableError: null,
      ...(normalizedCorrelationId ? { correlationId: normalizedCorrelationId } : {}),
    },
    { createIfMissing: true, filepath }
  );
};

export const markCaseResolverOcrJobCompleted = async (
  jobId: string,
  resultText: string
): Promise<CaseResolverOcrJobRecord | null> => {
  return updateCaseResolverOcrJob(jobId, {
    status: 'completed',
    resultText,
    errorMessage: null,
    errorCategory: null,
    retryableError: null,
    finishedAt: nowIso(),
  });
};

export const markCaseResolverOcrJobFailed = async (
  jobId: string,
  errorMessage: string,
  options?: {
    attemptsMade?: number;
    maxAttempts?: number;
    errorCategory?: CaseResolverOcrErrorCategory;
    retryableError?: boolean;
  }
): Promise<CaseResolverOcrJobRecord | null> => {
  const attemptsMade =
    typeof options?.attemptsMade === 'number' && Number.isFinite(options.attemptsMade)
      ? Math.max(0, Math.floor(options.attemptsMade))
      : undefined;
  const maxAttempts =
    typeof options?.maxAttempts === 'number' && Number.isFinite(options.maxAttempts)
      ? Math.max(1, Math.floor(options.maxAttempts))
      : undefined;
  const errorCategory = options?.errorCategory;
  const retryableError =
    typeof options?.retryableError === 'boolean' ? options.retryableError : undefined;
  return updateCaseResolverOcrJob(jobId, {
    status: 'failed',
    errorMessage: errorMessage.trim() || 'OCR runtime job failed.',
    ...(typeof attemptsMade === 'number' ? { attemptsMade } : {}),
    ...(typeof maxAttempts === 'number' ? { maxAttempts } : {}),
    ...(errorCategory ? { errorCategory } : {}),
    ...(typeof retryableError === 'boolean' ? { retryableError } : {}),
    finishedAt: nowIso(),
  });
};

export const markCaseResolverOcrJobQueuedForRetry = async (
  jobId: string,
  options?: {
    attemptsMade?: number;
    maxAttempts?: number;
    errorCategory?: CaseResolverOcrErrorCategory;
    retryableError?: boolean;
  }
): Promise<CaseResolverOcrJobRecord | null> => {
  const attemptsMade =
    typeof options?.attemptsMade === 'number' && Number.isFinite(options.attemptsMade)
      ? Math.max(0, Math.floor(options.attemptsMade))
      : undefined;
  const maxAttempts =
    typeof options?.maxAttempts === 'number' && Number.isFinite(options.maxAttempts)
      ? Math.max(1, Math.floor(options.maxAttempts))
      : undefined;
  const errorCategory = options?.errorCategory;
  const retryableError =
    typeof options?.retryableError === 'boolean' ? options.retryableError : undefined;
  return updateCaseResolverOcrJob(jobId, {
    status: 'queued',
    ...(typeof attemptsMade === 'number' ? { attemptsMade } : {}),
    ...(typeof maxAttempts === 'number' ? { maxAttempts } : {}),
    ...(errorCategory ? { errorCategory } : {}),
    ...(typeof retryableError === 'boolean' ? { retryableError } : {}),
    finishedAt: null,
  });
};

export const listCaseResolverRecentOcrJobs = async (
  limit = 120
): Promise<CaseResolverOcrJobRecord[]> => {
  const normalizedLimit =
    Number.isFinite(limit) && limit > 0 ? Math.min(400, Math.max(1, Math.floor(limit))) : 120;
  const redisIds = await readRecentJobIdsFromRedis(normalizedLimit);
  const fallbackIds = readInMemoryRecentJobIds(normalizedLimit);
  const candidateIds = (redisIds && redisIds.length > 0 ? redisIds : fallbackIds).slice(
    0,
    normalizedLimit
  );
  const uniqueIds = new Set<string>();
  const records: CaseResolverOcrJobRecord[] = [];
  for (const id of candidateIds) {
    if (uniqueIds.has(id)) continue;
    uniqueIds.add(id);
    const record = await getCaseResolverOcrJobById(id);
    if (!record) continue;
    records.push(record);
  }
  return records;
};

import 'server-only';

import path from 'path';

import type { CaseResolverOcrFileKind } from '@/shared/contracts/case-resolver/ocr';
import { badRequestError } from '@/shared/errors/app-error';
import { getDiskPathFromPublicPath } from '@/shared/lib/files/file-uploader';
import { caseResolverRoot } from '@/shared/lib/files/server-constants';

const CASE_RESOLVER_UPLOAD_PREFIX = '/uploads/case-resolver/';
const CASE_RESOLVER_IMAGE_EXTENSION_PATTERN = /\.(jpg|jpeg|png|gif|webp|bmp|tiff)$/i;
const CASE_RESOLVER_PDF_EXTENSION_PATTERN = /\.pdf$/i;
const CASE_RESOLVER_UPLOAD_DISK_PREFIX = path.resolve(caseResolverRoot);

export const normalizeCaseResolverPublicFilepath = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  const withoutOrigin = trimmed.replace(/^https?:\/\/[^/]+/i, '');
  const withoutQuery = withoutOrigin.split('?')[0] ?? '';
  const normalized = withoutQuery.startsWith('/') ? withoutQuery : `/${withoutQuery}`;
  return normalized || null;
};

export const isCaseResolverImageFilepath = (filepath: string): boolean => {
  const normalized = normalizeCaseResolverPublicFilepath(filepath);
  if (!normalized) return false;
  if (!normalized.startsWith(CASE_RESOLVER_UPLOAD_PREFIX)) return false;
  return CASE_RESOLVER_IMAGE_EXTENSION_PATTERN.test(normalized);
};

export const isCaseResolverPdfFilepath = (filepath: string): boolean => {
  const normalized = normalizeCaseResolverPublicFilepath(filepath);
  if (!normalized) return false;
  if (!normalized.startsWith(CASE_RESOLVER_UPLOAD_PREFIX)) return false;
  return CASE_RESOLVER_PDF_EXTENSION_PATTERN.test(normalized);
};

export const inferCaseResolverOcrFileKind = (filepath: string): CaseResolverOcrFileKind | null => {
  if (isCaseResolverImageFilepath(filepath)) return 'image';
  if (isCaseResolverPdfFilepath(filepath)) return 'pdf';
  return null;
};

export const isCaseResolverOcrFilepath = (filepath: string): boolean =>
  inferCaseResolverOcrFileKind(filepath) !== null;

export const resolveCaseResolverOcrDiskPath = (
  value: unknown
): {
  filepath: string;
  diskPath: string;
  kind: CaseResolverOcrFileKind;
} => {
  const filepath = normalizeCaseResolverPublicFilepath(value);
  if (!filepath) {
    throw badRequestError('Invalid filepath: filepath is required.');
  }
  if (!filepath.startsWith(CASE_RESOLVER_UPLOAD_PREFIX)) {
    throw badRequestError('Invalid file: Only Case Resolver uploaded files are supported.', {
      filepath,
    });
  }
  const kind = inferCaseResolverOcrFileKind(filepath);
  if (!kind) {
    throw badRequestError('Unsupported file type: only image and PDF files are supported for OCR.', {
      filepath,
    });
  }

  const diskPath = path.resolve(getDiskPathFromPublicPath(filepath));
  const allowedPrefix = `${CASE_RESOLVER_UPLOAD_DISK_PREFIX}${path.sep}`;
  if (diskPath !== CASE_RESOLVER_UPLOAD_DISK_PREFIX && !diskPath.startsWith(allowedPrefix)) {
    throw badRequestError('Security violation: resolved OCR path is outside Case Resolver uploads directory.', {
      filepath,
      diskPath,
    });
  }

  return {
    filepath,
    diskPath,
    kind,
  };
};

export const resolveCaseResolverImageDiskPath = (value: unknown): string =>
  resolveCaseResolverOcrDiskPath(value).diskPath;

/**
 * Edge Validation Service
 * 
 * Logic for validating, normalizing, and parsing Case Resolver graph edges.
 */

import { validationError } from '@/shared/errors/app-error';

export const CANONICAL_CASE_RESOLVER_EDGE_KEYS = new Set([
  'id', 'source', 'target', 'sourceHandle', 'targetHandle', 
  'label', 'type', 'data', 'createdAt', 'updatedAt',
]);

export const FORBIDDEN_CASE_RESOLVER_EDGE_HANDLE_NAMES = new Set(['textfield', 'content']);

/**
 * Creates a validation error for edge-specific context.
 */
export const buildInvalidCaseResolverEdgeError = (
  message: string,
  context: string,
  meta?: Record<string, unknown>
) =>
  validationError(message, {
    source: 'case_resolver.edge_validation',
    context,
    ...(meta ?? {}),
  });

/**
 * Normalizes an edge handle name.
 */
export const normalizeCaseResolverEdgeHandle = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

/**
 * Case Resolver Folder Records Service
 * 
 * Manages the logic for resolving, validating, and building folder records
 * from workspace source data, files, and assets.
 */

import { z } from 'zod';
import type { CaseResolverAssetFile, CaseResolverFile, CaseResolverFolderRecord } from '@/shared/contracts/case-resolver/file';

/**
 * Zod schema for a Case Resolver folder record.
 */
export const FolderRecordSchema = z.object({
  path: z.string().min(1),
  ownerCaseId: z.string().min(1).nullable().optional(),
});

/**
 * Normalizes a folder path string by sanitizing characters and trimming.
 */
export const normalizeFolderPath = (value: string): string => {
  const normalized = value.replace(/\\/g, '/').trim();
  const parts = normalized.split('/');
  const stack: string[] = [];

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === '' || trimmed === '.') continue;
    if (trimmed === '..') {
      stack.pop();
    } else {
      stack.push(trimmed.replace(/[^a-zA-Z0-9-_]/g, '_'));
    }
  }
  return stack.join('/');
};

/**
 * Expands a folder path into all its sub-paths.
 */
export const expandFolderPath = (value: string): string[] => {
  const normalized = normalizeFolderPath(value);
  if (!normalized) return [];
  const parts = normalized.split('/').filter(Boolean);
  return parts.map((_, index) => parts.slice(0, index + 1).join('/'));
};

/**
 * Builds a unique key for a folder record based on its path and case ID.
 */
export const buildCaseResolverFolderRecordKey = (path: string, ownerCaseId: string | null): string =>
  `${ownerCaseId ?? '__none__'}::${path}`;

/**
 * Sanitizes an optional ID string.
 */
export const sanitizeOptionalId = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

/**
 * Normalizes an owner case ID against a set of valid case IDs.
 */
export const normalizeFolderRecordOwnerCaseId = (
  value: unknown,
  validCaseIds: Set<string>
): string | null => {
  const normalized = sanitizeOptionalId(value);
  if (!normalized) return null;
  return validCaseIds.has(normalized) ? normalized : null;
};

/**
 * Parses and validates folder records from raw source data.
 */
export const parseCaseResolverFolderRecords = (
  source: unknown,
  validCaseIds: Set<string>
): CaseResolverFolderRecord[] => {
  if (!Array.isArray(source)) return [];
  const records = source
    .map((entry: unknown): CaseResolverFolderRecord | null => {
      const result = FolderRecordSchema.safeParse(entry);
      if (!result.success) {
        // Fallback for path key name
        const record = entry as Record<string, unknown>;
        const pathSource = typeof record['path'] === 'string' ? record['path'] : typeof record['folder'] === 'string' ? record['folder'] : '';
        const normalizedPath = normalizeFolderPath(pathSource);
        if (!normalizedPath) return null;
        return {
          path: normalizedPath,
          ownerCaseId: normalizeFolderRecordOwnerCaseId(record['ownerCaseId'], validCaseIds),
        };
      }
      return {
        ...result.data,
        ownerCaseId: normalizeFolderRecordOwnerCaseId(result.data.ownerCaseId, validCaseIds),
      } as CaseResolverFolderRecord;
    })
    .filter((entry): entry is CaseResolverFolderRecord => Boolean(entry));

  const ownedPaths = new Set<string>(
    records
      .filter((record: CaseResolverFolderRecord): boolean => Boolean(record.ownerCaseId))
      .map((record: CaseResolverFolderRecord): string => record.path)
  );
  return records.filter(
    (record: CaseResolverFolderRecord): boolean =>
      Boolean(record.ownerCaseId) || !ownedPaths.has(record.path)
  );
};

/**
 * Builds a collection of consolidated folder records from raw source data, files, and assets.
 */
export const buildCaseResolverFolderRecords = ({
  sourceRecords,
  files,
  assets,
  validCaseIds,
}: {
  sourceRecords: CaseResolverFolderRecord[];
  files: CaseResolverFile[];
  assets: CaseResolverAssetFile[];
  validCaseIds: Set<string>;
}): CaseResolverFolderRecord[] => {
  const fileOwnerCaseIdByFileId = buildCaseResolverFileOwnerCaseIdByFileId(files, validCaseIds);
  const recordsByKey = new Map<string, CaseResolverFolderRecord>();

  const registerRecord = (path: string, ownerCaseId: string | null): void => {
    const normalizedPath = normalizeFolderPath(path);
    if (!normalizedPath) return;
    expandFolderPath(normalizedPath).forEach((expandedPath: string): void => {
      const key = buildCaseResolverFolderRecordKey(expandedPath, ownerCaseId);
      if (recordsByKey.has(key)) return;
      recordsByKey.set(key, {
        path: expandedPath,
        ownerCaseId,
      });
    });
  };

  sourceRecords.forEach((record) => registerRecord(record.path, record.ownerCaseId ?? null));

  files.forEach((file) => {
    if (file.fileType === 'case') return;
    const ownerCaseId = fileOwnerCaseIdByFileId.get(file.id) ?? null;
    registerRecord(file.folder, ownerCaseId);
  });

  assets.forEach((asset) => {
    const sourceFileId = asset.sourceFileId?.trim() || null;
    const ownerCaseId = sourceFileId ? (fileOwnerCaseIdByFileId.get(sourceFileId) ?? null) : null;
    registerRecord(asset.folder, ownerCaseId);
  });

  return Array.from(recordsByKey.values()).sort(
    (a, b) => a.path.localeCompare(b.path) || (a.ownerCaseId ?? '').localeCompare(b.ownerCaseId ?? '')
  );
};

/**
 * Builds a mapping of file ID to owner Case ID.
 */
const buildCaseResolverFileOwnerCaseIdByFileId = (
  files: CaseResolverFile[],
  validCaseIds: Set<string>
): Map<string, string> => {
  const ownerByFileId = new Map<string, string>();
  files.forEach((file) => {
    if (file.fileType === 'case') {
      ownerByFileId.set(file.id, file.id);
    } else if (file.parentCaseId && validCaseIds.has(file.parentCaseId)) {
      ownerByFileId.set(file.id, file.parentCaseId);
    }
  });
  return ownerByFileId;
};

/**
 * Taxonomy Service
 * 
 * Logic for normalizing, validating, and managing Case Resolver taxonomy items
 * including identifiers, tags, and categories.
 */

/**
 * Normalizes a timestamp string.
 */
export const normalizeTimestamp = (value: unknown, fallback: string): string =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : fallback;

/**
 * Sanitizes an optional ID string.
 */
export const sanitizeOptionalId = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

/**
 * Normalizes a hex color string, falling back to a provided value.
 */
export const normalizeHexColor = (value: unknown, fallback: string): string => {
  if (typeof value !== 'string') return fallback;
  const normalized = value.trim();
  return /^#[0-9a-fA-F]{6}$/.test(normalized) || /^#[0-9a-fA-F]{3}$/.test(normalized)
    ? normalized
    : fallback;
};

/**
 * Resolves a safe parent ID, checking for circular references.
 */
export const resolveSafeParentId = <T extends { id: string; parentId?: string | null }>(
  itemId: string,
  parentId: string | null,
  map: Map<string, T>
): string | null => {
  if (!parentId || !map.has(parentId) || parentId === itemId) return null;
  let current: string | null = parentId;
  const visited = new Set<string>();
  while (current) {
    if (current === itemId || visited.has(current)) return null;
    visited.add(current);
    const parent = map.get(current);
    current = parent?.parentId ?? null;
  }
  return parentId;
};

/**
 * Node File Utils Service
 * 
 * Provides utilities for processing, normalizing, and resolving content for 
 * Case Resolver files and document nodes.
 */

import { CASE_RESOLVER_DOCUMENT_NODE_OUTPUT_PORTS, CASE_RESOLVER_EXPLANATORY_NODE_OUTPUT_PORTS } from '@/shared/contracts/case-resolver/constants';
import { type CaseResolverFile, type CaseResolverJoinMode, type CaseResolverScanSlot } from '@/shared/contracts/case-resolver';

export const PREVIEW_MAX_CHARS = 400;
export const SEARCHABLE_CONTENT_MAX_CHARS = 6000;
export const NODEFILE_JOIN_VALUE_MAP: Record<CaseResolverJoinMode, string> = {
  newline: '\n',
  tab: '\t',
  space: ' ',
  none: '',
};

/**
 * Normalizes a text string for search.
 */
export const normalizeSearchText = (value: string): string =>
  value.toLowerCase().replace(/\s+/g, ' ').trim();

/**
 * Normalizes folder path segments.
 */
export const normalizeFolderPathSegments = (folderPath: string): string[] =>
  folderPath
    .split('/')
    .map((segment) => segment.trim())
    .filter((segment) => segment.length > 0);

/**
 * Checks if a candidate path is within the scope of a scope path.
 */
export const isFolderPathWithinScope = (
  candidateFolderPath: string,
  scopeFolderPath: string
): boolean =>
  candidateFolderPath === scopeFolderPath || candidateFolderPath.startsWith(`${scopeFolderPath}/`);

/**
 * Resolves a search label for a party reference.
 */
export const resolvePartyReferenceSearchLabel = (
  reference: CaseResolverFile['addresser'] | CaseResolverFile['addressee']
): string => {
  if (!reference) return '';
  const kind = typeof reference.kind === 'string' ? reference.kind.trim() : '';
  const id = typeof reference.id === 'string' ? reference.id.trim() : '';
  if (!kind && !id) return '';
  return [kind, id].filter(Boolean).join(':');
};

/**
 * Resolves an identifier label.
 */
export const resolveIdentifierSearchLabel = (
  identifierId: string | null | undefined,
  labelsById: Map<string, string>
): string => {
  const normalizedIdentifierId = typeof identifierId === 'string' ? identifierId.trim() : '';
  if (!normalizedIdentifierId) return '';
  return labelsById.get(normalizedIdentifierId) ?? normalizedIdentifierId;
};

/**
 * Resolves a content preview for a file.
 */
export const resolveContentPreview = (file: CaseResolverFile): string => {
  if (file.fileType === 'document') {
    const text = file.documentContentPlainText.trim() || file.documentContentMarkdown.trim();
    return text.length > PREVIEW_MAX_CHARS ? `${text.slice(0, PREVIEW_MAX_CHARS)}…` : text;
  }
  if (file.fileType === 'scanfile') {
    const combined = file.scanSlots
      .map((slot: CaseResolverScanSlot): string => (slot.ocrText ?? '').trim())
      .filter(Boolean)
      .join('\n\n');
    return combined.length > PREVIEW_MAX_CHARS ? `${combined.slice(0, PREVIEW_MAX_CHARS)}…` : combined;
  }
  return '';
};

/**
 * Resolves content suitable for document searching.
 */
export const resolveSearchableDocumentContent = (file: CaseResolverFile): string => {
  if (file.fileType === 'document') {
    const text = (file.documentContentPlainText.trim() || file.documentContentMarkdown.trim() || file.documentContent.trim());
    return text.length > SEARCHABLE_CONTENT_MAX_CHARS ? text.slice(0, SEARCHABLE_CONTENT_MAX_CHARS) : text;
  }
  if (file.fileType === 'scanfile') {
    const combined = file.scanSlots
      .map((slot: CaseResolverScanSlot): string => (slot.ocrText ?? '').trim())
      .filter(Boolean)
      .join('\n\n');
    return combined.length > SEARCHABLE_CONTENT_MAX_CHARS ? combined.slice(0, SEARCHABLE_CONTENT_MAX_CHARS) : combined;
  }
  return '';
};

/**
 * Node port utility functions.
 */
export const isDocumentWysiwygTextPort = (port: string | null | undefined): boolean => port === CASE_RESOLVER_DOCUMENT_NODE_OUTPUT_PORTS[0];
export const isDocumentPlaintextContentPort = (port: string | null | undefined): boolean => port === CASE_RESOLVER_DOCUMENT_NODE_OUTPUT_PORTS[1];
export const isDocumentPlainTextPort = (port: string | null | undefined): boolean => port === CASE_RESOLVER_DOCUMENT_NODE_OUTPUT_PORTS[2];
export const isDocumentWysiwygContentPort = (port: string | null | undefined): boolean => port === CASE_RESOLVER_EXPLANATORY_NODE_OUTPUT_PORTS[3];

/**
 * Resolves output value by port.
 */
export const resolveOutputValueByPort = (
  outputs: { wysiwygText: string; plaintextContent: string; plainText: string; wysiwygContent: string } | null | undefined,
  fromPort: string | null | undefined,
  fallback: 'wysiwygText' | 'plaintextContent' | 'plainText' | 'wysiwygContent'
): string => {
  if (!outputs) return '';
  if (isDocumentWysiwygTextPort(fromPort)) return outputs.wysiwygText;
  if (isDocumentPlainTextPort(fromPort)) return outputs.plainText;
  if (isDocumentWysiwygContentPort(fromPort)) return outputs.wysiwygContent;
  if (isDocumentPlaintextContentPort(fromPort)) return outputs.plaintextContent;

  const map: Record<string, string> = {
    plainText: outputs.plainText,
    wysiwygContent: outputs.wysiwygContent,
    wysiwygText: outputs.wysiwygText,
    plaintextContent: outputs.plaintextContent,
  };
  return map[fallback] ?? outputs.plaintextContent;
};

/**
 * Joins string based on join mode.
 */
export const appendWithJoinMode = (current: string, value: string, joinMode: CaseResolverJoinMode): string => {
  if (!value) return current;
  if (!current) return value;
  return `${current}${NODEFILE_JOIN_VALUE_MAP[joinMode]}${value}`;
};

/**
 * Relation Tree Builder Service
 * 
 * Provides logic for building hierarchical master-tree representations 
 * of CaseResolver relation workspaces.
 */

import type { MasterTreeNode } from '@/shared/utils/master-folder-tree-contract';
import type { NodeFileDocumentSearchRow } from '../../components/CaseResolverNodeFileUtils';
import type { RelationTreeBuildResult } from '../../relation-search/types';
import {
  buildCaseBuckets,
  ensureFolderNode,
} from '@/features/case-resolver/services/tree';
import {
  buildRelationCaseNodeId,
  buildRelationCasePath,
  buildRelationFileNodeId,
} from '@/features/case-resolver/services/tree/relation-tree-helpers';

/**
 * Assigns sort orders to tree nodes based on parent-child relations and content type.
 */
export const assignSiblingSortOrders = (
  nodesById: Map<string, MasterTreeNode>,
  fileOrderByNodeId: Map<string, number>
): void => {
  const childrenByParent = new Map<string | null, MasterTreeNode[]>();
  nodesById.forEach((node) => {
    const siblings = childrenByParent.get(node.parentId) ?? [];
    siblings.push(node);
    childrenByParent.set(node.parentId, siblings);
  });

  childrenByParent.forEach((siblings) => {
    siblings.sort((left, right) => {
      const leftType = String(left.metadata?.['relationNodeType'] ?? '');
      const rightType = String(right.metadata?.['relationNodeType'] ?? '');
      const leftIsFile = leftType === 'file';
      const rightIsFile = rightType === 'file';
      if (leftIsFile !== rightIsFile) return leftIsFile ? 1 : -1;
      if (leftIsFile && rightIsFile) {
        const leftOrder = fileOrderByNodeId.get(left.id) ?? Number.MAX_SAFE_INTEGER;
        const rightOrder = fileOrderByNodeId.get(right.id) ?? Number.MAX_SAFE_INTEGER;
        if (leftOrder !== rightOrder) return leftOrder - rightOrder;
      }
      const nameDelta = left.name.localeCompare(right.name, undefined, { sensitivity: 'base' });
      if (nameDelta !== 0) return nameDelta;
      return left.id.localeCompare(right.id);
    });
    siblings.forEach((node, index) => {
      node.sortOrder = index;
    });
  });
};

/**
 * Builds the master tree structure from a set of search rows.
 */
export const buildRelationMasterTree = (rows: NodeFileDocumentSearchRow[]): RelationTreeBuildResult => {
  const nodesById = new Map<string, MasterTreeNode>();
  const fileRowByNodeId = new Map<string, NodeFileDocumentSearchRow>();
  const fileNodeIdByFileId = new Map<string, string>();
  const caseMetaByNodeId = new Map<
    string,
    { nodeType: 'case'; caseId: string | null; signatureLabel: string }
  >();
  const folderMetaByNodeId = new Map<
    string,
    { nodeType: 'folder'; caseId: string | null; folderPath: string }
  >();
  const visibleFileIdsInTreeOrder: string[] = [];
  const visibleFileIdSet = new Set<string>();
  const fileOrderByNodeId = new Map<string, number>();

  const caseBuckets = buildCaseBuckets(rows);
  caseBuckets.forEach((bucket) => {
    const caseNodeId = buildRelationCaseNodeId(bucket.caseId);
    const caseNode: MasterTreeNode = {
      id: caseNodeId,
      type: 'folder',
      kind: 'relation_case',
      parentId: null,
      name: bucket.signatureLabel,
      path: buildRelationCasePath(bucket.caseId),
      sortOrder: 0,
      metadata: {
        relationNodeType: 'case',
        caseId: bucket.caseId,
        signatureLabel: bucket.signatureLabel,
      },
    };
    nodesById.set(caseNodeId, caseNode);
    caseMetaByNodeId.set(caseNodeId, {
      nodeType: 'case',
      caseId: bucket.caseId,
      signatureLabel: bucket.signatureLabel,
    });

    bucket.rows.forEach((row) => {
      let parentId = caseNodeId;
      let folderPathCursor = '';
      row.folderSegments.forEach((segment) => {
        folderPathCursor = folderPathCursor ? `${folderPathCursor}/${segment}` : segment;
        const folderNode = ensureFolderNode({
          nodesById,
          parentId,
          caseId: bucket.caseId,
          folderPath: folderPathCursor,
          folderName: segment,
        });
        folderMetaByNodeId.set(folderNode.id, {
          nodeType: 'folder',
          caseId: bucket.caseId,
          folderPath: folderPathCursor,
        });
        parentId = folderNode.id;
      });

      const fileNodeId = buildRelationFileNodeId(row.file.id);
      const fileNode: MasterTreeNode = {
        id: fileNodeId,
        type: 'file',
        kind: 'relation_file',
        parentId,
        name: row.file.name,
        path: row.folderPath
          ? `${buildRelationCasePath(bucket.caseId)}/${row.folderPath}/${row.file.id}`
          : `${buildRelationCasePath(bucket.caseId)}/${row.file.id}`,
        sortOrder: 0,
        metadata: {
          relationNodeType: 'file',
          fileId: row.file.id,
        },
      };
      nodesById.set(fileNodeId, fileNode);
      fileRowByNodeId.set(fileNodeId, row);
      fileNodeIdByFileId.set(row.file.id, fileNodeId);
      if (!visibleFileIdSet.has(row.file.id)) {
        visibleFileIdSet.add(row.file.id);
        visibleFileIdsInTreeOrder.push(row.file.id);
      }
      fileOrderByNodeId.set(fileNodeId, visibleFileIdsInTreeOrder.length - 1);
    });
  });

  assignSiblingSortOrders(nodesById, fileOrderByNodeId);

  return {
    nodes: Array.from(nodesById.values()),
    lookup: {
      fileRowByNodeId,
      fileNodeIdByFileId,
      caseMetaByNodeId,
      folderMetaByNodeId,
    },
  };
};

/**
 * Relation Tree Helpers
 * 
 * Provides utility functions for generating Case Resolver relation tree IDs and paths.
 */

const RELATION_TREE_CASE_PREFIX = 'relation_case::';
const RELATION_TREE_FOLDER_PREFIX = 'relation_folder::';
const RELATION_TREE_FILE_PREFIX = 'relation_file::';

export const RELATION_TREE_UNASSIGNED_CASE_KEY = '__unassigned_case__';

const normalizeToken = (value: string): string => encodeURIComponent(value.trim().toLowerCase());

/**
 * Builds a stable node ID for a case node.
 */
export const buildRelationCaseNodeId = (caseId: string | null): string => {
  const normalizedCaseId = caseId?.trim() || RELATION_TREE_UNASSIGNED_CASE_KEY;
  return `${RELATION_TREE_CASE_PREFIX}${normalizeToken(normalizedCaseId)}`;
};

/**
 * Builds a stable node ID for a folder node.
 */
export const buildRelationFolderNodeId = (input: {
  caseId: string | null;
  folderPath: string;
}): string => {
  const normalizedCaseId = input.caseId?.trim() || RELATION_TREE_UNASSIGNED_CASE_KEY;
  const normalizedFolderPath = input.folderPath.trim() || '.';
  return `${RELATION_TREE_FOLDER_PREFIX}${normalizeToken(normalizedCaseId)}::${normalizeToken(
    normalizedFolderPath
  )}`;
};

/**
 * Builds a stable node ID for a file node.
 */
export const buildRelationFileNodeId = (fileId: string): string =>
  `${RELATION_TREE_FILE_PREFIX}${normalizeToken(fileId)}`;

/**
 * Builds a path string for a case node.
 */
export const buildRelationCasePath = (caseId: string | null): string =>
  caseId?.trim() ? `cases/${caseId.trim()}` : 'cases/unassigned';

/**
 * Builds a path string for a folder node.
 */
export const buildRelationFolderPath = (input: {
  caseId: string | null;
  folderPath: string;
}): string => {
  const casePath = buildRelationCasePath(input.caseId);
  const folderPath = input.folderPath.trim();
  return folderPath ? `${casePath}/${folderPath}` : casePath;
};

/**
 * Workspace Normalization Service
 *
 * Provides services for normalizing, validating, and repairing CaseResolver workspaces.
