      id: rawId,
      name: rawName || `Category ${raw.length + 1}`,
      parentId: sanitizeOptionalId(record['parentId']),
      sortOrder:
        typeof record['sortOrder'] === 'number' && Number.isFinite(record['sortOrder'])
          ? record['sortOrder']
          : index,
      description: typeof record['description'] === 'string' ? record['description'] : '',
      color: normalizeHexColor(record['color'], '#10b981'),
      createdAt: normalizeTimestamp(record['createdAt'], now),
      updatedAt: normalizeTimestamp(record['updatedAt'], now),
    });
  });

  const byId = new Map<string, CaseResolverCategory>(
    raw.map((category: CaseResolverCategory): [string, CaseResolverCategory] => [
      category.id,
      category,
    ])
  );
  const normalizedParents = raw.map(
    (category: CaseResolverCategory): CaseResolverCategory => ({
      ...category,
      parentId: resolveSafeCategoryParentId(category.id, category.parentId ?? null, byId),
    })
  );

  const grouped = new Map<string, CaseResolverCategory[]>();
  const getGroupKey = (parentId: string | null): string => parentId ?? '__root__';
  normalizedParents.forEach((category: CaseResolverCategory): void => {
    const key = getGroupKey(category.parentId ?? null);
    const current = grouped.get(key) ?? [];
    current.push(category);
    grouped.set(key, current);
  });

  const output: CaseResolverCategory[] = [];
  const visit = (parentId: string | null): void => {
    const key = getGroupKey(parentId);
    const group = grouped.get(key) ?? [];
    group
      .sort((left: CaseResolverCategory, right: CaseResolverCategory) => {
        const sortDelta = left.sortOrder - right.sortOrder;
        if (sortDelta !== 0) return sortDelta;
        const nameDelta = left.name.localeCompare(right.name);
        if (nameDelta !== 0) return nameDelta;
        return left.id.localeCompare(right.id);
      })
      .forEach((category: CaseResolverCategory, index: number): void => {
        output.push({
          ...category,
          sortOrder: index,
        });
        visit(category.id);
      });
  };

  visit(null);
  return output;
};

export const buildCaseResolverCategoryTree = (
  categories: CaseResolverCategory[]
): CaseResolverCategoryTreeNode[] => {
  const byId = new Map<string, CaseResolverCategoryTreeNode>();
  categories.forEach((category: CaseResolverCategory): void => {
    byId.set(category.id, { ...category, children: [] });
  });

  const roots: CaseResolverCategoryTreeNode[] = [];
  categories.forEach((category: CaseResolverCategory): void => {
    const current = byId.get(category.id);
    if (!current) return;
    if (!category.parentId) {
      roots.push(current);
      return;
    }
    const parent = byId.get(category.parentId);
    if (!parent) {
      roots.push(current);
      return;
    }
    parent.children.push(current);
  });

  const sortNodes = (nodes: CaseResolverCategoryTreeNode[]): void => {
    nodes.sort((left: CaseResolverCategoryTreeNode, right: CaseResolverCategoryTreeNode) => {
      const sortDelta = left.sortOrder - right.sortOrder;
      if (sortDelta !== 0) return sortDelta;
      const nameDelta = left.name.localeCompare(right.name);
      if (nameDelta !== 0) return nameDelta;
      return left.id.localeCompare(right.id);
    });
    nodes.forEach((node: CaseResolverCategoryTreeNode): void => {
      if (node.children.length > 0) sortNodes(node.children);
    });
  };
  sortNodes(roots);

  return roots;
};

export const parseCaseResolverTags = (raw: string | null | undefined): CaseResolverTag[] =>
  normalizeCaseResolverTags(parseJsonSetting<unknown>(raw, []));

export const parseCaseResolverIdentifiers = (
  raw: string | null | undefined
): CaseResolverIdentifier[] => normalizeCaseResolverIdentifiers(parseJsonSetting<unknown>(raw, []));

export const parseCaseResolverCategories = (
  raw: string | null | undefined
): CaseResolverCategory[] => normalizeCaseResolverCategories(parseJsonSetting<unknown>(raw, []));

import { type CaseResolverAssetFile, type CaseResolverAssetKind, type CaseResolverFile, type CaseResolverFolderTimestamp, type CaseResolverWorkspace } from '@/shared/contracts/case-resolver';

const normalizeFolderPath = (value: string): string => {
  const normalized = value.replace(/\\/g, '/').trim();
  const parts = normalized
    .split('/')
    .map((part: string) => part.trim())
    .filter((part: string) => part && part !== '.' && part !== '..')
    .map((part: string) => part.replace(/[^a-zA-Z0-9-_]/g, '_'))
    .filter(Boolean);
  return parts.join('/');
};

const expandFolderPath = (value: string): string[] => {
  const normalized = normalizeFolderPath(value);
  if (!normalized) return [];
  const parts = normalized.split('/').filter(Boolean);
  return parts.map((_: string, index: number) => parts.slice(0, index + 1).join('/'));
};

const normalizeTimestamp = (value: unknown, fallback: string): string =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : fallback;

const toTimestampMs = (value: string | null | undefined): number | null => {
  if (!value) return null;
  const timestamp = Date.parse(value);
  return Number.isFinite(timestamp) ? timestamp : null;
};

const pickEarliestTimestamp = (
  values: Array<string | null | undefined>,
  fallback: string
): string => {
  let best = fallback;
  let bestMs = toTimestampMs(fallback);
  values.forEach((value: string | null | undefined): void => {
    if (typeof value !== 'string') return;
    const valueMs = toTimestampMs(value);
    if (valueMs === null) return;
    if (bestMs === null || valueMs < bestMs) {
      best = value;
      bestMs = valueMs;
    }
  });
  return best;
};

const pickLatestTimestamp = (
  values: Array<string | null | undefined>,
  fallback: string
): string => {
  let best = fallback;
  let bestMs = toTimestampMs(fallback);
  values.forEach((value: string | null | undefined): void => {
    if (typeof value !== 'string') return;
    const valueMs = toTimestampMs(value);
    if (valueMs === null) return;
    if (bestMs === null || valueMs > bestMs) {
      best = value;
      bestMs = valueMs;
    }
  });
  return best;
};

export const inferCaseResolverAssetKind = ({
  kind,
  mimeType,
  name,
}: {
  kind?: string | null | undefined;
  mimeType?: string | null | undefined;
  name?: string | null | undefined;
}): CaseResolverAssetKind => {
  const normalizedKind = (kind ?? '').trim().toLowerCase();
  if (
    normalizedKind === 'node_file' ||
    normalizedKind === 'image' ||
    normalizedKind === 'pdf' ||
    normalizedKind === 'file'
  ) {
    return normalizedKind;
  }

  const normalizedMime = (mimeType ?? '').trim().toLowerCase();
  if (normalizedMime.startsWith('image/')) return 'image';
  if (normalizedMime === 'application/pdf') return 'pdf';

  const normalizedName = (name ?? '').trim().toLowerCase();
  if (
    normalizedName.endsWith('.jpg') ||
    normalizedName.endsWith('.jpeg') ||
    normalizedName.endsWith('.png') ||
    normalizedName.endsWith('.webp') ||
    normalizedName.endsWith('.gif') ||
    normalizedName.endsWith('.bmp') ||
    normalizedName.endsWith('.avif') ||
    normalizedName.endsWith('.heic') ||
    normalizedName.endsWith('.heif') ||
    normalizedName.endsWith('.tif') ||
    normalizedName.endsWith('.tiff') ||
    normalizedName.endsWith('.svg')
  ) {
    return 'image';
  }
  if (normalizedName.endsWith('.pdf')) return 'pdf';
  return 'file';
};

const resolveUploadBucketForAssetKind = (
  kind: CaseResolverAssetKind
): 'images' | 'pdfs' | 'files' => {
  if (kind === 'image') return 'images';
  if (kind === 'pdf') return 'pdfs';
  return 'files';
};

export const resolveCaseResolverUploadFolder = ({
  baseFolder,
  kind,
  mimeType,
  name,
}: {
  baseFolder?: string | null | undefined;
  kind?: string | null | undefined;
  mimeType?: string | null | undefined;
  name?: string | null | undefined;
}): string => {
  const base = normalizeFolderPath(baseFolder ?? '');
  const inferredKind = inferCaseResolverAssetKind({ kind, mimeType, name });

  if (inferredKind === 'node_file') {
    return base;
  }

  const bucket = resolveUploadBucketForAssetKind(inferredKind);
  return normalizeFolderPath(base ? `${base}/${bucket}` : bucket);
};

export const createCaseResolverAssetFile = (input: {
  id: string;
  name: string;
  workspaceId?: string;
  folderId?: string | null;
  folder?: string;
  kind?: string | null | undefined;
  filepath?: string | null | undefined;
  sourceFileId?: string | null | undefined;
  mimeType?: string | null | undefined;
  size?: number | null | undefined;
  textContent?: string | null | undefined;
  description?: string | null | undefined;
  metadata?: Record<string, unknown> | null | undefined;
  createdAt?: string;
  updatedAt?: string;
}): CaseResolverAssetFile => {
  const now = new Date().toISOString();
  const createdAt = normalizeTimestamp(input.createdAt, now);
  const updatedAt = normalizeTimestamp(input.updatedAt, createdAt);
  const metadata =
    input.metadata && typeof input.metadata === 'object' && !Array.isArray(input.metadata)
      ? { ...input.metadata }
      : undefined;
  return {
    id: input.id,
    workspaceId: input.workspaceId ?? 'default',
    folderId: input.folderId ?? null,
    name: input.name.trim() || 'Untitled File',
    folder: normalizeFolderPath(input.folder ?? ''),
    kind: inferCaseResolverAssetKind({
      kind: input.kind,
      mimeType: input.mimeType,
      name: input.name,
    }),
    filepath:
      typeof input.filepath === 'string' && input.filepath.trim().length > 0
        ? input.filepath.trim()
        : null,
    sourceFileId:
      typeof input.sourceFileId === 'string' && input.sourceFileId.trim().length > 0
        ? input.sourceFileId.trim()
        : null,
    mimeType:
      typeof input.mimeType === 'string' && input.mimeType.trim().length > 0
        ? input.mimeType.trim().toLowerCase()
        : null,
    size:
      typeof input.size === 'number' && Number.isFinite(input.size) && input.size >= 0
        ? Math.round(input.size)
        : null,
    textContent: typeof input.textContent === 'string' ? input.textContent : '',
    description: typeof input.description === 'string' ? input.description : '',
    ...(metadata ? { metadata } : {}),
    createdAt,
    updatedAt,
  };
};

export const normalizeCaseResolverFolderTimestamps = ({
  source,
  folders,
  files,
  assets,
  fallbackTimestamp,
}: {
  source: unknown;
  folders: string[];
  files: CaseResolverFile[];
  assets: CaseResolverAssetFile[];
  fallbackTimestamp: string;
}): Record<string, CaseResolverFolderTimestamp> => {
  const sourceRecord =
    source && typeof source === 'object' && !Array.isArray(source)
      ? (source as Record<string, unknown>)
      : {};

  const contentStatsByFolder = new Map<string, { createdAt: string; updatedAt: string }>();
  const registerContentTimestamps = (
    folderPath: string,
    createdAt: string,
    updatedAt: string
  ): void => {
    const ancestors = expandFolderPath(folderPath);
    ancestors.forEach((ancestor: string): void => {
      const current = contentStatsByFolder.get(ancestor);
      if (!current) {
        contentStatsByFolder.set(ancestor, { createdAt, updatedAt });
        return;
      }
      contentStatsByFolder.set(ancestor, {
        createdAt: pickEarliestTimestamp([current.createdAt, createdAt], current.createdAt),
        updatedAt: pickLatestTimestamp([current.updatedAt, updatedAt], current.updatedAt),
      });
    });
  };

  files.forEach((file: CaseResolverFile): void => {
    registerContentTimestamps(
      file.folder,
      normalizeTimestamp(file.createdAt, fallbackTimestamp),
      normalizeTimestamp(file.updatedAt, normalizeTimestamp(file.createdAt, fallbackTimestamp))
    );
  });
  assets.forEach((asset: CaseResolverAssetFile): void => {
    registerContentTimestamps(
      asset.folder,
      normalizeTimestamp(asset.createdAt, fallbackTimestamp),
      normalizeTimestamp(asset.updatedAt, normalizeTimestamp(asset.createdAt, fallbackTimestamp))
    );
  });

  const folderTimestamps: Record<string, CaseResolverFolderTimestamp> = {};
  folders.forEach((folderPath: string): void => {
    const rawEntry = sourceRecord[folderPath];
    const entryRecord =
      rawEntry && typeof rawEntry === 'object' && !Array.isArray(rawEntry)
        ? (rawEntry as Record<string, unknown>)
        : {};

    const recordedCreatedAt = normalizeTimestamp(entryRecord['createdAt'], fallbackTimestamp);
    const recordedUpdatedAt = normalizeTimestamp(entryRecord['updatedAt'], recordedCreatedAt);
    const contentStats = contentStatsByFolder.get(folderPath);

    const createdAt = pickEarliestTimestamp(
      [recordedCreatedAt, contentStats?.createdAt],
      recordedCreatedAt
    );
    const updatedAt = pickLatestTimestamp(
      [recordedUpdatedAt, contentStats?.updatedAt, createdAt],
      recordedUpdatedAt
    );

    folderTimestamps[folderPath] = {
      createdAt,
      updatedAt,
    };
  });

  return folderTimestamps;
};

const parseWorkspaceTimestampMs = (value: string | null | undefined): number => {
  if (!value) return 0;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : 0;
};

export const getCaseResolverWorkspaceLatestTimestampMs = (
  workspace: CaseResolverWorkspace
): number => {
  let latest = 0;
  workspace.files.forEach((file: CaseResolverFile): void => {
    latest = Math.max(
      latest,
      parseWorkspaceTimestampMs(file.createdAt),
      parseWorkspaceTimestampMs(file.updatedAt)
    );
  });
  workspace.assets.forEach((asset: CaseResolverAssetFile): void => {
    latest = Math.max(
      latest,
      parseWorkspaceTimestampMs(asset.createdAt),
      parseWorkspaceTimestampMs(asset.updatedAt)
    );
  });
  return latest;
};

export const renameFolderPath = (
  value: string,
  sourceFolder: string,
  targetFolder: string
): string => {
  const normalizedValue = normalizeFolderPath(value);
  const normalizedSource = normalizeFolderPath(sourceFolder);
  const normalizedTarget = normalizeFolderPath(targetFolder);
  if (!normalizedSource) return normalizedValue;
  if (normalizedValue === normalizedSource) return normalizedTarget;
  if (normalizedValue.startsWith(`${normalizedSource}/`)) {
    const suffix = normalizedValue.slice(normalizedSource.length + 1);
    if (!normalizedTarget) return suffix;
    return `${normalizedTarget}/${suffix}`;
  }
  return normalizedValue;
};

import type { CaseResolverEdge } from '@/shared/contracts/case-resolver/graph';
import {
  CANONICAL_CASE_RESOLVER_EDGE_KEYS,
  FORBIDDEN_CASE_RESOLVER_EDGE_HANDLE_NAMES,
  buildInvalidCaseResolverEdgeError,
  normalizeCaseResolverEdgeHandle,
} from '@/features/case-resolver/services/graph';
import { caseResolverEdgeSchema } from '@/shared/contracts/case-resolver/graph';

const findUnsupportedCaseResolverEdgeKeys = (record: Record<string, unknown>): string[] =>
  Object.keys(record).filter(
    (key: string): boolean => !CANONICAL_CASE_RESOLVER_EDGE_KEYS.has(key)
  );

const parseCaseResolverEdgeRecord = (
  input: unknown,
  context: string
): Record<string, unknown> => {
  if (!input || typeof input !== 'object' || Array.isArray(input)) {
    throw buildInvalidCaseResolverEdgeError('Invalid Case Resolver edge payload.', context, {
      reason: 'edge_not_object',
    });
  }

  return input as Record<string, unknown>;
};

const assertSupportedCaseResolverEdgeKeys = (
  record: Record<string, unknown>,
  context: string
): void => {
  const unsupportedKeys = findUnsupportedCaseResolverEdgeKeys(record);
  if (unsupportedKeys.length > 0) {
    throw buildInvalidCaseResolverEdgeError(
      'Case Resolver edge payload includes unsupported fields.',
      context,
      { unsupportedKeys }
    );
  }
};

const parseValidatedCaseResolverEdge = (
  record: Record<string, unknown>,
  context: string
): CaseResolverEdge => {
  const validation = caseResolverEdgeSchema.safeParse(record);
  if (validation.success) {
    return validation.data;
  }

  throw buildInvalidCaseResolverEdgeError('Invalid Case Resolver edge payload.', context, {
    issues: validation.error.flatten(),
  });
};

const assertCanonicalCaseResolverEdgeEndpoints = (
  edge: CaseResolverEdge,
  context: string
): { source: string; target: string } => {
  const source = typeof edge.source === 'string' ? edge.source.trim() : '';
  const target = typeof edge.target === 'string' ? edge.target.trim() : '';
  if (source && target) {
    return { source, target };
  }

  throw buildInvalidCaseResolverEdgeError(
    'Case Resolver edges must use canonical source/target fields.',
    context,
    {
      edgeId: edge.id,
    }
  );
};

const assertAllowedCaseResolverEdgeHandles = (
  edge: CaseResolverEdge,
  context: string
): { sourceHandle: string | null; targetHandle: string | null } => {
  const sourceHandle = normalizeCaseResolverEdgeHandle(edge.sourceHandle);
  const targetHandle = normalizeCaseResolverEdgeHandle(edge.targetHandle);
  if (
    (sourceHandle !== null && FORBIDDEN_CASE_RESOLVER_EDGE_HANDLE_NAMES.has(sourceHandle)) ||
    (targetHandle !== null && FORBIDDEN_CASE_RESOLVER_EDGE_HANDLE_NAMES.has(targetHandle))
  ) {
    throw buildInvalidCaseResolverEdgeError(
      'Case Resolver edge payload includes unsupported handle names.',
      context,
      {
        edgeId: edge.id,
        sourceHandle: sourceHandle ?? null,
        targetHandle: targetHandle ?? null,
      }
    );
  }

  return { sourceHandle, targetHandle };
};

export const parseCanonicalCaseResolverEdge = (input: unknown, context: string): CaseResolverEdge => {
  const record = parseCaseResolverEdgeRecord(input, context);
  assertSupportedCaseResolverEdgeKeys(record, context);
  const edge = parseValidatedCaseResolverEdge(record, context);
  const { source, target } = assertCanonicalCaseResolverEdgeEndpoints(edge, context);
  const { sourceHandle, targetHandle } = assertAllowedCaseResolverEdgeHandles(edge, context);

  return {
    ...edge,
    source,
    target,
    sourceHandle: sourceHandle ?? null,
    targetHandle: targetHandle ?? null,
  };
};

/**
 * settings.files.ts
 *
 * Normalises and validates CaseResolver file records (case files, scan files,
 * and asset files). Called during workspace normalisation to ensure all file
 * fields are correctly typed and internally consistent.
 *
 * Responsibilities:
 *  - Coerce missing/invalid fields to safe defaults.
 *  - Repair broken parent-case and reference-case links (drop dangling IDs).
 *  - Normalise document content (HTML vs. plain text, version migration).
 *  - Trim document history to the configured limit.
 *  - Sanitise the prompt graph embedded in each file.
 *  - Deduplicate scan slots and party references.
 */
import {
  deriveDocumentContentSync,
  ensureHtmlForPreview,
  hasHtmlMarkup,
  ensureSafeDocumentHtml,
  stripHtmlToPlainText,
  toStorageDocumentValue,
} from '@/shared/lib/document-editor/public';
import { type CaseResolverDocumentHistoryEntry, type CaseResolverDocumentVersion, type CaseResolverEditorType, type CaseResolverFile, type CaseResolverScanSlot, type CreateCaseResolverFileInput } from '@/shared/contracts/case-resolver';

import { sanitizeGraph } from './settings-graph';
import { DEFAULT_CASE_RESOLVER_SCANFILE_OCR_PROMPT } from './settings.constants';
import {
  normalizeCaseHappeningDate,
  normalizeCaseResolverCaseStatus,
  normalizeCaseResolverDocumentVersion,
  normalizeCaseResolverFileType,
  normalizeCaseTreeOrder,
  normalizeDocumentContentVersion,
  normalizeDocumentCity,
  normalizeDocumentDate,
  normalizeDocumentFormatVersion,
  normalizeFolderPath,
  normalizeTimestamp,
  sanitizeOptionalId,
  sanitizeOptionalIdArray,
  sanitizeOptionalMimeType,
  sanitizePartyReference,
} from './settings.helpers';

// Maximum number of document history snapshots to keep per file. Older
// snapshots are dropped during normalisation to prevent unbounded growth.
const CASE_RESOLVER_DOCUMENT_HISTORY_LIMIT = 120;

// Repairs broken parent-case and reference-case links by dropping IDs that
// don't correspond to any file in the workspace. Returns a new array of files
// with repaired links.
export const normalizeCaseResolverRelatedFileLinks = (
  files: CaseResolverFile[]
): CaseResolverFile[] => {
  if (files.length === 0) return files;

  const filesById = new Map<string, CaseResolverFile>(
    files.map((file: CaseResolverFile): [string, CaseResolverFile] => [file.id, file])
  );
  const relationMap = new Map<string, Set<string>>();

  files.forEach((file: CaseResolverFile): void => {
    relationMap.set(file.id, new Set<string>());
  });

  files.forEach((file: CaseResolverFile): void => {
    if (file.fileType === 'case') return;
    const sourceSet = relationMap.get(file.id);
    if (!sourceSet) return;
    (file.relatedFileIds ?? []).forEach((relatedFileId: string): void => {
      const normalizedRelatedFileId = relatedFileId.trim();
      if (!normalizedRelatedFileId || normalizedRelatedFileId === file.id) return;
      const relatedFile = filesById.get(normalizedRelatedFileId);
      if (!relatedFile || relatedFile.fileType === 'case') return;
      sourceSet.add(normalizedRelatedFileId);
    });
  });

  relationMap.forEach((relatedIds: Set<string>, sourceId: string): void => {
    relatedIds.forEach((targetId: string): void => {
      const reciprocal = relationMap.get(targetId);
      if (!reciprocal) return;
      reciprocal.add(sourceId);
    });
  });

  return files.map((file: CaseResolverFile): CaseResolverFile => {
    if (file.fileType === 'case') {
      if (!file.relatedFileIds || file.relatedFileIds.length === 0) return file;
      return {
        ...file,
        relatedFileIds: undefined,
      };
    }

    const normalizedRelatedFileIds = Array.from(relationMap.get(file.id) ?? []).sort(
      (left: string, right: string): number => left.localeCompare(right)
    );
    const currentRelatedFileIds = sanitizeOptionalIdArray(file.relatedFileIds).sort(
      (left: string, right: string): number => left.localeCompare(right)
    );
    const hasSameRelatedFileIds =
      normalizedRelatedFileIds.length === currentRelatedFileIds.length &&
      normalizedRelatedFileIds.every(
        (relatedFileId: string, index: number): boolean =>
          relatedFileId === currentRelatedFileIds[index]
      );
    if (hasSameRelatedFileIds) return file;
    return {
      ...file,
      relatedFileIds: normalizedRelatedFileIds.length > 0 ? normalizedRelatedFileIds : undefined,
    };
  });
};

export const normalizeCaseResolverDocumentHistory = (
  input: unknown,
  fallbackTimestamp: string,
  mode: 'markdown' | 'wysiwyg'
): CaseResolverDocumentHistoryEntry[] => {
  if (!Array.isArray(input)) return [];

  const seen = new Set<string>();
  const entries: CaseResolverDocumentHistoryEntry[] = [];

  input.forEach((entry: unknown, index: number): void => {
    if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return;
    const record = entry as Record<string, unknown>;

    const rawId =
      typeof record['id'] === 'string' && record['id'].trim().length > 0
        ? record['id'].trim()
        : `doc-history-${index + 1}`;
    if (seen.has(rawId)) return;
    seen.add(rawId);

    const fallbackContent =
      typeof record['documentContent'] === 'string' ? record['documentContent'] : '';
    const rawMarkdown =
      typeof record['documentContentMarkdown'] === 'string'
        ? record['documentContentMarkdown']
        : undefined;
    const rawHtml =
      typeof record['documentContentHtml'] === 'string' ? record['documentContentHtml'] : undefined;
    const activeDocumentVersion = normalizeCaseResolverDocumentVersion(
      record['activeDocumentVersion']
    );
    const canonical = (() => {
      if (mode === 'markdown') {
        const resolvedMarkdownContent = (() => {
          if (typeof rawMarkdown === 'string' && rawMarkdown.trim().length > 0) {
            return rawMarkdown;
          }
          if (
            typeof record['documentContentPlainText'] === 'string' &&
            record['documentContentPlainText'].trim().length > 0
          ) {
            return record['documentContentPlainText'];
          }
          if (fallbackContent.trim().length > 0) {
            return hasHtmlMarkup(fallbackContent)
              ? stripHtmlToPlainText(fallbackContent)
              : fallbackContent;
          }
          if (typeof rawHtml === 'string' && rawHtml.trim().length > 0) {
            return stripHtmlToPlainText(rawHtml);
          }
          return '';
        })();
        return deriveDocumentContentSync({
          mode: 'markdown',
          value: resolvedMarkdownContent,
          previousHtml: rawHtml,
          previousMarkdown: rawMarkdown,
        });
      }

      const resolvedHtmlContent = (() => {
        if (typeof rawHtml === 'string' && rawHtml.trim().length > 0) {
          return rawHtml;
        }
        if (typeof rawMarkdown === 'string' && rawMarkdown.trim().length > 0) {
          return ensureHtmlForPreview(rawMarkdown, 'markdown');
        }
        return ensureSafeDocumentHtml(fallbackContent);
      })();
      return deriveDocumentContentSync({
        mode: 'wysiwyg',
        value: resolvedHtmlContent,
        previousHtml: rawHtml,
        previousMarkdown: rawMarkdown,
      });
    })();

    entries.push({
      id: rawId,
      savedAt: normalizeTimestamp(record['savedAt'], fallbackTimestamp),
      documentContentVersion: normalizeDocumentContentVersion(record['documentContentVersion']),
      activeDocumentVersion,
      editorType: canonical.mode,
      documentContent: toStorageDocumentValue(canonical),
      documentContentMarkdown: canonical.markdown,
      documentContentHtml: canonical.html,
      documentContentPlainText: canonical.plainText,
    });
  });

  return entries
    .sort((left: CaseResolverDocumentHistoryEntry, right: CaseResolverDocumentHistoryEntry) => {
      const rightTimestamp = Date.parse(right.savedAt);
      const leftTimestamp = Date.parse(left.savedAt);
      if (
        Number.isFinite(rightTimestamp) &&
        Number.isFinite(leftTimestamp) &&
        rightTimestamp !== leftTimestamp
      ) {
        return rightTimestamp - leftTimestamp;
      }
      return right.documentContentVersion - left.documentContentVersion;
    })
    .slice(0, CASE_RESOLVER_DOCUMENT_HISTORY_LIMIT);
};

export const normalizeCaseResolverScanSlots = (
  input: unknown,
  fileId: string
): CaseResolverScanSlot[] => {
  if (!Array.isArray(input)) return [];

  const seen = new Set<string>();
  const slots: CaseResolverScanSlot[] = [];

  input.forEach((entry: unknown, index: number): void => {
    if (!entry || typeof entry !== 'object') return;
    const record = entry as Record<string, unknown>;

    const rawId =
      typeof record['id'] === 'string' && record['id'].trim().length > 0
        ? record['id'].trim()
        : `scan-slot-${index + 1}`;
    if (seen.has(rawId)) return;
    seen.add(rawId);

    const rawName = typeof record['name'] === 'string' ? record['name'].trim() : '';
    const rawStatus = typeof record['status'] === 'string' ? record['status'] : '';
    const status =
      rawStatus === 'pending' ||
      rawStatus === 'processing' ||
      rawStatus === 'completed' ||
      rawStatus === 'failed'
        ? rawStatus
        : 'completed';

    slots.push({
      id: rawId,
      fileId,
      status,
      progress: typeof record['progress'] === 'number' ? record['progress'] : 100,
      name: rawName || `Scan ${slots.length + 1}`,
      filepath: sanitizeOptionalId(record['filepath']),
      sourceFileId: sanitizeOptionalId(record['sourceFileId']),
      mimeType: sanitizeOptionalMimeType(record['mimeType']),
      size:
        typeof record['size'] === 'number' && Number.isFinite(record['size']) && record['size'] >= 0
          ? Math.round(record['size'])
          : undefined,
      ocrText: typeof record['ocrText'] === 'string' ? record['ocrText'] : '',
      ocrError:
        typeof record['ocrError'] === 'string' && record['ocrError'].trim().length > 0
          ? record['ocrError'].trim()
          : null,
    });
  });

  return slots;
};

export const createCaseResolverFile = (input: CreateCaseResolverFileInput): CaseResolverFile => {
  const now = new Date().toISOString();
  const createdAt = normalizeTimestamp(input.createdAt, now);
  const updatedAt = normalizeTimestamp(input.updatedAt, createdAt);
  const fallbackDocumentContent =
    typeof input.documentContent === 'string' ? input.documentContent : '';
  const originalDocumentContent =
    typeof input.originalDocumentContent === 'string'
      ? input.originalDocumentContent
      : fallbackDocumentContent;
  const explodedDocumentContent =
    typeof input.explodedDocumentContent === 'string' ? input.explodedDocumentContent : '';
  const requestedVersion = normalizeCaseResolverDocumentVersion(input.activeDocumentVersion);
  const activeDocumentVersion: CaseResolverDocumentVersion =
    requestedVersion === 'exploded' && explodedDocumentContent.trim().length === 0
      ? 'original'
      : requestedVersion;
  const activeDocumentContent =
    activeDocumentVersion === 'exploded' ? explodedDocumentContent : originalDocumentContent;
  const fileType = normalizeCaseResolverFileType(input.fileType);
  const caseStatus =
    fileType === 'case' ? normalizeCaseResolverCaseStatus(input.caseStatus) : undefined;
  const caseTreeOrder =
    fileType === 'case' ? normalizeCaseTreeOrder(input.caseTreeOrder) : undefined;
  const happeningDate =
    fileType === 'case' ? normalizeCaseHappeningDate(input.happeningDate) : null;
  const resolvedEditorType: 'markdown' | 'wysiwyg' =
    fileType === 'scanfile' ? 'markdown' : 'wysiwyg';
  const resolvedCanonicalSource = (() => {
    if (resolvedEditorType === 'markdown') {
      if (
        typeof input.documentContentMarkdown === 'string' &&
        input.documentContentMarkdown.trim().length > 0
      ) {
        return input.documentContentMarkdown;
      }
      if (
        typeof input.documentContentPlainText === 'string' &&
        input.documentContentPlainText.trim().length > 0
      ) {
        return input.documentContentPlainText;
      }
      if (activeDocumentContent.trim().length > 0) {
        return hasHtmlMarkup(activeDocumentContent)
          ? stripHtmlToPlainText(activeDocumentContent)
          : activeDocumentContent;
      }
      if (
        typeof input.documentContentHtml === 'string' &&
        input.documentContentHtml.trim().length > 0
      ) {
        return stripHtmlToPlainText(input.documentContentHtml);
      }
      return '';
    }
    if (
      typeof input.documentContentHtml === 'string' &&
      input.documentContentHtml.trim().length > 0
    ) {
      return input.documentContentHtml;
    }
    if (
      typeof input.documentContentMarkdown === 'string' &&
      input.documentContentMarkdown.trim().length > 0
    ) {
      return ensureHtmlForPreview(input.documentContentMarkdown, 'markdown');
    }
    return ensureSafeDocumentHtml(activeDocumentContent);
  })();
  const canonicalDocument = deriveDocumentContentSync({
    mode: resolvedEditorType,
    value: resolvedCanonicalSource,
    previousHtml: input.documentContentHtml,
    previousMarkdown: input.documentContentMarkdown,
  });
  const documentContent = toStorageDocumentValue(canonicalDocument);
  const editorType: CaseResolverEditorType = resolvedEditorType;
  const documentContentFormatVersion = normalizeDocumentFormatVersion(
    input.documentContentFormatVersion
  );
  const documentContentVersion = normalizeDocumentContentVersion(input.documentContentVersion);
  const documentConversionWarnings = Array.isArray(input.documentConversionWarnings)
    ? input.documentConversionWarnings
      .filter((entry: string | unknown): entry is string => typeof entry === 'string')
      .map((entry: string) => entry.trim())
      .filter((entry: string) => entry.length > 0)
    : canonicalDocument.warnings;
  const lastContentConversionAt = normalizeTimestamp(input.lastContentConversionAt, updatedAt);
  const parentCaseId = sanitizeOptionalId(input.parentCaseId);
  const referenceCaseIds = sanitizeOptionalIdArray(input.referenceCaseIds).filter(
    (referenceId: string): boolean => referenceId !== input.id
  );
  const relatedFileIds = sanitizeOptionalIdArray(input.relatedFileIds).filter(
    (relatedId: string): boolean => relatedId !== input.id
  );
  const scanOcrModel = typeof input.scanOcrModel === 'string' ? input.scanOcrModel.trim() : '';
  const scanOcrPrompt =
    typeof input.scanOcrPrompt === 'string' && input.scanOcrPrompt.trim().length > 0
      ? input.scanOcrPrompt.trim()
      : DEFAULT_CASE_RESOLVER_SCANFILE_OCR_PROMPT;
  return {
    id: input.id,
    workspaceId: input.workspaceId ?? 'default',
    version: input.version ?? 'original',
    fileType,
    caseStatus,
    caseTreeOrder,
    name: input.name.trim() || 'Untitled Case',
    folder: normalizeFolderPath(input.folder ?? ''),
    parentCaseId,
    referenceCaseIds,
    relatedFileIds: relatedFileIds.length > 0 ? relatedFileIds : undefined,
    documentDate: normalizeDocumentDate(input.documentDate),
    documentCity: normalizeDocumentCity(input.documentCity),
    happeningDate,
    originalDocumentContent,
    explodedDocumentContent,
    activeDocumentVersion,
    editorType,
    documentContentFormatVersion,
    documentContentVersion,
    documentContent,
    documentContentMarkdown: canonicalDocument.markdown,
    documentContentHtml: canonicalDocument.html,
    documentContentPlainText: canonicalDocument.plainText,
    documentHistory: normalizeCaseResolverDocumentHistory(
      input.documentHistory,
      updatedAt,
      resolvedEditorType
    ),
    documentConversionWarnings,
    lastContentConversionAt,
    scanSlots: normalizeCaseResolverScanSlots(input.scanSlots, input.id),
    scanOcrModel: fileType === 'scanfile' ? scanOcrModel : '',
    scanOcrPrompt: fileType === 'scanfile' ? scanOcrPrompt : '',
    isSent: input.isSent === true,
    isLocked: input.isLocked === true,
    addresser: sanitizePartyReference(input.addresser),
    addressee: sanitizePartyReference(input.addressee),
    tagId: sanitizeOptionalId(input.tagId),
    caseIdentifierId: sanitizeOptionalId(input.caseIdentifierId),
    categoryId: sanitizeOptionalId(input.categoryId),
    createdAt,
    updatedAt,
    graph: sanitizeGraph({
      nodes: input.graph?.nodes ?? [],
      edges: input.graph?.edges ?? [],
      nodeMeta: input.graph?.nodeMeta ?? {},
      edgeMeta: input.graph?.edgeMeta ?? {},
      pdfExtractionPresetId: input.graph?.pdfExtractionPresetId,
      documentFileLinksByNode: input.graph?.documentFileLinksByNode ?? {},
      documentDropNodeId: input.graph?.documentDropNodeId ?? null,
      documentSourceFileIdByNode: input.graph?.documentSourceFileIdByNode ?? {},
      nodeFileAssetIdByNode: input.graph?.nodeFileAssetIdByNode ?? {},
    }),
  };
};

/**
 * settings.helpers.ts
 *
 * Shared normalisation and validation helpers used across the case-resolver
 * settings layer. These functions coerce raw user input or persisted JSON
 * values into safe, canonical forms.
 *
 * Responsibilities:
 *  - Folder path normalisation (backslash → forward slash, sanitise segments).
 *  - Timestamp normalisation (coerce to ISO string or fallback).
 *  - ID sanitisation (trim, deduplicate, filter empty).
 *  - Enum coercion (file type, party search kind, document format, etc.).
 *  - Date formatting (ISO YYYY-MM-DD).
 */
import { type CaseResolverDocumentDateProposal, type CaseResolverDocumentFormatVersion, type CaseResolverFileType, type CaseResolverPartyReference } from '@/shared/contracts/case-resolver';

import { type CaseResolverPartySearchKind } from './settings.constants';

// Normalises a folder path: converts backslashes to forward slashes, trims
// segments, removes `.` and `..` traversals, replaces non-alphanumeric chars
// with underscores. Returns an empty string for the root folder.
export const normalizeFolderPath = (value: string): string => {
  const normalized = value.replace(/\\/g, '/').trim();
  const parts = normalized
    .split('/')
    .map((part: string) => part.trim())
    .filter((part: string) => part && part !== '.' && part !== '..')
    .map((part: string) => part.replace(/[^a-zA-Z0-9-_]/g, '_'))
    .filter(Boolean);
  return parts.join('/');
};

// Expands a folder path into all its ancestor paths. E.g. "a/b/c" becomes
// ["a", "a/b", "a/b/c"]. Used to ensure all parent folders exist.
export const expandFolderPath = (value: string): string[] => {
  const normalized = normalizeFolderPath(value);
  if (!normalized) return [];
  const parts = normalized.split('/').filter(Boolean);
  return parts.map((_: string, index: number) => parts.slice(0, index + 1).join('/'));
};

// Normalises an array of folder paths, expanding each to include all
// ancestors, deduplicating, and sorting lexicographically.
export const normalizeFolderPaths = (folders: string[]): string[] => {
  const set = new Set<string>();
  folders
    .flatMap((folder: string) => expandFolderPath(folder))
    .forEach((folder: string) => {
      if (folder) set.add(folder);
    });
  return Array.from(set).sort((left: string, right: string) => left.localeCompare(right));
};

// Coerces a value to a non-empty ISO timestamp string, falling back to
// `fallback` when the value is missing or invalid.
export const normalizeTimestamp = (value: unknown, fallback: string): string =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : fallback;

// Same as normalizeTimestamp but returns null instead of a fallback when the
// value is missing or invalid (used for optional timestamp fields).
export const normalizeOptionalTimestamp = (value: unknown): string | null =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;

// Coerces a value to a trimmed non-empty string ID, or null when invalid.
export const sanitizeOptionalId = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

// Sanitises an array of IDs: filters out non-strings, trims, deduplicates,
// and removes empty strings.
export const sanitizeOptionalIdArray = (value: unknown): string[] => {
  if (!Array.isArray(value)) return [];
  const unique = new Set<string>();
  value.forEach((entry: unknown): void => {
    if (typeof entry !== 'string') return;
    const normalized = entry.trim();
    if (!normalized) return;
    unique.add(normalized);
  });
  return Array.from(unique);
};

export const sanitizeOptionalMimeType = (value: unknown): string | undefined => {
  const normalized = sanitizeOptionalId(value);
  return normalized ? normalized.toLowerCase() : undefined;
};

export const normalizeWorkspaceRevision = (value: unknown): number => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return 0;
  if (value <= 0) return 0;
  return Math.floor(value);
};

export const normalizeDocumentCity = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

export const normalizeIsoDocumentDate = (value: string): string | null => {
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (/^\d{4}-\d{2}-\d{2}$/.test(trimmed)) {
      return trimmed;
    }
    if (/^\d{4}-\d{2}-\d{2}T/.test(trimmed)) {
      return trimmed.slice(0, 10);
    }
  }
  return null;
};

export const normalizeCaseHappeningDate = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const normalized = value.trim();
  if (!normalized) return null;
  return normalizeIsoDocumentDate(normalized) ?? normalized;
};

export const normalizeDocumentDateAction = (
  value: unknown
): CaseResolverDocumentDateProposal['action'] => {
  if (value === 'useDetectedDate' || value === 'keepText' || value === 'ignore') {
    return value;
  }
  return 'useDetectedDate';
};

export const normalizeDocumentDateSource = (
  value: unknown
): CaseResolverDocumentDateProposal['source'] => (value === 'metadata' ? 'metadata' : 'text');

export const normalizeDocumentDate = (value: unknown): CaseResolverDocumentDateProposal | null => {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    const record = value as Record<string, unknown>;
    const isoDate = normalizeIsoDocumentDate(
      typeof record['isoDate'] === 'string' ? record['isoDate'] : ''
    );
    if (!isoDate) return null;
    const cityHint = normalizeDocumentCity(record['cityHint']);
    const city = normalizeDocumentCity(record['city']);
    return {
      isoDate,
      source: normalizeDocumentDateSource(record['source']),
      sourceLine:
        typeof record['sourceLine'] === 'string' && record['sourceLine'].trim().length > 0
          ? record['sourceLine'].trim()
          : null,
      cityHint,
      city: city ?? cityHint,
      action: normalizeDocumentDateAction(record['action']),
    };
  }

  const isoDate = normalizeIsoDocumentDate(typeof value === 'string' ? value : '');
  if (!isoDate) return null;
  return {
    isoDate,
    source: 'text',
    sourceLine: null,
    cityHint: null,
    city: null,
    action: 'useDetectedDate',
  };
};

const isValidDocumentDatePart = (value: number, min: number, max: number): boolean =>
  Number.isInteger(value) && value >= min && value <= max;

const hasValidIsoDocumentDateParts = (year: number, month: number, day: number): boolean =>
  isValidDocumentDatePart(year, 1900, 2099) &&
  isValidDocumentDatePart(month, 1, 12) &&
  isValidDocumentDatePart(day, 1, 31);

const formatIsoDocumentDate = (year: number, month: number, day: number): string =>
  `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

export const toIsoDocumentDate = (year: number, month: number, day: number): string | null => {
  if (!hasValidIsoDocumentDateParts(year, month, day)) return null;

  const parsed = new Date(Date.UTC(year, month - 1, day));
  if (
    parsed.getUTCFullYear() !== year ||
    parsed.getUTCMonth() !== month - 1 ||
    parsed.getUTCDate() !== day
  ) {
    return null;
  }
  return formatIsoDocumentDate(year, month, day);
};

export const sanitizePartyReference = (value: unknown): CaseResolverPartyReference | null => {
  if (!value || typeof value !== 'object') return null;
  const record = value as Record<string, unknown>;
  const kindRaw = typeof record['kind'] === 'string' ? record['kind'].trim() : '';
  const id = typeof record['id'] === 'string' ? record['id'].trim() : '';
  if (!id) return null;
  if (kindRaw !== 'person' && kindRaw !== 'organization') return null;
  const kind: CaseResolverPartyReference['kind'] = kindRaw;
  return {
    kind,
    id,
  };
};

export const normalizeCaseResolverFileType = (value: unknown): CaseResolverFileType => {
  if (value === 'case' || value === 'document' || value === 'scanfile') {
    return value;
  }
  return 'document';
};

export const normalizeCaseResolverDocumentVersion = (value: unknown): 'original' | 'exploded' =>
  value === 'exploded' ? 'exploded' : 'original';

export const normalizeCaseResolverCaseStatus = (value: unknown): 'pending' | 'completed' =>
  value === 'completed' ? 'completed' : 'pending';

export const normalizeCaseTreeOrder = (value: unknown): number | undefined => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return undefined;
  const normalized = Math.floor(value);
  return normalized >= 0 ? normalized : undefined;
};

export const normalizeDocumentContentVersion = (value: unknown): number => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return 1;
  const normalized = Math.floor(value);
  return normalized > 0 ? normalized : 1;
};

export const normalizeCaseResolverDefaultDocumentFormatValue = (
  input: unknown
): 'wysiwyg' | 'markdown' | null => {
  if (typeof input !== 'string') return null;
  const normalized = input.trim().toLowerCase();
  if (normalized === 'wysiwyg' || normalized === 'markdown') {
    return normalized;
  }
  return null;
};

export const normalizeCaseResolverPartySearchKindValue = (
  input: unknown
): CaseResolverPartySearchKind | null => {
  if (typeof input !== 'string') return null;
  const normalized = input.trim().toLowerCase();
  if (normalized === 'person' || normalized === 'organization') {
    return normalized;
  }
  return null;
};

export const normalizeDocumentFormatVersion = (
  value: unknown
): CaseResolverDocumentFormatVersion => {
  if (value === 1) return 1;
  return 1;
};

