  workspace: CaseResolverWorkspace,
  diagnostics: Partial<CaseResolverWorkspaceNormalizationDiagnostics> | null | undefined
): CaseResolverWorkspace => {
  caseResolverWorkspaceNormalizationDiagnosticsByWorkspace.set(
