/**
 * Case Resolver Workspace Persistence Utilities
 * 
 * Utilities for persisting and managing Case Resolver workspace state.
 * Provides:
 * - Environment variable parsing
 * - Workspace state normalization
 * - Persistence configuration
 * - Error handling for workspace operations
 * - Configuration validation
 */

import { type CaseResolverWorkspace } from '@/shared/contracts/case-resolver';

import { normalizeCaseResolverWorkspace } from '../settings.workspace';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

/** Reads and validates a positive integer from environment variables */
export const readPositiveIntegerEnv = (key: string, fallback: number): number => {
  const value = process.env[key];
  if (!value) return fallback;
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  const normalized = Math.floor(parsed);
  if (normalized <= 0) return fallback;
  return normalized;
};

export const formatByteCount = (value: number): string => {
  if (!Number.isFinite(value) || value <= 0) return '0 B';
  const units = ['B', 'KB', 'MB', 'GB'];
  let normalized = value;
  let unitIndex = 0;
  while (normalized >= 1024 && unitIndex < units.length - 1) {
    normalized /= 1024;
    unitIndex += 1;
  }
  const rounded =
    normalized >= 10 || unitIndex === 0 ? normalized.toFixed(0) : normalized.toFixed(1);
  return `${rounded} ${units[unitIndex]}`;
};

const normalizePositiveInteger = (value: unknown, fallback: number): number => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return fallback;
  }
  const normalized = Math.floor(value);
  return normalized > 0 ? normalized : fallback;
};

const normalizeNonNegativeInteger = (value: unknown, fallback: number): number => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return fallback;
  }
  const normalized = Math.floor(value);
  return normalized >= 0 ? normalized : fallback;
};

const resolveCaseResolverConflictRetryConfig = (
  attempt: number,
  options?: {
    baseDelayMs?: number;
    maxDelayMs?: number;
    jitterMs?: number;
  },
  defaults?: {
    baseDelayMs: number;
    maxDelayMs: number;
    jitterMs: number;
  }
): {
  attempt: number;
  baseDelayMs: number;
  maxDelayMs: number;
  jitterMs: number;
} => {
  const normalizedAttempt = normalizePositiveInteger(attempt, 1);
  const baseDelayMs = normalizePositiveInteger(options?.baseDelayMs, defaults?.baseDelayMs ?? 150);
  const maxDelayMs = Math.max(
    baseDelayMs,
    normalizePositiveInteger(options?.maxDelayMs, defaults?.maxDelayMs ?? 1500)
  );
  const jitterMs = normalizeNonNegativeInteger(options?.jitterMs, defaults?.jitterMs ?? 120);
  return {
    attempt: normalizedAttempt,
    baseDelayMs,
    maxDelayMs,
    jitterMs,
  };
};

const computeExponentialRetryDelayMs = (input: {
  attempt: number;
  baseDelayMs: number;
  maxDelayMs: number;
}): number =>
  Math.min(input.maxDelayMs, input.baseDelayMs * Math.pow(2, input.attempt - 1));

const computeRetryJitterMs = (jitterMs: number): number =>
  jitterMs > 0 ? Math.floor(Math.random() * (jitterMs + 1)) : 0;

export const computeCaseResolverConflictRetryDelayMs = (
  attempt: number,
  options?: {
    baseDelayMs?: number;
    maxDelayMs?: number;
    jitterMs?: number;
  },
  defaults?: {
    baseDelayMs: number;
    maxDelayMs: number;
    jitterMs: number;
  }
): number => {
  const config = resolveCaseResolverConflictRetryConfig(attempt, options, defaults);
  return (
    computeExponentialRetryDelayMs(config) +
    computeRetryJitterMs(config.jitterMs)
  );
};

export const createCaseResolverWorkspaceMutationId = (
  prefix = 'case-resolver-workspace'
): string => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return `${prefix}-${crypto.randomUUID()}`;
  }
  return `${prefix}-${Math.random().toString(36).slice(2, 10)}-${Date.now()}`;
};

export const getCaseResolverWorkspaceRevision = (workspace: {
  workspaceRevision?: unknown;
}): number => {
  const candidate = workspace.workspaceRevision;
  if (typeof candidate !== 'number' || !Number.isFinite(candidate)) return 0;
  if (candidate <= 0) return 0;
  return Math.floor(candidate);
};

export const stampCaseResolverWorkspaceMutation = (
  workspace: CaseResolverWorkspace,
  input: {
    baseRevision: number;
    mutationId: string;
    timestamp?: string;
    normalizeWorkspace?: boolean;
  }
): CaseResolverWorkspace => {
  const baseWorkspace =
    input.normalizeWorkspace === false ? workspace : normalizeCaseResolverWorkspace(workspace);
  const baseRevision =
    typeof input.baseRevision === 'number' && Number.isFinite(input.baseRevision)
      ? Math.max(0, Math.floor(input.baseRevision))
      : 0;
  const nextRevision = Math.max(getCaseResolverWorkspaceRevision(baseWorkspace), baseRevision + 1);
  return {
    ...baseWorkspace,
    workspaceRevision: nextRevision,
    lastMutationId: input.mutationId.trim() || null,
    lastMutationAt: (input.timestamp ?? new Date().toISOString()).trim(),
  };
};

export const safeParseJson = <T>(value: string): T | null => {
  try {
    return JSON.parse(value) as T;
  } catch (error) {
    logClientError(error);
    return null;
  }
};

import {
  type CaseResolverWorkspaceFetchAttemptProfile,
  type CaseResolverWorkspaceMetadata,
} from '@/shared/contracts/case-resolver';

export const CASE_RESOLVER_WORKSPACE_KEY = 'case_resolver_workspace_v2';
export const CASE_RESOLVER_WORKSPACE_HISTORY_KEY = 'case_resolver_workspace_v2_history';
export const CASE_RESOLVER_WORKSPACE_DOCUMENTS_KEY = 'case_resolver_workspace_v2_documents';

export type SettingsRecordLike = {
  key?: unknown;
  value?: unknown;
  conflict?: unknown;
  idempotent?: unknown;
  currentRevision?: unknown;
};

export type WorkspaceMetadataLike = {
  key?: unknown;
  revision?: unknown;
  lastMutationId?: unknown;
  exists?: unknown;
};

export type WorkspaceSettingsPayloadLike = {
  settings?: unknown;
  key?: unknown;
  value?: unknown;
};

export const readWorkspaceMetadata = (
  payload: WorkspaceMetadataLike | null
): CaseResolverWorkspaceMetadata => {
  const revisionRaw = payload?.revision;
  const revision =
    typeof revisionRaw === 'number' && Number.isFinite(revisionRaw) && revisionRaw > 0
      ? Math.floor(revisionRaw)
      : 0;
  const lastMutationIdRaw = payload?.lastMutationId;
  const lastMutationId =
    typeof lastMutationIdRaw === 'string' && lastMutationIdRaw.trim().length > 0
      ? lastMutationIdRaw
      : null;
  const exists = payload?.exists !== false;
  return {
    revision,
    lastMutationId,
    exists,
  };
};

export const readSettingsRecordsFromPayload = (payload: unknown): SettingsRecordLike[] => {
  if (Array.isArray(payload)) {
    return payload.filter(
      (entry: unknown): entry is SettingsRecordLike => Boolean(entry) && typeof entry === 'object'
    );
  }
  if (!payload || typeof payload !== 'object') return [];
  const payloadRecord = payload as WorkspaceSettingsPayloadLike;
  if (Array.isArray(payloadRecord.settings)) {
    return payloadRecord.settings.filter(
      (entry: unknown): entry is SettingsRecordLike => Boolean(entry) && typeof entry === 'object'
    );
  }
  if (typeof payloadRecord.key === 'string' && typeof payloadRecord.value === 'string') {
    return [payloadRecord as SettingsRecordLike];
  }
  return [];
};

export const resolveWorkspaceRecordFromSettingsPayload = (
  payload: unknown
): SettingsRecordLike | null => {
  const records = readSettingsRecordsFromPayload(payload);
  return (
    records.find(
      (entry: SettingsRecordLike): boolean =>
        entry?.key === CASE_RESOLVER_WORKSPACE_KEY && typeof entry?.value === 'string'
    ) ?? null
  );
};

export const resolveSettingRecordFromSettingsPayload = (
  payload: unknown,
  key: string
): SettingsRecordLike | null => {
  const records = readSettingsRecordsFromPayload(payload);
  return (
    records.find(
      (entry: SettingsRecordLike): boolean => entry?.key === key && typeof entry?.value === 'string'
    ) ?? null
  );
};

export const buildSettingRecordFetchAttempts = ({
  key,
  strategy,
  fresh,
}: {
  key: string;
  strategy: 'light_then_heavy' | 'light_only' | 'heavy_only';
  fresh: boolean;
}): Array<{ scope: 'light' | 'heavy'; key: string; url: string }> => {
  const attemptScopes: Array<'light' | 'heavy'> =
    strategy === 'heavy_only'
      ? ['heavy']
      : strategy === 'light_only'
        ? ['light']
        : ['light', 'heavy'];
  const attempts: Array<{ scope: 'light' | 'heavy'; key: string; url: string }> = [];
  attemptScopes.forEach((scope): void => {
    if (fresh) {
      attempts.push({
        scope,
        key: `${scope}_fresh_key`,
        url: `/api/settings?scope=${scope}&fresh=1&key=${encodeURIComponent(key)}`,
      });
    }
    attempts.push({
      scope,
      key: `${scope}_cached_key`,
      url: `/api/settings?scope=${scope}&key=${encodeURIComponent(key)}`,
    });
  });
  return attempts;
};

export const buildWorkspaceRecordFetchAttempts = ({
  strategy,
  fresh,
  attemptProfile,
}: {
  strategy: 'light_then_heavy' | 'light_only' | 'heavy_only';
  fresh: boolean;
  attemptProfile: CaseResolverWorkspaceFetchAttemptProfile;
}): Array<{ key: string; url: string; scope: 'light' | 'heavy' }> => {
  const attemptScopes: Array<'light' | 'heavy'> =
    strategy === 'heavy_only'
      ? ['heavy']
      : strategy === 'light_only'
        ? ['light']
        : ['light', 'heavy'];
  if (!fresh) {
    return attemptScopes.map((scope) => ({
      key: `${scope}_cached_key`,
      scope,
      url: `/api/settings?scope=${scope}&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
    }));
  }

  if (attemptProfile === 'context_fast' && strategy === 'light_then_heavy') {
    return [
      {
        key: 'light_fresh_key',
        scope: 'light',
        url: `/api/settings?scope=light&fresh=1&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
      },
      {
        key: 'heavy_fresh_key',
        scope: 'heavy',
        url: `/api/settings?scope=heavy&fresh=1&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
      },
      {
        key: 'light_cached_key',
        scope: 'light',
        url: `/api/settings?scope=light&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
      },
      {
        key: 'heavy_cached_key',
        scope: 'heavy',
        url: `/api/settings?scope=heavy&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
      },
    ];
  }

  const attempts: Array<{ key: string; url: string; scope: 'light' | 'heavy' }> = [];
  attemptScopes.forEach((scope): void => {
    attempts.push(
      {
        key: `${scope}_fresh_key`,
        scope,
        url: `/api/settings?scope=${scope}&fresh=1&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
      },
      {
        key: `${scope}_cached_key`,
        scope,
        url: `/api/settings?scope=${scope}&key=${encodeURIComponent(CASE_RESOLVER_WORKSPACE_KEY)}`,
      }
    );
  });
  return attempts;
};

import { detectCaseResolverOcrProvider } from '@/features/case-resolver/ocr-provider';
import type { CaseResolverOcrProvider } from '@/shared/contracts/case-resolver/base';
import { configurationError } from '@/shared/errors/app-error';

import type { CaseResolverResolvedOcrModel } from './types';

export const parseProviderPrefixedModel = (value: string): CaseResolverResolvedOcrModel | null => {
  const trimmed = value.trim();
  if (!trimmed) return null;

  const match = trimmed.match(/^(openai|anthropic|gemini|ollama)\s*[:/]\s*(.+)$/i);
  if (!match) return null;

  const providerRaw = match[1]?.toLowerCase();
  const modelRaw = match[2]?.trim() ?? '';
  if (!providerRaw || !modelRaw) return null;

  if (
    providerRaw !== 'openai' &&
    providerRaw !== 'anthropic' &&
    providerRaw !== 'gemini' &&
    providerRaw !== 'ollama'
  ) {
    return null;
  }

  return {
    provider: providerRaw as CaseResolverOcrProvider,
    model: modelRaw,
  };
};

export const inferCaseResolverOcrProviderFromModel = (modelName: string): CaseResolverOcrProvider =>
  detectCaseResolverOcrProvider(modelName);

export const resolveCaseResolverOcrModel = (
  model: string,
  fallbackModel: string = ''
): CaseResolverResolvedOcrModel => {
  const runtimeModel = model.trim();
  const selectedModel = runtimeModel || fallbackModel.trim();
  if (!selectedModel) {
    throw configurationError('No OCR model is configured.', {
      model,
      fallbackModel,
    });
  }
  const explicitModel = parseProviderPrefixedModel(selectedModel);
  if (explicitModel) return explicitModel;
  return {
    model: selectedModel,
    provider: inferCaseResolverOcrProviderFromModel(selectedModel),
  };
};

export const resolveCaseResolverOcrModelCandidates = (
  model: string,
  fallbackModel: string = ''
): CaseResolverResolvedOcrModel[] => {
  const runtimeCandidates = model
    .split(/[\n,;]+/)
    .map((entry: string): string => entry.trim())
    .filter(Boolean);
  const fallbackCandidate = fallbackModel.trim();
  const candidateValues =
    runtimeCandidates.length > 0 ? runtimeCandidates : fallbackCandidate ? [fallbackCandidate] : [];

  if (candidateValues.length === 0) {
    throw configurationError('No OCR models are configured.', {
      model,
      fallbackModel,
    });
  }

  const uniqueCandidates = new Set<string>();
  const resolvedCandidates: CaseResolverResolvedOcrModel[] = [];

  for (const entry of candidateValues) {
    const normalizedEntry = entry.toLowerCase();
    if (uniqueCandidates.has(normalizedEntry)) continue;
    uniqueCandidates.add(normalizedEntry);
    resolvedCandidates.push(resolveCaseResolverOcrModel(entry));
  }

  return resolvedCandidates;
};

import { resolveBrainProviderCredential } from '@/shared/lib/ai-brain/provider-credentials';
import { externalServiceError } from '@/shared/errors/app-error';

import { REMOTE_OCR_TIMEOUT_MS } from '../config';
import { parseAnthropicResponseText } from '../response-parsers';
import { type AnthropicMessageResponse } from '../types';
import { buildOcrPromptContent, fetchWithTimeout } from '../utils';

export const runAnthropicOcrRequest = async (input: {
  model: string;
  prompt: string;
  filepath: string;
  base64Image?: string | undefined;
  mimeType?: string | undefined;
  extractedDocumentText?: string | undefined;
}): Promise<string> => {
  const apiKey = await resolveBrainProviderCredential('anthropic');
  const content = [
    {
      type: 'text',
      text:
        typeof input.base64Image === 'string'
          ? input.prompt
          : buildOcrPromptContent({
            prompt: input.prompt,
            filepath: input.filepath,
            extractedDocumentText: input.extractedDocumentText,
          }),
    },
    ...(typeof input.base64Image === 'string' && input.base64Image.length > 0
      ? [
        {
          type: 'image',
          source: {
            type: 'base64',
            media_type: input.mimeType || 'image/jpeg',
            data: input.base64Image,
          },
        },
      ]
      : []),
  ];
  const response = await fetchWithTimeout(
    'https://api.anthropic.com/v1/messages',
    {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
      },
      body: JSON.stringify({
        model: input.model,
        max_tokens: 1500,
        messages: [
          {
            role: 'user',
            content,
          },
        ],
      }),
    },
    REMOTE_OCR_TIMEOUT_MS,
    'Anthropic OCR'
  );

  if (!response.ok) {
    const responseBody = await response.text();
    // Anthropic API returned an error response
    throw externalServiceError(`Anthropic OCR request failed with status ${response.status}.`, {
      status: response.status,
      responseBody,
      model: input.model,
    });
  }
  const payload = (await response.json()) as AnthropicMessageResponse;
  return parseAnthropicResponseText(payload);
};

import { resolveBrainProviderCredential } from '@/shared/lib/ai-brain/provider-credentials';
import { externalServiceError } from '@/shared/errors/app-error';

import { REMOTE_OCR_TIMEOUT_MS } from '../config';
import { parseGeminiResponseText } from '../response-parsers';
import { type GeminiResponse } from '../types';
import { buildOcrPromptContent, fetchWithTimeout } from '../utils';

export const runGeminiOcrRequest = async (input: {
  model: string;
  prompt: string;
  filepath: string;
  base64Image?: string | undefined;
  mimeType?: string | undefined;
  extractedDocumentText?: string | undefined;
}): Promise<string> => {
  const apiKey = await resolveBrainProviderCredential('gemini');
  const parts = [
    {
      text:
        typeof input.base64Image === 'string'
          ? input.prompt
          : buildOcrPromptContent({
            prompt: input.prompt,
            filepath: input.filepath,
            extractedDocumentText: input.extractedDocumentText,
          }),
    },
    ...(typeof input.base64Image === 'string' && input.base64Image.length > 0
      ? [
        {
          inline_data: {
            mime_type: input.mimeType || 'image/jpeg',
            data: input.base64Image,
          },
        },
      ]
      : []),
  ];
  const response = await fetchWithTimeout(
    `https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(
      input.model
    )}:generateContent?key=${encodeURIComponent(apiKey)}`,
    {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({
        contents: [{ role: 'user', parts }],
        generationConfig: { maxOutputTokens: 1500 },
      }),
    },
    REMOTE_OCR_TIMEOUT_MS,
    'Gemini OCR'
  );

  if (!response.ok) {
    const responseBody = await response.text();
    // Gemini API returned an error response
    throw externalServiceError(`Gemini OCR request failed with status ${response.status}.`, {
      status: response.status,
      responseBody,
      model: input.model,
    });
  }
  const payload = (await response.json()) as GeminiResponse;
  return parseGeminiResponseText(payload);
};

import OpenAI from 'openai';
import { type ChatCompletionContentPart } from 'openai/resources/chat/completions';

import { externalServiceError } from '@/shared/errors/app-error';
import { resolveBrainProviderCredential } from '@/shared/lib/ai-brain/provider-credentials';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

import { REMOTE_OCR_TIMEOUT_MS } from '../config';
import { parseOpenAiResponseText } from '../response-parsers';
import { buildOcrPromptContent, withPromiseTimeout } from '../utils';


export const runOpenAiOcrRequest = async (input: {
  model: string;
  prompt: string;
  filepath: string;
  base64Image?: string | undefined;
  mimeType?: string | undefined;
  extractedDocumentText?: string | undefined;
}): Promise<string> => {
  const apiKey = await resolveBrainProviderCredential('openai');
  const client = new OpenAI({ apiKey });

  const content: string | ChatCompletionContentPart[] =
    typeof input.base64Image === 'string' && input.base64Image.length > 0
      ? [
        {
          type: 'text' as const,
          text: input.prompt,
        },
        {
          type: 'image_url' as const,
          image_url: {
            url: `data:${input.mimeType || 'image/jpeg'};base64,${input.base64Image}`,
          },
        },
      ]
      : buildOcrPromptContent({
        prompt: input.prompt,
        filepath: input.filepath,
        extractedDocumentText: input.extractedDocumentText,
      });
  const messages = [
    {
      role: 'user' as const,
      content,
    },
  ];

  try {
    const completion = await withPromiseTimeout(
      client.chat.completions.create({
        model: input.model,
        messages,
        max_completion_tokens: 1500,
      }),
      REMOTE_OCR_TIMEOUT_MS,
      'OpenAI OCR'
    );
    return parseOpenAiResponseText(completion);
  } catch (error) {
    void ErrorSystem.captureException(error);
    const errorMessage = error instanceof Error ? error.message : '';
    if (!/max_completion_tokens/i.test(errorMessage)) {
      throw externalServiceError('OpenAI OCR request failed.', {
        model: input.model,
        cause: error,
      });
    }

    const completion = await withPromiseTimeout(
      client.chat.completions.create({
        model: input.model,
        messages,
        max_tokens: 1500,
      }),
      REMOTE_OCR_TIMEOUT_MS,
      'OpenAI OCR'
    );
    return parseOpenAiResponseText(completion);
  }
};

import type {
  OllamaChatPayload,
  AnthropicMessageResponse,
  GeminiResponse,
} from './types';

export const parseOllamaResponseText = (payload: OllamaChatPayload): string => {
  const message =
    typeof payload.message?.content === 'string'
      ? payload.message.content
      : typeof payload.response === 'string'
        ? payload.response
        : '';
  return message.trim();
};

export const parseOpenAiResponseText = (payload: unknown): string => {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return '';
  const content = (payload as { choices?: Array<{ message?: { content?: unknown } }> }).choices?.[0]
    ?.message?.content;
  if (typeof content === 'string') return content.trim();
  if (Array.isArray(content)) {
    return content
      .map((part: unknown): string => {
        if (!part || typeof part !== 'object') return '';
        const text = (part as { text?: unknown }).text;
        return typeof text === 'string' ? text : '';
      })
      .join('')
      .trim();
  }
  return '';
};

export const parseAnthropicResponseText = (payload: AnthropicMessageResponse): string => {
  return (payload.content ?? [])
    .map((part): string => {
      if (part?.type !== 'text') return '';
      return typeof part.text === 'string' ? part.text : '';
    })
    .join('')
    .trim();
};

export const parseGeminiResponseText = (payload: GeminiResponse): string => {
  return (payload.candidates?.[0]?.content?.parts ?? [])
    .map((part): string => (typeof part.text === 'string' ? part.text : ''))
    .join('')
    .trim();
};

import {
  safeSetTimeout,
  safeClearTimeout,
} from '@/shared/lib/timers';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
export const fetchWithTimeout = async (
  input: RequestInfo | URL,
  init: RequestInit,
  timeoutMs: number,
  source: string
): Promise<Response> => {
  const controller = new AbortController();
  const timeoutId = safeSetTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(input, {
      ...init,
      signal: controller.signal,
    });
  } catch (error) {
    void ErrorSystem.captureException(error);
    if (error instanceof Error && error.name === 'AbortError') {
      throw new Error(`${source} request timed out after ${timeoutMs}ms.`, { cause: error });
    }
    throw error;
  } finally {
    safeClearTimeout(timeoutId);
  }
};

export const withPromiseTimeout = async <T>(
  promise: Promise<T>,
  timeoutMs: number,
  source: string
): Promise<T> => {
  let timeoutId: ReturnType<typeof safeSetTimeout> | null = null;
  const timeoutPromise = new Promise<T>((_, reject) => {
    timeoutId = safeSetTimeout(() => {
      reject(new Error(`${source} request timed out after ${timeoutMs}ms.`));
    }, timeoutMs);
  });
  try {
    return await Promise.race([promise, timeoutPromise]);
  } finally {
    if (timeoutId) safeClearTimeout(timeoutId);
  }
};

export const buildOcrPromptContent = (input: {
  prompt: string;
  filepath: string;
  extractedDocumentText?: string | undefined;
}): string => {
  if (typeof input.extractedDocumentText !== 'string') {
    return input.prompt;
  }
  return [
    input.prompt,
    `Source file path: ${input.filepath}`,
    'DOCUMENT_TEXT_BEGIN',
    input.extractedDocumentText || '(No readable text extracted from the document.)',
    'DOCUMENT_TEXT_END',
  ].join('\n\n');
};

