export const logCaseResolverWorkspaceEvent = (
  event: Omit<CaseResolverWorkspaceDebugEvent, 'id' | 'timestamp'>
): void => {
  const entry: CaseResolverWorkspaceDebugEvent = {
    id: createCaseResolverWorkspaceMutationId('workspace-debug'),
    timestamp: new Date().toISOString(),
    ...event,
  };
  const nextEvents = [...readDebugBuffer(), entry].slice(-CASE_RESOLVER_WORKSPACE_DEBUG_LIMIT);
  writeDebugBuffer(nextEvents);
  if (typeof window !== 'undefined') {
    // Defer notification so debug-panel state updates never run inside another component render.
    window.setTimeout(() => {
      window.dispatchEvent(new CustomEvent(CASE_RESOLVER_WORKSPACE_DEBUG_EVENT_NAME));
    }, 0);
  }
};

export const readCaseResolverWorkspaceDebugEvents = (): CaseResolverWorkspaceDebugEvent[] => [
  ...readDebugBuffer(),
];

export const getCaseResolverWorkspaceDebugEventName = (): string =>
  CASE_RESOLVER_WORKSPACE_DEBUG_EVENT_NAME;

const percentile = (values: number[], ratio: number): number => {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const index = Math.min(sorted.length - 1, Math.max(0, Math.floor((sorted.length - 1) * ratio)));
  return sorted[index] ?? 0;
};

const buildPercentileSnapshot = (values: number[]): PercentileSnapshot => {
  return {
    count: values.length,
    p50: percentile(values, 0.5),
    p95: percentile(values, 0.95),
    max: values.length > 0 ? Math.max(...values) : 0,
  };
};

const countByAction = (events: CaseResolverWorkspaceDebugEvent[]): Record<string, number> => {
  return events.reduce<Record<string, number>>((acc, event) => {
    const action = event.action.trim() || 'unknown';
    acc[action] = (acc[action] ?? 0) + 1;
    return acc;
  }, {});
};

const parseEventMessageTokens = (message: string | null | undefined): Record<string, string> => {
  if (typeof message !== 'string' || message.trim().length === 0) return {};
  return message
    .trim()
    .split(/\s+/)
    .reduce<Record<string, string>>((acc, token) => {
      const separatorIndex = token.indexOf('=');
      if (separatorIndex <= 0) return acc;
      const key = token.slice(0, separatorIndex).trim();
      const value = token.slice(separatorIndex + 1).trim();
      if (!key) return acc;
      acc[key] = value;
      return acc;
    }, {});
};

const parseBooleanToken = (value: string | undefined): boolean | null => {
  if (value === 'true') return true;
  if (value === 'false') return false;
  return null;
};

const normalizeNullableValue = (value: string | undefined): string | null => {
  if (!value || value === 'none' || value === '<none>' || value === '-') return null;
  return value;
};

const parsePositiveIntegerToken = (value: string | undefined): number => {
  if (!value) return 0;
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) return 0;
  return Math.floor(parsed);
};

const sumCounterMetric = (events: CaseResolverWorkspaceDebugEvent[], action: string): number =>
  events.reduce((count: number, event: CaseResolverWorkspaceDebugEvent): number => {
    if (event.action !== action) return count;
    const tokens = parseEventMessageTokens(event.message);
    const step = parsePositiveIntegerToken(tokens['count']);
    return count + (step > 0 ? step : 1);
  }, 0);

const collectDurationMetricValues = (
  events: CaseResolverWorkspaceDebugEvent[],
  action: string
): number[] =>
  events
    .filter((event: CaseResolverWorkspaceDebugEvent): boolean => event.action === action)
    .map((event: CaseResolverWorkspaceDebugEvent): number => event.durationMs ?? 0)
    .filter((value: number): boolean => Number.isFinite(value) && value >= 0);

const getLatestHydrationSelection = (
  events: CaseResolverWorkspaceDebugEvent[]
): WorkspaceHydrationSelectionSnapshot | null => {
  const latestEvent = [...events]
    .reverse()
    .find(
      (event: CaseResolverWorkspaceDebugEvent): boolean =>
        event.action === 'hydrate_workspace_source_selected'
    );
  if (!latestEvent) return null;
  const messageTokens = parseEventMessageTokens(latestEvent.message);
  return {
    timestamp: latestEvent.timestamp,
    source: normalizeNullableValue(messageTokens['source']),
    reason: normalizeNullableValue(messageTokens['reason']),
    hasStore: parseBooleanToken(messageTokens['has_store']),
    hasHeavy: parseBooleanToken(messageTokens['has_heavy']),
    workspaceRevision:
      typeof latestEvent.workspaceRevision === 'number' &&
      Number.isFinite(latestEvent.workspaceRevision)
        ? latestEvent.workspaceRevision
        : null,
  };
};

const getLatestRequestedContext = (
  events: CaseResolverWorkspaceDebugEvent[]
): RequestedContextSnapshot | null => {
  const latestEvent = [...events]
    .reverse()
    .find((event: CaseResolverWorkspaceDebugEvent): boolean =>
      event.action.startsWith('requested_context_')
    );
  if (!latestEvent) return null;
  const messageTokens = parseEventMessageTokens(latestEvent.message);
  return {
    timestamp: latestEvent.timestamp,
    action: latestEvent.action,
    requestKey: normalizeNullableValue(messageTokens['request_key']),
    requestedCaseStatus: normalizeNullableValue(messageTokens['requested_case_status']),
    requestedCaseIssue: normalizeNullableValue(messageTokens['requested_case_issue']),
    resolvedVia: normalizeNullableValue(messageTokens['resolved_via']),
  };
};

export const buildCaseResolverWorkspaceObservabilitySnapshot = (
  events: CaseResolverWorkspaceDebugEvent[],
  nowMs: number = Date.now()
): CaseResolverWorkspaceObservabilitySnapshot => {
  const actionCounts = countByAction(events);
  const persistAttempts = actionCounts['persist_attempt'] ?? 0;
  const persistSuccesses = actionCounts['persist_success'] ?? 0;
  const persistConflicts = actionCounts['persist_conflict'] ?? 0;
  const persistFailures =
    (actionCounts['persist_failed'] ?? 0) +
    (actionCounts['persist_rejected_payload_too_large'] ?? 0);
  const conflictRate = persistAttempts > 0 ? persistConflicts / persistAttempts : 0;
  const saveSuccessRate = persistAttempts > 0 ? persistSuccesses / persistAttempts : 0;

  const persistDurations = events
    .filter(
      (event): boolean =>
        event.action === 'persist_success' ||
        event.action === 'persist_conflict' ||
        event.action === 'persist_failed'
    )
    .map((event): number => event.durationMs ?? 0)
    .filter((value): boolean => Number.isFinite(value) && value >= 0);
  const payloadSizes = events
    .filter((event): boolean => event.action === 'persist_attempt')
    .map((event): number => event.payloadBytes ?? 0)
    .filter((value): boolean => Number.isFinite(value) && value >= 0);
  const runtimeCounters: RuntimeCounterSnapshot = {
    selectorRecomputeCount: sumCounterMetric(events, 'selector_recompute_count'),
    contextStateTransitionCount: sumCounterMetric(events, 'context_state_transition_count'),
  };
  const runtimeDurations: RuntimeDurationSnapshot = {
    treeScopeResolveMs: buildPercentileSnapshot(
      collectDurationMetricValues(events, 'tree_scope_resolve_ms')
    ),
    caseSearchFilterMs: buildPercentileSnapshot(
      collectDurationMetricValues(events, 'case_search_filter_ms')
    ),
    editorDirtyEvalMs: buildPercentileSnapshot(
      collectDurationMetricValues(events, 'editor_dirty_eval_ms')
    ),
  };
  const latestHydrationSelection = getLatestHydrationSelection(events);
  const latestRequestedContext = getLatestRequestedContext(events);

  return {
    generatedAt: new Date(nowMs).toISOString(),
    sampleSize: events.length,
    actionCounts,
    persistAttempts,
    persistSuccesses,
    persistConflicts,
    persistFailures,
    conflictRate,
    saveSuccessRate,
    persistDurationMs: buildPercentileSnapshot(persistDurations),
    payloadBytes: buildPercentileSnapshot(payloadSizes),
    runtimeCounters,
    runtimeDurations,
    latestHydrationSelection,
    latestRequestedContext,
  };
};

export const readCaseResolverWorkspaceObservabilitySnapshot =
  (): CaseResolverWorkspaceObservabilitySnapshot => {
    const events = readCaseResolverWorkspaceDebugEvents();
    return buildCaseResolverWorkspaceObservabilitySnapshot(events);
  };

import { z } from 'zod';
import { type CaseResolverWorkspace } from '@/shared/contracts/case-resolver';

import {
  getCaseResolverWorkspaceRevision,
  safeParseJson,
} from './utils/workspace-persistence-utils';

export const CASE_RESOLVER_WORKSPACE_DETACHED_DOCUMENTS_SCHEMA_V2 =
  'case_resolver_workspace_detached_documents_v2';
const CASE_RESOLVER_WORKSPACE_DETACHED_DOCUMENTS_SCHEMA =
  CASE_RESOLVER_WORKSPACE_DETACHED_DOCUMENTS_SCHEMA_V2;
const CASE_RESOLVER_WORKSPACE_LIGHTWEIGHT_TEXT_MAX_CHARS = 6_000;

/**
 * Zod schema for a single detached document file entry.
 */
/**
 * Zod schema for a scan slot.
 */
export const ScanSlotSchema = z.object({
  id: z.string().min(1),
  fileId: z.string().min(1),
  status: z.enum(['pending', 'processing', 'completed', 'failed']),
  progress: z.number().nonnegative(),
  ocrText: z.string().optional(),
});

export type CaseResolverScanSlot = z.infer<typeof ScanSlotSchema>;

// Update DetachedFileEntrySchema to use the ScanSlotSchema
export const DetachedFileEntrySchema = z.object({
  id: z.string().min(1),
  documentContent: z.string().optional(),
  documentContentHtml: z.string().optional(),
  documentContentMarkdown: z.string().optional(),
  documentContentPlainText: z.string().optional(),
  originalDocumentContent: z.string().optional(),
  explodedDocumentContent: z.string().optional(),
  ocrText: z.string().optional(),
  scanSlots: z.array(ScanSlotSchema).optional(),
});

export type CaseResolverWorkspaceDetachedDocumentsFileEntry = z.infer<typeof DetachedFileEntrySchema>;

/**
 * Zod schema for the entire detached documents payload.
 */
export const DetachedDocumentsPayloadSchema = z.object({
  schema: z.literal(CASE_RESOLVER_WORKSPACE_DETACHED_DOCUMENTS_SCHEMA),
  workspaceRevision: z.number().int().positive(),
  lastMutationId: z.string().trim().min(1).nullable(),
  files: z.array(DetachedFileEntrySchema),
});

export type CaseResolverWorkspaceDetachedDocumentsPayload = z.infer<
  typeof DetachedDocumentsPayloadSchema
>;

const coerceDetachedWorkspaceFile = (
  value: unknown
): CaseResolverWorkspace['files'][number] => value as CaseResolverWorkspace['files'][number];

const truncate = (value: string, maxChars: number): string =>
  value.length > maxChars ? value.slice(0, maxChars) : value;

const normalizeWhitespace = (value: string): string => value.replace(/\s+/g, ' ').trim();

const stripHtmlTags = (value: string): string => value.replace(/<[^>]*>/g, ' ');

const resolveTextContent = (file: CaseResolverWorkspace['files'][number]): string => {
  const sources = [
    file.documentContentPlainText,
    file.documentContentMarkdown,
    file.documentContentHtml,
    file.documentContent,
  ];

  for (const source of sources) {
    if (typeof source === 'string' && source.trim().length > 0) {
      return source.includes('<') ? stripHtmlTags(source) : source;
    }
  }
  return '';
};

const resolveLightweightDocumentText = (file: CaseResolverWorkspace['files'][number]): string => {
  const text = resolveTextContent(file);
  return text.trim().length > 0
    ? truncate(normalizeWhitespace(text), CASE_RESOLVER_WORKSPACE_LIGHTWEIGHT_TEXT_MAX_CHARS)
    : '';
};



const resolveDetachedDocumentsEntry = (
  file: CaseResolverWorkspace['files'][number]
): CaseResolverWorkspaceDetachedDocumentsFileEntry | null => {
  const entry: CaseResolverWorkspaceDetachedDocumentsFileEntry = { id: file.id };
  let hasHeavyPayload = false;
  const addString = (
    key: Exclude<keyof CaseResolverWorkspaceDetachedDocumentsFileEntry, 'id' | 'scanSlots'>,
    value: unknown,
    options?: { heavy?: boolean }
  ): void => {
    if (typeof value !== 'string') return;
    if (value.length === 0) return;
    entry[key] = value;
    if (options?.heavy !== false) {
      hasHeavyPayload = true;
    }
  };

  addString('documentContent', file.documentContent);
  addString('documentContentHtml', file.documentContentHtml);
  addString('documentContentMarkdown', file.documentContentMarkdown);
  addString('documentContentPlainText', file.documentContentPlainText, { heavy: false });
  addString('originalDocumentContent', file.originalDocumentContent);
  addString('explodedDocumentContent', file.explodedDocumentContent);
  addString('ocrText', file.ocrText);

  if (!hasHeavyPayload) {
    return null;
  }

  if (Array.isArray(file.scanSlots) && file.scanSlots.length > 0) {
    entry.scanSlots = file.scanSlots;
  }

  return entry;
};

export const buildCaseResolverWorkspaceDetachedDocumentsPayload = (
  workspace: CaseResolverWorkspace
): CaseResolverWorkspaceDetachedDocumentsPayload => ({
  schema: CASE_RESOLVER_WORKSPACE_DETACHED_DOCUMENTS_SCHEMA,
  workspaceRevision: getCaseResolverWorkspaceRevision(workspace),
  lastMutationId:
    typeof workspace.lastMutationId === 'string' && workspace.lastMutationId.trim().length > 0
      ? workspace.lastMutationId.trim()
      : null,
  files: workspace.files
    .filter((file): boolean => file.fileType === 'document' || file.fileType === 'scanfile')
    .map((file): CaseResolverWorkspaceDetachedDocumentsFileEntry | null =>
      resolveDetachedDocumentsEntry(file)
    )
    .filter(
      (
        entry: CaseResolverWorkspaceDetachedDocumentsFileEntry | null
      ): entry is CaseResolverWorkspaceDetachedDocumentsFileEntry => Boolean(entry)
    ),
});

const stripDetachedDocumentFields = (file: CaseResolverWorkspace['files'][number]): CaseResolverWorkspace['files'][number] => {
      if (file.fileType !== 'document' && file.fileType !== 'scanfile') return file;

      const fileRecord: Record<string, unknown> = { ...file };
      const keysToRemove = [
        'documentContent',
        'documentContentHtml',
        'documentContentMarkdown',
        'originalDocumentContent',
        'explodedDocumentContent',
        'ocrText',
      ];
      keysToRemove.forEach((key) => delete fileRecord[key]);

      if (file.fileType === 'document') {
        const lightweightText = resolveLightweightDocumentText(file);
        if (lightweightText.length > 0) {
          fileRecord['documentContentPlainText'] = lightweightText;
        } else {
          delete fileRecord['documentContentPlainText'];
        }
      }

      return fileRecord as unknown as CaseResolverWorkspace['files'][number];
    };

    export const stripCaseResolverWorkspaceDetachedDocuments = (
      workspace: CaseResolverWorkspace
    ): CaseResolverWorkspace => {
      if (!Array.isArray(workspace.files) || workspace.files.length === 0) return workspace;
      return {
        ...workspace,
        files: workspace.files.map(stripDetachedDocumentFields),
      };
    };
export const parseCaseResolverWorkspaceDetachedDocumentsPayload = (
  raw: string | null | undefined
): CaseResolverWorkspaceDetachedDocumentsPayload | null => {
  if (typeof raw !== 'string' || raw.trim().length === 0) return null;
  const parsed = safeParseJson<unknown>(raw);
  if (!parsed) return null;

  const result = DetachedDocumentsPayloadSchema.safeParse(parsed);
  return result.success ? result.data : null;
};

export const applyCaseResolverWorkspaceDetachedDocumentsPayload = ({
  workspace,
  detachedDocumentsPayload,
}: {
  workspace: CaseResolverWorkspace;
  detachedDocumentsPayload: CaseResolverWorkspaceDetachedDocumentsPayload | null;
}): CaseResolverWorkspace => {
  if (!detachedDocumentsPayload) return workspace;
  const workspaceRevision = getCaseResolverWorkspaceRevision(workspace);
  if (workspaceRevision <= 0 || detachedDocumentsPayload.workspaceRevision !== workspaceRevision) {
    return workspace;
  }
  const workspaceLastMutationId =
    typeof workspace.lastMutationId === 'string' && workspace.lastMutationId.trim().length > 0
      ? workspace.lastMutationId.trim()
      : null;
  if (
    detachedDocumentsPayload.lastMutationId !== null &&
    detachedDocumentsPayload.lastMutationId !== workspaceLastMutationId
  ) {
    return workspace;
  }
  if (detachedDocumentsPayload.files.length === 0 || workspace.files.length === 0) return workspace;
  const payloadByFileId = new Map<string, CaseResolverWorkspaceDetachedDocumentsFileEntry>(
    detachedDocumentsPayload.files.map(
      (entry): [string, CaseResolverWorkspaceDetachedDocumentsFileEntry] => [entry.id, entry]
    )
  );
  let updated = false;
  const files = workspace.files.map((file): CaseResolverWorkspace['files'][number] => {
    const payload = payloadByFileId.get(file.id);
    if (!payload) return file;
    updated = true;
    const fileRecord: Record<string, unknown> = { ...file };
    const mergeString = (
      key: Exclude<keyof CaseResolverWorkspaceDetachedDocumentsFileEntry, 'id' | 'scanSlots'>
    ): void => {
      const value = payload[key];
      if (typeof value !== 'string' || value.length === 0) return;
      fileRecord[key] = value;
    };
    mergeString('documentContent');
    mergeString('documentContentHtml');
    mergeString('documentContentMarkdown');
    mergeString('documentContentPlainText');
    mergeString('originalDocumentContent');
    mergeString('explodedDocumentContent');
    mergeString('ocrText');
    if (Array.isArray(payload.scanSlots)) {
      fileRecord['scanSlots'] = payload.scanSlots;
    }
    return coerceDetachedWorkspaceFile(fileRecord);
  });
  return updated ? { ...workspace, files } : workspace;
};

import { type CaseResolverWorkspace } from '@/shared/contracts/case-resolver';

import {
  getCaseResolverWorkspaceRevision,
  safeParseJson,
} from './utils/workspace-persistence-utils';
import { type CaseResolverWorkspaceDetachedPayload } from './workspace-persistence-detached.types';

export const CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA_V2 =
  'case_resolver_workspace_detached_history_v2';
const CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA =
  CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA_V2;
const CASE_RESOLVER_DOCUMENT_HISTORY_VERSIONS = new Set(['original', 'exploded']);
const CASE_RESOLVER_DOCUMENT_HISTORY_EDITORS = new Set([
  'wysiwyg',
  'markdown',
  'code',
  'rich-text',
  'plain-text',
]);

type CaseResolverWorkspaceDetachedHistoryFileEntry = {
  id: string;
  documentHistory: CaseResolverWorkspace['files'][number]['documentHistory'];
};

export type CaseResolverWorkspaceDetachedHistoryPayload = CaseResolverWorkspaceDetachedPayload<
  typeof CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA,
  CaseResolverWorkspaceDetachedHistoryFileEntry
>;

const coerceDetachedWorkspaceFile = (
  value: unknown
): CaseResolverWorkspace['files'][number] => value as CaseResolverWorkspace['files'][number];

const isCaseResolverDocumentHistoryEntry = (
  entry: unknown
): entry is CaseResolverWorkspace['files'][number]['documentHistory'][number] => {
  if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return false;
  const record = entry as Record<string, unknown>;

  const id = record['id'];
  const savedAt = record['savedAt'];
  const documentContentVersion = record['documentContentVersion'];
  const activeDocumentVersion = record['activeDocumentVersion'];
  const editorType = record['editorType'];
  const documentContent = record['documentContent'];

  return (
    typeof id === 'string' &&
    id.trim().length > 0 &&
    typeof savedAt === 'string' &&
    savedAt.trim().length > 0 &&
    typeof documentContentVersion === 'number' &&
    Number.isFinite(documentContentVersion) &&
    typeof activeDocumentVersion === 'string' &&
    CASE_RESOLVER_DOCUMENT_HISTORY_VERSIONS.has(activeDocumentVersion) &&
    typeof editorType === 'string' &&
    CASE_RESOLVER_DOCUMENT_HISTORY_EDITORS.has(editorType) &&
    typeof documentContent === 'string'
  );
};

const normalizeDetachedHistoryFiles = (
  input: unknown
): CaseResolverWorkspaceDetachedHistoryPayload['files'] => {
  if (!Array.isArray(input)) return [];
  const seen = new Set<string>();
  return input
    .map((entry: unknown): CaseResolverWorkspaceDetachedHistoryFileEntry | null => {
      if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return null;
      const entryRecord = entry as Record<string, unknown>;
      const id = typeof entryRecord['id'] === 'string' ? entryRecord['id'].trim() : '';
      if (!id || seen.has(id)) return null;
      const documentHistory = entryRecord['documentHistory'];
      if (!Array.isArray(documentHistory) || documentHistory.length === 0) return null;
      seen.add(id);
      return {
        id,
        documentHistory: documentHistory.filter(isCaseResolverDocumentHistoryEntry),
      };
    })
    .filter(
      (
        entry: CaseResolverWorkspaceDetachedHistoryFileEntry | null
      ): entry is CaseResolverWorkspaceDetachedHistoryFileEntry => Boolean(entry)
    );
};

export const buildCaseResolverWorkspaceDetachedHistoryPayload = (
  workspace: CaseResolverWorkspace
): CaseResolverWorkspaceDetachedHistoryPayload => ({
  schema: CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA,
  workspaceRevision: getCaseResolverWorkspaceRevision(workspace),
  lastMutationId:
    typeof workspace.lastMutationId === 'string' && workspace.lastMutationId.trim().length > 0
      ? workspace.lastMutationId.trim()
      : null,
  files: Array.isArray(workspace.files)
    ? workspace.files
      .map((file): CaseResolverWorkspaceDetachedHistoryFileEntry | null => {
        const documentHistory = Array.isArray(file.documentHistory) ? file.documentHistory : [];
        if (documentHistory.length === 0) return null;
        return {
          id: file.id,
          documentHistory,
        };
      })
      .filter(
        (
          entry: CaseResolverWorkspaceDetachedHistoryFileEntry | null
        ): entry is CaseResolverWorkspaceDetachedHistoryFileEntry => Boolean(entry)
      )
    : [],
});

export const stripCaseResolverWorkspaceDetachedHistory = (
  workspace: CaseResolverWorkspace
): CaseResolverWorkspace => {
  if (!Array.isArray(workspace.files) || workspace.files.length === 0) return workspace;
  return {
    ...workspace,
    files: workspace.files.map((file): CaseResolverWorkspace['files'][number] => {
      const fileRecord: Record<string, unknown> = { ...file };
      delete fileRecord['documentHistory'];
      return coerceDetachedWorkspaceFile(fileRecord);
    }),
  };
};

export const parseCaseResolverWorkspaceDetachedHistoryPayload = (
  raw: string | null | undefined
): CaseResolverWorkspaceDetachedHistoryPayload | null => {
  if (typeof raw !== 'string' || raw.trim().length === 0) return null;
  const parsed = safeParseJson<unknown>(raw);
  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return null;
  const record = parsed as Record<string, unknown>;
  const schemaRaw = record['schema'];
  if (
    typeof schemaRaw !== 'string' ||
    schemaRaw !== CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA
  ) {
    return null;
  }
  const workspaceRevisionRaw = record['workspaceRevision'];
  const workspaceRevision =
    typeof workspaceRevisionRaw === 'number' &&
    Number.isFinite(workspaceRevisionRaw) &&
    workspaceRevisionRaw > 0
      ? Math.floor(workspaceRevisionRaw)
      : 0;
  const lastMutationIdRaw = record['lastMutationId'];
  const lastMutationId =
    typeof lastMutationIdRaw === 'string' && lastMutationIdRaw.trim().length > 0
      ? lastMutationIdRaw.trim()
      : null;
  return {
    schema: CASE_RESOLVER_WORKSPACE_DETACHED_HISTORY_SCHEMA,
    workspaceRevision,
    lastMutationId,
    files: normalizeDetachedHistoryFiles(record['files']),
  };
};

export const applyCaseResolverWorkspaceDetachedHistoryPayload = ({
  workspace,
  detachedHistoryPayload,
}: {
  workspace: CaseResolverWorkspace;
  detachedHistoryPayload: CaseResolverWorkspaceDetachedHistoryPayload | null;
}): CaseResolverWorkspace => {
  if (!detachedHistoryPayload) return workspace;
  const workspaceRevision = getCaseResolverWorkspaceRevision(workspace);
  if (workspaceRevision <= 0 || detachedHistoryPayload.workspaceRevision !== workspaceRevision) {
    return workspace;
  }
  const workspaceLastMutationId =
    typeof workspace.lastMutationId === 'string' && workspace.lastMutationId.trim().length > 0
      ? workspace.lastMutationId.trim()
      : null;
  if (
    detachedHistoryPayload.lastMutationId !== null &&
    detachedHistoryPayload.lastMutationId !== workspaceLastMutationId
  ) {
    return workspace;
  }
  if (detachedHistoryPayload.files.length === 0 || workspace.files.length === 0) {
    return workspace;
  }
  const historyByFileId = new Map<
    string,
    CaseResolverWorkspace['files'][number]['documentHistory']
  >(
    detachedHistoryPayload.files.map(
      (entry): [string, CaseResolverWorkspace['files'][number]['documentHistory']] => [
        entry.id,
        entry.documentHistory,
      ]
    )
  );
  let updated = false;
  const files = workspace.files.map((file): CaseResolverWorkspace['files'][number] => {
    const detachedHistory = historyByFileId.get(file.id);
    if (!detachedHistory) return file;
    updated = true;
    return {
      ...file,
      documentHistory: detachedHistory,
    };
  });
  return updated
    ? {
      ...workspace,
      files,
    }
    : workspace;
};

